--------------------------------------------------------
--  DDL for View EMP_DEPT_V
--------------------------------------------------------

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "TEREXT"."EMP_DEPT_V" ("EMPNO", "ENAME", "JOB", "MGR", "HIREDATE", "SAL", "COMM", "DEPTNO", "DNAME", "LOC") DEFAULT COLLATION "USING_NLS_COMP"  AS 
  select e.empno
,      e.ename
,      e.job
,      (select m.ename from emp m where e.mgr = m.empno) mgr
,      e.hiredate
,      e.sal
,      e.comm
,      d.deptno
,      d.dname
,      d.loc
from emp e
,    dept d
where e.deptno = d.deptno (+)
;
--------------------------------------------------------
--  DDL for View TEREXT_SLOT_CR_DTLS_V
--------------------------------------------------------

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "TEREXT"."TEREXT_SLOT_CR_DTLS_V" ("SLOT_NUMBER", "PLATFORM", "SYSTEM", "SLOT_TYPE", "SLOT_STATUS", "CR_NUMBER", "RAISED_BY", "REQUEST_DATE", "REQUEST_STATUS") DEFAULT COLLATION "USING_NLS_COMP"  AS 
  select
hdr.SLOT_NUMBER,
hdr.PLATFORM,
hdr.SYSTEM,
hdr.SLOT_TYPE,
hdr.SLOT_STATUS,
NVL(cr.CR_NUMBER,null) as CR_NUMBER,
cr.RAISED_BY,
cr.REQUEST_DATE,
cr.REQUEST_STATUS
from
terext_slot_plan_dtls hdr
LEFT JOIN TEREXT_SLOT_CR_DTLS cr
ON hdr.SLOT_NUMBER = cr.SLOT_NUMBER
and cr.REQUEST_STATUS='Submitted'
--where hdr.slot_status NOT IN ('Shipped','Booked');
where hdr.slot_status NOT IN ('Shipped')
;
--------------------------------------------------------
--  DDL for View TEREXT_SLOT_CR_REVIEW_DTLS_V
--------------------------------------------------------

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "TEREXT"."TEREXT_SLOT_CR_REVIEW_DTLS_V" ("SLOT_NUMBER", "CR_NUMBER", "PLATFORM", "SYSTEM", "SLOT_TYPE", "SLOT_STATUS", "OLD_FORECAST_NAME", "OLD_CUSTOMER_NAME", "OLD_CONFIG_NUMBER", "OLD_SALES_ORDER", "OLD_PROMISED_DATE", "NEW_FORECAST_NAME", "NEW_SLOT_STATUS", "NEW_CUSTOMER_NAME", "NEW_CUSTOMER_SITE", "NEW_CONFIG_NUMBER", "NEW_SALES_ORDER", "NEW_PROMISED_DATE", "REQUEST_DATE", "RAISED_BY", "REQUEST_STATUS", "NEW_OPERATION_COMMENTS", "NEW_MARKETING_COMMENTS") DEFAULT COLLATION "USING_NLS_COMP"  AS 
  select
hdr.SLOT_NUMBER,
cr.cr_number,
hdr.PLATFORM,
hdr.SYSTEM,
hdr.SLOT_TYPE,
hdr.SLOT_STATUS,
mkt.FORECAST_NAME as OLD_FORECAST_NAME,
hdr.CUSTOMER as OLD_CUSTOMER_NAME,
hdr.CONFIG_NUMBER as OLD_CONFIG_NUMBER,
ops.SALES_ORDER as OLD_SALES_ORDER,
hdr.PROMISED_DATE as OLD_PROMISED_DATE,
cr.NEW_FORECAST_NAME,
cr.NEW_SLOT_STATUS,
cr.NEW_CUSTOMER_NAME, 
cr.NEW_CUSTOMER_SITE, 
cr.NEW_CONFIG_NUMBER,       
cr.NEW_SALES_ORDER,  
cr.NEW_PROMISED_DATE,
cr.REQUEST_DATE,
cr.RAISED_BY,
cr.REQUEST_STATUS,
cr.OPERATION_COMMENTS as NEW_OPERATION_COMMENTS,
cr.MARKETING_COMMENTS as NEW_MARKETING_COMMENTS
from
terext_slot_plan_dtls hdr
LEFT JOIN TEREXT_SLOT_CR_DTLS cr
ON hdr.SLOT_NUMBER = cr.SLOT_NUMBER
LEFT JOIN TEREXT_SLOT_PLAN_MKT_DTLS mkt
ON hdr.SLOT_NUMBER = mkt.SLOT_NUMBER
LEFT JOIN TEREXT_SLOT_PLAN_OPS_DTLS ops
ON hdr.SLOT_NUMBER = ops.SLOT_NUMBER
;
--------------------------------------------------------
--  DDL for View TERSLOT_PLAN_DTLS_V
--------------------------------------------------------

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "TEREXT"."TERSLOT_PLAN_DTLS_V" ("SNO_NUMBER", "SLOT_NUMBER", "PD_QTR", "MRP_QTR", "PLATFORM", "SYSTEM", "SLOT_TYPE", "SLOT_STATUS", "CUSTOMER", "DEMAND_CLASS", "SCHEDULE_DATE", "PROMISED_DATE", "ACTUAL_DATE", "SALES_ORDER", "PLANNING_ORGANIZATION", "MFR", "MFR_SITE", "FORECAST_NAME", "REVENUE", "CONFIG_NUMBER", "REQUEST_NUMBER", "CUSTOMER_DATE", "CUSTOMER_SITE_ID", "REVENUE_QTR", "SYSTEM_COUNT", "REVENUE_SYSTEM_COUNT", "SYSTEM_COUNT_ADJ", "REVENUE_ADJ", "COGS_ADJ", "ADJUSTMENT_COMMENT", "FINANCE_COMMENTS", "MARKETING_COMMENTS", "OPERATIONS_COMMENTS") DEFAULT COLLATION "USING_NLS_COMP"  AS 
  SELECT
    ROWNUM       AS sno_number,
--    hdr.slot_id,
    hdr.slot_number,
    hdr.pd_qtr,
    hdr.mrp_qtr,
    hdr.platform,
    hdr.system,
    hdr.slot_type,
    hdr.slot_status,
    hdr.customer,
    hdr.demand_class,
    hdr.schedule_date,
    hdr.promised_date,
    --pt.quantity,
    --pt.part_number,
    --pt.part_description,
    ops.actual_date,
    ops.sales_order,
    --ops.planning_organization,
    NVL(ops.planning_organization,hdr.planning_organization) planning_organization,
--    ops.mfr,
    NVL(ops.mfr,hdr.manufacture) mfr,
--    ops.mfr_site,
    NVL(ops.mfr_site,hdr.manufacture_site)mfr_site,
    mkt.forecast_name,
    mkt.revenue,
--    mkt.config_number,
    NVL(mkt.config_number,hdr.config_number) config_number,
    mkt.request_number,
    mkt.customer_date,
    mkt.customer_site_id,
    fin.revenue_qtr,
    fin.system_count,
    fin.revenue_system_count,
    fin.system_count_adj,
    fin.revenue_adj,
    fin.cogs_adj,
    fin.adjustment_comment,
    fin.finance_comments,
--    mkt.marketing_comments,
    NVL(mkt.marketing_comments,hdr.marketing_comments) marketing_comments,
--    mkt.operations_comments
    NVL(ops.operations_comments,hdr.operation_comments) operations_comments

FROM
    terext_slot_plan_dtls     hdr,
    --terext_slot_parts         pt,
    terext_slot_plan_ops_dtls ops,
    terext_slot_plan_mkt_dtls mkt,
    terext_slot_plan_fin_dtls fin
WHERE 1=1
   -- AND hdr.slot_number = pt.slot_number (+)
    AND hdr.slot_number = ops.slot_number (+)
    AND hdr.slot_number = mkt.slot_number (+)
    AND hdr.slot_number = fin.slot_number (+)
;
