  CREATE OR REPLACE EDITIONABLE TRIGGER "TEREXT"."SL_GL_COA_DISABLE_AUR_T" 
After Update on SL_GL_COA_SEGMENT_VALUE_STG 
for each row
   WHEN ((new.flag='N') OR (NEW.END_DATE < OLD.END_DATE)) Declare
PRAGMA AUTONOMOUS_TRANSACTION;  
BEGIN

--insert into SL_GL_TBL_TIME_HIST (a) values ('After Update on SL_GL_COA_SEGMENT_VALUE_STG start');
--commit;
/* -- COMMENTED ON 26-AUG-2024
dbms_scheduler.create_job (
  job_name   =>  'Update_COA_DISABLE_FLAG'||SL_GL_COA_DISABLE_S.nextval,
  job_type   => 'PLSQL_BLOCK',
  job_action => 
    'BEGIN 
       SL_GL_DISABLED_COA_HANDLE_PKG.GL_DISABLED_COA_HANDLE_PRC('||NVL(''''||:old.SOURCE_SEGMENT1||'''','NULL')||','||NVL(''''||:old.SOURCE_SEGMENT2||'''','NULL')||','||NVL(''''||:old.SOURCE_SEGMENT3||'''','NULL')||','||NVL(''''||:old.SOURCE_SEGMENT4||'''','NULL')||','||NVL(''''||:old.SOURCE_SEGMENT5||'''','NULL')||','||NVL(''''||:old.SOURCE_SEGMENT6||'''','NULL')||','||NVL(''''||:old.SOURCE_SEGMENT7||'''','NULL')||','||NVL(''''||:old.SOURCE_SEGMENT8||'''','NULL')||','||NVL(''''||:old.SOURCE_SEGMENT9||'''','NULL')||','||NVL(''''||:old.SOURCE_SEGMENT10||'''','NULL')||','||:old.rule_id||');
     END;',
  enabled   =>  TRUE,  
  auto_drop =>  TRUE, 
  comments  =>  'Update_COA_DISABLE_FLAG '); */


-- Commented On 03-Sep-2024
-- ADDED ON 26-AUG-2024
-- below blocks to update end date
-- no need to update end date for from old.flag N to new.flag Y, its new derivation through conversion

--Insert into xx_text (s_no, error_message,stage) values (21,'Entered Trigger','Trigger');

IF  ((:new.flag = 'Y' and :old.flag = 'Y') or 
     (:new.flag = 'N' and :old.flag = 'Y')) and 
     ((:new.END_DATE < :old.END_DATE) or 
      (:new.END_DATE > :old.END_DATE))
then

--Insert into xx_text (s_no, error_message,stage) values (21,'P_IN_VALUE_ID => '||:old.VALUE_ID,'Trigger');
commit;
dbms_scheduler.create_job (
  job_name   =>  'Update_COA_END_DATE'||SL_GL_COA_DISABLE_S.nextval,
  job_type   => 'PLSQL_BLOCK',
  job_action => 
    'BEGIN
	 SL_GL_DISABLED_COA_HANDLE_PKG.COA_update_CCID_end_date_PRC (P_IN_VALUE_ID => '||:old.VALUE_ID||');
	 END;',
  enabled   =>  TRUE,  
  auto_drop =>  TRUE, 
  comments  =>  'Update_COA_END_DATE ');  
end if;

-- ADDED ON 26-AUG-2024
-- Disable cahce when any one source segment get disabled
IF :new.flag='N' THEN
dbms_scheduler.create_job (
  job_name   =>  'Update_COA_DISABLE_FLAG'||SL_GL_COA_DISABLE_S.nextval,
  job_type   => 'PLSQL_BLOCK',
  job_action => 
    'BEGIN
	 SL_GL_DISABLED_COA_HANDLE_PKG.COA_DISABLE_CCID_PRC (P_IN_VALUE_ID => '||:old.VALUE_ID||');
	 END;',
  enabled   =>  TRUE,  
  auto_drop =>  TRUE, 
  comments  =>  'Update_COA_DISABLE_FLAG '); 
END IF; 


/*
-- Added on 03-Sep-2024
-- Below block only get combination in cache table and update the End Date, Doesn't consider Flag
IF :new.END_DATE <> :old.END_DATE
then
Insert into xx_text (s_no, error_message,stage) values (21,'P_IN_VALUE_ID => '||:old.VALUE_ID,'Trigger');
commit;
dbms_scheduler.create_job (
  job_name   =>  'Update_COA_END_DATE'||SL_GL_COA_DISABLE_S.nextval,
  job_type   => 'PLSQL_BLOCK',
  job_action => 
    'BEGIN
	 SL_GL_DISABLED_COA_HANDLE_PKG.COA_update_CCID_end_date_PRC (P_IN_VALUE_ID => '||:old.VALUE_ID||');
	 END;',
  enabled   =>  TRUE,  
  auto_drop =>  TRUE, 
