end if;

-- Below block only get combination in cache table and update the Flag, Doesn't consider End Date
IF :new.flag <> :old.flag THEN
dbms_scheduler.create_job (
  job_name   =>  'Update_COA_DISABLE_FLAG'||SL_GL_COA_DISABLE_S.nextval,
