	 SL_GL_DISABLED_COA_HANDLE_PKG.COA_DISABLE_CCID_PRC (P_IN_VALUE_ID => '||:old.VALUE_ID||',P_IN_FLAG => '''||:new.flag||''');
	 END;',
  enabled   =>  TRUE,  
  auto_drop =>  TRUE, 
  comments  =>  'Update_COA_DISABLE_FLAG '); 
END IF; */
