--------------------------------------------------------
--  DDL for Procedure DELETEOPENONLYSLOTHEADERANDDETAILS
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "TEREXT"."DELETEOPENONLYSLOTHEADERANDDETAILS" 
IS
    v_child_count  NUMBER := 0;
    v_parent_count NUMBER := 0;
BEGIN
    -- Delete children for slots whose parent is Open
    DELETE FROM terext_slot_parts c
     WHERE EXISTS (
           SELECT 1
             FROM terext_slot_plan_dtls p
            WHERE p.slot_id = c.slot_id
              AND p.slot_status = 'Open'
     );

    v_child_count := SQL%ROWCOUNT;

    -- Delete parent rows that are Open
    DELETE FROM terext_slot_plan_dtls
     WHERE slot_status = 'Open';

    v_parent_count := SQL%ROWCOUNT;

    COMMIT;

    dbms_output.put_line('Deleted ' || v_child_count  || ' rows from TEREXT_SLOT_PARTS.');
    dbms_output.put_line('Deleted ' || v_parent_count || ' rows from TEREXT_SLOT_PLAN_DTLS.');
EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        dbms_output.put_line('Error occurred: ' || SQLERRM);
        RAISE;
END deleteopenonlyslotheaderanddetails;

/
--------------------------------------------------------
--  DDL for Procedure DELETESLOTHEADERANDDETAILS
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "TEREXT"."DELETESLOTHEADERANDDETAILS" (
    SLOT_ID IN NUMBER
    --ID IN NUMBER
)
IS
    -- Variable to hold count of deleted rows if needed
    v_child_count NUMBER;
    v_parent_count NUMBER;
BEGIN
    -- Delete from child table first (to maintain foreign key integrity)
    DELETE FROM TEREXT_SLOT_PARTS
    WHERE SLOT_ID = SLOT_ID ;

    v_child_count := SQL%ROWCOUNT; -- number of child rows deleted

    -- Delete from parent table
    DELETE FROM TEREXT_SLOT_PLAN_DTLS
    WHERE SLOT_ID= SLOT_ID ;

    v_parent_count := SQL%ROWCOUNT; -- number of parent rows deleted

    -- Commit the changes
    COMMIT;

    -- Optional: feedback
    DBMS_OUTPUT.PUT_LINE('Deleted ' || v_child_count || ' rows from child_table.');
    DBMS_OUTPUT.PUT_LINE('Deleted ' || v_parent_count || ' row from parent_table.');

EXCEPTION
    WHEN OTHERS THEN
        -- Rollback in case of any error
        ROLLBACK;
        DBMS_OUTPUT.PUT_LINE('Error occurred: ' || SQLERRM);
END DeleteslotheaderAndDetails;

/
--------------------------------------------------------
--  DDL for Procedure GET_SLOT_PLAN_DETAILS
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "TEREXT"."GET_SLOT_PLAN_DETAILS" (
  p_slot_status           IN  VARCHAR2  DEFAULT NULL,
  p_system                IN  VARCHAR2  DEFAULT NULL,
  p_planning_org          IN  VARCHAR2  DEFAULT NULL,
  p_result                OUT SYS_REFCURSOR
)
AS
BEGIN
  OPEN p_result FOR
  SELECT 
      SPD.SLOT_STATUS,
      SPD.SYSTEM,
      SPD.PLANNING_ORGANIZATION,
      SPD.CUSTOMER_ID,
      SPD.CUSTOMER_SITE_ID,
      SPD.DEMAND_CLASS,
      SPD.SCHEDULE_DATE,
      CASE 
          WHEN SPD.SLOT_STATUS = 'OPEN'       THEN DC.QUANTITY
          WHEN SPD.SLOT_STATUS = 'Identified'  THEN QC.QUANTITY
          WHEN SPD.SLOT_STATUS = 'Booked'      THEN SO.QUANTITY
          ELSE SP.QUANTITY
      END                                 AS QUANTITY,
      CASE 
          WHEN SPD.SLOT_STATUS = 'OPEN'       THEN DC.PART_NUMBER
          WHEN SPD.SLOT_STATUS = 'Identified'  THEN QC.PART_NUMBER
          WHEN SPD.SLOT_STATUS = 'Booked'      THEN SO.PART_NUMBER
          ELSE SP.PART_NUMBER
      END                                 AS PART_NUMBER
  FROM 
      TEREXT_SLOT_PLAN_DTLS       SPD
  LEFT JOIN 
      TEREXT_SLOT_PARTS           SP
      ON  SP.SLOT_NUMBER          = SPD.SLOT_NUMBER
      AND SP.CONFIG_NUM           = SPD.CONFIG_NUMBER
  LEFT JOIN 
      TEREXT_SLOT_DEFAULT_CONFIG       DC
      ON  DC.CONFIG_NUMBER        = SPD.CONFIG_NUMBER
  LEFT JOIN 
      TEREXT_QUOTE_CONFIG_DTLS    QC
      ON  QC.CONFIG_NUMBER        = SPD.CONFIG_NUMBER
  LEFT JOIN 
      TEREXT_SO_LINE_DTLS         SO
      ON  SO.SALES_ORDER_NUM      = SPD.SALES_ORDER
  WHERE 
      (p_slot_status IS NULL OR SPD.SLOT_STATUS = p_slot_status)
      AND (p_system IS NULL OR SPD.SYSTEM = p_system)
      AND (p_planning_org IS NULL OR SPD.PLANNING_ORGANIZATION = p_planning_org);
EXCEPTION
  WHEN OTHERS THEN
      IF p_result%ISOPEN THEN
          CLOSE p_result;
      END IF;
      RAISE;
END GET_SLOT_PLAN_DETAILS;

/
--------------------------------------------------------
--  DDL for Procedure GET_SLOT_PLAN_DETAILS_LIST
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "TEREXT"."GET_SLOT_PLAN_DETAILS_LIST" (
  -- Input filters
  p_slot_status               IN  VARCHAR2  DEFAULT NULL,
  p_system                    IN  VARCHAR2  DEFAULT NULL,
  p_planning_org              IN  VARCHAR2  DEFAULT NULL,
  -- Output cursor with named columns for mapping
  x_slot_plan_cursor          OUT SYS_REFCURSOR,
  x_record_count              OUT NUMBER,
  x_return_status             OUT VARCHAR2,
  x_return_message            OUT VARCHAR2
)
AS
BEGIN
  x_return_status  := 'S';
  x_return_message := NULL;
  -- Get record count
  SELECT COUNT(*)
  INTO   x_record_count
  FROM   TEREXT_SLOT_PLAN_DTLS SPD
  WHERE  (p_slot_status IS NULL OR SPD.SLOT_STATUS = p_slot_status)
         AND (p_system IS NULL OR SPD.SYSTEM = p_system)
         AND (p_planning_org IS NULL OR SPD.PLANNING_ORGANIZATION = p_planning_org);
  -- Open cursor with named columns
  OPEN x_slot_plan_cursor FOR
  SELECT 
      SPD.SLOT_STATUS             AS SLOT_STATUS,
      SPD.SYSTEM                  AS SYSTEM,
      SPD.PLANNING_ORGANIZATION   AS PLANNING_ORGANIZATION,
      SPD.CUSTOMER_ID             AS CUSTOMER_ID,
      SPD.CUSTOMER_SITE_ID        AS CUSTOMER_SITE_ID,
      SPD.DEMAND_CLASS            AS DEMAND_CLASS,
      SPD.SCHEDULE_DATE           AS SCHEDULE_DATE,
      CASE 
          WHEN SPD.SLOT_STATUS = 'OPEN'        THEN DC.QUANTITY
          WHEN SPD.SLOT_STATUS = 'Identified'   THEN QC.QUANTITY
          WHEN SPD.SLOT_STATUS = 'Booked'       THEN SO.QUANTITY
          ELSE SP.QUANTITY
      END                         AS QUANTITY,
      CASE 
          WHEN SPD.SLOT_STATUS = 'OPEN'        THEN DC.PART_NUMBER
          WHEN SPD.SLOT_STATUS = 'Identified'   THEN QC.PART_NUMBER
          WHEN SPD.SLOT_STATUS = 'Booked'       THEN SO.PART_NUMBER
          ELSE SP.PART_NUMBER
      END                         AS PART_NUMBER
  FROM 
      TEREXT_SLOT_PLAN_DTLS       SPD
  LEFT JOIN 
      TEREXT_SLOT_PARTS           SP
      ON  SP.SLOT_NUMBER          = SPD.SLOT_NUMBER
      AND SP.CONFIG_NUM           = SPD.CONFIG_NUMBER
  LEFT JOIN 
      TEREXT_SLOT_DEFAULT_CONFIG       DC
      ON  DC.CONFIG_NUMBER        = SPD.CONFIG_NUMBER
  LEFT JOIN 
      TEREXT_QUOTE_CONFIG_DTLS    QC
      ON  QC.CONFIG_NUMBER        = SPD.CONFIG_NUMBER
  LEFT JOIN 
      TEREXT_SO_LINE_DTLS         SO
      ON  SO.SALES_ORDER_NUM      = SPD.SALES_ORDER
  WHERE 
      (p_slot_status IS NULL OR SPD.SLOT_STATUS = p_slot_status)
      AND (p_system IS NULL OR SPD.SYSTEM = p_system)
      AND (p_planning_org IS NULL OR SPD.PLANNING_ORGANIZATION = p_planning_org)
  ORDER BY
      SPD.SCHEDULE_DATE,
      SPD.SLOT_STATUS;
EXCEPTION
  WHEN OTHERS THEN
      x_return_status  := 'E';
      x_return_message := 'Error: ' || SQLERRM;
      IF x_slot_plan_cursor%ISOPEN THEN
          CLOSE x_slot_plan_cursor;
      END IF;
END GET_SLOT_PLAN_DETAILS_LIST;

/
--------------------------------------------------------
--  DDL for Procedure INSERT_TEREXT_SLOT_PLAN_DTLS
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "TEREXT"."INSERT_TEREXT_SLOT_PLAN_DTLS" (
    p_slot_id           IN NUMBER,
    p_slot_number       IN VARCHAR2,
    p_slot_period       IN VARCHAR2,
    p_slot_category     IN VARCHAR2,
