    p_slot_type         IN VARCHAR2,
    p_slot_status       IN VARCHAR2,
    p_demand_class      IN VARCHAR2,
    p_customer          IN VARCHAR2,
    p_customer_id       IN NUMBER,
    p_customer_site_id  IN NUMBER,
    p_config_number     IN NUMBER,
    p_partial_flag      IN VARCHAR2,
    p_schedule_date     IN DATE,
    p_promised_date     IN DATE,
    p_mrp_qtr           IN VARCHAR2,
    p_sf_flag           IN VARCHAR2,
    p_bi_flag           IN VARCHAR2,
    p_notication_flag   IN VARCHAR2,
    p_source            IN VARCHAR2,
    p_read_only         IN VARCHAR2,
    p_created_by        IN VARCHAR2,
    p_creation_date     IN DATE,
    p_last_updated_by   IN VARCHAR2,
    p_last_update_date  IN DATE
)
IS
BEGIN
    INSERT INTO TEREXT_SLOT_PLAN_DTLS (
        SLOT_ID, SLOT_NUMBER, SLOT_PERIOD, SLOT_CATEGORY, SLOT_ITEM,
        SLOT_TYPE, SLOT_STATUS, DEMAND_CLASS, CUSTOMER, CUSTOMER_ID, CUSTOMER_SITE_ID,
        CONFIG_NUMBER, PARTIAL_FLAG, SCHEDULE_DATE, PROMISED_DATE, MRP_QTR,
        SF_FLAG, BI_FLAG, NOTICATION_FLAG, SOURCE, READ_ONLY,
