        p_created_by, p_creation_date, p_last_updated_by, p_last_update_date
    );
END;

/
--------------------------------------------------------
--  DDL for Procedure OPEN_DELETESLOTHEADERANDDETAILS
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "TEREXT"."OPEN_DELETESLOTHEADERANDDETAILS" (
    p_slot_id IN NUMBER
) IS
    v_child_count  NUMBER := 0;
    v_parent_count NUMBER := 0;
    v_open_exists  NUMBER := 0;
BEGIN
    -- Check parent status first (assumes slot_status is on TEREXT_SLOT_PLAN_DTLS)
    SELECT COUNT(*)
      INTO v_open_exists
      FROM terext_slot_plan_dtls
     WHERE slot_id = p_slot_id
       AND slot_status = 'Open';

    IF v_open_exists = 0 THEN
        dbms_output.put_line('No delete: slot not Open (or not found). slot_id=' || p_slot_id);
        RETURN;
    END IF;

    -- Delete child rows first
    DELETE FROM terext_slot_parts
     WHERE slot_id = p_slot_id;

    v_child_count := SQL%ROWCOUNT;

    -- Delete parent row(s) (guarded by status)
    DELETE FROM terext_slot_plan_dtls
     WHERE slot_id = p_slot_id
       AND slot_status = 'Open';

    v_parent_count := SQL%ROWCOUNT;

    COMMIT;

    dbms_output.put_line('Deleted ' || v_child_count  || ' rows from TEREXT_SLOT_PARTS.');
    dbms_output.put_line('Deleted ' || v_parent_count || ' rows from TEREXT_SLOT_PLAN_DTLS.');
EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        dbms_output.put_line('Error occurred: ' || SQLERRM);
        RAISE;
END Open_deleteslotheaderanddetails;

/
--------------------------------------------------------
--  DDL for Procedure TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "TEREXT"."TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC" (
    p_date    IN  VARCHAR2,
    p_rec_cnt OUT NUMBER
)
AS
    l_cnt NUMBER := 0;
    TYPE TERDTP_SHIPHIST_OBJ IS RECORD (
        CUSTOMER_ID      VARCHAR2(2000),
        CUSTOMER_NAME    VARCHAR2(2000),
        PART_NAME        VARCHAR2(2000),
        SITE_VALUE       VARCHAR2(2000),
        ACTUAL_SHIP_DATE VARCHAR2(2000),
        QUANTITY         VARCHAR2(2000),
        REQUEST_DATE     VARCHAR2(2000),
        ORDER_ID         VARCHAR2(2000),
        LINE_NUM         VARCHAR2(2000),
        ORDER_SITE       VARCHAR2(2000),
        UNIT_PRICE       VARCHAR2(2000),
        U_DEMAND_CLASS   VARCHAR2(2000),
        UNIT_COST        VARCHAR2(2000)
    );

    TYPE TERDTP_SHIPHIST_TAB IS TABLE OF TERDTP_SHIPHIST_OBJ;

    lv_shiphist_tbl TERDTP_SHIPHIST_TAB;

BEGIN

    -- -----------------------------------------------------------------------
    -- Step 1 : Purge staging tables
    -- -----------------------------------------------------------------------
    BEGIN
        DELETE FROM TERDTP_MSC_CUST_FLAT_STG;
        DELETE FROM TERDTP_DOO_FULFILL_LINES_STG;
        DELETE FROM TERDTP_CST_STD_COSTS_STG;
        DELETE FROM TERDTP_RR_SHIPHISTORY_STG;
        COMMIT;
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM, 1, 250);
        INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
        VALUES (p_date, 'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - Deletion', 'ERROR', gv_error);
        COMMIT;
    END;

    -- -----------------------------------------------------------------------
    -- Step 2a : Load MSC_DEMANDS BIP extract
    --           (TERDTP_MSC_DEMANDS may be shared; skip purge if shared)
    -- -----------------------------------------------------------------------
    BEGIN
        DELETE FROM TERDTP_MSC_DEMANDS;
        COMMIT;
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM, 1, 250);
        INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
        VALUES (p_date, 'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - Delete MSC_DEMANDS', 'ERROR', gv_error);
        COMMIT;
    END;

    BEGIN
        DBMS_CLOUD.COPY_DATA(
            table_name      => 'TERDTP_MSC_DEMANDS',
            credential_name => 'TER_FUSION_INT_TO_TEREXT',
            file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date ||'/*DemandPlanningBIP*.csv',
            format => JSON_OBJECT(
                'delimiter'       VALUE ',',
                'skipheaders'     VALUE '1',
                'timestampformat' VALUE 'YYYY-MM-DD HH24:MI:SS.FF6',
                'removequotes'    VALUE 'true'
            )
        );
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM, 1, 250);
        INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, FILE_NAME, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
        VALUES (p_date, 'shipHistoryDemandBIP',
                'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - COPY_DATA MSC_DEMANDS', 'ERROR', gv_error);
        COMMIT;
    END;

    BEGIN
        DBMS_CLOUD.COPY_DATA(
            table_name      => 'TERDTP_MSC_CUST_FLAT_STG',
            credential_name => 'TER_FUSION_INT_TO_TEREXT',
            file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date || '/*analyticalCustFlatBIP*.csv',
            format => JSON_OBJECT(
                'delimiter'       VALUE ',',
                'skipheaders'     VALUE '1',
                'timestampformat' VALUE 'YYYY-MM-DD HH24:MI:SS.FF6',
                'removequotes'    VALUE 'true'
            )
        );
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM, 1, 250);
        INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, FILE_NAME, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
        VALUES (p_date, 'analyticalCustFlatBIP',
                'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - COPY_DATA CUST_FLAT', 'ERROR', gv_error);
        COMMIT;
    END;

    BEGIN
        DBMS_CLOUD.COPY_DATA(
            table_name      => 'TERDTP_DOO_FULFILL_LINES_STG',
            credential_name => 'TER_FUSION_INT_TO_TEREXT',
            file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'
                               || p_date || '/*dooFulfillLinesBIP*.csv',
            format => JSON_OBJECT(
                'delimiter'       VALUE ',',
                'skipheaders'     VALUE '1',
                'timestampformat' VALUE 'YYYY-MM-DD HH24:MI:SS.FF6',
                'removequotes'    VALUE 'true'
            )
        );
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM, 1, 250);
        INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, FILE_NAME, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
        VALUES (p_date, 'dooFulfillLinesBIP',
                'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - COPY_DATA DOO_FULFILL_LINES', 'ERROR', gv_error);
        COMMIT;
    END;
    BEGIN
      SELECT DISTINCT
           cust.CUSTOMER_ID AS customer_id,
           cust.CUSTOMER_NAME AS customer_name,
           itm.Item_name   AS part_name,
           MAP.ORGANIZATION_CODE     AS site_value,
           ffl.ACTUAL_SHIP_DATE AS actual_ship_date,
          dem.COMPLETED_QUANTITY AS quantity,
          dem.REQUEST_DATE AS request_date,
          dem.SALES_ORDER_NUMBER AS order_id,
          dem.SO_LINE_NUM AS line_num,
          MAP.ORGANIZATION_CODE             AS order_site,
          dem.SELLING_PRICE  AS unit_price,
          ffl.DEMAND_CLASS_CODE AS u_demand_class,
          cst.TOTAL_COST AS unit_cost     
        FROM
            MSC_DEMANDS dem
            LEFT JOIN MSC_ANALYTIC_CUST_FLAT_V_DYD  cust
                ON  dem.CUSTOMER_ID = cust.CUSTOMER_ID
            LEFT JOIN DOO_FULFILL_LINES_ALL ffl
                ON  dem.SALES_ORDER_NUMBER = ffl.SOURCE_ORDER_NUMBER
                AND dem.SO_LINE_NUM = ffl.SOURCE_LINE_NUMBER
            LEFT JOIN MSC_SYSTEM_ITEMS  itm
                ON  dem.INVENTORY_ITEM_ID=itm.INVENTORY_ITEM_ID
                AND dem.ORGANIZATION_ID = itm.ORGANIZATION_ID
            LEFT JOIN CST_STD_COSTS cst
                ON  ffl.INVENTORY_ITEM_ID= cst.INVENTORY_ITEM_ID
                AND ffl.INVENTORY_ORGANIZATION_ID = cst.INVENTORY_ORG_ID
            LEFT JOIN MSC_PARAMETERS MAP
                  ON dem.ORGANIZATION_ID=MAP.ORGANIZATION_ID
            JOIN FND_LOOKUP_VALUES lkp
                ON lkp.LOOKUP_TYPE = 'TER_INT_RAPID_RESPONSE'
                AND lkp.LOOKUP_CODE = MAP.ORGANIZATION_CODE
        WHERE
            TRUNC(ffl.ACTUAL_SHIP_DATE) >= TRUNC(TO_DATE(p_date, 'YYYYMMDD'), 'IW') - 7
           -- AND TRUNC(ffl.ACTUAL_SHIP_DATE) < TRUNC(TO_DATE(p_date, 'YYYYMMDD'), 'IW')
        ORDER BY
            order_id,
            line_num;

    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM, 1, 250);
        INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
        VALUES (p_date, 'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - Data Transformation', 'ERROR', gv_error);
        COMMIT;
    END;

    DBMS_OUTPUT.PUT_LINE('Records fetched: ' || lv_shiphist_tbl.COUNT);

    -- -----------------------------------------------------------------------
    -- Step 4 : FORALL INSERT into output staging table
    -- -----------------------------------------------------------------------
    IF lv_shiphist_tbl.COUNT > 0 THEN

        FORALL i IN lv_shiphist_tbl.FIRST .. lv_shiphist_tbl.LAST
            INSERT INTO TERDTP_RR_SHIPHISTORY_STG (
                CUSTOMER_ID,
                CUSTOMER_NAME,
                PART_NAME,
                SITE_VALUE,
                ACTUAL_SHIP_DATE,
                QUANTITY,
                REQUEST_DATE,
                ORDER_ID,
                LINE_NUM,
                ORDER_SITE,
                UNIT_PRICE,
                U_DEMAND_CLASS,
                UNIT_COST
            ) VALUES (
                lv_shiphist_tbl(i).CUSTOMER_ID,
                lv_shiphist_tbl(i).CUSTOMER_NAME,
                lv_shiphist_tbl(i).PART_NAME,
                lv_shiphist_tbl(i).SITE_VALUE,
                lv_shiphist_tbl(i).ACTUAL_SHIP_DATE,
                lv_shiphist_tbl(i).QUANTITY,
                lv_shiphist_tbl(i).REQUEST_DATE,
                lv_shiphist_tbl(i).ORDER_ID,
                lv_shiphist_tbl(i).LINE_NUM,
                lv_shiphist_tbl(i).ORDER_SITE,
                lv_shiphist_tbl(i).UNIT_PRICE,
                lv_shiphist_tbl(i).U_DEMAND_CLASS,
                lv_shiphist_tbl(i).UNIT_COST
            );

        DBMS_OUTPUT.PUT_LINE('Records inserted: ' || SQL%ROWCOUNT);
        l_cnt := SQL%ROWCOUNT;
        COMMIT;

        IF (lv_shiphist_tbl.COUNT = l_cnt) THEN
            DBMS_OUTPUT.PUT_LINE('Success.');

            -- -----------------------------------------------------------------
            -- Step 5 : Export pipe-delimited output file to Object Storage
            --          File name: OF_HistoricalDemandActual.csv
            -- -----------------------------------------------------------------
            BEGIN
                DBMS_CLOUD.EXPORT_DATA(
                    credential_name => 'TER_FUSION_INT_TO_TEREXT',
                    file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Outbound/'
                                       || p_date || '/OF_HistoricalDemandActual.csv',
                    query           => 'SELECT * FROM TERDTP_RR_SHIPHISTORY_STG ORDER BY ORDER_ID, LINE_NUM',
                    format => JSON_OBJECT(
                        'type'        VALUE 'csv',
                        'delimiter'   VALUE '|',
                        'maxfilesize' VALUE '1048576000'
                    )
                );
            EXCEPTION WHEN OTHERS THEN
                gv_error := SUBSTR(SQLERRM, 1, 250);
                INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, FILE_NAME, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
                VALUES (p_date, 'OF_HistoricalDemandActual',
                        'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - EXPORT_DATA', 'ERROR', gv_error);
                COMMIT;
            END;

            -- -----------------------------------------------------------------
            -- Step 6a : Archive MSC_DEMANDS source files
            -- -----------------------------------------------------------------
            BEGIN
                DBMS_CLOUD.BULK_MOVE(
                    source_credential_name => 'TER_FUSION_INT_TO_TEREXT',
                    source_location_uri    => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'
                                              || p_date || '/*shipHistoryDemandBIP*',
                    target_credential_name => 'TER_FUSION_INT_TO_TEREXT',
                    target_location_uri    => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Archive/'
                                              || p_date || '/',
                    format => JSON_OBJECT('logretention' VALUE 7, 'logprefix' VALUE 'BULKOP')
                );
            EXCEPTION WHEN OTHERS THEN
                gv_error := SUBSTR(SQLERRM, 1, 250);
                INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, FILE_NAME, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
                VALUES (p_date, 'shipHistoryDemandBIP',
                        'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - Archive Processed Files', 'ERROR', gv_error);
                COMMIT;
            END;

            -- -----------------------------------------------------------------
            -- Step 6b : Archive Customer flat source files
            -- -----------------------------------------------------------------
            BEGIN
                DBMS_CLOUD.BULK_MOVE(
                    source_credential_name => 'TER_FUSION_INT_TO_TEREXT',
                    source_location_uri    => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'
                                              || p_date || '/*analyticalCustFlatBIP*',
                    target_credential_name => 'TER_FUSION_INT_TO_TEREXT',
                    target_location_uri    => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Archive/'
                                              || p_date || '/',
                    format => JSON_OBJECT('logretention' VALUE 7, 'logprefix' VALUE 'BULKOP')
                );
            EXCEPTION WHEN OTHERS THEN
                gv_error := SUBSTR(SQLERRM, 1, 250);
                INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, FILE_NAME, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
                VALUES (p_date, 'analyticalCustFlatBIP',
                        'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - Archive Processed Files', 'ERROR', gv_error);
                COMMIT;
            END;

            -- -----------------------------------------------------------------
            -- Step 6c : Archive DOO Fulfill Lines source files
            -- -----------------------------------------------------------------
            BEGIN
                DBMS_CLOUD.BULK_MOVE(
                    source_credential_name => 'TER_FUSION_INT_TO_TEREXT',
                    source_location_uri    => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'
                                              || p_date || '/*dooFulfillLinesBIP*',
                    target_credential_name => 'TER_FUSION_INT_TO_TEREXT',
