--------------------------------------------------------
--  DDL for Procedure TERDTP_ONHAND_PRC
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "TEREXT"."TERDTP_ONHAND_PRC" (
  p_date                      IN VARCHAR2,
  p_rec_cnt                   OUT NUMBER
)
AS
  gv_error VARCHAR2(250);
  l_cnt NUMBER := 0;

  TYPE TERDTP_ONHAND_DATA IS RECORD (
    Item_Name                 VARCHAR2(1000),
    Subinventory_Code         VARCHAR2(1000),
    Locator_Name              VARCHAR2(1000),
    Netting_Type              VARCHAR2(1000),
    TotalTransactionQuantity  NUMBER,
    ORGANIZATION_CODE         VARCHAR2(1000)
  );

  TYPE TERDTP_ONHAND_TAB IS TABLE OF TERDTP_ONHAND_DATA;

  lv_partms_tbl   TERDTP_ONHAND_TAB;                 
  lv_success_tbl  TERDTP_ONHAND_TAB := TERDTP_ONHAND_TAB();
  lv_error_tbl    TERDTP_ONHAND_TAB := TERDTP_ONHAND_TAB();

BEGIN
  BEGIN
  DELETE FROM TERDTP_RR_ONHAND_ITEMS;
    DELETE FROM TERDTP_RR_ONHAND_RECORDS;
    DELETE FROM TERDTP_RR_ONHAND_ERROR_RECORDS;
    COMMIT;
  EXCEPTION
    WHEN OTHERS THEN
      gv_error := SUBSTR(SQLERRM, 1, 250);
      INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
      VALUES (p_date, 'TERDTP_ONHAND_PRC - Deletion', 'ERROR', gv_error);
      COMMIT;
  END;

BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERDTP_RR_ONHAND_ITEMS',   
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*wpoh_orcl_ITEM*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'wpoh_orcl_ITEM BIP Report','TERDTP_ONHAND_PRC - COPY_DATA','ERROR',gv_error);
    COMMIT;
END;
  BEGIN
    WITH onhand AS (
      SELECT
        o.ITEMBPEOORGANIZATIONID                     AS OrganizationId,
        o.ITEMBPEOITEMNUMBER                         AS ItemNumber,
        o.InventoryOnhandPEOSubinventoryCode         AS SubinventoryCode,
        o.InventoryOnhandPEOLocatorId                AS InventoryLocationId,
        SUM(o.InventoryOnhandPEOTransactionQuantity) AS TotalTransactionQuantity
      FROM TERDTP_RR_ONHAND_QUANTITY o
      GROUP BY
        o.ITEMBPEOORGANIZATIONID,
        o.ITEMBPEOITEMNUMBER,
        o.InventoryOnhandPEOSubinventoryCode,
        o.InventoryOnhandPEOLocatorId
    )
    SELECT DISTINCT
      tmi.ITEM_NAME                                   AS Item_Name,
      oh.SubinventoryCode                             AS Subinventory_Code,
      loc.LocatorName                                 AS Locator_Name,
      CASE WHEN nt.NETTING_TYPE = 2 THEN 'NNET' ELSE 'NET' END AS Netting_Type,
      oh.TotalTransactionQuantity                     AS TotalTransactionQuantity,
      tmi.ORGANIZATION_CODE                           AS ORGANIZATION_CODE
    BULK COLLECT INTO lv_partms_tbl
    FROM TERDTP_RR_ONHAND_ITEMS tmi
    JOIN TERDTP_RR_ORGCODE tis
      ON tmi.ORGANIZATION_CODE = tis.ORG_ORGANIZATIONCODE
    LEFT JOIN onhand oh
      ON oh.OrganizationId = tis.ORGANIZATIONID
     AND oh.ItemNumber      = tmi.ITEM_NAME
    LEFT JOIN TERINV_SUBINV_LOCATOR_STG loc
      ON loc.InventoryLocationId = oh.InventoryLocationId
    LEFT JOIN TERDTP_RR_SUBINV_NETTYPE nt
      ON nt.PLAN_ID            = tmi.PLAN_ID
     AND nt.ORGANIZATION_ID    = tmi.ORGANIZATION_ID
     AND nt.SUB_INVENTORY_CODE = oh.SubinventoryCode;

  EXCEPTION
    WHEN OTHERS THEN
      gv_error := SUBSTR(SQLERRM, 1, 250);
      INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
      VALUES (p_date, 'TERDTP_ONHAND_PRC - Data Transformation', 'ERROR', gv_error);
      COMMIT;
  END;

  FOR i IN 1 .. lv_partms_tbl.COUNT LOOP
    IF lv_partms_tbl(i).Subinventory_Code IS NOT NULL
       AND lv_partms_tbl(i).ORGANIZATION_CODE IS NOT NULL
       AND lv_partms_tbl(i).TotalTransactionQuantity IS NOT NULL
    THEN
      lv_success_tbl.EXTEND;
      lv_success_tbl(lv_success_tbl.LAST) := lv_partms_tbl(i);
    ELSE
      lv_error_tbl.EXTEND;
      lv_error_tbl(lv_error_tbl.LAST) := lv_partms_tbl(i);
    END IF;
  END LOOP;

  IF lv_success_tbl.COUNT > 0 THEN
    FORALL i IN 1 .. lv_success_tbl.COUNT
      INSERT INTO TERDTP_RR_ONHAND_RECORDS (
        item_name,
        subinventory_code,
        locator_name,
        netting_type,
        totaltransactionquantity,
        organization_code
      )
      VALUES (
        lv_success_tbl(i).Item_Name,
        lv_success_tbl(i).Subinventory_Code,
        lv_success_tbl(i).Locator_Name,
        lv_success_tbl(i).Netting_Type,
        lv_success_tbl(i).TotalTransactionQuantity,
        lv_success_tbl(i).ORGANIZATION_CODE
      );
  END IF;
  IF lv_error_tbl.COUNT > 0 THEN
    FORALL i IN 1 .. lv_error_tbl.COUNT
      INSERT INTO TERDTP_RR_ONHAND_ERROR_RECORDS (
        item_name,
        subinventory_code,
        locator_name,
        netting_type,
        totaltransactionquantity,
        organization_code,
        error_reason
      )
      VALUES (
        lv_error_tbl(i).Item_Name,
        lv_error_tbl(i).Subinventory_Code,
        lv_error_tbl(i).Locator_Name,
        lv_error_tbl(i).Netting_Type,
        lv_error_tbl(i).TotalTransactionQuantity,
        lv_error_tbl(i).ORGANIZATION_CODE,
        'MISSING_REQUIRED_FIELDS'
      );
  END IF;

EXCEPTION
  WHEN OTHERS THEN
     gv_error := SUBSTR(SQLERRM, 1, 250);
      INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
      VALUES (p_date, 'TERDTP_ONHAND_PRC - Data Transformation', 'ERROR', gv_error);
      COMMIT;

END TERDTP_ONHAND_PRC;

/
--------------------------------------------------------
--  DDL for Procedure TERDTP_PARTSOURCE_PRC
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "TEREXT"."TERDTP_PARTSOURCE_PRC" (
  p_date                      IN VARCHAR2
)
AS
  gv_error VARCHAR2(250);
  l_cnt NUMBER := 0;

  TYPE TERDTP_PARTSOURCE_PRC_DATA IS RECORD (
    base_key VARCHAR2(2000),
    postprocessing_lead_time NUMBER,
    effectiveindate VARCHAR2(1000),
    effectiveoutdate VARCHAR2(1000),
    fixed_lead_time NUMBER,
    maximum_order_quantity NUMBER,
    minimum_order_quantity NUMBER,
    fixed_lot_multiplier NUMBER,
    part_name VARCHAR2(2000),
    PartSite_Value VARCHAR2(2000),
    planning_time_fence_days NUMBER,
    allocation_percent NUMBER,
    source_code VARCHAR2(200),
    PARTNER_Name VARCHAR2(2000),
    item_name VARCHAR2(2000),
    TRANSFERPARTSITE VARCHAR2(2000)
  );

  TYPE TERDTP_PARTSOURCE_TAB IS TABLE OF TERDTP_PARTSOURCE_PRC_DATA;

  lv_partms_tbl   TERDTP_PARTSOURCE_TAB;                 



BEGIN

BEGIN
  DELETE FROM TERDTP_RR_PART_SOURCE_LEVEL;
  DELETE FROM TERDTP_RR_MSC_SOURCE;
  DELETE FROM TERDTP_RR_MSC_RECEIPT;
  DELETE FROM TERDTP_RR_MSC_ASSIGNMENT;
  COMMIT;
  EXCEPTION
    WHEN OTHERS THEN
      gv_error := SUBSTR(SQLERRM, 1, 250);
      INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
      VALUES (p_date, 'TERDTP_PARTSOURCE_PRC - Deletion', 'ERROR', gv_error);
      COMMIT;
  END;

BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERDTP_RR_MSC_SOURCE',   
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*wpoh_orcl_ITEM*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'wpoh_orcl_ITEM BIP Report','TERDTP_PARTSOURCE_PRC- COPY_DATA','ERROR',gv_error);
    COMMIT;
END;

BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERDTP_RR_MSC_RECEIPT',   
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*wpoh_orcl_Subinv*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'wpoh_orcl_Subinv BIP Report','TERDTP_PARTSOURCE_PRC - COPY_DATA','ERROR',gv_error);
    COMMIT;
END;

BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERDTP_RR_MSC_ASSIGNMENT',   
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*inventoryonhandpvo*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'inventoryonhandpvo','TERDTP_PARTSOURCE_PRC - COPY_DATA','ERROR',gv_error);
    COMMIT;
END;

BEGIN
WITH cal AS(
  SELECT
      MIN(calendar_date) AS min_cal_key,
      MAX(calendar_date) AS max_cal_key
  FROM TERDTP_RR_ORG_CALENDAR
),
base AS (
  SELECT
      ms.item_name as part_name,
      ms.organization_code,
      ms.postprocessing_lead_time,
      ms.fixed_lead_time,
      ms.fixed_lot_multiplier,
      ms.planning_time_fence_days,
      mss.allocation_percent,
      mss.source_code,
      mss.source_type,
      CASE
        WHEN mr.effective_date IS NULL
          OR mr.effective_date < cal.min_cal_key
          THEN 'PAST'
          WHEN mr.effective_date<= cal.max_cal_key
           THEN mr.effective_date
        ELSE 'FUTURE'
      END AS effectiveindate,
     CASE
        WHEN mr.disable_date IS NULL
          OR mr.disable_date > cal.max_cal_key
          THEN 'FUTURE'
        WHEN mr.disable_date < cal.min_cal_key
          THEN 'PAST'
        ELSE mr.disable_date
      END AS effectiveoutdate,
      CASE
        WHEN NVL(ms.fixed_order_quantity, 0) > 0 THEN ms.fixed_order_quantity
        ELSE ms.maximum_order_quantity
      END AS maximum_order_quantity,
      CASE
        WHEN NVL(ms.fixed_order_quantity, 0) > 0 THEN ms.fixed_order_quantity
        ELSE ms.minimum_order_quantity
      END AS minimum_order_quantity,
      CASE mss.source_type
        WHEN 1 THEN MAP.ORGANIZATION_CODE
        WHEN 2 THEN ms.organization_code
        WHEN 3 THEN ms.organization_code
        ELSE NULL
      END AS PartSite_Value,
      CASE mss.source_type
        WHEN 3 THEN mp.partnername
        ELSE NULL
      END AS PARTNER_NAME,
       ms.item_name,
      CASE mss.source_type
        WHEN 1 THEN MAS.ORGANIZATION_CODE
        WHEN 2 THEN ms.organization_code
        WHEN 3 THEN ms.organization_code
        ELSE NULL
      END AS TRANSFERPARTSITE
  FROM TERmsc_system_items ms
  JOIN TERFND_CMNLKP_VAUES lkp
    ON lkp.meaning = ms.organization_code
   AND lkp.lookuptype = 'TER_INT_RAPID_RESPONSE'
  LEFT JOIN TERDTP_RR_msc_assignment ma
    ON ms.inventory_item_id = ma.inventory_item_id
   AND ms.organization_id   = ma.organization_id
  LEFT JOIN TERDTP_RR_msc_receipt mr
    ON ma.sourcing_rule_id  = mr.sourcing_rule_id
  LEFT JOIN TERDTP_RR_msc_source mss
    ON mr.sr_receipt_id     = mss.sr_receipt_id
  LEFT JOIN TERPO_SUPPLIER_STG mp
    ON mp.tpid = mss.source_partner_id
  LEFT JOIN TERDTP_MSC_PARAMETERS MAP
    ON MA.ORGANIZATION_ID=MAP.ORGANIZATION_ID
  LEFT JOIN TERDTP_MSC_PARAMETERS MAS
     ON MSS.ORGANIZATION_ID=MAS.ORGANIZATION_ID
  CROSS JOIN cal
  WHERE ms.plan_id = -1

)
SELECT DISTINCT
    item_name
    || '_' || organization_code
    || partner_name 
    || '_' || CAST(effectiveindate AS VARCHAR2(100))
    || '_' || CAST(effectiveoutdate AS VARCHAR2(100)) AS base_key,
    postprocessing_lead_time,
    effectiveindate,
    effectiveoutdate,
    fixed_lead_time,
    maximum_order_quantity,
    minimum_order_quantity,
    fixed_lot_multiplier,
    part_name,
    PartSite_Value,
    planning_time_fence_days,
    allocation_percent,
    source_code,
    PARTNER_Name,
    item_name,
    TRANSFERPARTSITE
BULK COLLECT INTO lv_partms_tbl
FROM base;
  EXCEPTION
    WHEN OTHERS THEN
      gv_error := SUBSTR(SQLERRM, 1, 250);
      INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
      VALUES (p_date, 'TERDTP_PARTSOURCE_PRC - Data Transformation', 'ERROR', gv_error);
      COMMIT;
  END;
  IF lv_partms_tbl.COUNT > 0 THEN
    FORALL i IN 1 .. lv_partms_tbl.COUNT
      INSERT INTO TERDTP_RR_PART_SOURCE_LEVEL (
       base_key,
       postprocessing_lead_time,
       effectiveindate ,
       effectiveoutdate,
       fixed_lead_time ,
       maximum_order_quantity ,
       minimum_order_quantity ,
       fixed_lot_multiplier ,
       part_name,
       PartSite_Value,
       planning_time_fence_days ,
       allocation_percent ,
       source_code,
       PARTNER_Name,
       item_name,
       TRANSFERPARTSITE 
       )
      VALUES (
      lv_partms_tbl(i).base_key,
      lv_partms_tbl(i).postprocessing_lead_time,
      lv_partms_tbl(i).effectiveindate ,
      lv_partms_tbl(i).effectiveoutdate,
      lv_partms_tbl(i).fixed_lead_time ,
      lv_partms_tbl(i).maximum_order_quantity ,
      lv_partms_tbl(i).minimum_order_quantity ,
      lv_partms_tbl(i).fixed_lot_multiplier ,
      lv_partms_tbl(i).part_name,
      lv_partms_tbl(i).PartSite_Value,
      lv_partms_tbl(i).planning_time_fence_days ,
      lv_partms_tbl(i).allocation_percent ,
      lv_partms_tbl(i).source_code,
      lv_partms_tbl(i).PARTNER_Name,
      lv_partms_tbl(i).item_name,
      lv_partms_tbl(i).TRANSFERPARTSITE
      );
  END IF;
EXCEPTION
  WHEN OTHERS THEN
     gv_error := SUBSTR(SQLERRM, 1, 250);
      INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
      VALUES (p_date, 'TERDTP_PARTSOURCE_PRC - Data Transformation', 'ERROR', gv_error);
      COMMIT;
END TERDTP_PARTSOURCE_PRC;



