)
AS
  lv_map_name VARCHAR2(200) := UPPER(p_map_name);
BEGIN
  IF lv_map_name = 'Navision to Fusion' THEN
      MERGE INTO TER_RTR_NAVISION_RAW_STG stg
      USING (
          SELECT 
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 1)  AS SRC1,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 2)  AS SRC2,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 3)  AS SRC3,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 4)  AS SRC4,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 5)  AS SRC5,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 6)  AS SRC6,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 7)  AS SRC7,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 8)  AS SRC8,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 9)  AS SRC9,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 10) AS SRC10,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 1)  AS TGT1,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 2)  AS TGT2,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 3)  AS TGT3,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 4)  AS TGT4,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 5)  AS TGT5,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 6)  AS TGT6,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 7)  AS TGT7,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 8)  AS TGT8,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 9)  AS TGT9,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 10) AS TGT10
          FROM SL_GL_CCID_MAPPING_STG
          WHERE UPPER(COA_MAP_NAME) = lv_map_name
      ) map
      ON (
              stg.BATCH_ID = p_batch_id
          AND NVL(stg.SOURCE_SEGMENT1,  '000')        = NVL(map.SRC1,  '000')
          AND NVL(stg.SOURCE_SEGMENT2,  '0000000')    = NVL(map.SRC2,  '0000000')
          AND NVL(stg.SOURCE_SEGMENT3,  '000000')     = NVL(map.SRC3,  '000000')
          AND NVL(stg.SOURCE_SEGMENT4,  '000')        = NVL(map.SRC4,  '000')
          AND NVL(stg.SOURCE_SEGMENT5,  '000000')     = NVL(map.SRC5,  '000000')
          AND NVL(stg.SOURCE_SEGMENT6,  '00000')      = NVL(map.SRC6,  '00000')
          AND NVL(stg.SOURCE_SEGMENT7,  '0000')       = NVL(map.SRC7,  '0000')
          AND NVL(stg.SOURCE_SEGMENT8,  '0000000000') = NVL(map.SRC8,  '0000000000')
          AND NVL(stg.SOURCE_SEGMENT9,  '000000')     = NVL(map.SRC9,  '000000')
          AND NVL(stg.SOURCE_SEGMENT10, '0000000')    = NVL(map.SRC10, '0000000')
      )
      WHEN MATCHED THEN UPDATE SET
          stg.TARGET_SEGMENT1  = map.TGT1,
          stg.TARGET_SEGMENT2  = map.TGT2,
          stg.TARGET_SEGMENT3  = map.TGT3,
          stg.TARGET_SEGMENT4  = map.TGT4,
          stg.TARGET_SEGMENT5  = map.TGT5,
          stg.TARGET_SEGMENT6  = map.TGT6,
          stg.TARGET_SEGMENT7  = map.TGT7,
          stg.TARGET_SEGMENT8  = map.TGT8,
          stg.TARGET_SEGMENT9  = map.TGT9,
          stg.TARGET_SEGMENT10 = map.TGT10;
      COMMIT;
  ELSIF lv_map_name = 'AX to Fusion' THEN
      MERGE INTO TER_RTR_ORACLE_AX_RAW_STG stg
      USING (
          SELECT 
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 1)  AS SRC1,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 2)  AS SRC2,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 3)  AS SRC3,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 4)  AS SRC4,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 5)  AS SRC5,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 6)  AS SRC6,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 7)  AS SRC7,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 8)  AS SRC8,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 9)  AS SRC9,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 10) AS SRC10,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 1)  AS TGT1,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 2)  AS TGT2,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 3)  AS TGT3,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 4)  AS TGT4,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 5)  AS TGT5,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 6)  AS TGT6,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 7)  AS TGT7,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 8)  AS TGT8,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 9)  AS TGT9,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 10) AS TGT10
          FROM SL_GL_CCID_MAPPING_STG
          WHERE UPPER(COA_MAP_NAME) = lv_map_name
      ) map
      ON (
              stg.BATCH_ID = p_batch_id
          AND NVL(stg.SOURCE_SEGMENT1,  '000')        = NVL(map.SRC1,  '000')
          AND NVL(stg.SOURCE_SEGMENT2,  '0000000')    = NVL(map.SRC2,  '0000000')
          AND NVL(stg.SOURCE_SEGMENT3,  '000000')     = NVL(map.SRC3,  '000000')
          AND NVL(stg.SOURCE_SEGMENT4,  '000')        = NVL(map.SRC4,  '000')
          AND NVL(stg.SOURCE_SEGMENT5,  '000000')     = NVL(map.SRC5,  '000000')
          AND NVL(stg.SOURCE_SEGMENT6,  '00000')      = NVL(map.SRC6,  '00000')
          AND NVL(stg.SOURCE_SEGMENT7,  '0000')       = NVL(map.SRC7,  '0000')
          AND NVL(stg.SOURCE_SEGMENT8,  '0000000000') = NVL(map.SRC8,  '0000000000')
          AND NVL(stg.SOURCE_SEGMENT9,  '000000')     = NVL(map.SRC9,  '000000')
          AND NVL(stg.SOURCE_SEGMENT10, '0000000')    = NVL(map.SRC10, '0000000')
      )
      WHEN MATCHED THEN UPDATE SET
          stg.TARGET_SEGMENT1  = map.TGT1,
          stg.TARGET_SEGMENT2  = map.TGT2,
          stg.TARGET_SEGMENT3  = map.TGT3,
          stg.TARGET_SEGMENT4  = map.TGT4,
          stg.TARGET_SEGMENT5  = map.TGT5,
          stg.TARGET_SEGMENT6  = map.TGT6,
          stg.TARGET_SEGMENT7  = map.TGT7,
          stg.TARGET_SEGMENT8  = map.TGT8,
          stg.TARGET_SEGMENT9  = map.TGT9,
          stg.TARGET_SEGMENT10 = map.TGT10;
      COMMIT;
  ELSIF lv_map_name = '11i to Fusion' THEN
      MERGE INTO TER_RTR_ORACLE_11I_RAW_STG stg
      USING (
          SELECT 
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 1)  AS SRC1,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 2)  AS SRC2,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 3)  AS SRC3,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 4)  AS SRC4,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 5)  AS SRC5,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 6)  AS SRC6,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 7)  AS SRC7,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 8)  AS SRC8,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 9)  AS SRC9,
              REGEXP_SUBSTR(SOURCE_SEGMENT, '[^.]+', 1, 10) AS SRC10,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 1)  AS TGT1,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 2)  AS TGT2,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 3)  AS TGT3,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 4)  AS TGT4,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 5)  AS TGT5,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 6)  AS TGT6,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 7)  AS TGT7,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 8)  AS TGT8,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 9)  AS TGT9,
              REGEXP_SUBSTR(TARGET_SEGMENT, '[^.]+', 1, 10) AS TGT10
          FROM SL_GL_CCID_MAPPING_STG
          WHERE UPPER(COA_MAP_NAME) = lv_map_name
      ) map
      ON (
              stg.BATCH_ID = p_batch_id
          AND NVL(stg.SOURCE_SEGMENT1,  '000')        = NVL(map.SRC1,  '000')
          AND NVL(stg.SOURCE_SEGMENT2,  '0000000')    = NVL(map.SRC2,  '0000000')
          AND NVL(stg.SOURCE_SEGMENT3,  '000000')     = NVL(map.SRC3,  '000000')
          AND NVL(stg.SOURCE_SEGMENT4,  '000')        = NVL(map.SRC4,  '000')
          AND NVL(stg.SOURCE_SEGMENT5,  '000000')     = NVL(map.SRC5,  '000000')
          AND NVL(stg.SOURCE_SEGMENT6,  '00000')      = NVL(map.SRC6,  '00000')
          AND NVL(stg.SOURCE_SEGMENT7,  '0000')       = NVL(map.SRC7,  '0000')
          AND NVL(stg.SOURCE_SEGMENT8,  '0000000000') = NVL(map.SRC8,  '0000000000')
          AND NVL(stg.SOURCE_SEGMENT9,  '000000')     = NVL(map.SRC9,  '000000')
          AND NVL(stg.SOURCE_SEGMENT10, '0000000')    = NVL(map.SRC10, '0000000')
      )
      WHEN MATCHED THEN UPDATE SET
          stg.TARGET_SEGMENT1  = map.TGT1,
          stg.TARGET_SEGMENT2  = map.TGT2,
          stg.TARGET_SEGMENT3  = map.TGT3,
          stg.TARGET_SEGMENT4  = map.TGT4,
          stg.TARGET_SEGMENT5  = map.TGT5,
          stg.TARGET_SEGMENT6  = map.TGT6,
          stg.TARGET_SEGMENT7  = map.TGT7,
          stg.TARGET_SEGMENT8  = map.TGT8,
          stg.TARGET_SEGMENT9  = map.TGT9,
          stg.TARGET_SEGMENT10 = map.TGT10;
      COMMIT;
  END IF;
EXCEPTION
  WHEN OTHERS THEN
      ROLLBACK;
      RAISE_APPLICATION_ERROR(-20001, 
          'TERGL_COA_TARGETMAP_PRC failed: ' || SQLERRM);
END TERGL_COA_TARGETMAP_PRC;

