  CREATE OR REPLACE EDITIONABLE PACKAGE "TEREXT"."TERPO_BPA_ATP_PKG" IS
  /* Staging: saari rows (instance + status match) */
  PROCEDURE stg_status_proc(
    p_oic_instance_id_in     IN terpo_bpa_hdr_stg.oic_instance_id%TYPE,
    p_process_set_status_in  IN terpo_bpa_hdr_stg.process_status%TYPE,
    p_process_whr_status_in  IN terpo_bpa_hdr_stg.process_status%TYPE
  );

  /* Staging: sirf ek header + uski child rows (header_key) */
  PROCEDURE stg_status_by_header_proc(
    p_oic_instance_id_in     IN terpo_bpa_hdr_stg.oic_instance_id%TYPE,
    p_header_key_in          IN terpo_bpa_hdr_stg.header_key%TYPE,
    p_process_set_status_in  IN terpo_bpa_hdr_stg.process_status%TYPE,
    p_process_whr_status_in  IN terpo_bpa_hdr_stg.process_status%TYPE
  );

  PROCEDURE stg_inprogress_proc(
    p_oic_instance_id_in    IN terpo_bpa_hdr_stg.oic_instance_id%TYPE,
    p_process_set_status_in IN terpo_bpa_hdr_stg.process_status%TYPE,
    p_set_batchid_in        IN terpo_bpa_hdr_stg.batch_id%TYPE,
    p_bu_id_in              IN terpo_bpa_hdr_stg.bu_id%TYPE
  );

  PROCEDURE stg_interfaceload_proc(
    p_oic_instance_id_in      IN terpo_bpa_hdr_stg.oic_instance_id%TYPE,
    p_process_set_status_in   IN terpo_bpa_hdr_stg.process_status%TYPE,
    p_process_whr_status_in   IN terpo_bpa_hdr_stg.process_status%TYPE,
    p_interface_request_id_in IN terpo_bpa_hdr_stg.interface_request_id%TYPE,
    p_bu_id_in                IN terpo_bpa_hdr_stg.bu_id%TYPE
  );

  PROCEDURE stg_importload_proc(
    p_process_set_status_in       IN terpo_bpa_hdr_stg.process_status%TYPE,
    p_import_set_request_id_in    IN terpo_bpa_hdr_stg.import_request_id%TYPE,
    p_process_whr_status_in       IN terpo_bpa_hdr_stg.process_status%TYPE,
    p_interface_whr_request_id_in IN terpo_bpa_hdr_stg.interface_request_id%TYPE
  );

  PROCEDURE stg_recon_proc(
    p_process_set_status_in IN terpo_bpa_hdr_stg.process_status%TYPE,
    p_header_key_in         IN terpo_bpa_hdr_stg.header_key%TYPE,
    p_oic_instance_id_in    IN terpo_bpa_hdr_stg.oic_instance_id%TYPE,
    p_load_request_id_in    IN terpo_bpa_hdr_stg.interface_request_id%TYPE
  );

  /* HDR + saari child staging par ERROR + message */
  PROCEDURE stg_set_error_proc(
    p_oic_instance_id_in IN terpo_bpa_hdr_stg.oic_instance_id%TYPE,
    p_header_key_in      IN terpo_bpa_hdr_stg.header_key%TYPE,
    p_error_desc_in      IN terpo_bpa_hdr_stg.error_desc%TYPE
  );

  /* Cancel queue: instance + status bulk */
  PROCEDURE cancel_stg_status_proc(
    p_oic_instance_id_in     IN terpo_bpa_cancel_stg.oic_instance_id%TYPE,
    p_process_set_status_in    IN terpo_bpa_cancel_stg.process_status%TYPE,
    p_process_whr_status_in    IN terpo_bpa_cancel_stg.process_status%TYPE
  );

  /* Cancel queue: ek row (cancel_key) */
  PROCEDURE cancel_stg_row_proc(
    p_cancel_key_in       IN terpo_bpa_cancel_stg.cancel_key%TYPE,
    p_process_status_in   IN terpo_bpa_cancel_stg.process_status%TYPE,
    p_error_desc_in       IN terpo_bpa_cancel_stg.error_desc%TYPE DEFAULT NULL
  );

END terpo_bpa_atp_pkg;

