--------------------------------------------------------
--  DDL for Package Body SIT_AX_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."SIT_AX_PKG" AS   
FUNCTION get_target_coa (
        p_in_coa IN VARCHAR2
        ) RETURN VARCHAR
IS 
l_tgt_coa VARCHAR2(1000);
BEGIN    
select target_segment INTO l_tgt_coa 
from SL_GL_CCID_MAPPING_STG where 1=1
and enable_flag='Y'
and coa_map_name='AX to Fusion'
and source_segment=p_in_coa
;
RETURN l_tgt_coa;
EXCEPTION
WHEN OTHERS THEN 
RETURN null;
end get_target_coa;

PROCEDURE TERGL_COA_TARGETMAP_PRC_V(
    p_batch_id  NUMBER,
    p_sub_batch_id NUMBER,
    p_map_name  VARCHAR2
)
IS
CURSOR get_ax_raw_stg IS 
select rowid row_id,
source_segment1,
source_segment2,
source_segment3,
source_segment4,
source_segment5
--, source_segment1||'.' ||source_segment2||'.'||source_segment3||'.'||source_segment4||'.'||source_segment5||'.....' legacy_coa
, get_target_coa(source_segment1||'.' ||source_segment2||'.'||source_segment3||'.'||source_segment4||'.'||source_segment5||'.....') target_coa
from TER_RTR_ORACLE_AX_RAW_STG 
where batch_id=p_batch_id
and sub_batch_id=p_sub_batch_id
and status_code='NEW'
;

TYPE typ_ax_raw_stg_details IS TABLE OF get_ax_raw_stg%rowtype INDEX BY BINARY_INTEGER;
tab_ax_raw_stg_details    typ_ax_raw_stg_details;

l_target_coa VARCHAR2(1000);

BEGIN
        OPEN get_ax_raw_stg;
        LOOP 
        FETCH get_ax_raw_stg BULK COLLECT INTO tab_ax_raw_stg_details LIMIT 1000;
        EXIT WHEN tab_ax_raw_stg_details.COUNT = 0;
       -- CLOSE get_ax_raw_stg; 

        IF tab_ax_raw_stg_details.count > 0 THEN

         FORALL i IN tab_ax_raw_stg_details.first..tab_ax_raw_stg_details.last --SAVE EXCEPTIONS
                    UPDATE TER_RTR_ORACLE_AX_RAW_STG 
                        SET
                    TARGET_SEGMENT1  = REGEXP_SUBSTR(tab_ax_raw_stg_details(i).target_coa, '[^.]+',1),
                    TARGET_SEGMENT2  = REGEXP_SUBSTR(tab_ax_raw_stg_details(i).target_coa, '[^.]+',1,2),
                    TARGET_SEGMENT3  = REGEXP_SUBSTR(tab_ax_raw_stg_details(i).target_coa, '[^.]+',1,3),
                    TARGET_SEGMENT4  = REGEXP_SUBSTR(tab_ax_raw_stg_details(i).target_coa, '[^.]+',1,4),
                    TARGET_SEGMENT5  = REGEXP_SUBSTR(tab_ax_raw_stg_details(i).target_coa, '[^.]+',1,5),
                    TARGET_SEGMENT6  = REGEXP_SUBSTR(tab_ax_raw_stg_details(i).target_coa, '[^.]+',1,6),
                    TARGET_SEGMENT7  = REGEXP_SUBSTR(tab_ax_raw_stg_details(i).target_coa, '[^.]+',1,7),
                    TARGET_SEGMENT8  = REGEXP_SUBSTR(tab_ax_raw_stg_details(i).target_coa, '[^.]+',1,8),
                    TARGET_SEGMENT9  = REGEXP_SUBSTR(tab_ax_raw_stg_details(i).target_coa, '[^.]+',1,9),
                    TARGET_SEGMENT10 = REGEXP_SUBSTR(tab_ax_raw_stg_details(i).target_coa, '[^.]+',1,10)

                  WHERE batch_id = p_batch_id
                  AND sub_batch_id= p_sub_batch_id
                  AND rowid= tab_ax_raw_stg_details(i).row_id
                  ;



        END IF;

        END LOOP;
         CLOSE get_ax_raw_stg; 
        COMMIT;

EXCEPTION 
WHEN OTHERS THEN 
ROLLBACK ;
null;
END;

END SIT_AX_PKG;

/
--------------------------------------------------------
--  DDL for Package Body SL_COA_ENGINE_MAINTENANCE_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."SL_COA_ENGINE_MAINTENANCE_PKG" 
AS

gc_success_status constant varchar2(20) := 'Success';
gc_error_status constant varchar2(20) := 'Error';

PROCEDURE COA_SEGMENT_VALUE_UPLOAD_PRC (P_IN_USER_NAME IN VARCHAR2)
AS

CURSOR CUR_INTF_N IS SELECT ROWID IDENTIFIER, X.* FROM SL_COA_SEGMENT_VALUES_INTF X WHERE USER_NAME = P_IN_USER_NAME 
AND ERROR_STATUS IS NULL AND FLAG = 'N';

CURSOR CUR_INTF_Y IS SELECT ROWID IDENTIFIER, X.* FROM SL_COA_SEGMENT_VALUES_INTF X WHERE USER_NAME = P_IN_USER_NAME 
AND ERROR_STATUS IS NULL AND FLAG = 'Y';

LV_COUNT NUMBER;
LV_VALUE_ID NUMBER;
LV_error_msg varchar2(500);
BEGIN

-- Common Validation Check Rule Name and Source Segments for Flag N & Y

UPDATE SL_COA_SEGMENT_VALUES_INTF 
   SET ERROR_DESC = (CASE WHEN SL_GL_UNIVERSAL_PKG.COA_VALUE_SEGMENT_EXISTS_RULE_NAME(RULE_NAME) = 0
                          THEN RULE_NAME || ' :: RULE_NAME value is invalid. Please verify.' END)
 WHERE USER_NAME = P_IN_USER_NAME;

UPDATE SL_COA_SEGMENT_VALUES_INTF CSVI
   SET RULE_ID = (SELECT DISTINCT CMRT.RULE_ID FROM SL_GL_COA_MAPPING_RULES_STG CMRT WHERE CMRT.RULE_NAME = CSVI.RULE_NAME)
 WHERE USER_NAME = P_IN_USER_NAME
   AND ERROR_DESC IS NULL;

UPDATE SL_COA_SEGMENT_VALUES_INTF 
   SET ERROR_DESC = ERROR_DESC || (CASE WHEN ((SOURCE_SEGMENT1 is null)and(SOURCE_SEGMENT2 is null) and (SOURCE_SEGMENT3 is null )and (SOURCE_SEGMENT4 is null) and (SOURCE_SEGMENT5 is null)
            and (SOURCE_SEGMENT6 is null) and (SOURCE_SEGMENT7 is null) and (SOURCE_SEGMENT8 is null) and (SOURCE_SEGMENT9 is null) and (SOURCE_SEGMENT10 is null))
                          THEN ' -> Atleast one source segment should have a value.' END)
 WHERE USER_NAME = P_IN_USER_NAME;

UPDATE SL_COA_SEGMENT_VALUES_INTF 
   SET ERROR_DESC = ERROR_DESC || (CASE WHEN START_DATE > END_DATE
                          THEN ' -> Start Date Should not be greater than End Date.' END)
 WHERE USER_NAME = P_IN_USER_NAME; 

UPDATE SL_COA_SEGMENT_VALUES_INTF 
   SET ERROR_DESC = ERROR_DESC || (CASE WHEN START_DATE is NULL
                          THEN ' -> Start Date Should have Value.' END)
 WHERE USER_NAME = P_IN_USER_NAME;  

UPDATE SL_COA_SEGMENT_VALUES_INTF 
   SET ERROR_DESC = ERROR_DESC || (CASE WHEN END_DATE is NULL
                          THEN ' -> End Date Should have Value.' END)
 WHERE USER_NAME = P_IN_USER_NAME;  

UPDATE SL_COA_SEGMENT_VALUES_INTF 
   SET ERROR_DESC = ERROR_DESC || (CASE WHEN TARGET_SEGMENT is NULL
                          THEN ' -> Target Segment Should have Value.' END)
 WHERE USER_NAME = P_IN_USER_NAME;   

UPDATE SL_COA_SEGMENT_VALUES_INTF 
   SET ERROR_DESC = ERROR_DESC || (CASE WHEN FLAG is NULL
                          THEN ' -> Flag Should have Value.' END)
 WHERE USER_NAME = P_IN_USER_NAME;    

UPDATE SL_COA_SEGMENT_VALUES_INTF 
   SET ERROR_DESC = ERROR_DESC || (CASE WHEN SL_GL_UNIVERSAL_PKG.COA_VALUE_SEG_IS_NUMBER(TARGET_SEGMENT) = 0
                          THEN ' -> '||TARGET_SEGMENT ||  ' :: TARGET_SEGMENT must have a numeric value.' END)
 WHERE USER_NAME = P_IN_USER_NAME; 

 COMMIT;

UPDATE SL_COA_SEGMENT_VALUES_INTF 
   SET ERROR_Status = (CASE WHEN ERROR_DESC is not null
                            THEN gc_error_status END)
 WHERE USER_NAME = P_IN_USER_NAME;

COMMIT;

-- Loop to Update Flag N

FOR CUR_N IN CUR_INTF_N LOOP

BEGIN
LV_COUNT := 0;
SELECT COUNT(*), VALUE_ID
  INTO LV_COUNT, LV_VALUE_ID
FROM SL_GL_COA_SEGMENT_VALUE_STG CSVT
WHERE (CUR_N.SOURCE_SEGMENT1 = CSVT.SOURCE_SEGMENT1 OR CSVT.SOURCE_SEGMENT1 IS NULL)
    AND	(CUR_N.SOURCE_SEGMENT2 = CSVT.SOURCE_SEGMENT2 OR CSVT.SOURCE_SEGMENT2 IS NULL)
	AND	(CUR_N.SOURCE_SEGMENT3 = CSVT.SOURCE_SEGMENT3 OR CSVT.SOURCE_SEGMENT3 IS NULL)
	AND	(CUR_N.SOURCE_SEGMENT4 = CSVT.SOURCE_SEGMENT4 OR CSVT.SOURCE_SEGMENT4 IS NULL)
	AND	(CUR_N.SOURCE_SEGMENT5 = CSVT.SOURCE_SEGMENT5 OR CSVT.SOURCE_SEGMENT5 IS NULL)
	AND	(CUR_N.SOURCE_SEGMENT6 = CSVT.SOURCE_SEGMENT6 OR CSVT.SOURCE_SEGMENT6 IS NULL)
	AND	(CUR_N.SOURCE_SEGMENT7 = CSVT.SOURCE_SEGMENT7 OR CSVT.SOURCE_SEGMENT7 IS NULL)
	AND	(CUR_N.SOURCE_SEGMENT8 = CSVT.SOURCE_SEGMENT8 OR CSVT.SOURCE_SEGMENT8 IS NULL)
	AND	(CUR_N.SOURCE_SEGMENT9 = CSVT.SOURCE_SEGMENT9 OR CSVT.SOURCE_SEGMENT9 IS NULL)
	AND	(CUR_N.SOURCE_SEGMENT10 = CSVT.SOURCE_SEGMENT10 OR CSVT.SOURCE_SEGMENT10 IS NULL)
	AND CUR_N.TARGET_SEGMENT = CSVT.TARGET_SEGMENT
	AND CUR_N.START_DATE = CSVT.START_DATE
	AND CUR_N.RULE_NAME = CSVT.RULE_NAME
  GROUP BY VALUE_ID;

EXCEPTION WHEN OTHERS THEN 
LV_COUNT:= 0;
END;

IF LV_COUNT > 0 
THEN 
UPDATE SL_GL_COA_SEGMENT_VALUE_STG 
   SET FLAG = CUR_N.FLAG , 
       END_DATE = CUR_N.END_DATE
 WHERE VALUE_ID = LV_VALUE_ID;

UPDATE SL_COA_SEGMENT_VALUES_INTF 
   SET ERROR_STATUS = gc_success_status 
 WHERE ROWID = CUR_N.IDENTIFIER;

ELSE 

UPDATE SL_COA_SEGMENT_VALUES_INTF 
   SET ERROR_STATUS = gc_error_status,
       ERROR_DESC = ERROR_DESC || ' -> Cannot Create Disabled Segment Mapping Values.'
 WHERE ROWID = CUR_N.IDENTIFIER;
END IF;	 

END LOOP;
COMMIT;

-- Validation Check Target Segments Datatype for Flag Y

-- UPDATE SL_COA_SEGMENT_VALUES_INTF 
   -- SET ERROR_DESC = ERROR_DESC || (CASE WHEN SL_GL_UNIVERSAL_PKG.COA_VALUE_SEG_IS_NUMBER(TARGET_SEGMENT) = 0
                          -- THEN ' -> '||TARGET_SEGMENT ||  ' :: TARGET_SEGMENT must have a numeric value.' END)
 -- WHERE USER_NAME = P_IN_USER_NAME
   -- AND FLAG = 'Y';

-- Different Target Name exists for the below combination with over lap dates   
UPDATE SL_COA_SEGMENT_VALUES_INTF 
   SET ERROR_DESC = ERROR_DESC || (CASE WHEN SL_COA_ENGINE_MAINTENANCE_PKG.COA_VALUE_SEG_DUPLICATE_FNC ( 
    p_in_rule_name => rule_name,
    p_in_source_segment1 => source_segment1,
    p_in_source_segment2 => source_segment2,
    p_in_source_segment3 => source_segment3,
    p_in_source_segment4 => source_segment4,
    p_in_source_segment5 => source_segment5,
    p_in_source_segment6 => source_segment6,
    p_in_source_segment7 => source_segment7,
    p_in_source_segment8 => source_segment8,
    p_in_source_segment9 => source_segment9,
    p_in_source_segment10 => source_segment10,
	p_in_target_segment => target_segment,
    p_in_start_date  => start_date,
    p_in_end_date => end_date) = 1
                          THEN ' -> Duplicate Record for given date range.' END)
 WHERE USER_NAME = P_IN_USER_NAME
   AND FLAG = 'Y';  

-- Validate Different Start Date for same combination

UPDATE SL_COA_SEGMENT_VALUES_INTF CSVI
   SET ERROR_DESC = ERROR_DESC || (CASE WHEN SL_COA_ENGINE_MAINTENANCE_PKG.COA_VALUE_SEG_CHK_START_DATE_FNC ( 
    p_in_rule_name => rule_name,
    p_in_source_segment1 => source_segment1,
    p_in_source_segment2 => source_segment2,
    p_in_source_segment3 => source_segment3,
    p_in_source_segment4 => source_segment4,
    p_in_source_segment5 => source_segment5,
    p_in_source_segment6 => source_segment6,
    p_in_source_segment7 => source_segment7,
    p_in_source_segment8 => source_segment8,
    p_in_source_segment9 => source_segment9,
    p_in_source_segment10 => source_segment10,
	p_in_target_segment => target_segment,
    p_in_start_date  => start_date,
    p_in_end_date => end_date) = 1
                          THEN ' -> Start Date cannot be updated. Please create new mapping with appropriate start date and end date.' END)
 WHERE USER_NAME = P_IN_USER_NAME
   AND FLAG = 'Y';    

UPDATE SL_COA_SEGMENT_VALUES_INTF 
   SET ERROR_Status = (CASE WHEN ERROR_DESC is not null
                            THEN gc_error_status END)
 WHERE USER_NAME = P_IN_USER_NAME
   AND FLAG = 'Y';

   COMMIT;

-- Loop to Update END DATE AND UPDATE Flag as well

FOR CUR_Y IN CUR_INTF_Y LOOP

BEGIN
LV_COUNT := 0;

SELECT COUNT(*), VALUE_ID
  INTO LV_COUNT, LV_VALUE_ID
FROM SL_GL_COA_SEGMENT_VALUE_STG CSVT
WHERE (CUR_Y.SOURCE_SEGMENT1 = CSVT.SOURCE_SEGMENT1 OR CSVT.SOURCE_SEGMENT1 IS NULL)
    AND	(CUR_Y.SOURCE_SEGMENT2 = CSVT.SOURCE_SEGMENT2 OR CSVT.SOURCE_SEGMENT2 IS NULL)
	AND	(CUR_Y.SOURCE_SEGMENT3 = CSVT.SOURCE_SEGMENT3 OR CSVT.SOURCE_SEGMENT3 IS NULL)
	AND	(CUR_Y.SOURCE_SEGMENT4 = CSVT.SOURCE_SEGMENT4 OR CSVT.SOURCE_SEGMENT4 IS NULL)
	AND	(CUR_Y.SOURCE_SEGMENT5 = CSVT.SOURCE_SEGMENT5 OR CSVT.SOURCE_SEGMENT5 IS NULL)
	AND	(CUR_Y.SOURCE_SEGMENT6 = CSVT.SOURCE_SEGMENT6 OR CSVT.SOURCE_SEGMENT6 IS NULL)
	AND	(CUR_Y.SOURCE_SEGMENT7 = CSVT.SOURCE_SEGMENT7 OR CSVT.SOURCE_SEGMENT7 IS NULL)
	AND	(CUR_Y.SOURCE_SEGMENT8 = CSVT.SOURCE_SEGMENT8 OR CSVT.SOURCE_SEGMENT8 IS NULL)
	AND	(CUR_Y.SOURCE_SEGMENT9 = CSVT.SOURCE_SEGMENT9 OR CSVT.SOURCE_SEGMENT9 IS NULL)
	AND	(CUR_Y.SOURCE_SEGMENT10 = CSVT.SOURCE_SEGMENT10 OR CSVT.SOURCE_SEGMENT10 IS NULL)
	AND CUR_Y.TARGET_SEGMENT = CSVT.TARGET_SEGMENT
	AND CUR_Y.START_DATE = CSVT.START_DATE
	AND CUR_Y.RULE_NAME = CSVT.RULE_NAME
  GROUP BY VALUE_ID;

EXCEPTION WHEN OTHERS THEN 
LV_COUNT:= 0;
END;

IF LV_COUNT > 0 
THEN 

UPDATE SL_GL_COA_SEGMENT_VALUE_STG 
   SET END_DATE = CUR_Y.END_DATE,
       FLAG = CUR_Y.FLAG
 WHERE VALUE_ID = LV_VALUE_ID;

UPDATE SL_COA_SEGMENT_VALUES_INTF 
   SET ERROR_STATUS = gc_success_status 
 WHERE ROWID = CUR_Y.IDENTIFIER;

END IF;
END LOOP;   

COMMIT;

-- INSERT ERROR RECORD

INSERT INTO SL_GL_CONSOLIDATION_RULE_ERR_HIST(RULE_NAME,
                RULE_ID,
                value_id,
                SOURCE_SEGMENT1,
                SOURCE_SEGMENT2,
                SOURCE_SEGMENT3,
                SOURCE_SEGMENT4,
                SOURCE_SEGMENT5,
                SOURCE_SEGMENT6,
                SOURCE_SEGMENT7,
                SOURCE_SEGMENT8,
                SOURCE_SEGMENT9,
                SOURCE_SEGMENT10,
                TARGET_SEGMENT,
                ERROR_DESC,
				USERNAME,
				start_date,
				end_date,
				FLAG
            ) SELECT RULE_NAME,
                RULE_ID,
                SL_GL_COA_SAGMENT_VALUE_ID_S.nextval,
                SOURCE_SEGMENT1,
                SOURCE_SEGMENT2,
                SOURCE_SEGMENT3,
                SOURCE_SEGMENT4,
                SOURCE_SEGMENT5,
                SOURCE_SEGMENT6,
                SOURCE_SEGMENT7,
                SOURCE_SEGMENT8,
                SOURCE_SEGMENT9,
                SOURCE_SEGMENT10,
                TARGET_SEGMENT,
                ERROR_DESC,
				P_IN_USER_NAME,
				start_date,
				end_date,
				FLAG FROM SL_COA_SEGMENT_VALUES_INTF
				WHERE 1=1
				  AND USER_NAME = P_IN_USER_NAME
				  AND ERROR_STATUS = gc_error_status;

INSERT INTO SL_GL_COA_SEGMENT_VALUE_STG(RULE_NAME,
			RULE_ID,
			value_id,
			SOURCE_SEGMENT1,
			SOURCE_SEGMENT2,
			SOURCE_SEGMENT3,
			SOURCE_SEGMENT4,
			SOURCE_SEGMENT5,
			SOURCE_SEGMENT6,
			SOURCE_SEGMENT7,
			SOURCE_SEGMENT8,
			SOURCE_SEGMENT9,
			SOURCE_SEGMENT10,
			TARGET_SEGMENT,
			USER_NAME,
            FLAG,
            created_by,
            last_updated_by,
			start_date,
			end_date
		) SELECT RULE_NAME,
                RULE_ID,
                SL_GL_COA_SAGMENT_VALUE_ID_S.nextval,
                SOURCE_SEGMENT1,
                SOURCE_SEGMENT2,
                SOURCE_SEGMENT3,
                SOURCE_SEGMENT4,
                SOURCE_SEGMENT5,
                SOURCE_SEGMENT6,
                SOURCE_SEGMENT7,
                SOURCE_SEGMENT8,
                SOURCE_SEGMENT9,
                SOURCE_SEGMENT10,
                TARGET_SEGMENT,
                P_IN_USER_NAME,
                FLAG,
                P_IN_USER_NAME,
                P_IN_USER_NAME,
			    start_date,
			    end_date FROM SL_COA_SEGMENT_VALUES_INTF
				WHERE 1=1
				  AND USER_NAME = P_IN_USER_NAME
				  AND ERROR_STATUS IS NULL
				  AND FLAG = 'Y';

UPDATE SL_COA_SEGMENT_VALUES_INTF 
   SET ERROR_STATUS = gc_success_status 
 WHERE 1=1
   AND USER_NAME = P_IN_USER_NAME
   AND ERROR_STATUS IS NULL
   AND FLAG = 'Y';

 COMMIT;


EXCEPTION WHEN OTHERS THEN 
dbms_output.put_line('error');  
	  LV_error_msg := sqlerrm; -- added on 09-Aug-2024

END COA_SEGMENT_VALUE_UPLOAD_PRC;

FUNCTION  COA_VALUE_SEG_DUPLICATE_FNC ( 
    p_in_rule_name in VARCHAR2,
    p_in_source_segment1 in VARCHAR2,
    p_in_source_segment2 in VARCHAR2,
    p_in_source_segment3 in VARCHAR2,
    p_in_source_segment4 in VARCHAR2,
    p_in_source_segment5 in VARCHAR2,
    p_in_source_segment6 in VARCHAR2,
    p_in_source_segment7 in VARCHAR2,
    p_in_source_segment8 in VARCHAR2,
    p_in_source_segment9 in VARCHAR2,
    p_in_source_segment10 in VARCHAR2,
	p_in_target_segment in varchar2,
    p_in_start_date  in VARCHAR2,
    p_in_end_date in VARCHAR2
) RETURN NUMBER IS 
    lv_ret_count NUMBER;
	lv_start_date date := to_date(p_in_start_date,'dd-mm-yyyy');
	lv_end_date date := to_date(p_in_end_date,'dd-mm-yyyy');
    begin

 lv_ret_count:= 0;

select count(*) into lv_ret_count from SL_GL_COA_SEGMENT_VALUE_STG
where nvl(rule_name,1) = nvl(p_in_rule_name,1)
and nvl(SOURCE_SEGMENT1,1) = nvl(p_in_source_segment1,1)
and nvl(SOURCE_SEGMENT2,1) = nvl(p_in_source_segment2,1)
and nvl(SOURCE_SEGMENT3,1) = nvl(p_in_source_segment3,1)
and nvl(SOURCE_SEGMENT4,1) = nvl(p_in_source_segment4,1)
and nvl(SOURCE_SEGMENT5,1) = nvl(p_in_source_segment5,1)
and nvl(SOURCE_SEGMENT6,1) = nvl(p_in_source_segment6,1)
and nvl(SOURCE_SEGMENT7,1) = nvl(p_in_source_segment7,1)
and nvl(SOURCE_SEGMENT8,1) = nvl(p_in_source_segment8,1)
and nvl(SOURCE_SEGMENT9,1) = nvl(p_in_source_segment9,1)
and nvl(SOURCE_SEGMENT10,1) = nvl(p_in_source_segment10,1)
and nvl(target_segment,1) <> nvl(p_in_target_segment,1)
and( ( lv_start_date between start_date and end_date ) or (lv_end_date between start_date and end_date)
or (lv_start_date<= start_date) and (lv_end_date>= end_date));
--and flag = 'Y';

-- END

    IF lv_ret_count > 0 THEN 

        RETURN 1; 
    ELSE 

        RETURN 0; 
    END IF; 
EXCEPTION 
    WHEN no_data_found THEN 
        RETURN 0; 
    WHEN OTHERS THEN 
        RETURN 0;
    end COA_VALUE_SEG_DUPLICATE_FNC;

FUNCTION  COA_VALUE_SEG_CHK_START_DATE_FNC ( 
    p_in_rule_name in VARCHAR2,
    p_in_source_segment1 in VARCHAR2,
    p_in_source_segment2 in VARCHAR2,
    p_in_source_segment3 in VARCHAR2,
    p_in_source_segment4 in VARCHAR2,
    p_in_source_segment5 in VARCHAR2,
    p_in_source_segment6 in VARCHAR2,
    p_in_source_segment7 in VARCHAR2,
    p_in_source_segment8 in VARCHAR2,
    p_in_source_segment9 in VARCHAR2,
    p_in_source_segment10 in VARCHAR2,
	p_in_target_segment in varchar2,
    p_in_start_date  in VARCHAR2,
    p_in_end_date in VARCHAR2
) RETURN NUMBER IS 
    lv_ret_count NUMBER;
	lv_start_date date := to_date(p_in_start_date,'dd-mm-yyyy');
	lv_end_date date := to_date(p_in_end_date,'dd-mm-yyyy');
    begin

 lv_ret_count:= 0;

select count(*) into lv_ret_count from SL_GL_COA_SEGMENT_VALUE_STG
where nvl(rule_name,1) = nvl(p_in_rule_name,1)
and nvl(SOURCE_SEGMENT1,1) = nvl(p_in_source_segment1,1)
and nvl(SOURCE_SEGMENT2,1) = nvl(p_in_source_segment2,1)
and nvl(SOURCE_SEGMENT3,1) = nvl(p_in_source_segment3,1)
and nvl(SOURCE_SEGMENT4,1) = nvl(p_in_source_segment4,1)
and nvl(SOURCE_SEGMENT5,1) = nvl(p_in_source_segment5,1)
and nvl(SOURCE_SEGMENT6,1) = nvl(p_in_source_segment6,1)
and nvl(SOURCE_SEGMENT7,1) = nvl(p_in_source_segment7,1)
and nvl(SOURCE_SEGMENT8,1) = nvl(p_in_source_segment8,1)
and nvl(SOURCE_SEGMENT9,1) = nvl(p_in_source_segment9,1)
and nvl(SOURCE_SEGMENT10,1) = nvl(p_in_source_segment10,1)
-- and nvl(target_segment,1) = nvl(p_in_target_segment,1)
AND start_date <> lv_start_date;
--and flag = 'Y';

-- END

    IF lv_ret_count > 0 THEN 

        RETURN 1; 
    ELSE 

        RETURN 0; 
    END IF; 
EXCEPTION 
    WHEN no_data_found THEN 
        RETURN 0; 
    WHEN OTHERS THEN 
        RETURN 0;
    end COA_VALUE_SEG_CHK_START_DATE_FNC;	

PROCEDURE COA_CCID_UPLOAD_PRC (P_IN_USER_NAME IN VARCHAR2)
AS

CURSOR CUR_INTF_N IS SELECT ROWID IDENTIFIER, X.* FROM SL_COA_GL_CCID_MAPPING_INTF X WHERE USER_NAME = P_IN_USER_NAME 
AND ERROR_STATUS IS NULL AND ENABLE_FLAG = 'N';

CURSOR CUR_INTF_Y IS SELECT ROWID IDENTIFIER, X.* FROM SL_COA_GL_CCID_MAPPING_INTF X WHERE USER_NAME = P_IN_USER_NAME 
AND ERROR_STATUS IS NULL AND ENABLE_FLAG = 'Y';

LV_COUNT NUMBER;
LV_VALUE_ID NUMBER;
LV_error_msg varchar2(500);

BEGIN

-- Common Validation Check COA Map Name and Source Segments for Flag N & Y

UPDATE SL_COA_GL_CCID_MAPPING_INTF 
   SET ERROR_DESC = (CASE WHEN SL_GL_UNIVERSAL_PKG.CCID_EXIST_COA_MAP_NAME(COA_MAP_NAME) = 0
                          THEN COA_MAP_NAME || ' :: COA_MAP_NAME value is invalid. Please verify.' END)
 WHERE USER_NAME = P_IN_USER_NAME;

UPDATE SL_COA_GL_CCID_MAPPING_INTF CSVI
   SET COA_MAP_ID = (SELECT CMRT.COA_MAP_ID FROM SL_GL_COA_MAP_STG CMRT WHERE UPPER(CMRT.COA_MAP_NAME) = UPPER(CSVI.COA_MAP_NAME))
 WHERE USER_NAME = P_IN_USER_NAME
   AND ERROR_DESC IS NULL; 

UPDATE SL_COA_GL_CCID_MAPPING_INTF 
   SET ERROR_DESC = ERROR_DESC|| ' -> SOURCE_SEGMENT value is invalid. Please verify.'
 WHERE USER_NAME = P_IN_USER_NAME
   AND SOURCE_SEGMENT IS NULL;   

UPDATE SL_COA_GL_CCID_MAPPING_INTF 
   SET ERROR_DESC = ERROR_DESC|| ' -> TARGET_SEGMENT value is invalid. Please verify.'
 WHERE USER_NAME = P_IN_USER_NAME
   AND TARGET_SEGMENT IS NULL;    


UPDATE SL_COA_GL_CCID_MAPPING_INTF 
   SET ERROR_DESC = ERROR_DESC|| ' -> ENABLE_FLAG value is invalid. Please verify.'
 WHERE USER_NAME = P_IN_USER_NAME
   AND ENABLE_FLAG IS NULL;   

/*
-- Commented On 06-Sep-2024, No start date and end date occur on UI Level
UPDATE SL_COA_GL_CCID_MAPPING_INTF 
   SET ERROR_DESC = ERROR_DESC|| ' -> START_DATE should be less than END_DATE. Please verify.'
 WHERE USER_NAME = P_IN_USER_NAME
   AND END_DATE < START_DATE;     

UPDATE SL_COA_GL_CCID_MAPPING_INTF 
   SET ERROR_DESC = ERROR_DESC|| ' -> START_DATE/END_DATE should have Value. Please verify.'
 WHERE USER_NAME = P_IN_USER_NAME
   AND START_DATE IS NULL OR END_DATE IS NULL; */

UPDATE SL_COA_GL_CCID_MAPPING_INTF 
   SET ERROR_Status = (CASE WHEN ERROR_DESC is not null
                            THEN gc_error_status END)
 WHERE USER_NAME = P_IN_USER_NAME;

COMMIT;

-- Loop to Update Flag N

FOR CUR_N IN CUR_INTF_N LOOP

BEGIN
LV_COUNT := 0;
SELECT COUNT(*), CCID_VALUE_ID
  INTO LV_COUNT, LV_VALUE_ID
FROM SL_GL_CCID_MAPPING_STG CSVT
WHERE (CUR_N.SOURCE_SEGMENT = CSVT.SOURCE_SEGMENT)
    AND	(CUR_N.TARGET_SEGMENT = CSVT.TARGET_SEGMENT)
	AND	(CUR_N.COA_MAP_NAME = CSVT.COA_MAP_NAME)
	AND	(CUR_N.COA_MAP_ID = CSVT.COA_MAP_ID)
    AND UI_FLAG = 'Y'
	--AND CUR_N.START_DATE = CSVT.START_DATE  -- Commented On 06-Sep-2024, No start date and end date occur on UI Level
  GROUP BY CCID_VALUE_ID;
EXCEPTION WHEN OTHERS THEN 
LV_COUNT:= 0;
END;  

IF LV_COUNT > 0 
THEN 
UPDATE SL_GL_CCID_MAPPING_STG 
   SET ENABLE_FLAG = CUR_N.ENABLE_FLAG  
     --  ,END_DATE = CUR_N.END_DATE -- Commented On 06-Sep-2024, No start date and end date occur on UI Level
 WHERE CCID_VALUE_ID = LV_VALUE_ID;

UPDATE SL_COA_GL_CCID_MAPPING_INTF 
   SET ERROR_STATUS = gc_success_status 
 WHERE ROWID = CUR_N.IDENTIFIER;

ELSE 

UPDATE SL_COA_GL_CCID_MAPPING_INTF 
   SET ERROR_STATUS = gc_error_status,
       ERROR_DESC = ERROR_DESC || ' -> Cannot Create Disabled CCID Values.'
 WHERE ROWID = CUR_N.IDENTIFIER;
END IF;

END LOOP;
COMMIT;


/*  
-- Commented On 06-Sep-2024, No start date and end date occur on UI Level

-- Different Target Name exists for the below combination with over lap dates 

UPDATE SL_COA_GL_CCID_MAPPING_INTF 
   SET ERROR_DESC = ERROR_DESC || (CASE WHEN SL_COA_ENGINE_MAINTENANCE_PKG.COA_CCID_TARGET_DUPLICATE_FNC ( 
    p_in_COA_MAP_NAME => COA_MAP_NAME,
    p_in_source_segment => SOURCE_SEGMENT,
    p_in_COA_MAP_ID => COA_MAP_ID,
	p_in_target_segment => target_segment,
    p_in_start_date  => start_date,
    p_in_end_date => end_date) = 1
                          THEN ' -> Duplicate Record for given date range.' END)
 WHERE USER_NAME = P_IN_USER_NAME
   AND ENABLE_FLAG = 'Y';  

-- Validate Different Start Date for same combination

UPDATE SL_COA_GL_CCID_MAPPING_INTF CSVI
   SET ERROR_DESC = ERROR_DESC || (CASE WHEN SL_COA_ENGINE_MAINTENANCE_PKG.COA_CCID_CHK_START_DATE_FNC ( 
    p_in_COA_MAP_NAME => COA_MAP_NAME,
    p_in_source_segment => SOURCE_SEGMENT,
    p_in_COA_MAP_ID => COA_MAP_ID,
	p_in_target_segment => target_segment,
    p_in_start_date  => start_date,
    p_in_end_date => end_date) = 1
                          THEN ' -> Start Date cannot be updated. Please create new mapping with appropriate start date and end date.' END)
 WHERE USER_NAME = P_IN_USER_NAME
   AND ENABLE_FLAG = 'Y';      

*/   

-- Added On 06-Sep-2024, No start date and end date occur on UI Level

UPDATE SL_COA_GL_CCID_MAPPING_INTF 
   SET ERROR_DESC = ERROR_DESC || (CASE WHEN SL_GL_UNIVERSAL_PKG.CCID_DUPLICATE(COA_MAP_NAME, 
         SOURCE_SEGMENT) = 1
                          THEN --' -> Duplicate Record for given date range.' -- Commented On 06-Sep-2024, No start date and end date occur on UI Level
						       'Duplicate Value is not allow.'
						  END)
 WHERE USER_NAME = P_IN_USER_NAME
   AND ENABLE_FLAG = 'Y'; 

UPDATE SL_COA_GL_CCID_MAPPING_INTF 
   SET ERROR_Status = (CASE WHEN ERROR_DESC is not null
                            THEN gc_error_status END)
 WHERE USER_NAME = P_IN_USER_NAME
   AND ENABLE_FLAG = 'Y';

   COMMIT;

-- Loop to Update END DATE AND UPDATE Flag as well

FOR CUR_Y IN CUR_INTF_Y LOOP

BEGIN
LV_COUNT := 0;

SELECT COUNT(*), CCID_VALUE_ID
  INTO LV_COUNT, LV_VALUE_ID
FROM SL_GL_CCID_MAPPING_STG CSVT
WHERE (CUR_Y.SOURCE_SEGMENT = CSVT.SOURCE_SEGMENT)
    AND	(CUR_Y.TARGET_SEGMENT = CSVT.TARGET_SEGMENT)
	AND	(CUR_Y.COA_MAP_NAME = CSVT.COA_MAP_NAME)
	AND	(CUR_Y.COA_MAP_ID = CSVT.COA_MAP_ID)
    AND UI_FLAG = 'Y'
	--AND CUR_Y.START_DATE = CSVT.START_DATE -- Commented On 06-Sep-2024, No start date and end date occur on UI Level
	AND ENABLE_FLAG = 'Y' -- Added On 06-Sep-2024, No start date and end date occur on UI Level
  GROUP BY CCID_VALUE_ID;

EXCEPTION WHEN OTHERS THEN 
LV_COUNT:= 0;
END;   

IF LV_COUNT > 0 
THEN 

UPDATE SL_GL_CCID_MAPPING_STG 
   SET --END_DATE = CUR_Y.END_DATE,
       ENABLE_FLAG = CUR_Y.ENABLE_FLAG
 WHERE CCID_VALUE_ID = LV_VALUE_ID;

UPDATE SL_COA_GL_CCID_MAPPING_INTF 
   SET ERROR_STATUS = gc_success_status 
 WHERE ROWID = CUR_Y.IDENTIFIER;

END IF;

END LOOP;

COMMIT;

-- INSERT ERROR RECORD

INSERT INTO SL_GL_CCID_MAPPING_ERR_HIST(COA_MAP_NAME,
                COA_MAP_ID,
                SOURCE_SEGMENT,
                TARGET_SEGMENT,
                ERROR_DESC,
                user_name,
                CCID_VALUE_ID,
				-- Commented On 06-Sep-2024, No start date and end date occur on UI Level
				--START_DATE,
				--END_DATE,
				ENABLE_FLAG
            )
             SELECT COA_MAP_NAME,
                COA_MAP_ID,
                SOURCE_SEGMENT,
                TARGET_SEGMENT,
                ERROR_DESC,
                user_name,
                SL_GL_CCID_VALUE_ID_MAPPING_S.NEXTVAL,
				-- Commented On 06-Sep-2024, No start date and end date occur on UI Level
                --START_DATE,
				--END_DATE,
                ENABLE_FLAG				
				FROM SL_COA_GL_CCID_MAPPING_INTF
				WHERE 1=1
				  AND USER_NAME = P_IN_USER_NAME
				  AND ERROR_STATUS = gc_error_status;

INSERT INTO SL_GL_CCID_MAPPING_STG (COA_MAP_NAME,
                COA_MAP_ID,
                SOURCE_SEGMENT,
                TARGET_SEGMENT,
                ENABLE_FLAG,
                user_name,
                UI_Flag,
                CCID_VALUE_ID,
                created_by,
                last_updated_by
				-- Commented On 06-Sep-2024, No start date and end date occur on UI Level
				--,START_DATE,
				--END_DATE
            )
            SELECT COA_MAP_NAME,
                COA_MAP_ID,
                SOURCE_SEGMENT,
                TARGET_SEGMENT,
				ENABLE_FLAG,
				user_name,
				'Y',
                SL_GL_CCID_VALUE_ID_MAPPING_S.NEXTVAL,
				P_IN_USER_NAME,
				P_IN_USER_NAME
				-- Commented On 06-Sep-2024, No start date and end date occur on UI Level
                --,START_DATE,
				--END_DATE			
				FROM SL_COA_GL_CCID_MAPPING_INTF
				WHERE 1=1
				  AND USER_NAME = P_IN_USER_NAME
				  AND ERROR_STATUS IS NULL
				  AND ENABLE_FLAG = 'Y';

UPDATE SL_COA_GL_CCID_MAPPING_INTF 
   SET ERROR_STATUS = gc_success_status 
 WHERE 1=1
   AND USER_NAME = P_IN_USER_NAME
   AND ERROR_STATUS IS NULL
   AND ENABLE_FLAG = 'Y';

 COMMIT;


EXCEPTION WHEN OTHERS THEN 
dbms_output.put_line('error');  
	  LV_error_msg := sqlerrm; -- added on 09-Aug-2024

END COA_CCID_UPLOAD_PRC;   

FUNCTION  COA_CCID_TARGET_DUPLICATE_FNC ( 
    p_in_COA_MAP_NAME in VARCHAR2,
    p_in_source_segment in VARCHAR2,
    p_in_target_segment in VARCHAR2,
    p_in_COA_MAP_ID in NUMBER,
    p_in_start_date  in VARCHAR2,
    p_in_end_date in VARCHAR2
) RETURN NUMBER IS 
    lv_ret_count NUMBER;
	lv_start_date date := to_date(p_in_start_date,'dd-mm-yyyy');
	lv_end_date date := to_date(p_in_end_date,'dd-mm-yyyy');
    begin

 lv_ret_count:= 0;

select count(*) into lv_ret_count from SL_GL_CCID_MAPPING_STG
where nvl(COA_MAP_NAME,1) = nvl(p_in_COA_MAP_NAME,1)
and nvl(source_segment,1) = nvl(p_in_source_segment,1)
and nvl(target_segment,1) <> nvl(p_in_target_segment,1)
and nvl(COA_MAP_ID,0) = nvl(p_in_COA_MAP_ID,1)
and( ( lv_start_date between start_date and end_date ) or (lv_end_date between start_date and end_date)
or (lv_start_date<= start_date) and (lv_end_date>= end_date))
and ENABLE_FLAG = 'Y';

-- END

    IF lv_ret_count > 0 THEN 

        RETURN 1; 
    ELSE 

        RETURN 0; 
    END IF; 
EXCEPTION 
    WHEN no_data_found THEN 
        RETURN 0; 
    WHEN OTHERS THEN 
        RETURN 0;
end COA_CCID_TARGET_DUPLICATE_FNC;   

FUNCTION  COA_CCID_CHK_START_DATE_FNC ( 
    p_in_COA_MAP_NAME in VARCHAR2,
    p_in_source_segment in VARCHAR2,
    p_in_target_segment in VARCHAR2,
    p_in_COA_MAP_ID in NUMBER,
    p_in_start_date  in VARCHAR2,
    p_in_end_date in VARCHAR2
) RETURN NUMBER IS 
    lv_ret_count NUMBER;
	lv_start_date date := to_date(p_in_start_date,'dd-mm-yyyy');
	lv_end_date date := to_date(p_in_end_date,'dd-mm-yyyy');
    begin

 lv_ret_count:= 0;

select count(*) into lv_ret_count from SL_GL_CCID_MAPPING_STG
where nvl(COA_MAP_NAME,1) = nvl(p_in_COA_MAP_NAME,1)
and nvl(source_segment,1) = nvl(p_in_source_segment,1)
and nvl(COA_MAP_ID,0) = nvl(p_in_COA_MAP_ID,1)
-- and nvl(target_segment,1) = nvl(p_in_target_segment,1)
AND start_date <> lv_start_date
and ENABLE_FLAG = 'Y';

-- END

    IF lv_ret_count > 0 THEN 

        RETURN 1; 
    ELSE 

        RETURN 0; 
    END IF; 
EXCEPTION 
    WHEN no_data_found THEN 
        RETURN 0; 
    WHEN OTHERS THEN 
        RETURN 0;
    end COA_CCID_CHK_START_DATE_FNC;

END SL_COA_ENGINE_MAINTENANCE_PKG;

/
