--  DDL for Package Body SL_COA_TRANSFORMATION_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."SL_COA_TRANSFORMATION_PKG" 
AS 
/************************************************************************* */
/*                                                                           */
/* Name      : SL_COA_TRANSFORMATION_PKG                                */
/* Created On: 14-Aug-2024                                                  */
/* Created By: SureshKumar Ravichandran                                                 */
/* Purpose   : COA Transformation from Source Segment to Target Segment              */
/*                                                                           */
/*                                                                           */
/* ************************************************************************* */
/* Modification History:                                                     */
/* Version   By                          Date        Comments                          */
/*     1.0   SureshKumar Ravichandran    14-Aug-24   Initial Version                    */                                                                       
/* ***************************************************************************/


--========================================================================
-- PROCEDURE : COA_MAIN_PRC
-- COMMENT   : This procedure is Main, which calls Validation, CCID Matching, COA Segment Matching, Insert Prc
--=========================================================================

gc_success_msg CONSTANT varchar2(20) := 'Success';
gc_error_msg CONSTANT varchar2(20) := 'Error';

PROCEDURE COA_MAIN_PRC (P_IN_SOURCE_SYSTEM IN VARCHAR2,
                P_IN_TARGET_SYSTEM IN VARCHAR2,
				P_IN_SEGMENT1 IN VARCHAR2,
				P_IN_SEGMENT2 IN VARCHAR2,
				P_IN_SEGMENT3 IN VARCHAR2,
				P_IN_SEGMENT4 IN VARCHAR2,
				P_IN_SEGMENT5 IN VARCHAR2,
				P_IN_SEGMENT6 IN VARCHAR2,
				P_IN_SEGMENT7 IN VARCHAR2,
				P_IN_SEGMENT8 IN VARCHAR2,
				P_IN_SEGMENT9 IN VARCHAR2,
				P_IN_SEGMENT10 IN VARCHAR2,
				P_IN_TRANSACTION_DATE IN DATE,
				P_OUT_TARGET_SYSTEM OUT VARCHAR2,
				P_OUT_STATUS OUT VARCHAR2,
				P_OUT_MESSAGE OUT VARCHAR2) AS

LV_VALIDATION_MSG VARCHAR2(500);
LV_CCID_TARGET_SEGMENT VARCHAR2(300);
LV_TARGET_SEGMENT VARCHAR2(300);
LV_UI_FLAG VARCHAR2(3);
LV_CCID_VALUE_ID NUMBER;
LV_COUNT NUMBER;
LV_START_DATE DATE;
LV_END_DATE DATE;
LV_SEGMENT_VALUE1 NUMBER;
LV_SEGMENT_VALUE2 NUMBER;
LV_SEGMENT_VALUE3 NUMBER;
LV_SEGMENT_VALUE4 NUMBER;
LV_SEGMENT_VALUE5 NUMBER;
LV_SEGMENT_VALUE6 NUMBER;
LV_SEGMENT_VALUE7 NUMBER;
LV_SEGMENT_VALUE8 NUMBER;
LV_SEGMENT_VALUE9 NUMBER;
LV_SEGMENT_VALUE10 NUMBER;
LV_ERROR_FLAG VARCHAR2(3);
LV_ERROR_MSG VARCHAR2(500);
LV_COA_MAP_NAME VARCHAR2(30);
LV_COA_MAP_ID NUMBER;
BEGIN

-- CALL VALIDATION FUNCTION TO VALIDATE THE PARAMETER
BEGIN
LV_VALIDATION_MSG := COA_VALIDATION_FNC (P_IN_SOURCE_SYSTEM => P_IN_SOURCE_SYSTEM,
                                  P_IN_TARGET_SYSTEM => P_IN_TARGET_SYSTEM,
				                  P_IN_SEGMENT1 => P_IN_SEGMENT1,
				                  P_IN_SEGMENT2 => P_IN_SEGMENT2,
				                  P_IN_SEGMENT3 => P_IN_SEGMENT3,
				                  P_IN_SEGMENT4 => P_IN_SEGMENT4,
				                  P_IN_SEGMENT5 => P_IN_SEGMENT5,
				                  P_IN_SEGMENT6 => P_IN_SEGMENT6,
				                  P_IN_SEGMENT7 => P_IN_SEGMENT7,
				                  P_IN_SEGMENT8 => P_IN_SEGMENT8,
				                  P_IN_SEGMENT9 => P_IN_SEGMENT9,
				                  P_IN_SEGMENT10 => P_IN_SEGMENT10,
				                  P_IN_TRANSACTION_DATE => P_IN_TRANSACTION_DATE);

-- IF GIVEN PARAMETER IS IN-VALID THEN IT WILL THROW VALIDATION ERROR AND STOP FURTHER PROCESS								  
IF 	LV_VALIDATION_MSG IS NOT NULL	
THEN 
-- SET FINAL VALUE 
P_OUT_TARGET_SYSTEM := NULL;
P_OUT_STATUS := 'Parameter Error';
P_OUT_MESSAGE := LV_VALIDATION_MSG;
END IF;
END;

-- IF GIVEN PARAMETER IS VALID THEN WE NEED TO GET THE TARGET SEGMENT
IF LV_VALIDATION_MSG IS NULL
THEN

-- CALL COA_CCID_MAPPING_PRC TO CHECK CCID AVAILABILITY IN USER VALUES UI FLAG AS N
BEGIN 

						COA_CCID_MAPPING_PRC (P_IN_SOURCE_SYSTEM => P_IN_SOURCE_SYSTEM,
                                  P_IN_TARGET_SYSTEM => P_IN_TARGET_SYSTEM,
				                  P_IN_SEGMENT1 => P_IN_SEGMENT1,
				                  P_IN_SEGMENT2 => P_IN_SEGMENT2,
				                  P_IN_SEGMENT3 => P_IN_SEGMENT3,
				                  P_IN_SEGMENT4 => P_IN_SEGMENT4,
				                  P_IN_SEGMENT5 => P_IN_SEGMENT5,
				                  P_IN_SEGMENT6 => P_IN_SEGMENT6,
				                  P_IN_SEGMENT7 => P_IN_SEGMENT7,
				                  P_IN_SEGMENT8 => P_IN_SEGMENT8,
				                  P_IN_SEGMENT9 => P_IN_SEGMENT9,
				                  P_IN_SEGMENT10 => P_IN_SEGMENT10,
				                  P_IN_TRANSACTION_DATE => P_IN_TRANSACTION_DATE,
								  P_IN_UI_FLAG => 'N',
								  P_OUT_TARGET_SEGMENT => LV_CCID_TARGET_SEGMENT,
								  P_OUT_UI_FLAG => LV_UI_FLAG,
								  P_OUT_CCID_VALUE_ID => LV_CCID_VALUE_ID);
-- IF TARGET SEGMENT FOUND IN CCID THEN STOP FURTHER PROCESS							  
IF 	LV_CCID_TARGET_SEGMENT IS NOT NULL 
THEN 		
-- SET FINAL VALUE 
P_OUT_TARGET_SYSTEM := LV_CCID_TARGET_SEGMENT;
P_OUT_STATUS := gc_success_msg;
P_OUT_MESSAGE := 'Fetched Target Segment From CCID';--Null
END IF;			  
END;

IF LV_CCID_TARGET_SEGMENT IS NULL
THEN
LV_COUNT := 0;

COA_MAP_NAME_PRC (P_IN_SOURCE_SYSTEM => P_IN_SOURCE_SYSTEM,
                P_IN_TARGET_SYSTEM => P_IN_TARGET_SYSTEM,
				P_OUT_COA_MAP_NAME => LV_COA_MAP_NAME,
				P_OUT_COA_MAP_ID => LV_COA_MAP_ID);

BEGIN

--DBMS_OUTPUT.PUT_LINE('Entered to check Postponed Dates');
SELECT COUNT(*), GCMT.CCID_VALUE_ID, min(SVT.end_date), GCMT.TARGET_SEGMENT 
into LV_COUNT, LV_CCID_VALUE_ID, LV_END_DATE, LV_CCID_TARGET_SEGMENT 
FROM SL_GL_CCID_MAPPING_STG GCMT, 
SL_GL_COA_SEGMENT_VALUE_STG SVT
WHERE 1=1
  AND GCMT.Enable_Flag='Y'
  AND SVT.FLAG = 'Y'
  AND GCMT.SOURCE_SEGMENT IN (P_IN_SEGMENT1||'.'||P_IN_SEGMENT2||'.'||P_IN_SEGMENT3||'.'||P_IN_SEGMENT4||'.'||P_IN_SEGMENT5||'.'||
P_IN_SEGMENT6||'.'||P_IN_SEGMENT7||'.'||P_IN_SEGMENT8||'.'||P_IN_SEGMENT9||'.'||P_IN_SEGMENT10)
  AND (GCMT.SOURCE_SEGMENT1 = P_IN_SEGMENT1 OR P_IN_SEGMENT1 IS NULL)
  AND (GCMT.SOURCE_SEGMENT2= P_IN_SEGMENT2 OR P_IN_SEGMENT2 IS NULL)
  AND (GCMT.SOURCE_SEGMENT3 = P_IN_SEGMENT3 OR P_IN_SEGMENT3 IS NULL)
  AND (GCMT.SOURCE_SEGMENT4 = P_IN_SEGMENT4 OR P_IN_SEGMENT4 IS NULL)
  AND (GCMT.SOURCE_SEGMENT5 = P_IN_SEGMENT5 OR P_IN_SEGMENT5 IS NULL)
  AND (GCMT.SOURCE_SEGMENT6= P_IN_SEGMENT6 OR P_IN_SEGMENT6 IS NULL)
  AND (GCMT.SOURCE_SEGMENT7 = P_IN_SEGMENT7 OR P_IN_SEGMENT7 IS NULL)
  AND (GCMT.SOURCE_SEGMENT8 = P_IN_SEGMENT8 OR P_IN_SEGMENT8 IS NULL)
  AND (GCMT.SOURCE_SEGMENT9= P_IN_SEGMENT9 OR P_IN_SEGMENT9 IS NULL)
  AND (GCMT.SOURCE_SEGMENT10= P_IN_SEGMENT10 OR P_IN_SEGMENT10 IS NULL) 
  AND GCMT.COA_MAP_ID = LV_COA_MAP_ID
  AND GCMT.COA_MAP_NAME = LV_COA_MAP_NAME 
  AND ((GCMT.SEGMENT_VALUE1 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE2 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE3 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE4 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE5 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE6 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE7 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE8 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE9 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE10 = SVT.VALUE_ID))
  AND P_IN_TRANSACTION_DATE BETWEEN SVT.START_DATE AND SVT.END_DATE
  group by GCMT.CCID_VALUE_ID, GCMT.TARGET_SEGMENT;		  

--DBMS_OUTPUT.PUT_LINE('Postponed Dates Count: '||LV_COUNT||', CCID Value ID: '||LV_CCID_VALUE_ID
--||', End Date: '||LV_END_DATE||', Target Segment: '||LV_CCID_TARGET_SEGMENT );
IF LV_COUNT > 0 THEN 
UPDATE SL_GL_CCID_MAPPING_STG
SET END_DATE = LV_END_DATE
WHERE CCID_VALUE_ID = LV_CCID_VALUE_ID;

P_OUT_TARGET_SYSTEM := LV_CCID_TARGET_SEGMENT;
P_OUT_STATUS := gc_success_msg;
P_OUT_MESSAGE := 'Fetched Target Segment From CCID';--Null
ELSE 
LV_CCID_TARGET_SEGMENT := NULL;
P_OUT_TARGET_SYSTEM := NULL;
P_OUT_STATUS := 'CCID Update Error';
P_OUT_MESSAGE := LV_TARGET_SEGMENT;	
END IF;

EXCEPTION WHEN OTHERS THEN
--DBMS_OUTPUT.PUT_LINE('Postponed Dates Exception: '||sqlerrm);
LV_CCID_TARGET_SEGMENT := NULL;
P_OUT_TARGET_SYSTEM := NULL;
P_OUT_STATUS := 'CCID Update Error';
P_OUT_MESSAGE := LV_TARGET_SEGMENT;			  
END;
end if; 

-- IF TARGET SEGMENT NOT FOUND IN CCID THEN CHECK UNDER COA SEGMENT VALUE IN COA_SEGMENT_VALUE_MAPPING_PRC
IF LV_CCID_TARGET_SEGMENT IS NULL
THEN


BEGIN

LV_END_DATE := null;
                COA_SEGMENT_VALUE_MAPPING_PRC (P_IN_SOURCE_SYSTEM => P_IN_SOURCE_SYSTEM,
                                  P_IN_TARGET_SYSTEM => P_IN_TARGET_SYSTEM,
				                  P_IN_SEGMENT1 => P_IN_SEGMENT1,
				                  P_IN_SEGMENT2 => P_IN_SEGMENT2,
				                  P_IN_SEGMENT3 => P_IN_SEGMENT3,
				                  P_IN_SEGMENT4 => P_IN_SEGMENT4,
				                  P_IN_SEGMENT5 => P_IN_SEGMENT5,
				                  P_IN_SEGMENT6 => P_IN_SEGMENT6,
				                  P_IN_SEGMENT7 => P_IN_SEGMENT7,
				                  P_IN_SEGMENT8 => P_IN_SEGMENT8,
				                  P_IN_SEGMENT9 => P_IN_SEGMENT9,
				                  P_IN_SEGMENT10 => P_IN_SEGMENT10,
				                  P_IN_TRANSACTION_DATE => P_IN_TRANSACTION_DATE,
								  P_OUT_TARGET_SEGMENT => LV_TARGET_SEGMENT,
				                  P_OUT_START_DATE => LV_START_DATE,
				                  P_OUT_END_DATE => LV_END_DATE,
				                  P_OUT_ERROR_FLAG => LV_ERROR_FLAG,
								  p_out_segment_value1 => LV_SEGMENT_VALUE1,
		                          p_out_segment_value2 => LV_SEGMENT_VALUE2,
		                          p_out_segment_value3 => LV_SEGMENT_VALUE3,
		                          p_out_segment_value4 => LV_SEGMENT_VALUE4,
		                          p_out_segment_value5 => LV_SEGMENT_VALUE5,
		                          p_out_segment_value6 => LV_SEGMENT_VALUE6,
		                          p_out_segment_value7 => LV_SEGMENT_VALUE7,
		                          p_out_segment_value8 => LV_SEGMENT_VALUE8,
		                          p_out_segment_value9 => LV_SEGMENT_VALUE9,
		                          p_out_segment_value10 => LV_SEGMENT_VALUE10);
-- IF WE GOT ERROR 	THEN ITS STOP FOR FURTHER PROCESS							  
IF LV_ERROR_FLAG = 'Y'
THEN
-- SET FINAL VALUE 
P_OUT_TARGET_SYSTEM := NULL;
P_OUT_STATUS := 'COA Segment Mapping Transformation Error';
P_OUT_MESSAGE := LV_TARGET_SEGMENT;
END IF;						  
END;

-- IF WE GOT TARGET SEGMENT FROM COA SEGMENT VALUE THEN INSERT INTO CCID USING COA_INSERT_CCID_PRC
IF NVL(LV_ERROR_FLAG,'N') <> 'Y'
THEN

                 COA_INSERT_CCID_PRC (P_IN_SOURCE_SYSTEM => P_IN_SOURCE_SYSTEM,
                                  P_IN_TARGET_SYSTEM => P_IN_TARGET_SYSTEM,
				                  P_IN_SEGMENT1 => P_IN_SEGMENT1,
				                  P_IN_SEGMENT2 => P_IN_SEGMENT2,
				                  P_IN_SEGMENT3 => P_IN_SEGMENT3,
				                  P_IN_SEGMENT4 => P_IN_SEGMENT4,
				                  P_IN_SEGMENT5 => P_IN_SEGMENT5,
				                  P_IN_SEGMENT6 => P_IN_SEGMENT6,
				                  P_IN_SEGMENT7 => P_IN_SEGMENT7,
				                  P_IN_SEGMENT8 => P_IN_SEGMENT8,
				                  P_IN_SEGMENT9 => P_IN_SEGMENT9,
				                  P_IN_SEGMENT10 => P_IN_SEGMENT10,
				                  P_IN_TRANSACTION_DATE => P_IN_TRANSACTION_DATE,
								  P_IN_TARGET_SEGMENT => LV_TARGET_SEGMENT,
				                  P_IN_START_DATE => LV_START_DATE,
				                  P_IN_END_DATE => LV_END_DATE,
								  p_in_segment_value1 => LV_SEGMENT_VALUE1,
		                          p_in_segment_value2 => LV_SEGMENT_VALUE2,
		                          p_in_segment_value3 => LV_SEGMENT_VALUE3,
		                          p_in_segment_value4 => LV_SEGMENT_VALUE4,
		                          p_in_segment_value5 => LV_SEGMENT_VALUE5,
		                          p_in_segment_value6 => LV_SEGMENT_VALUE6,
		                          p_in_segment_value7 => LV_SEGMENT_VALUE7,
		                          p_in_segment_value8 => LV_SEGMENT_VALUE8,
		                          p_in_segment_value9 => LV_SEGMENT_VALUE9,
		                          p_in_segment_value10 => LV_SEGMENT_VALUE10);

-- SET FINAL VALUE 
P_OUT_TARGET_SYSTEM := LV_TARGET_SEGMENT;
P_OUT_STATUS := gc_success_msg;
P_OUT_MESSAGE := 'Fetched and Created Target Segment in CCID';--NULL;

END IF; -- END INSERT INTO CCID

IF LV_ERROR_FLAG = 'Y'
THEN
-- CALL COA_CCID_MAPPING_PRC TO CHECK CCID AVAILABILITY IN UI VALUES WHERE UI FLAG AS Y
BEGIN 						  
						COA_CCID_MAPPING_PRC (P_IN_SOURCE_SYSTEM => P_IN_SOURCE_SYSTEM,
                                  P_IN_TARGET_SYSTEM => P_IN_TARGET_SYSTEM,
				                  P_IN_SEGMENT1 => P_IN_SEGMENT1,
				                  P_IN_SEGMENT2 => P_IN_SEGMENT2,
				                  P_IN_SEGMENT3 => P_IN_SEGMENT3,
				                  P_IN_SEGMENT4 => P_IN_SEGMENT4,
				                  P_IN_SEGMENT5 => P_IN_SEGMENT5,
				                  P_IN_SEGMENT6 => P_IN_SEGMENT6,
				                  P_IN_SEGMENT7 => P_IN_SEGMENT7,
				                  P_IN_SEGMENT8 => P_IN_SEGMENT8,
				                  P_IN_SEGMENT9 => P_IN_SEGMENT9,
				                  P_IN_SEGMENT10 => P_IN_SEGMENT10,
				                  P_IN_TRANSACTION_DATE => P_IN_TRANSACTION_DATE,
								  P_IN_UI_FLAG => 'Y',
								  P_OUT_TARGET_SEGMENT => LV_CCID_TARGET_SEGMENT,
								  P_OUT_UI_FLAG => LV_UI_FLAG,
								  P_OUT_CCID_VALUE_ID => LV_CCID_VALUE_ID);
-- IF TARGET SEGMENT FOUND IN CCID THEN STOP FURTHER PROCESS							  
IF 	LV_CCID_TARGET_SEGMENT IS NOT NULL 
THEN 		
-- SET FINAL VALUE 
P_OUT_TARGET_SYSTEM := LV_CCID_TARGET_SEGMENT;
P_OUT_STATUS := gc_success_msg;
P_OUT_MESSAGE := 'Fetched Target Segment From CCID';
END IF;			  
END;
END IF;

END IF; -- END TO CHECK TARGET SEGMENT FROM COA SEGMENT VALUE




END IF; -- END TO GET THE TARGET SEGMENT
COMMIT;
--DBMS_OUTPUT.PUT_LINE('Completed Successfully');
EXCEPTION WHEN OTHERS THEN 
LV_ERROR_MSG := SQLERRM;
P_OUT_STATUS := 'Exception Error';
P_OUT_MESSAGE := LV_ERROR_MSG;
--DBMS_OUTPUT.PUT_LINE('Completed with Error: '||LV_ERROR_MSG);
ROLLBACK;
END COA_MAIN_PRC;		

--========================================================================
-- FUNCTION : COA_VALIDATION_FNC
-- COMMENT   : THIS FUNCTION IS TO VALIDATE GIVEN PARAMETER
--=========================================================================

FUNCTION COA_VALIDATION_FNC (P_IN_SOURCE_SYSTEM IN VARCHAR2,
                P_IN_TARGET_SYSTEM IN VARCHAR2,
				P_IN_SEGMENT1 IN VARCHAR2,
				P_IN_SEGMENT2 IN VARCHAR2,
				P_IN_SEGMENT3 IN VARCHAR2,
				P_IN_SEGMENT4 IN VARCHAR2,
				P_IN_SEGMENT5 IN VARCHAR2,
				P_IN_SEGMENT6 IN VARCHAR2,
				P_IN_SEGMENT7 IN VARCHAR2,
				P_IN_SEGMENT8 IN VARCHAR2,
				P_IN_SEGMENT9 IN VARCHAR2,
				P_IN_SEGMENT10 IN VARCHAR2,
				P_IN_TRANSACTION_DATE IN DATE) 
		 RETURN VARCHAR2
AS		 
LV_ERROR_MSG VARCHAR2(500);
LV_ERROR_FLAG VARCHAR2(3) := 'N';		 
LV_COUNT NUMBER := 0;
BEGIN

BEGIN
-- CHECK ANY SEGMENT SHOULD HAVE VALUE
IF ((P_IN_SEGMENT1 IS NULL)AND(P_IN_SEGMENT2 IS NULL) AND (P_IN_SEGMENT3 IS NULL )AND (P_IN_SEGMENT4 IS NULL) AND (P_IN_SEGMENT5 IS NULL)
            AND (P_IN_SEGMENT6 IS NULL) AND (P_IN_SEGMENT7 IS NULL) AND (P_IN_SEGMENT8 IS NULL) AND (P_IN_SEGMENT9 IS NULL) AND (P_IN_SEGMENT10 IS NULL))
THEN	
LV_ERROR_FLAG := 'Y';
LV_ERROR_MSG := 'Atleast one source segment should have a value';
END IF;		
END;

BEGIN
-- CHECK TARGET SYSTEM IS VALID OR NOT
LV_COUNT := 0;
SELECT COUNT(*) 
  INTO LV_COUNT
  FROM SL_GL_COA_MAP_STG
 WHERE 1=1
   AND TARGET_SYSTEM = P_IN_TARGET_SYSTEM;

IF LV_COUNT = 0 
THEN
LV_ERROR_FLAG := 'Y';
LV_ERROR_MSG := LV_ERROR_MSG || ', ' || 'Target system should have value/invalid';
END IF;
END;

BEGIN
-- CHECK SOURCE SYSTEM IS VALID OR NOT
LV_COUNT := 0;
SELECT COUNT(*) 
  INTO LV_COUNT
  FROM SL_GL_COA_MAP_STG
 WHERE 1=1
   AND SOURCE_SYSTEM = P_IN_SOURCE_SYSTEM;

IF LV_COUNT = 0 
THEN
LV_ERROR_FLAG := 'Y';
LV_ERROR_MSG := LV_ERROR_MSG || ', ' || 'Source system should have value/invalid';
END IF;
END;

BEGIN
-- CHECK TRANSACTION DATE IS NULL OR NOT

IF P_IN_TRANSACTION_DATE IS NULL
THEN
LV_ERROR_FLAG := 'Y';
LV_ERROR_MSG := LV_ERROR_MSG || ', ' || 'Transaction Date should have value';
END IF;
END;

-- RETURN VALUE
IF LV_ERROR_FLAG = 'Y'
THEN
RETURN LTRIM(LV_ERROR_MSG, ', ');
ELSE
RETURN NULL;
END IF;

END COA_VALIDATION_FNC;

--========================================================================
-- FUNCTION : COA_CCID_MAPPING_FNC
-- COMMENT   : THIS FUNCTION IS TO GET TARGET SEGMENT FROM CCID TABLE
--=========================================================================

FUNCTION COA_CCID_MAPPING_FNC (P_IN_SOURCE_SYSTEM IN VARCHAR2,
                P_IN_TARGET_SYSTEM IN VARCHAR2,
				P_IN_SEGMENT1 IN VARCHAR2,
				P_IN_SEGMENT2 IN VARCHAR2,
				P_IN_SEGMENT3 IN VARCHAR2,
				P_IN_SEGMENT4 IN VARCHAR2,
				P_IN_SEGMENT5 IN VARCHAR2,
				P_IN_SEGMENT6 IN VARCHAR2,
				P_IN_SEGMENT7 IN VARCHAR2,
				P_IN_SEGMENT8 IN VARCHAR2,
				P_IN_SEGMENT9 IN VARCHAR2,
				P_IN_SEGMENT10 IN VARCHAR2,
				P_IN_TRANSACTION_DATE IN DATE)
		RETURN VARCHAR2
AS	

LV_COA_MAP_NAME VARCHAR2(30);
LV_COA_MAP_ID NUMBER;
LV_CONCATENATED_SEGMENTS VARCHAR2(200);
LV_TARGET_SEGMENT VARCHAR2(300);
LV_ERROR_MSG VARCHAR2(3);
BEGIN	

BEGIN
-- COA MAP NAME AND ID
COA_MAP_NAME_PRC (P_IN_SOURCE_SYSTEM => P_IN_SOURCE_SYSTEM,
                P_IN_TARGET_SYSTEM => P_IN_TARGET_SYSTEM,
				P_OUT_COA_MAP_NAME => LV_COA_MAP_NAME,
				P_OUT_COA_MAP_ID => LV_COA_MAP_ID);
END;

BEGIN
-- CONCATENATED SEGMENTS
LV_CONCATENATED_SEGMENTS := P_IN_SEGMENT1||'.'||P_IN_SEGMENT2||'.'||P_IN_SEGMENT3||'.'||P_IN_SEGMENT4||'.'||P_IN_SEGMENT5||'.'||
P_IN_SEGMENT6||'.'||P_IN_SEGMENT7||'.'||P_IN_SEGMENT8||'.'||P_IN_SEGMENT9||'.'||P_IN_SEGMENT10;
END;

BEGIN
-- CHECK COMBINATION AVAILABLE IN CCID TABLE
SELECT TARGET_SEGMENT 
  INTO LV_TARGET_SEGMENT
  FROM SL_GL_CCID_MAPPING_STG
 WHERE 1=1
   AND ENABLE_FLAG = 'Y'
   --AND UI_FLAG = 'Y'
   AND SOURCE_SEGMENT = LV_CONCATENATED_SEGMENTS
   AND COA_MAP_ID = LV_COA_MAP_ID
   AND COA_MAP_NAME = LV_COA_MAP_NAME
   AND P_IN_TRANSACTION_DATE BETWEEN START_DATE AND END_DATE;

 --  DBMS_OUTPUT.PUT_LINE('LV_TARGET_SEGMENT: '||LV_TARGET_SEGMENT||', P_IN_TRANSACTION_DATE: '||P_IN_TRANSACTION_DATE);

EXCEPTION WHEN OTHERS THEN 
   LV_ERROR_MSG := 'Y';
END;

-- RETURN VALUE
IF LV_ERROR_MSG = 'Y' OR LV_TARGET_SEGMENT IS NULL
THEN
RETURN NULL;
ELSE
RETURN LV_TARGET_SEGMENT;
END IF;

END COA_CCID_MAPPING_FNC;

--========================================================================
-- PROCEDURE : COA_CCID_MAPPING_PRC
-- COMMENT   : THIS FUNCTION IS TO GET TARGET SEGMENT FROM CCID TABLE
--=========================================================================

PROCEDURE COA_CCID_MAPPING_PRC (P_IN_SOURCE_SYSTEM IN VARCHAR2,
                P_IN_TARGET_SYSTEM IN VARCHAR2,
				P_IN_SEGMENT1 IN VARCHAR2,
				P_IN_SEGMENT2 IN VARCHAR2,
				P_IN_SEGMENT3 IN VARCHAR2,
				P_IN_SEGMENT4 IN VARCHAR2,
				P_IN_SEGMENT5 IN VARCHAR2,
				P_IN_SEGMENT6 IN VARCHAR2,
				P_IN_SEGMENT7 IN VARCHAR2,
				P_IN_SEGMENT8 IN VARCHAR2,
				P_IN_SEGMENT9 IN VARCHAR2,
				P_IN_SEGMENT10 IN VARCHAR2,
				P_IN_TRANSACTION_DATE IN DATE,
				P_IN_UI_FLAG IN VARCHAR2,
				P_OUT_TARGET_SEGMENT OUT VARCHAR2,
				P_OUT_UI_FLAG OUT VARCHAR2,
				P_OUT_CCID_VALUE_ID OUT NUMBER)
AS	

LV_COA_MAP_NAME VARCHAR2(30);
LV_COA_MAP_ID NUMBER;
LV_CONCATENATED_SEGMENTS VARCHAR2(200);
LV_TARGET_SEGMENT VARCHAR2(300);
LV_ERROR_MSG VARCHAR2(3);
LV_UI_FLAG VARCHAR2(3);
LV_CCID_VALUE_ID NUMBER;
BEGIN	

BEGIN
-- COA MAP NAME AND ID
COA_MAP_NAME_PRC (P_IN_SOURCE_SYSTEM => P_IN_SOURCE_SYSTEM,
                P_IN_TARGET_SYSTEM => P_IN_TARGET_SYSTEM,
				P_OUT_COA_MAP_NAME => LV_COA_MAP_NAME,
				P_OUT_COA_MAP_ID => LV_COA_MAP_ID);
END;

BEGIN
-- CONCATENATED SEGMENTS
LV_CONCATENATED_SEGMENTS := P_IN_SEGMENT1||'.'||P_IN_SEGMENT2||'.'||P_IN_SEGMENT3||'.'||P_IN_SEGMENT4||'.'||P_IN_SEGMENT5||'.'||
P_IN_SEGMENT6||'.'||P_IN_SEGMENT7||'.'||P_IN_SEGMENT8||'.'||P_IN_SEGMENT9||'.'||P_IN_SEGMENT10;
END;

BEGIN
-- CHECK COMBINATION AVAILABLE IN CCID TABLE
SELECT TARGET_SEGMENT, UI_FLAG, CCID_VALUE_ID
  INTO LV_TARGET_SEGMENT, LV_UI_FLAG, LV_CCID_VALUE_ID
  FROM SL_GL_CCID_MAPPING_STG
 WHERE 1=1
   AND ENABLE_FLAG = 'Y'
   AND UI_FLAG = P_IN_UI_FLAG
   AND SOURCE_SEGMENT = LV_CONCATENATED_SEGMENTS
   AND COA_MAP_ID = LV_COA_MAP_ID
   AND COA_MAP_NAME = LV_COA_MAP_NAME
   AND P_IN_TRANSACTION_DATE BETWEEN NVL(START_DATE,P_IN_TRANSACTION_DATE) AND NVL(END_DATE,P_IN_TRANSACTION_DATE);

 --  DBMS_OUTPUT.PUT_LINE('LV_TARGET_SEGMENT: '||LV_TARGET_SEGMENT||', P_IN_TRANSACTION_DATE: '||P_IN_TRANSACTION_DATE);

EXCEPTION WHEN OTHERS THEN 
   LV_ERROR_MSG := 'Y';
END;

-- RETURN VALUE
IF LV_ERROR_MSG = 'Y' OR LV_TARGET_SEGMENT IS NULL
THEN
P_OUT_TARGET_SEGMENT := NULL;
P_OUT_UI_FLAG := NULL;
P_OUT_CCID_VALUE_ID := NULL;
ELSE
P_OUT_TARGET_SEGMENT := LV_TARGET_SEGMENT;
P_OUT_UI_FLAG := LV_UI_FLAG;
P_OUT_CCID_VALUE_ID := LV_CCID_VALUE_ID;
END IF;

END COA_CCID_MAPPING_PRC;

