--========================================================================
-- PROCEDURE : COA_INSERT_CCID_PRC
-- COMMENT   : THIS PROCEDURE IS TO INSERT NEW TARGET SEGMENT INTO CCID TABLE
--=========================================================================

PROCEDURE COA_INSERT_CCID_PRC (P_IN_SOURCE_SYSTEM IN VARCHAR2,
                P_IN_TARGET_SYSTEM IN VARCHAR2,
				P_IN_SEGMENT1 IN VARCHAR2,
				P_IN_SEGMENT2 IN VARCHAR2,
				P_IN_SEGMENT3 IN VARCHAR2,
				P_IN_SEGMENT4 IN VARCHAR2,
				P_IN_SEGMENT5 IN VARCHAR2,
				P_IN_SEGMENT6 IN VARCHAR2,
				P_IN_SEGMENT7 IN VARCHAR2,
				P_IN_SEGMENT8 IN VARCHAR2,
				P_IN_SEGMENT9 IN VARCHAR2,
				P_IN_SEGMENT10 IN VARCHAR2,
				P_IN_TRANSACTION_DATE IN DATE,
				P_IN_TARGET_SEGMENT IN VARCHAR2,
				P_IN_START_DATE IN DATE,
				P_IN_END_DATE IN DATE,
				p_in_segment_value1 IN number,
		        p_in_segment_value2 IN number,
		        p_in_segment_value3 IN number,
		        p_in_segment_value4 IN number,
		        p_in_segment_value5 IN number,
		        p_in_segment_value6 IN number,
		        p_in_segment_value7 IN number,
		        p_in_segment_value8 IN number,
		        p_in_segment_value9 IN number,
		        p_in_segment_value10 IN number)
AS	
LV_COA_MAP_NAME VARCHAR2(30);
LV_COA_MAP_ID NUMBER;
LV_CCID_VALUE_ID NUMBER := SL_GL_CCID_VALUE_ID_MAPPING_S.NEXTVAL;
LV_CONCATENATED_SEGMENTS VARCHAR2(200); 
BEGIN	
-- COA MAP NAME AND ID
COA_MAP_NAME_PRC (P_IN_SOURCE_SYSTEM => P_IN_SOURCE_SYSTEM,
                P_IN_TARGET_SYSTEM => P_IN_TARGET_SYSTEM,
				P_OUT_COA_MAP_NAME => LV_COA_MAP_NAME,
				P_OUT_COA_MAP_ID => LV_COA_MAP_ID);

LV_CONCATENATED_SEGMENTS := P_IN_SEGMENT1||'.'||P_IN_SEGMENT2||'.'||P_IN_SEGMENT3||'.'||P_IN_SEGMENT4||'.'||P_IN_SEGMENT5||'.'||
P_IN_SEGMENT6||'.'||P_IN_SEGMENT7||'.'||P_IN_SEGMENT8||'.'||P_IN_SEGMENT9||'.'||P_IN_SEGMENT10;

-- INSERT INTO CCID TABLE	
INSERT INTO SL_GL_CCID_MAPPING_STG (COA_MAP_NAME,
                COA_MAP_ID,
                SOURCE_SEGMENT,
                TARGET_SEGMENT,
                ENABLE_FLAG,
                UI_FLAG,
                CCID_VALUE_ID,
				START_DATE,
				END_DATE,
				SEGMENT_VALUE1,
				SEGMENT_VALUE2,
				SEGMENT_VALUE3,
				SEGMENT_VALUE4,
				SEGMENT_VALUE5,
				SEGMENT_VALUE6,
				SEGMENT_VALUE7,
				SEGMENT_VALUE8,
				SEGMENT_VALUE9,
				SEGMENT_VALUE10,
                SOURCE_SEGMENT1,
                SOURCE_SEGMENT2,
                SOURCE_SEGMENT3,
                SOURCE_SEGMENT4,
                SOURCE_SEGMENT5,
                SOURCE_SEGMENT6,
                SOURCE_SEGMENT7,
                SOURCE_SEGMENT8,
                SOURCE_SEGMENT9,
                SOURCE_SEGMENT10
            )
            VALUES(LV_COA_MAP_NAME,
                LV_COA_MAP_ID,
                LV_CONCATENATED_SEGMENTS,
                P_IN_TARGET_SEGMENT,
                'Y',
                'N',
                LV_CCID_VALUE_ID,
				P_IN_START_DATE,
                P_IN_END_DATE,
				p_in_segment_value1,
				p_in_segment_value2,
				p_in_segment_value3,
				p_in_segment_value4,
				p_in_segment_value5,
				p_in_segment_value6,
				p_in_segment_value7,
				p_in_segment_value8,
				p_in_segment_value9,
				p_in_segment_value10,
                P_IN_SEGMENT1,
                P_IN_SEGMENT2,
                P_IN_SEGMENT3,
                P_IN_SEGMENT4,
                P_IN_SEGMENT5,
                P_IN_SEGMENT6,
                P_IN_SEGMENT7,
                P_IN_SEGMENT8,
                P_IN_SEGMENT9,
                P_IN_SEGMENT10
            );			

END COA_INSERT_CCID_PRC;

--========================================================================
-- PROCEDURE : COA_MAP_NAME_PRC
-- COMMENT   : THIS PROCEDURE IS TO GET COA MAP NAME AND ID
--=========================================================================

PROCEDURE COA_MAP_NAME_PRC (P_IN_SOURCE_SYSTEM IN VARCHAR2,
                P_IN_TARGET_SYSTEM IN VARCHAR2,
				P_OUT_COA_MAP_NAME OUT VARCHAR2,
				P_OUT_COA_MAP_ID OUT NUMBER)
AS	
LV_COA_MAP_ID NUMBER;
LV_COA_MAP_NAME VARCHAR2(30);
BEGIN	

SELECT COA_MAP_ID, COA_MAP_NAME
  INTO LV_COA_MAP_ID, LV_COA_MAP_NAME
  FROM SL_GL_COA_MAP_STG 
 WHERE 1=1
   AND SOURCE_SYSTEM = P_IN_SOURCE_SYSTEM 
   AND TARGET_SYSTEM = P_IN_TARGET_SYSTEM;

P_OUT_COA_MAP_NAME := LV_COA_MAP_NAME;
P_OUT_COA_MAP_ID := LV_COA_MAP_ID;
END COA_MAP_NAME_PRC;		

--========================================================================
-- FUNCTION : COA_SEGMENT_VALUE_MAPPING_DATE_FNC
-- COMMENT   : THIS FUNCTION IS TO GET START DATE AND END DATE FROM COA SEGMENT VALUE TABLE
--=========================================================================

FUNCTION COA_SEGMENT_VALUE_MAPPING_DATE_FNC (P_IN_SOURCE_SYSTEM IN VARCHAR2,
                P_IN_TARGET_SYSTEM IN VARCHAR2,
				P_IN_SEGMENT1 IN VARCHAR2,
				P_IN_SEGMENT2 IN VARCHAR2,
				P_IN_SEGMENT3 IN VARCHAR2,
				P_IN_SEGMENT4 IN VARCHAR2,
				P_IN_SEGMENT5 IN VARCHAR2,
				P_IN_SEGMENT6 IN VARCHAR2,
				P_IN_SEGMENT7 IN VARCHAR2,
				P_IN_SEGMENT8 IN VARCHAR2,
				P_IN_SEGMENT9 IN VARCHAR2,
				P_IN_SEGMENT10 IN VARCHAR2,
				P_IN_TRANSACTION_DATE IN DATE,
				P_IN_RETURN_DATE_TYPE IN VARCHAR2) -- 'Start Date' or 'End Date')	

		  RETURN DATE
AS	

        LV_TGT_VALUE VARCHAR2(100);
		LV_TGT_VALUE_FINAL VARCHAR2(300);
        /*LV_ERROR_FLAG VARCHAR2(100) := 'FALSE';
        LV_ERROR_FLAG_FINAL VARCHAR2(100) := 'FALSE';
	    LV_ERROR_MSG VARCHAR2(1000) := NULL;
        LV_ERROR_MSG_FINAL VARCHAR2(1000) := NULL;*/
        LV_SEG_NAME VARCHAR2(100) := NULL;
		LV_COA_MAP_ID NUMBER;
		LV_START_DATE_CUR DATE := NULL;
		LV_END_DATE_CUR DATE := NULL;
		LV_START_DATE DATE := NULL;
		LV_END_DATE DATE := NULL;


		CURSOR CUR_COA_MAP_ID IS
		SELECT COA_MAP_ID 
		FROM SL_GL_COA_MAP_STG WHERE SOURCE_SYSTEM = P_IN_SOURCE_SYSTEM AND TARGET_SYSTEM = P_IN_TARGET_SYSTEM;

		CURSOR CUR_SEGMENT_NAME IS
		SELECT SEGMENT_NAME
		FROM SL_GL_COA_SEGMENT_DEFINITIONS_STG
		WHERE SYSTEM_NAME = P_IN_TARGET_SYSTEM
		ORDER BY DISPLAY_SEQUENCE;

		CURSOR CUR_MAPPING_RULE(CUR_P_SEGMENT_NAME VARCHAR2, CUR_P_COA_MAP_ID NUMBER) IS 
		SELECT RULE_PRIORITY, RULE_ID FROM SL_GL_COA_MAPPING_RULES_STG
		WHERE SOURCE_SYSTEM = P_IN_SOURCE_SYSTEM AND TARGET_SYSTEM = P_IN_TARGET_SYSTEM 
        AND TARGET_SEGMENT = CUR_P_SEGMENT_NAME AND COA_MAP_ID = CUR_P_COA_MAP_ID AND DEFAULT_VALUE IS NULL
		ORDER BY RULE_PRIORITY;

		CURSOR CUR_DEF_TGT_VAL(CUR_P_SEGMENT_NAME VARCHAR2, CUR_P_COA_MAP_ID NUMBER) IS
		SELECT DEFAULT_VALUE
		FROM SL_GL_COA_MAPPING_RULES_STG WHERE SOURCE_SYSTEM = P_IN_SOURCE_SYSTEM 
        AND TARGET_SYSTEM = P_IN_TARGET_SYSTEM AND TARGET_SEGMENT = CUR_P_SEGMENT_NAME 
        AND COA_MAP_ID = CUR_P_COA_MAP_ID AND DEFAULT_VALUE IS NOT NULL;

        CURSOR CUR_SEGMENT_DESC(CUR_P_SGT_NAME VARCHAR2, CUR_P_TGT_SYSTEM VARCHAR2) IS
        SELECT SEGMENT_DESC
        FROM SL_GL_COA_SEGMENT_DEFINITIONS_STG
        WHERE SEGMENT_NAME = CUR_P_SGT_NAME AND SYSTEM_NAME = CUR_P_TGT_SYSTEM;

		CURSOR CUR_TGT_VAL(CUR_P_R_ID VARCHAR2, CUR_P_SEGMENT_NAME VARCHAR2, CUR_P_COA_MAP_ID NUMBER) IS 
		SELECT VALUES_TABLE.TARGET_SEGMENT, VALUES_TABLE.START_DATE, VALUES_TABLE.END_DATE
		FROM SL_GL_COA_MAPPING_RULES_STG MAPPING_TABLE, 
		SL_GL_COA_SEGMENT_VALUE_STG VALUES_TABLE
		WHERE
		COA_MAP_ID = CUR_P_COA_MAP_ID
		AND 
		VALUES_TABLE.FLAG = 'Y'
		AND
		((MAPPING_TABLE.TARGET_SEGMENT = CUR_P_SEGMENT_NAME AND MAPPING_TABLE.SOURCE_SEGMENT1='Y' AND MAPPING_TABLE.RULE_ID = VALUES_TABLE.RULE_ID AND VALUES_TABLE.SOURCE_SEGMENT1 = P_IN_SEGMENT1) OR MAPPING_TABLE.SOURCE_SEGMENT1 IS  NULL) 
		AND 
		((MAPPING_TABLE.TARGET_SEGMENT = CUR_P_SEGMENT_NAME AND MAPPING_TABLE.SOURCE_SEGMENT2='Y' AND MAPPING_TABLE.RULE_ID = VALUES_TABLE.RULE_ID AND VALUES_TABLE.SOURCE_SEGMENT2 = P_IN_SEGMENT2) OR MAPPING_TABLE.SOURCE_SEGMENT2 IS  NULL) 
		AND 
		((MAPPING_TABLE.TARGET_SEGMENT = CUR_P_SEGMENT_NAME AND MAPPING_TABLE.SOURCE_SEGMENT3='Y' AND MAPPING_TABLE.RULE_ID = VALUES_TABLE.RULE_ID AND VALUES_TABLE.SOURCE_SEGMENT3 = P_IN_SEGMENT3) OR MAPPING_TABLE.SOURCE_SEGMENT3 IS  NULL) 
		AND 
		((MAPPING_TABLE.TARGET_SEGMENT = CUR_P_SEGMENT_NAME AND MAPPING_TABLE.SOURCE_SEGMENT4='Y' AND MAPPING_TABLE.RULE_ID = VALUES_TABLE.RULE_ID AND VALUES_TABLE.SOURCE_SEGMENT4 = P_IN_SEGMENT4) OR MAPPING_TABLE.SOURCE_SEGMENT4 IS  NULL) 
		AND 
		((MAPPING_TABLE.TARGET_SEGMENT = CUR_P_SEGMENT_NAME AND MAPPING_TABLE.SOURCE_SEGMENT5='Y' AND MAPPING_TABLE.RULE_ID = VALUES_TABLE.RULE_ID AND VALUES_TABLE.SOURCE_SEGMENT5 = P_IN_SEGMENT5) OR MAPPING_TABLE.SOURCE_SEGMENT5 IS  NULL) 
		AND 
		((MAPPING_TABLE.TARGET_SEGMENT = CUR_P_SEGMENT_NAME AND MAPPING_TABLE.SOURCE_SEGMENT6='Y' AND MAPPING_TABLE.RULE_ID = VALUES_TABLE.RULE_ID AND VALUES_TABLE.SOURCE_SEGMENT6 = P_IN_SEGMENT6) OR MAPPING_TABLE.SOURCE_SEGMENT6 IS  NULL) 
		AND 
		((MAPPING_TABLE.TARGET_SEGMENT = CUR_P_SEGMENT_NAME AND MAPPING_TABLE.SOURCE_SEGMENT7='Y' AND MAPPING_TABLE.RULE_ID = VALUES_TABLE.RULE_ID AND VALUES_TABLE.SOURCE_SEGMENT7 = P_IN_SEGMENT7) OR MAPPING_TABLE.SOURCE_SEGMENT7 IS  NULL) 
		AND 
		((MAPPING_TABLE.TARGET_SEGMENT = CUR_P_SEGMENT_NAME AND MAPPING_TABLE.SOURCE_SEGMENT8='Y' AND MAPPING_TABLE.RULE_ID = VALUES_TABLE.RULE_ID AND VALUES_TABLE.SOURCE_SEGMENT8 = P_IN_SEGMENT8) OR MAPPING_TABLE.SOURCE_SEGMENT8 IS  NULL) 
		AND 
		((MAPPING_TABLE.TARGET_SEGMENT = CUR_P_SEGMENT_NAME AND MAPPING_TABLE.SOURCE_SEGMENT9='Y' AND MAPPING_TABLE.RULE_ID = VALUES_TABLE.RULE_ID AND VALUES_TABLE.SOURCE_SEGMENT9 = P_IN_SEGMENT9) OR MAPPING_TABLE.SOURCE_SEGMENT9 IS  NULL) 
		AND 
		((MAPPING_TABLE.TARGET_SEGMENT = CUR_P_SEGMENT_NAME AND MAPPING_TABLE.SOURCE_SEGMENT10='Y' AND MAPPING_TABLE.RULE_ID = VALUES_TABLE.RULE_ID AND VALUES_TABLE.SOURCE_SEGMENT10 = P_IN_SEGMENT10) OR MAPPING_TABLE.SOURCE_SEGMENT10 IS  NULL) 
		AND 
     --   GL_DATE BETWEEN VALUES_TABLE.START_DATE AND VALUES_TABLE.END_DATE
       -- AND
		MAPPING_TABLE.RULE_ID = CUR_P_R_ID
		AND P_IN_TRANSACTION_DATE BETWEEN START_DATE AND END_DATE;


	BEGIN
        -- CURSOR TO GET COA MAP ID
		OPEN CUR_COA_MAP_ID;
		FETCH CUR_COA_MAP_ID INTO LV_COA_MAP_ID;
		CLOSE CUR_COA_MAP_ID;

        -- OPEN LOOP FOR CUR_SEGMENT_NAME CURSOR TO GET SEGMENT WISE COMBINATION  
		FOR SGT_NAME IN CUR_SEGMENT_NAME
		LOOP
            LV_TGT_VALUE := NULL;

		-- OPEN LOOP FOR CUR_MAPPING_RULE TO GET THE RULE ID AND PRIORITY
			FOR MAPPING_RULE IN CUR_MAPPING_RULE(SGT_NAME.SEGMENT_NAME,LV_COA_MAP_ID)
			LOOP 

			-- CUR_TGT_VAL CURSOR TO GET THE TARGET SEGMENT VALUE, START DATE & END DATE
				OPEN CUR_TGT_VAL(MAPPING_RULE.RULE_ID, SGT_NAME.SEGMENT_NAME, LV_COA_MAP_ID);
				FETCH CUR_TGT_VAL INTO LV_TGT_VALUE, LV_START_DATE_CUR, LV_END_DATE_CUR;
				CLOSE CUR_TGT_VAL; 

				IF LV_TGT_VALUE IS NOT NULL THEN

					EXIT;
				END IF;
			END LOOP; 

			-- BELOW CONDITIONS IS TO FETCH DEFAULT VALUE FROM MAPPING RULE TABLE 
			/* IF LV_TGT_VALUE IS NULL THEN
				OPEN CUR_DEF_TGT_VAL(SGT_NAME.SEGMENT_NAME, LV_COA_MAP_ID);
				FETCH CUR_DEF_TGT_VAL INTO LV_TGT_VALUE;
				CLOSE CUR_DEF_TGT_VAL; 

				IF LV_TGT_VALUE IS NULL THEN 
                    OPEN CUR_SEGMENT_DESC(SGT_NAME.SEGMENT_NAME, P_IN_TARGET_SYSTEM);
                    FETCH CUR_SEGMENT_DESC INTO LV_SEG_NAME;
                    CLOSE CUR_SEGMENT_DESC; 

					LV_ERROR_FLAG := 'TRUE';
                    LV_ERROR_MSG := LV_ERROR_MSG || LV_SEG_NAME || ' NOT FOUND ';


				END IF;
			END IF;

			IF SGT_NAME.SEGMENT_NAME = 'SEGMENT1' THEN
				LV_TGT_VALUE_FINAL := LV_TGT_VALUE;
			ELSE
				LV_TGT_VALUE_FINAL := LV_TGT_VALUE_FINAL || '.' ||LV_TGT_VALUE;
			END IF; */


		 IF LV_START_DATE_CUR >= NVL(LV_START_DATE,LV_START_DATE_CUR)
		 THEN LV_START_DATE := LV_START_DATE_CUR;
		 END IF;

		 IF LV_END_DATE_CUR <= NVL(LV_END_DATE,LV_END_DATE_CUR)
		 THEN LV_END_DATE := LV_END_DATE_CUR;
		 END IF;


		END LOOP;

		/*IF (LV_ERROR_FLAG = 'TRUE') THEN
			LV_TGT_VALUE_FINAL :=  'ERROR: '||LV_ERROR_MSG;
		ELSE
			LV_TGT_VALUE_FINAL := LV_TGT_VALUE_FINAL;
		END IF;*/

		IF P_IN_RETURN_DATE_TYPE = 'Start Date' 
		THEN 
		 RETURN LV_START_DATE;
		ELSIF P_IN_RETURN_DATE_TYPE = 'End Date'
        THEN
		 RETURN LV_END_DATE;
		END IF;  

END COA_SEGMENT_VALUE_MAPPING_DATE_FNC;		  

END SL_COA_TRANSFORMATION_PKG;

