--
--
-- The following staging tables must be created before 
-- 1. SL_GL_CCID_MISMATCH_DATA_HDR_STG
-- 2. SL_GL_CCID_MISMATCH_DATA_STG
-- 3. SL_GL_CCID_MISMATCH_REPORT_STG


--
