    PROCEDURE COA_CCID (
        p_coa_map_id  NUMBER,
        p_batch_id    NUMBER,
        p_username    VARCHAR2
    ) IS

--To find out mismatch data from temp table minu cache table
        CURSOR cur_mismatch_data IS
        SELECT
            target_coa,
            source_segment1,
            source_segment2,
            source_segment3,
            source_segment4,
            source_segment5,
            source_segment6,
            source_segment7,
            source_segment8,
            source_segment9,
            source_segment10,
            source_segment,
			start_date, -- added on 28-Aug-2024
			end_date -- added on 28-Aug-2024
        FROM
            SL_GL_CCID_MISMATCH_REPORT_STG
        WHERE
            batch_id = p_batch_id
        MINUS
        SELECT
            target_segment,
            source_segment1,
            source_segment2,
            source_segment3,
            source_segment4,
            source_segment5,
            source_segment6,
            source_segment7,
            source_segment8,
            source_segment9,
            source_segment10,
            source_segment,
			start_date, -- added on 28-Aug-2024
			end_date -- added on 28-Aug-2024
        FROM
            SL_GL_CCID_MAPPING_STG
        WHERE
            enable_flag = 'Y';

--Select coa map name, source system and target system based on coa map id
        CURSOR cur_coa_map_id IS
        SELECT
            coa_map_name,
            source_system,
            target_system
        FROM
            SL_GL_COA_MAP_STG
        WHERE
            coa_map_id = p_coa_map_id;


        lv_coa_map_name   VARCHAR2(100);
        lv_source_system  VARCHAR2(100);
        lv_target_system  VARCHAR2(100);

        min_seq           NUMBER;
        max_seq           NUMBER;
        p_total_count     NUMBER;
        f_total_count     NUMBER;
        p_loop_count      NUMBER; 

--to calculate count of total number of rows inserted in report table, loop count
        CURSOR cur_seq_num IS 
        SELECT
            MIN(CCID_MISMATCH_SEQ_NUM),
            MAX(CCID_MISMATCH_SEQ_NUM),
            COUNT(1),
            MAX(CCID_MISMATCH_SEQ_NUM) - MIN(CCID_MISMATCH_SEQ_NUM) loop_count
        FROM
            SL_GL_CCID_MISMATCH_REPORT_STG
        WHERE
            batch_id = p_batch_id;

--to get count, remaining and completed count
        CURSOR cur_com_count IS
        SELECT
            COUNT(1)
        FROM
            SL_GL_CCID_MISMATCH_REPORT_STG
        WHERE
            target_coa IS NOT NULL
            AND batch_id = p_batch_id;

        com_count         NUMBER;
        rem_count         NUMBER;
        err_msg           VARCHAR2(1000);
    BEGIN
        OPEN cur_coa_map_id;
        FETCH cur_coa_map_id INTO
            lv_coa_map_name,
            lv_source_system,
            lv_target_system;
        CLOSE cur_coa_map_id;

--delete older record from header table
        DELETE FROM SL_GL_CCID_MISMATCH_DATA_HDR_STG
        WHERE
            coa_name = lv_coa_map_name;

        COMMIT;

-- insert new records with starting process of validation
        INSERT INTO SL_GL_CCID_MISMATCH_DATA_HDR_STG (
            username,
            batch_id,
            status,
            coa_name
        ) VALUES (
            p_username,
            p_batch_id,
            'In Process',
            lv_coa_map_name
        );

        COMMIT;

--delete older record/s from mismatch table
        DELETE FROM SL_GL_CCID_MISMATCH_DATA_STG
        WHERE
            coa_name = lv_coa_map_name;

        COMMIT;

--delete older record/s from mismatch report table
        DELETE FROM SL_GL_CCID_MISMATCH_REPORT_STG
        WHERE
            coa_name = lv_coa_map_name;

        COMMIT;

-- insert all the rows from cache table to temp(report) table to run engine on this table
        INSERT INTO SL_GL_CCID_MISMATCH_REPORT_STG (
            coa_name,
            source_segment1,
            source_segment2,
            source_segment3,
            source_segment4,
            source_segment5,
            source_segment6,
            source_segment7,
            source_segment8,
            source_segment9,
            source_segment10,
            batch_id,
            source_segment,
			start_date, -- added on 28-Aug-2024
			end_date -- added on 28-Aug-2024
        )
            SELECT
                lv_coa_map_name,
                source_segment1,
                source_segment2,
                source_segment3,
                source_segment4,
                source_segment5,
                source_segment6,
                source_segment7,
                source_segment8,
                source_segment9,
                source_segment10,
                p_batch_id,
                source_segment,
				start_date, -- added on 28-Aug-2024
			    end_date -- added on 28-Aug-2024
            FROM
                SL_GL_CCID_MAPPING_STG
            WHERE
                    enable_flag = 'Y'
                AND coa_map_id = p_coa_map_id;

        COMMIT;


-- fetch for total count, setting completed count as 0 and remaining as total count
        OPEN cur_seq_num;
        FETCH cur_seq_num INTO
            min_seq,
            max_seq,
            p_total_count,
            p_loop_count;
        CLOSE cur_seq_num;
        f_total_count := p_total_count;
        UPDATE SL_GL_CCID_MISMATCH_DATA_HDR_STG
        SET
            total_count = p_total_count,
            complete_count = 0,
            remaining_count = p_total_count
        WHERE
            batch_id = p_batch_id;

        COMMIT;


--p_total_count is to get loop count (added 5 for the backup purpose only)
        p_total_count := trunc(p_loop_count / 100) + 5;



/* -- commented on 28-Aug-2024
        IF ( p_coa_map_id = 2 ) THEN
            FOR b IN 1..p_total_count LOOP
-- Run engine on tempp table
                UPDATE SL_GL_CCID_MISMATCH_REPORT_STG a
                SET
                    a.target_coa = SL_GL_COA_MAPPING_PKG.coa_mapping(lv_source_system, lv_target_system, a.source_segment1, a.source_segment2,
                    a.source_segment3,
                                                                      a.source_segment4,
                                                                      a.source_segment5,
                                                                      nvl(a.source_segment6, '00000'),
                                                                      a.source_segment7,
                                                                      a.source_segment8,
                                                                      NULL,
                                                                      NULL,
																	  NULL) -- added on 19-Aug-2024
                WHERE
                    ( CCID_MISMATCH_SEQ_NUM BETWEEN min_seq AND min_seq + 100 )
                    AND coa_name = lv_coa_map_name
                    AND target_coa IS NULL
                    AND batch_id = p_batch_id;

                COMMIT;
                OPEN cur_com_count;
                FETCH cur_com_count INTO com_count;
                CLOSE cur_com_count;
 --update completed count and remaining count
                UPDATE SL_GL_CCID_MISMATCH_DATA_HDR_STG
                SET
                    complete_count = com_count,
                    remaining_count = f_total_count - com_count
                WHERE
                    batch_id = p_batch_id;

                COMMIT;
                min_seq := min_seq + 100;
            END LOOP;

        ELSE
            FOR b IN 1..p_total_count LOOP
                UPDATE SL_GL_CCID_MISMATCH_REPORT_STG a
                SET
                    a.target_coa = SL_GL_COA_MAPPING_PKG.coa_mapping(lv_source_system, lv_target_system, a.source_segment1, a.source_segment2,
                    a.source_segment3,
                                                                      a.source_segment4,
                                                                      a.source_segment5,
                                                                      a.source_segment6,
                                                                      a.source_segment7,
                                                                      a.source_segment8,
                                                                      NULL,
                                                                      NULL,
																	  null) -- added on 19-Aug-2024
                WHERE
                    ( CCID_MISMATCH_SEQ_NUM BETWEEN min_seq AND min_seq + 100 )
                    AND coa_name = lv_coa_map_name
                    AND target_coa IS NULL
                    AND batch_id = p_batch_id;

                COMMIT;
                OPEN cur_com_count;
                FETCH cur_com_count INTO com_count;
                CLOSE cur_com_count;
                UPDATE SL_GL_CCID_MISMATCH_DATA_HDR_STG
                SET
                    complete_count = com_count,
                    remaining_count = f_total_count - com_count
                WHERE
                    batch_id = p_batch_id;

                COMMIT;
                min_seq := min_seq + 100;
            END LOOP;

        END IF; */

-- added on 28-Aug-2024

 FOR b IN 1..p_total_count LOOP
                UPDATE SL_GL_CCID_MISMATCH_REPORT_STG a
                SET
                    a.target_coa = SL_GL_COA_MAPPING_PKG.coa_mapping(lv_source_system, lv_target_system, a.source_segment1, a.source_segment2,
                    a.source_segment3,
                                                                      a.source_segment4,
                                                                      a.source_segment5,
                                                                      a.source_segment6,
                                                                      a.source_segment7,
                                                                      a.source_segment8,
                                                                      a.source_segment9,
                                                                      a.source_segment10,
																	  a.start_date) -- added on 19-Aug-2024
                WHERE
                    ( CCID_MISMATCH_SEQ_NUM BETWEEN min_seq AND min_seq + 100 )
                    AND coa_name = lv_coa_map_name
                    AND target_coa IS NULL
                    AND batch_id = p_batch_id;

                COMMIT;
                OPEN cur_com_count;
                FETCH cur_com_count INTO com_count;
                CLOSE cur_com_count;
                UPDATE SL_GL_CCID_MISMATCH_DATA_HDR_STG
                SET
                    complete_count = com_count,
                    remaining_count = f_total_count - com_count
                WHERE
                    batch_id = p_batch_id;

                COMMIT;
                min_seq := min_seq + 100;
            END LOOP;

    --cur to check differnce between temp and cache and insert into main mismatch data table
        FOR i IN cur_mismatch_data LOOP
            INSERT INTO SL_GL_CCID_MISMATCH_DATA_STG (
                coa_name,
                source_segment1,
                source_segment2,
                source_segment3,
                source_segment4,
                source_segment5,
                source_segment6,
                source_segment7,
                source_segment8,
                source_segment9,
                source_segment10,
                target_segment_new,
                batch_id,
                source_segment,
				start_date, -- added on 28-Aug-2024
			    end_date -- added on 28-Aug-2024
            ) VALUES (
                lv_coa_map_name,
                i.source_segment1,
                i.source_segment2,
                i.source_segment3,
                i.source_segment4,
                i.source_segment5,
                i.source_segment6,
                i.source_segment7,
                i.source_segment8,
                i.source_segment9,
                i.source_segment10,
                i.target_coa,
                p_batch_id,
                i.source_segment,
				i.start_date, -- added on 28-Aug-2024
			    i.end_date -- added on 28-Aug-2024
            );

            COMMIT;
        END LOOP;

    --updating mismatch data with older target segment from cache table
        MERGE INTO SL_GL_CCID_MISMATCH_DATA_STG a
        USING SL_GL_CCID_MAPPING_STG b ON ( a.source_segment = b.source_segment
                                           AND a.batch_id = p_batch_id
                                           AND b.enable_flag = 'Y' 
										   and a.start_date = b.start_date -- added on 28-Aug-2024
										   )
        WHEN MATCHED THEN UPDATE
        SET a.target_segment_old = b.target_segment;

        COMMIT;

        UPDATE SL_GL_CCID_MISMATCH_DATA_HDR_STG
        SET
            status = 'Success',
            ccid_status =
                CASE
                    WHEN (
                        SELECT
                            COUNT(1)
                        FROM
                            SL_GL_CCID_MISMATCH_DATA_STG
                        WHERE
                            batch_id = p_batch_id
                    ) = 0 THEN
                        'No Action Required'
                    ELSE
                        'Action Required'
                END,
            last_update_date = sysdate,
            total_mismatch = (
                SELECT
                    COUNT(1)
                FROM
                    SL_GL_CCID_MISMATCH_DATA_STG
                WHERE
                    batch_id = p_batch_id
            )
        WHERE
            batch_id = p_batch_id;

        COMMIT;
    EXCEPTION
        WHEN OTHERS THEN
            UPDATE SL_GL_CCID_MISMATCH_DATA_HDR_STG
            SET
                status = 'Error'
            WHERE
                batch_id = p_batch_id;

            COMMIT;
            err_msg := sqlerrm;
            INSERT INTO SL_GL_TBL_TIME_HIST (
                a,
                b,
                c
            ) VALUES (
                err_msg,
                sysdate,
                909090
            );

            COMMIT;
    END;

    PROCEDURE COA_CCID_UPDATE (
        p_username      VARCHAR2,
        p_coa_map_name  VARCHAR2
    ) IS
    BEGIN
        UPDATE SL_GL_CCID_MISMATCH_DATA_HDR_STG
        SET
            ccid_status = 'In Process'
        WHERE
            coa_name = p_coa_map_name;
--    WHERE BATCH_ID = P_BATCH_ID;
        COMMIT;

--    insert into SL_GL_TBL_TIME_HIST values(P_USERNAME||'123_'||P_COA_MAP_NAME,sysdate,909090990);
--    commit;
--

        UPDATE SL_GL_CCID_MAPPING_STG b
        SET
            enable_flag = 'N',
            last_update_date = sysdate,
            last_updated_by = 'VALIDATED - ' || p_username
        WHERE
		enable_flag = 'Y' AND
            EXISTS (
                SELECT
                    1
                FROM
                    SL_GL_COA_MAP_STG a
                WHERE
                        a.coa_map_name = p_coa_map_name
                    AND a.coa_map_id = b.coa_map_id
            )
            AND (source_segment,start_date) IN (
                SELECT
                    source_segment,start_date
                FROM
                    SL_GL_CCID_MISMATCH_DATA_STG
                WHERE
                    target_segment_old <> target_segment_new
            );

        COMMIT;
        UPDATE SL_GL_CCID_MISMATCH_DATA_HDR_STG b
        SET
            ccid_status = 'Success'
        WHERE
            coa_name = p_coa_map_name
--    where exists (select 1 from SL_GL_COA_MAP_STG a where a.coa_map_name = P_COA_MAP_NAME 
--    and a.COA_MAP_ID = b.COA_MAP_ID ) 
            ;
--    WHERE BATCH_ID = P_BATCH_ID;
        COMMIT;
    END;

    PROCEDURE COA_MISMATCH_CCID_DOWNLOAD (
        o_clobdata       OUT  CLOB,
        p_ccid_map_name  IN   VARCHAR2
    ) IS
        l_blob  BLOB;
        l_clob  CLOB;
    BEGIN 

--INSERT INTO SL_GL_TBL_TIME_HIST (A) VALUES(P_CCID_MAP_ID);
--INSERT INTO SL_GL_TBL_TIME_HIST (A) VALUES(P_ACC_STATUS);
--INSERT INTO SL_GL_TBL_TIME_HIST (A) VALUES(P_ACCOUNTING_PERIOD);
--INSERT INTO SL_GL_TBL_TIME_HIST (A) VALUES(P_SOURCE_SYSTEM);
--COMMIT;
        dbms_lob.createtemporary(lob_loc => l_clob, cache => true,
                                dur => dbms_lob.call); 
--null;
        SELECT
            clob_val
        INTO l_clob
        FROM
            (
                SELECT
                    XMLCAST(XMLAGG(XMLELEMENT(
                        e, col_value
                          || CHR(13)
                          || CHR(10)
                    )) AS CLOB)    AS clob_val,
                    COUNT(*)       AS number_of_rows
                FROM
                    (
                        SELECT
                            'COA_NAME,SOURCE_SEGMENT1,SOURCE_SEGMENT2,SOURCE_SEGMENT3,SOURCE_SEGMENT4,SOURCE_SEGMENT5,SOURCE_SEGMENT6,SOURCE_SEGMENT7,SOURCE_SEGMENT8,SOURCE_SEGMENT9,SOURCE_SEGMENT10,TARGET TEMP TABLE,TARGET CACHE TABLE,START_DATE,END_DATE,MISMATCHED?'
                            AS col_value
                        FROM
                            dual
                        UNION ALL
                        SELECT
                            coa_name
                            || ','
                            || source_segment1
                            || ','
                            || source_segment2
                            || ','
                            || source_segment3
                            || ','
                            || source_segment4
                            || ','
                            || source_segment5
                            || ','
                            || source_segment6
                            || ','
                            || source_segment7
                            || ','
                            || source_segment8
                            || ','
                            || source_segment9
                            || ','
                            || source_segment10
                            || ','
                            || target_segment_new
                            || ','
                            || target_segment_old
                            || ','
							|| START_DATE
                            || ','
							|| END_DATE
                            || ','
                            || mismatch_status
                        FROM
                            (
                                SELECT
                                    coa_name,
                                    source_segment1,
                                    source_segment2,
                                    source_segment3,
                                    source_segment4,
                                    source_segment5,
                                    source_segment6,
                                    source_segment7,
                                    source_segment8,
                                    source_segment9,
                                    source_segment10,
                                    target_segment_new,
                                    target_segment_old,
									START_DATE,
									END_DATE,
                                    'Y' mismatch_status
                                FROM
                                    SL_GL_CCID_MISMATCH_DATA_STG a
--                    ,
--                    SL_GL_COA_MAP_STG c
--                    where c.coa_map_name = a.coa_name
--                    and c.coa_map_id = P_CCID_MAP_ID
                                WHERE
                                    a.coa_name = p_ccid_map_name
                                UNION ALL
                                SELECT 
                    -- DECODE(COA_MAP_ID,1,'SuperLedger to Cloud',2,'Anixter to Cloud',3,'Central to Cloud',4,'POC to Cloud','Peoplesoft to Cloud'),
--                    c.coa_map_name,
                                    b.coa_name,
                                    a.source_segment1,
                                    a.source_segment2,
                                    a.source_segment3,
                                    a.source_segment4,
                                    a.source_segment5,
                                    a.source_segment6,
                                    a.source_segment7,
                                    a.source_segment8,
                                    a.source_segment9,
                                    a.source_segment10,
                                    a.target_segment,
                                    a.target_segment,
									A.START_DATE,
									A.END_DATE,
                                    'N'
                                FROM
                                    SL_GL_CCID_MAPPING_STG         a,
                                    SL_GL_CCID_MISMATCH_DATA_HDR_STG  b,
                                    SL_GL_COA_MAP_STG              c
                    --SL_GL_CCID_MISMATCH_DATA_STG b
                                WHERE 
                    --not exists(select 1 from SL_GL_CCID_MISMATCH_DATA_STG
                    --where a.source_segment = b.source_segment)
                                    (a.source_segment,A.START_DATE) NOT IN (
                                        SELECT
                                            source_segment,START_DATE
                                        FROM
                                            SL_GL_CCID_MISMATCH_DATA_STG
                                    )
                    --and
                                    AND b.status = 'Success'
                                    AND c.coa_map_name = b.coa_name
                                    AND b.coa_name = p_ccid_map_name
                                    AND a.coa_map_id = c.coa_map_id
                                    AND a.enable_flag = 'Y'
--                    and a.coa_map_id = P_CCID_MAP_ID
                            )
                    )
            );

        o_clobdata := l_clob;
    END;

    PROCEDURE COA_CCID_ALL (
        p_coa_map_id  NUMBER,
        p_username    VARCHAR2
    ) IS

        p_batch_id     NUMBER;
        CURSOR cur_coa_map_id IS
        SELECT
            coa_map_id
        FROM
            SL_GL_COA_MAP_STG
        WHERE 1=1;
           -- coa_map_id <> 5; -- COMMENTED ON 28-AUG-2024

        lv_coa_map_id  VARCHAR2(100);
    BEGIN
        FOR i IN cur_coa_map_id LOOP
            lv_coa_map_id := i.coa_map_id;
            p_batch_id := SL_GL_CCID_MISMATCH_BATCH_ID_S.nextval;
            BEGIN
                dbms_scheduler.create_job(job_name => 'SL_GL_CCID_MISMATCH_REPORT_STG_ALL_' || p_batch_id, job_type => 'PLSQL_BLOCK',
                                         job_action => 'DECLARE
        L_ERR_MSG VARCHAR2(2000);
        L_ERR_CODE VARCHAR2(2);
        BEGIN 
            SL_GL_CCID_MISMATCH_REPORT_PKG.COA_CCID('
                                                       || lv_coa_map_id
                                                       || ','
                                                       || p_batch_id
                                                       || ','''
                                                       || p_username
                                                       || ''');
        END;',
                                         enabled => true,
                                         auto_drop => true,
                                         comments => 'SL_GL_CCID_MISMATCH_REPORT_STG');
            END;

        END LOOP;
    END;

END SL_GL_CCID_MISMATCH_REPORT_PKG;

/
