--  DDL for Package Body SL_GL_DISABLED_COA_HANDLE_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."SL_GL_DISABLED_COA_HANDLE_PKG" as

Procedure GL_DISABLED_COA_HANDLE_PRC (P_SEG1 VARCHAR2,
                                      P_SEG2 VARCHAR2,
                                      P_SEG3 VARCHAR2,
                                      P_SEG4 VARCHAR2,
                                      P_SEG5 VARCHAR2,
                                      P_SEG6 VARCHAR2,
                                      P_SEG7 VARCHAR2,
                                      P_SEG8 VARCHAR2,
                                      P_SEG9 VARCHAR2,
                                      P_SEG10 VARCHAR2,
                                      P_RULE_ID VARCHAR2) IS


Begin
--     insert into tbl_time_t values ('IN PKG' ||P_SEG1 ||P_SEG8 ||P_RULE_ID,sysdate,1);


/* -- Commented below script On 06-Sep-2024 
-- Going to update Cache Table based on lower Priority
  UPDATE SL_GL_CCID_MAPPING_STG 
  Set Enable_Flag='N',
      LAST_UPDATE_DATE=Sysdate,
      Version=SL_GL_COA_DISABLE_VER_S.nextval
  where 1=1
  AND (SOURCE_SEGMENT1 = P_SEG1 OR P_SEG1 IS NULL)
  AND (SOURCE_SEGMENT2=P_SEG2 OR P_SEG2 IS NULL)
  AND (SOURCE_SEGMENT3 =P_SEG3 OR P_SEG3 IS NULL)
  AND (SOURCE_SEGMENT4 =P_SEG4 OR P_SEG4 IS NULL)
  AND (SOURCE_SEGMENT5 =P_SEG5 OR P_SEG5 IS NULL)
  AND (SOURCE_SEGMENT6=P_SEG6 OR P_SEG6 IS NULL)
  AND (SOURCE_SEGMENT7 =P_SEG7 OR P_SEG7 IS NULL)
  AND (SOURCE_SEGMENT8 =P_SEG8 OR P_SEG8 IS NULL)
  AND (SOURCE_SEGMENT9=P_SEG9 OR P_SEG9 IS NULL)
  AND (SOURCE_SEGMENT10=P_SEG10 OR P_SEG10 IS NULL)
  AND COA_MAP_ID IN (SELECT COA_MAP_ID FROM SL_GL_COA_MAPPING_RULES_STG where rule_id=P_RULE_ID)
