--  insert into tbl_time_t values ('IN PKG' ||P_SEG2 ||P_RULE_ID,sysdate,1);

-- added below script On 06-Sep-2024 
-- update cache table based on low Priority

 UPDATE SL_GL_CCID_MAPPING_STG GCMT
 Set Enable_Flag='N',
      LAST_UPDATE_DATE=Sysdate,
      Version=SL_GL_COA_DISABLE_VER_S.nextval
  where 1=1
  AND Enable_Flag='Y'
  AND UI_FLAG = 'N'
  AND (GCMT.SOURCE_SEGMENT1 = P_SEG1 OR P_SEG1 IS NULL)
  AND (GCMT.SOURCE_SEGMENT2=P_SEG2 OR P_SEG2 IS NULL)
  AND (GCMT.SOURCE_SEGMENT3 =P_SEG3 OR P_SEG3 IS NULL)
  AND (GCMT.SOURCE_SEGMENT4 =P_SEG4 OR P_SEG4 IS NULL)
  AND (GCMT.SOURCE_SEGMENT5 =P_SEG5 OR P_SEG5 IS NULL)
  AND (GCMT.SOURCE_SEGMENT6=P_SEG6 OR P_SEG6 IS NULL)
  AND (GCMT.SOURCE_SEGMENT7 =P_SEG7 OR P_SEG7 IS NULL)
  AND (GCMT.SOURCE_SEGMENT8 =P_SEG8 OR P_SEG8 IS NULL)
  AND (GCMT.SOURCE_SEGMENT9=P_SEG9 OR P_SEG9 IS NULL)
  AND (GCMT.SOURCE_SEGMENT10=P_SEG10 OR P_SEG10 IS NULL)
  AND ((EXISTS (SELECT 1 
                FROM SL_GL_COA_SEGMENT_VALUE_STG SVT
               WHERE 1=1
                 AND ((GCMT.SEGMENT_VALUE1 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE2 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE3 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE4 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE5 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE6 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE7 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE8 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE9 = SVT.VALUE_ID)
                  OR (GCMT.SEGMENT_VALUE10 = SVT.VALUE_ID))
                 AND SVT.RULE_ID IN (SELECT CMRTP.RULE_ID FROM
                                         (SELECT RULE_PRIORITY, COA_MAP_ID,  RULE_ID, TARGET_SEGMENT FROM SL_GL_COA_MAPPING_RULES_STG  
                                           WHERE RULE_ID = P_RULE_ID) CMRT, SL_GL_COA_MAPPING_RULES_STG CMRTP
                                           WHERE 1=1 AND CMRTP.TARGET_SEGMENT = CMRT.TARGET_SEGMENT AND CMRTP.COA_MAP_ID = CMRT.COA_MAP_ID
                                           AND CMRTP.RULE_PRIORITY > CMRT.RULE_PRIORITY)))
		OR (SELECT COUNT(*) 
										   FROM SL_GL_COA_MAPPING_RULES_STG A
										   WHERE (COA_MAP_ID, TARGET_SEGMENT) IN (
										   SELECT COA_MAP_ID, TARGET_SEGMENT FROM SL_GL_COA_MAPPING_RULES_STG  
                                           WHERE RULE_ID = P_RULE_ID)
												AND RULE_ID IN (SELECT SVT.RULE_ID
					FROM SL_GL_COA_SEGMENT_VALUE_STG SVT
				   WHERE 1=1
					 AND ((GCMT.SEGMENT_VALUE1 = SVT.VALUE_ID)
					  OR (GCMT.SEGMENT_VALUE2 = SVT.VALUE_ID)
					  OR (GCMT.SEGMENT_VALUE3 = SVT.VALUE_ID)
					  OR (GCMT.SEGMENT_VALUE4 = SVT.VALUE_ID)
					  OR (GCMT.SEGMENT_VALUE5 = SVT.VALUE_ID)
					  OR (GCMT.SEGMENT_VALUE6 = SVT.VALUE_ID)
					  OR (GCMT.SEGMENT_VALUE7 = SVT.VALUE_ID)
					  OR (GCMT.SEGMENT_VALUE8 = SVT.VALUE_ID)
					  OR (GCMT.SEGMENT_VALUE9 = SVT.VALUE_ID)
					  OR (GCMT.SEGMENT_VALUE10 = SVT.VALUE_ID)))) = 0);
 -- AND COA_MAP_ID IN (SELECT COA_MAP_ID FROM SL_GL_COA_MAPPING_RULES_STG where rule_id= P_RULE_ID)

commit;
exception when others then  -- added exception on 06-Sep-2024
null;
END;

Procedure GL_DISABLED_CCID_HANDLE_PRC (P_SOURCE_SEGMENT VARCHAR2,
                                       P_COA_MAP_ID VARCHAR2) IS


Begin
--insert into tbl_time_t values ('IN PKG' || P_SOURCE_SEGMENT || '-' || P_COA_MAP_ID,sysdate,3);
commit;

  UPDATE SL_GL_CCID_MAPPING_STG 
  Set Enable_Flag='N',
      LAST_UPDATE_DATE=Sysdate,
      Version=SL_GL_COA_DISABLE_VER_S.nextval
  where 1=1
  AND SOURCE_SEGMENT = TRIM(P_SOURCE_SEGMENT) 
  AND COA_MAP_ID = P_COA_MAP_ID
  AND Enable_Flag='Y'
  AND UI_FLAG = 'N';          
  Commit;
--  insert into tbl_time_t values ('IN PKG AFTER' || P_SOURCE_SEGMENT,sysdate,4);
commit;
END;
--

Procedure GL_SYNC_CCID_COA_PRC is
BEGIN
    MERGE INTO SL_GL_CCID_MAPPING_STG WGM
    USING (select distinct WGCM.CCID_VALUE_ID from SL_GL_CCID_MAPPING_STG WGCM,
    SL_GL_COA_SEGMENT_VALUE_STG wgcs
    where 1=1
    AND ((WGCM.source_segment1=wgcs.source_segment1 OR wgcs.source_segment1 is NULL) and wgcs.flag='N' and WGCM.enable_flag='Y')
    AND ((WGCM.source_segment2=wgcs.source_segment2 OR wgcs.source_segment2 is NULL) and wgcs.flag='N' and WGCM.enable_flag='Y')
    AND ((WGCM.source_segment3=wgcs.source_segment3 OR wgcs.source_segment3 is NULL) and wgcs.flag='N' and WGCM.enable_flag='Y')
    AND ((WGCM.source_segment4=wgcs.source_segment4 OR wgcs.source_segment4 is NULL) and wgcs.flag='N' and WGCM.enable_flag='Y')
    AND ((WGCM.source_segment5=wgcs.source_segment5 OR wgcs.source_segment5 is NULL) and wgcs.flag='N' and WGCM.enable_flag='Y')
    AND ((WGCM.source_segment6=wgcs.source_segment6 OR wgcs.source_segment6 is NULL) and wgcs.flag='N' and WGCM.enable_flag='Y')
    AND ((WGCM.source_segment7=wgcs.source_segment7 OR wgcs.source_segment7 is NULL) and wgcs.flag='N' and WGCM.enable_flag='Y')
    AND ((WGCM.source_segment8=wgcs.source_segment8 OR wgcs.source_segment8 is NULL) and wgcs.flag='N' and WGCM.enable_flag='Y')
    AND ((WGCM.source_segment9=wgcs.source_segment9 OR wgcs.source_segment9 is NULL) and wgcs.flag='N' and WGCM.enable_flag='Y')
    AND ((WGCM.source_segment10=wgcs.source_segment10 OR wgcs.source_segment10 is NULL) and wgcs.flag='N' and WGCM.enable_flag='Y')) WVIEW
    ON (WGM.CCID_VALUE_ID=WVIEW.CCID_VALUE_ID )
    WHEN MATCHED then update set WGM.ENABLE_FLAG='N',
                                Version=SL_GL_COA_DISABLE_VER_S.nextval;

EXCEPTION
WHEN OTHERS THEN
      NULL;
END;

