Version=SL_GL_COA_DISABLE_VER_S.nextval
WHERE 1=1
AND ((nvl(GCMT.segment_value1,0) = P_IN_VALUE_ID) or
     (nvl(GCMT.segment_value2,0) = P_IN_VALUE_ID) or
