     (nvl(GCMT.segment_value4,0) = P_IN_VALUE_ID) or
     (nvl(GCMT.segment_value5,0) = P_IN_VALUE_ID) or
     (nvl(GCMT.segment_value6,0) = P_IN_VALUE_ID) or
     (nvl(GCMT.segment_value7,0) = P_IN_VALUE_ID) or
     (nvl(GCMT.segment_value8,0) = P_IN_VALUE_ID) or
     (nvl(GCMT.segment_value9,0) = P_IN_VALUE_ID) or
     (nvl(GCMT.segment_value10,0) = P_IN_VALUE_ID))
AND (SELECT COUNT(*) FROM SL_GL_COA_SEGMENT_VALUE_STG SVT
WHERE 1=1 
AND SVT.FLAG = 'N'
AND ((GCMT.SEGMENT_VALUE1 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE2 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE3 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE4 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE5 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE6 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE7 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE8 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE9 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE10 = SVT.VALUE_ID))) = 0;
COMMIT;	 

END IF;*/

END COA_DISABLE_CCID_PRC;


/*
PROCEDURE : COA_update_CCID_end_date_PRC
Created ON: 26-Aug-2024
Created By: SureshKumar Ravichandran
Description: To Update CCID End Date with derived values when Segment value table updated with Preponing End Date.
*/
PROCEDURE COA_update_CCID_end_date_PRC (P_IN_VALUE_ID IN NUMBER)
is

CURSOR CUR_CCID IS SELECT GCMT.CCID_VALUE_ID, GCMT.END_DATE
FROM SL_GL_CCID_MAPPING_STG gcmt, SL_GL_COA_MAP_STG CMT
WHERE 1=1
AND GCMT.COA_MAP_ID = CMT.COA_MAP_ID
--and ENABLE_FLAG = 'Y'
and ((nvl(segment_value1,0) = P_IN_VALUE_ID) or
     (nvl(segment_value2,0) = P_IN_VALUE_ID) or
     (nvl(segment_value3,0) = P_IN_VALUE_ID) or
     (nvl(segment_value4,0) = P_IN_VALUE_ID) or
     (nvl(segment_value5,0) = P_IN_VALUE_ID) or
     (nvl(segment_value6,0) = P_IN_VALUE_ID) or
     (nvl(segment_value7,0) = P_IN_VALUE_ID) or
     (nvl(segment_value8,0) = P_IN_VALUE_ID) or
     (nvl(segment_value9,0) = P_IN_VALUE_ID) or
     (nvl(segment_value10,0) = P_IN_VALUE_ID));

LV_end_date date;
lv_status varchar2(15);
lv_error_msg varchar2(500);
Begin

FOR CUR_UPD IN CUR_CCID
LOOP
lv_status := 'Success';
lv_end_date := NULL;

BEGIN

select MIN(SVT.END_DATE) INTO lv_end_date from SL_GL_CCID_MAPPING_STG GCMT, 
SL_GL_COA_SEGMENT_VALUE_STG SVT
where GCMT.CCID_VALUE_ID = CUR_UPD.CCID_VALUE_ID
AND SVT.END_DATE IS NOT NULL
--AND SVT.FLAG = 'Y'
AND ((GCMT.SEGMENT_VALUE1 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE2 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE3 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE4 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE5 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE6 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE7 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE8 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE9 = SVT.VALUE_ID)
OR (GCMT.SEGMENT_VALUE10 = SVT.VALUE_ID));

EXCEPTION WHEN OTHERS THEN 
lv_status := 'Error';
lv_end_date := NULL;
END;


IF lv_status = 'Success' --and lv_end_date < CUR_UPD.END_DATE
THEN 
update SL_GL_CCID_MAPPING_STG set end_date = lv_end_date,
LAST_UPDATE_DATE=Sysdate,
Version=SL_GL_COA_DISABLE_VER_S.nextval
where 1=1
  and CCID_VALUE_ID = CUR_UPD.CCID_VALUE_ID;
END IF;

END LOOP;
-- Insert into xx_text (s_no, error_message,stage) values (21,'Completed: '|| lv_end_date,'COA_update_CCID_end_date_PRC');
-- commit;
exception when others then 
lv_error_msg := sqlerrm;
-- Insert into xx_text (s_no, error_message,stage) values (21,'Exception '||lv_error_msg,'COA_update_CCID_end_date_PRC');
-- commit;
end COA_update_CCID_end_date_PRC;

END SL_GL_DISABLED_COA_HANDLE_PKG;

