  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."SL_GL_UNIVERSAL_PKG" IS
FUNCTION  "CCID_DUPLICATE" ( 
    P_COA_MAP_NAME VARCHAR2,
    P_source_segment VARCHAR2
    /*
    -- Commented On 06-Sep-2024, No start date and end date occur on UI Level
	,start_datev  VARCHAR2, -- ADDED ON 13-Aug-2024
    end_datev VARCHAR2 -- ADDED ON 13-Aug-2024
    */
)RETURN NUMBER IS 
    v_ret_count NUMBER := 0;
    /*
    -- Commented On 06-Sep-2024, No start date and end date occur on UI Level
	v_start_datev date := to_date(start_datev,'dd-mm-yyyy'); -- ADDED ON 13-Aug-2024
	v_end_datev date := to_date(end_datev,'dd-mm-yyyy'); -- ADDED ON 13-Aug-2024
    */
begin


select count(*) into v_ret_count from SL_GL_CCID_MAPPING_STG
where nvl(UPPER(COA_MAP_NAME),'1') = nvl(trim(UPPER(P_COA_MAP_NAME)),'1')
and nvl(SOURCE_SEGMENT,'1') = nvl(trim(P_source_segment),'1')
and enable_flag = 'Y';

/*
    -- Commented On 06-Sep-2024, No start date and end date occur on UI Level
 select count(*) into v_ret_count from SL_GL_CCID_MAPPING_STG
where nvl(UPPER(COA_MAP_NAME),'1') = nvl(trim(UPPER(P_COA_MAP_NAME)),'1')
and nvl(SOURCE_SEGMENT,'1') = nvl(trim(P_source_segment),'1')
and(( v_start_datev between start_date and end_date ) or (v_end_datev between start_date and end_date)
or (v_start_datev<= start_date) and (v_end_datev>= end_date)) -- ADDED ON 13-Aug-2024
and enable_flag = 'Y';
*/
    IF v_ret_count > 0 THEN 
        RETURN 1; 
    ELSE 
        RETURN 0; 
    END IF; 
EXCEPTION 
    WHEN no_data_found THEN 
        RETURN 0; 
    WHEN OTHERS THEN 
        RETURN 0;
    end;
    FUNCTION  "CCID_EXIST_COA_MAP_NAME" ( 
    i_value VARCHAR2  
) RETURN NUMBER IS v_ret_count NUMBER; 
BEGIN 
    SELECT COUNT(*) 
    INTO v_ret_count 
    FROM SL_GL_COA_MAP_STG
    WHERE UPPER(COA_MAP_NAME) = UPPER(TRIM(i_value)); 
	IF v_ret_count > 0 THEN RETURN 1; 
	ELSE RETURN 0; 
	END IF; 
EXCEPTION 
    WHEN no_data_found THEN RETURN 0; 
    WHEN OTHERS THEN RETURN 0; 
END;
FUNCTION  "COA_VALUE_SEGMENT_EXISTS_RULE_NAME" ( 
