PROCEDURE ccid_map_name (o_Clobdata OUT CLOB , P_CCID_MAP_NAME IN Number) IS 
  l_Blob         BLOB; 
  l_Clob         CLOB; 

BEGIN 

  Dbms_Lob.Createtemporary(Lob_Loc => l_Clob, 
                           Cache   => TRUE, 
                           Dur     => Dbms_Lob.Call); 
  SELECT Clob_Val INTO l_Clob 
    FROM (SELECT Xmlcast(Xmlagg(Xmlelement(e, 
                                           Col_Value || Chr(13) || 
                                           Chr(10))) AS CLOB) AS Clob_Val, 
                 COUNT(*) AS Number_Of_Rows 
            FROM (SELECT 'coa_map_name,SOURCE_SEGMENT,TARGET_SEGMENT,Flag,START_DATE,END_DATE' AS Col_Value 
                    FROM Dual 
                  UNION ALL 
                  SELECT coa_map_name||','||SOURCE_SEGMENT||','||TARGET_SEGMENT||','||ENABLE_FLAG||','||START_DATE||','||END_DATE AS Col_Value 
                    FROM (SELECT
    values1.coa_map_name,
    values1.COA_MAP_ID,   
    values1.SOURCE_SEGMENT,
    values1.TARGET_SEGMENT,
	values1.ENABLE_FLAG,
	values1.START_DATE,
	values1.END_DATE
FROM
    SL_GL_CCID_MAPPING_STG values1
WHERE
    ui_flag = 'Y'
    and values1.coa_map_id = nvl(P_CCID_MAP_NAME,values1.coa_map_id)))); 

  o_Clobdata := l_Clob; 
EXCEPTION 
  WHEN OTHERS THEN 
    NULL; 
END;
