 UNION ALL SELECT COA_MAP_NAME||',' ||SOURCE_SEGMENT1||','||SOURCE_SEGMENT2||','||SOURCE_SEGMENT3||','||SOURCE_SEGMENT4||','||SOURCE_SEGMENT5||','||SOURCE_SEGMENT6||','||SOURCE_SEGMENT7||','||SOURCE_SEGMENT8||','||SOURCE_SEGMENT9||','||SOURCE_SEGMENT10||','||TARGET_SEGMENT1||','||TARGET_SEGMENT2||','||TARGET_SEGMENT3||','||TARGET_SEGMENT4||','||TARGET_SEGMENT5||','||TARGET_SEGMENT6||','||TARGET_SEGMENT7||','||TARGET_SEGMENT8||','||TARGET_SEGMENT9||','||TARGET_SEGMENT10||','||TO_CHAR(TRANSACTION_DATE,'DD-MON-YYYY')||','||ERROR_MESSAGE AS Col_Value 
FROM (SELECT COA_MAP_NAME,
