TARGET_SEGMENT6,
TARGET_SEGMENT7,
TARGET_SEGMENT8,
TARGET_SEGMENT9,
TARGET_SEGMENT10,
TRANSACTION_DATE,
START_DATE,
END_DATE,
ERROR_MESSAGE from
SL_GL_USER_COA_MAPPING_STG where user_name = P_USER_NAME order by LINE_ID))); 

  o_Clobdata := l_Clob;
  else
  SELECT Clob_Val 
INTO l_Clob 
FROM (SELECT Xmlcast(Xmlagg(Xmlelement(e, 
                                           Col_Value || Chr(13) || 
                                           Chr(10))) AS CLOB) AS Clob_Val, 
                 COUNT(*) AS Number_Of_Rows 
FROM (SELECT 'COA_MAP_NAME,SOURCE_SEGMENT1, SOURCE_SEGMENT2,SOURCE_SEGMENT3, SOURCE_SEGMENT4,SOURCE_SEGMENT5,SOURCE_SEGMENT6, SOURCE_SEGMENT7,SOURCE_SEGMENT8,SOURCE_SEGMENT9,SOURCE_SEGMENT10,TARGET_SEGMENT1,TARGET_SEGMENT2,TARGET_SEGMENT3, TARGET_SEGMENT4,TARGET_SEGMENT5,TARGET_SEGMENT6,TARGET_SEGMENT7,TARGET_SEGMENT8,TARGET_SEGMENT9,TARGET_SEGMENT10,TRANSACTION_DATE,ERROR_MESSAGE'AS Col_Value FROM Dual)); 
o_Clobdata := l_Clob;
end if;
EXCEPTION 
  WHEN OTHERS THEN 
  errm:= sqlerrm;
    -- insert into tbl_time_t values (errm,sysdate,1);
    -- commit;

END;
PROCEDURE user_coa_map_name (o_Clobdata OUT CLOB , P_COA_MAP_NAME IN Number) IS 
  l_Blob         BLOB; 
  l_Clob         CLOB; 

BEGIN 

  Dbms_Lob.Createtemporary(Lob_Loc => l_Clob, 
                           Cache   => TRUE, 
                           Dur     => Dbms_Lob.Call); 
  SELECT Clob_Val 
    INTO l_Clob 
    FROM (SELECT Xmlcast(Xmlagg(Xmlelement(e, 
                                           Col_Value || Chr(13) || 
                                           Chr(10))) AS CLOB) AS Clob_Val, 
                 COUNT(*) AS Number_Of_Rows 
            FROM (SELECT 'RULE_NAME, SOURCE_SEGMENT1, SOURCE_SEGMENT2,SOURCE_SEGMENT3, SOURCE_SEGMENT4, SOURCE_SEGMENT5,SOURCE_SEGMENT6,SOURCE_SEGMENT7,SOURCE_SEGMENT8,SOURCE_SEGMENT9,SOURCE_SEGMENT10,TARGET_SEGMENT,Flag' AS Col_Value 
                    FROM Dual 
                  UNION ALL 
                  SELECT RULE_NAME||','||SOURCE_SEGMENT1||','||SOURCE_SEGMENT2||','||SOURCE_SEGMENT3||','||SOURCE_SEGMENT4||','||SOURCE_SEGMENT5||','||SOURCE_SEGMENT6||','||SOURCE_SEGMENT7||','||SOURCE_SEGMENT8||','||SOURCE_SEGMENT9||','||SOURCE_SEGMENT10||','||TARGET_SEGMENT||','||Flag AS Col_Value 
                    FROM (SELECT
    values1.VALUE_ID,
    values1.RULE_NAME,
    values1.RULE_ID,   
    values1.SOURCE_SEGMENT1,
    values1.SOURCE_SEGMENT2,
    values1.SOURCE_SEGMENT3,
    values1.SOURCE_SEGMENT4,
    values1.SOURCE_SEGMENT5,
    values1.SOURCE_SEGMENT6,
    values1.SOURCE_SEGMENT7,
    values1.SOURCE_SEGMENT8,
    values1.SOURCE_SEGMENT9,
    values1.SOURCE_SEGMENT10,
    values1.TARGET_SEGMENT,
	values1.Flag
FROM
    SL_GL_COA_SEGMENT_VALUE_STG values1,
    SL_GL_COA_MAPPING_RULES_STG mapping1
WHERE
    values1.rule_name = mapping1.rule_name
    and mapping1.coa_map_id = nvl(P_COA_MAP_NAME,mapping1.coa_map_id)))); 

  o_Clobdata := l_Clob; 
EXCEPTION 
  WHEN OTHERS THEN 
    NULL; 
END;
