PROCEDURE VALUE_SEG_CAHE_DOWNLOAD (o_Clobdata OUT CLOB , P_COA_MAP_NAME IN Number) IS 
  l_Blob         BLOB; 
  l_Clob         CLOB; 

BEGIN 

  Dbms_Lob.Createtemporary(Lob_Loc => l_Clob, 
                           Cache   => TRUE, 
                           Dur     => Dbms_Lob.Call); 
  SELECT Clob_Val INTO l_Clob 
    FROM (SELECT Xmlcast(Xmlagg(Xmlelement(e, 
                                           Col_Value || Chr(13) || 
                                           Chr(10))) AS CLOB) AS Clob_Val, 
                 COUNT(*) AS Number_Of_Rows 
            FROM (SELECT 'COA_MAP_NAME, SOURCE_SEGMENT,TARGET_SEGMENT,ENABLE_FLAG,UI_FLAG,START_DATE,END_DATE,CREATION_DATE,LAST_UPDATE_DATE' AS Col_Value 
                    FROM Dual 
                  UNION ALL 
                  SELECT coa_map_name||','||SOURCE_SEGMENT||','||TARGET_SEGMENT||','||ENABLE_FLAG||','||UI_FLAG||','||START_DATE||','||END_DATE||','||CREATION_DATE||','||LAST_UPDATE_DATE AS Col_Value 
                    FROM (SELECT
    cache.COA_MAP_NAME,
    values1.COA_MAP_ID,   
    values1.SOURCE_SEGMENT,
    values1.TARGET_SEGMENT,
	values1.ENABLE_FLAG,
    values1.UI_FLAG,
	values1.START_DATE,
	values1.END_DATE,
    to_char(values1.creation_date, 'dd-mon-yyyy hh24:mi:ss') as CREATION_DATE, 
    to_char(values1.LAST_UPDATE_DATE, 'dd-mon-yyyy hh24:mi:ss') as LAST_UPDATE_DATE
FROM
    SL_GL_CCID_MAPPING_STG values1, SL_GL_COA_MAP_STG cache
    where   cache.COA_MAP_ID = values1.COA_MAP_ID
    and values1.coa_map_id = nvl(P_COA_MAP_NAME,values1.coa_map_id)  
    order by LAST_UPDATE_DATE desc))); 

  o_Clobdata := l_Clob; 
EXCEPTION 
  WHEN OTHERS THEN 
    NULL; 
END;
