            FROM (SELECT 'RULE_NAME,SOURCE_SEGMENT1,SOURCE_SEGMENT2,SOURCE_SEGMENT3,SOURCE_SEGMENT4,SOURCE_SEGMENT5,SOURCE_SEGMENT6,SOURCE_SEGMENT7,SOURCE_SEGMENT8,SOURCE_SEGMENT9,SOURCE_SEGMENT10,TARGET_SEGMENT,Flag,START_DATE,END_DATE' AS Col_Value 
                    FROM Dual 
                  UNION ALL 
                  SELECT RULE_NAME||','||SOURCE_SEGMENT1||','||SOURCE_SEGMENT2||','||SOURCE_SEGMENT3||','||SOURCE_SEGMENT4||','||SOURCE_SEGMENT5||','||SOURCE_SEGMENT6||','||SOURCE_SEGMENT7||','||SOURCE_SEGMENT8||','||SOURCE_SEGMENT9||','||SOURCE_SEGMENT10||','||TARGET_SEGMENT||','||Flag||','||START_DATE||','||END_DATE AS Col_Value 
                    FROM (SELECT
    values1.VALUE_ID,
    case when values1.RULE_NAME like '%,%' then '"'||values1.RULE_NAME||'"' else values1.RULE_NAME end RULE_NAME,
    values1.RULE_ID,   
    values1.SOURCE_SEGMENT1,
    values1.SOURCE_SEGMENT2,
    values1.SOURCE_SEGMENT3,
    values1.SOURCE_SEGMENT4,
    values1.SOURCE_SEGMENT5,
    values1.SOURCE_SEGMENT6,
    values1.SOURCE_SEGMENT7,
    values1.SOURCE_SEGMENT8,
    values1.SOURCE_SEGMENT9,
    values1.SOURCE_SEGMENT10,
    values1.TARGET_SEGMENT,
	values1.Flag,
	values1.Start_Date,
	values1.End_Date
FROM
    SL_GL_COA_SEGMENT_VALUE_STG values1,
    SL_GL_COA_MAPPING_RULES_STG mapping1
WHERE
    values1.rule_name = mapping1.rule_name
    and mapping1.coa_map_id = nvl(P_COA_MAP_NAME,mapping1.coa_map_id)))); 

  o_Clobdata := l_Clob; 
EXCEPTION 
  WHEN OTHERS THEN 
    NULL; 
END;
end SL_GL_UNIVERSAL_PKG;

/
