--  DDL for Package Body SL_GL_USER_COA_TRANSFORMATION_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."SL_GL_USER_COA_TRANSFORMATION_PKG" IS

    FUNCTION transformation_one ( 
        P_COA_MAP_NAME in varchar2,
        p_src_sgt1 IN varchar2,
        pp_src_sgt2 IN varchar2,
        p_src_sgt3 IN varchar2,
        p_src_sgt4 IN varchar2,
        p_src_sgt5 IN varchar2,
        p_src_sgt6 IN varchar2,
        p_src_sgt7 IN varchar2,
        p_src_sgt8 IN varchar2,
        p_src_sgt9 IN varchar2,
        p_src_sgt10 IN varchar2,
        p_user_name  IN varchar2
    ) RETURN VARCHAR2 IS
    
    LV_COA_MAP_ID number;
    lv_tgt_sgt varchar2(1000) := null;
    lv_target_system varchar2(200) := null;
    lv_source_system varchar2(200):= null ;
    lv_error_msg varchar2(1000) := null;

    p_src_sgt2 varchar2(100) := case when (P_COA_MAP_NAME = 'SuperLedger to Cloud') 
    then LPAD(pp_src_sgt2, 6, '0')
    else pp_src_sgt2 end ;

--    DECODE(P_COA_MAP_NAME,'SuperLedger to Cloud',LPAD(pp_src_sgt2, 6, '0'),pp_src_sgt2);

    lv_src_sgt varchar2(1000) := case when p_src_sgt1 is not null then p_src_sgt1 else null end ||
    case when p_src_sgt2 is not null then '.'|| p_src_sgt2 else null end ||
    case when p_src_sgt3 is not null then '.'|| p_src_sgt3 else null end ||
    case when p_src_sgt4 is not null then '.'|| p_src_sgt4 else null end ||
    case when P_COA_MAP_NAME in ('SuperLedger2 to Cloud')  then '.'|| p_src_sgt5 when p_src_sgt5 is not null then '.'|| p_src_sgt5 else null end ||
    case when p_src_sgt6 is not null then '.'|| case when P_COA_MAP_NAME = 'SuperLedger2 to Cloud' then nvl(p_src_sgt6,'00000') else p_src_sgt6 end else null end ||
    case when p_src_sgt7 is not null then '.'|| p_src_sgt7 else null end ||
    case when P_COA_MAP_NAME in ('SuperLedger to Cloud' , 'SuperLedger3 to Cloud') then '.'|| p_src_sgt8 when p_src_sgt8 is not null  then '.'|| p_src_sgt8 else null end ||
    case when p_src_sgt9 is not null then '.'|| p_src_sgt9 else null end ||
    case when p_src_sgt10 is not null then '.'|| p_src_sgt10 else null end;

    BEGIN  
    --dbms_output.put_line(lv_src_sgt);
    begin
        select coa_map_id into LV_COA_MAP_ID from SL_GL_COA_MAP_STG where upper(coa_map_name) = upper(p_coa_map_name);
    exception 
    WHEN OTHERS THEN 
         LV_COA_MAP_ID := null;
    end;
    --dbms_output.put_line('2 ' ||LV_COA_MAP_ID);

    begin
        select TARGET_SEGMENT into lv_tgt_sgt from SL_GL_CCID_MAPPING_STG
        where SOURCE_SEGMENT = lv_src_sgt and COA_MAP_ID = LV_COA_MAP_ID and ENABLE_FLAG = 'Y';
    exception
    WHEN OTHERS THEN 
         lv_tgt_sgt := null;
    end;
    --dbms_output.put_line('3 '||lv_tgt_sgt);

    begin
       /*
       -- Commented on 19-Aug-2024
	   lv_error_msg := case when upper(P_COA_MAP_NAME) = upper('SuperLedger to Cloud') and (p_src_sgt1 is null and p_src_sgt8 is not null) then 
            'Source Segment 1 Required'
            when upper(P_COA_MAP_NAME) = upper('SuperLedger to Cloud') and (p_src_sgt1 is not null and p_src_sgt8 is null) then 
            'Reference 1 Required'
            when upper(P_COA_MAP_NAME) = upper('SuperLedger to Cloud') and (p_src_sgt9 is not null or p_src_sgt10 is not null) then 
            'Reference 2 and 3 not Required'
            when upper(P_COA_MAP_NAME) = upper('SuperLedger2 to Cloud') and (p_src_sgt1 is null and p_src_sgt2 is not null and p_src_sgt3 is not null and p_src_sgt4 is not null) then 
            'Source Segment 1 to 4 Required'
            when upper(P_COA_MAP_NAME) = upper('SuperLedger3 to Cloud') and (p_src_sgt1 is null and p_src_sgt8 is not null) then 
            'Source Segment 1 Required'
            when upper(P_COA_MAP_NAME) = upper('SuperLedger3 to Cloud') and (p_src_sgt1 is not null and p_src_sgt8 is null) then 
            'Reference 1 Required'
            when upper(P_COA_MAP_NAME) = upper('SuperLedger3 to Cloud') and (p_src_sgt9 is not null or p_src_sgt10 is not null) then 
            'Reference 2 and 3 not Required'
            when upper(P_COA_MAP_NAME) = upper('SuperLedger4 to Cloud') and (p_src_sgt3 is not null or p_src_sgt4 is not null
            or p_src_sgt5 is not null or p_src_sgt6 is not null or p_src_sgt7 is not null or p_src_sgt8 is not null
            or p_src_sgt9 is not null or p_src_sgt10 is not null) then 
            'Source Segment 3 to 7 and Reference 1 to 3 not Required'
            else null end; */
        if lv_error_msg is not null then
            return lv_error_msg;
        end if;
    exception
    WHEN OTHERS THEN 
         null;
    end;
        if lv_tgt_sgt is not null then
            return lv_tgt_sgt;
        else
            select target_system, source_system into lv_target_system, lv_source_system
              from SL_GL_COA_MAP_STG
             where COA_MAP_ID = LV_COA_MAP_ID;
    --dbms_output.put_line(lv_target_system);
    --dbms_output.put_line(lv_source_system);
             lv_tgt_sgt  := SL_GL_COA_MAPPING_PKG.coa_mapping(lv_source_system,lv_target_system,
                p_src_sgt1, p_src_sgt2,p_src_sgt3,
                p_src_sgt4,p_src_sgt5,case when P_COA_MAP_NAME = 'SuperLedger2 to Cloud' then nvl(p_src_sgt6,'00000') else p_src_sgt6 end,
                p_src_sgt7,p_src_sgt8,null,null,NULL);
    --dbms_output.put_line('3'||lv_tgt_sgt);
    if  substr(lv_tgt_sgt,1,instr(lv_tgt_sgt,'.',1,1)-1) is not null then 

            insert into SL_GL_CCID_MAPPING_STG(CCID_VALUE_ID, COA_MAP_ID, SOURCE_SEGMENT, TARGET_SEGMENT, 
            CREATION_DATE, LAST_UPDATE_DATE, ENABLE_FLAG,UI_FLAG, created_by,last_updated_by,source_segment1,source_segment2,source_segment3,source_segment4,source_segment5,
                    source_segment6,source_segment7,source_segment8,source_segment9,source_segment10)
            values (SL_GL_CCID_VALUE_ID_MAPPING_S.nextval,LV_COA_MAP_ID,lv_src_sgt ,
            lv_tgt_sgt,sysdate, sysdate, 'Y','N',p_user_name,p_user_name,p_src_sgt1, p_src_sgt2,p_src_sgt3,
                p_src_sgt4,p_src_sgt5,decode(P_COA_MAP_NAME,'SuperLedger2 to Cloud',nvl(p_src_sgt6,'00000'),p_src_sgt6),
                p_src_sgt7,p_src_sgt8,null,null);
            commit;
        end if;
            return lv_tgt_sgt;
        end if;
    EXCEPTION 
        WHEN OTHERS THEN 
            RETURN null; 
    END transformation_one;

    FUNCTION  "EXIT_COA_MAP_NAME" ( 
        i_value in VARCHAR2
    ) 
    RETURN NUMBER IS 
        v_ret_count NUMBER;
    begin
        select count(*) into v_ret_count from SL_GL_COA_MAP_STG where COA_MAP_NAME = i_value; 
        if(v_ret_count > 0)then
            Return 1;
        else
            Return 0;
        End IF;
        COMMIT;
    Exception
        when no_data_found then
        return 0;
        WHEN OTHERS THEN 
        RETURN 0; 
    end;

    FUNCTION  ccid_match ( 
        src_sgt IN varchar2,
        P_COA_MAP_ID in  number,
		p_transaction_date in date
    ) RETURN VARCHAR2 IS
        f_tgt_sgt varchar2(1000);
        cursor tgt_sgt is select TARGET_SEGMENT from SL_GL_CCID_MAPPING_STG
        where SOURCE_SEGMENT = src_sgt and COA_MAP_ID = P_COA_MAP_ID and ENABLE_FLAG = 'Y'
		and p_transaction_date between start_date and end_date;
    BEGIN  
        open tgt_sgt;
        fetch tgt_sgt into f_tgt_sgt;
        close tgt_sgt;
        return f_tgt_sgt;
    EXCEPTION 
        WHEN no_data_found THEN 
            RETURN null; 
        WHEN OTHERS THEN 
            RETURN null; 
    END ccid_match;

	PROCEDURE leg_coa_transformation(p_batch_id IN number, p_user_name in varchar2) IS

		cursor cur_coa_map_id is 
			select distinct coa_map.coa_map_id, coa_map.target_system, coa_map.source_system
			  from SL_GL_COA_MAP_STG coa_map, SL_GL_USER_COA_MAPPING_STG user_coa
			 where coa_map.COA_MAP_NAME = user_coa.COA_MAP_NAME 
			   and user_coa.batch_id = p_batch_id
               and error_message is null
               order by coa_map_id;

		Cursor cur_user_coa (c_batch_id number, c_coa_map_id number, c_source_system varchar2, c_target_system varchar2) is -- ADDED CURSOR ON 29-Aug-2024
		    SELECT ROWID IDENTIFIER, transaction_date,LEGACY_COA,SOURCE_SEGMENT1,SOURCE_SEGMENT2,SOURCE_SEGMENT3,SOURCE_SEGMENT4,SOURCE_SEGMENT5,
                SOURCE_SEGMENT6,SOURCE_SEGMENT7,SOURCE_SEGMENT8,SOURCE_SEGMENT9,SOURCE_SEGMENT10,
				c_source_system SOURCE_SYSTEM,c_target_system TARGET_SYSTEM
			  FROM  SL_GL_USER_COA_MAPPING_STG line
   			 where batch_id = c_batch_id and error_message is null
                 and COA_MAP_NAME = (select coa_map_name from SL_GL_COA_MAP_STG where COA_MAP_ID = c_coa_map_id);
	    type user_tgt_coa_type is table of cur_user_coa%rowtype;
        lv_tgt_coa user_tgt_coa_type;
/*
		cursor cur_leg_seg_value(cur_p_src_system varchar2, cur_p_tgt_system varchar2, cur_coa_mapid number) is		
			select tgt_coa.LEGACY_COA,SL_GL_COA_MAPPING_PKG.coa_mapping(cur_p_src_system,cur_p_tgt_system,
                tgt_coa.SOURCE_SEGMENT1	,
				tgt_coa.SOURCE_SEGMENT2,tgt_coa.SOURCE_SEGMENT3,tgt_coa.SOURCE_SEGMENT4,tgt_coa.SOURCE_SEGMENT5,
                tgt_coa.SOURCE_SEGMENT6,
				tgt_coa.SOURCE_SEGMENT7,tgt_coa.SOURCE_SEGMENT8,null,null) target_coa from 
                (select line.LEGACY_COA, line.SOURCE_SEGMENT1, line.SOURCE_SEGMENT2, line.SOURCE_SEGMENT3, 
					line.SOURCE_SEGMENT4, line.SOURCE_SEGMENT5, line.SOURCE_SEGMENT6, line.SOURCE_SEGMENT7, line.SOURCE_SEGMENT8
                from SL_GL_USER_COA_MAPPING_STG line
               where line.batch_id = p_batch_id and line.target_coa is null and line.error_message is null
               and COA_MAP_NAME = (select coa_map_name from SL_GL_COA_MAP_STG where COA_MAP_ID = cur_coa_mapid)
				) tgt_coa;
*/
    cursor cur_leg_seg_value(cur_p_src_system varchar2, cur_p_tgt_system varchar2, cur_coa_mapid number) is	
        select tgt_coa.LEGACY_COA,SL_GL_COA_MAPPING_PKG.coa_mapping(cur_p_src_system,cur_p_tgt_system,
                tgt_coa.SOURCE_SEGMENT1	,
				tgt_coa.SOURCE_SEGMENT2,tgt_coa.SOURCE_SEGMENT3,tgt_coa.SOURCE_SEGMENT4,tgt_coa.SOURCE_SEGMENT5,
