        from SL_GL_USER_COA_MAPPING_STG;

	begin 



         /*
		 -- Commented on 19-Aug-2024
		 update SL_GL_USER_COA_MAPPING_STG set ERROR_MESSAGE = case when upper(COA_MAP_NAME) = upper('SuperLedger to Cloud') and (SOURCE_SEGMENT1 is null and SOURCE_SEGMENT8 is not null) then 
