          update SL_GL_USER_COA_MAPPING_STG a set ERROR_MESSAGE = lv_error_msg || ' -> ' || a.COA_MAP_NAME || ' :: COA Map Name value is invalid. Please verify.'
              where SL_GL_USER_COA_TRANSFORMATION_PKG.EXIT_COA_MAP_NAME(a.COA_MAP_NAME) = 0 and batch_id = p_batch_id;
