          update SL_GL_USER_COA_MAPPING_STG a set ERROR_MESSAGE = ERROR_MESSAGE || case when transaction_date is null then ' -> Transaction Date Should have Value' else null end
		  where batch_id = p_batch_id;
		 commit;     

		for lv_coa in cur_coa_map_id 
