--            commit;
			begin
                update SL_GL_USER_COA_MAPPING_STG tgt_coa set target_coa = SL_GL_COA_MAPPING_PKG.coa_mapping(lv_src_system,
                lv_tgt_system,
                tgt_coa.SOURCE_SEGMENT1	,
				tgt_coa.SOURCE_SEGMENT2,tgt_coa.SOURCE_SEGMENT3,tgt_coa.SOURCE_SEGMENT4,tgt_coa.SOURCE_SEGMENT5,
                tgt_coa.SOURCE_SEGMENT6,
				tgt_coa.SOURCE_SEGMENT7,tgt_coa.SOURCE_SEGMENT8,null,null, tgt_coa.TRANSACTION_DATE),  ATTRIBUTE1 = 'Y', 
					LAST_UPDATE_DATE = sysdate 
					where batch_id = p_batch_id and error_message is null
                    and target_coa is null 
                    and COA_MAP_NAME = (select coa_map_name from SL_GL_COA_MAP_STG where COA_MAP_ID = lv_coa_mapid)
                    ;   
                    commit;
