insert into SL_GL_CCID_MAPPING_STG(CCID_VALUE_ID, COA_MAP_ID, SOURCE_SEGMENT, TARGET_SEGMENT, 
                    CREATION_DATE, LAST_UPDATE_DATE, ENABLE_FLAG,UI_FLAG,CREATED_BY,LAST_UPDATED_BY,
                    source_segment1,source_segment2,source_segment3,source_segment4,source_segment5,
                    source_segment6,source_segment7,source_segment8,source_segment9,source_segment10,
					start_date, end_date) -- added start_date and end_date on 19-Aug-2024
select SL_GL_CCID_VALUE_ID_MAPPING_S.nextval , lv_coa_mapid, LEGACY_COA,TARGET_COA,sysdate, sysdate, 'Y','N', p_user_name,p_user_name,source_segment1,source_segment2,source_segment3,source_segment4,source_segment5,
                    source_segment6,source_segment7,source_segment8,source_segment9,source_segment10,
					(SL_COA_TRANSFORMATION_PKG.COA_SEGMENT_VALUE_MAPPING_DATE_FNC (P_IN_SOURCE_SYSTEM => lv_src_system,
                                  P_IN_TARGET_SYSTEM => lv_tgt_system,
				                  P_IN_SEGMENT1 => source_segment1,
				                  P_IN_SEGMENT2 => source_segment2,
				                  P_IN_SEGMENT3 => source_segment3,
				                  P_IN_SEGMENT4 => source_segment4,
				                  P_IN_SEGMENT5 => source_segment5,
				                  P_IN_SEGMENT6 => source_segment6,
				                  P_IN_SEGMENT7 => source_segment7,
				                  P_IN_SEGMENT8 => source_segment8,
				                  P_IN_SEGMENT9 => source_segment9,
				                  P_IN_SEGMENT10 => source_segment10,
				                  P_IN_TRANSACTION_DATE => transaction_date,
								  P_IN_RETURN_DATE_TYPE => 'Start Date')),
					(SL_COA_TRANSFORMATION_PKG.COA_SEGMENT_VALUE_MAPPING_DATE_FNC (P_IN_SOURCE_SYSTEM => lv_src_system,
                                  P_IN_TARGET_SYSTEM => lv_tgt_system,
				                  P_IN_SEGMENT1 => source_segment1,
				                  P_IN_SEGMENT2 => source_segment2,
				                  P_IN_SEGMENT3 => source_segment3,
				                  P_IN_SEGMENT4 => source_segment4,
				                  P_IN_SEGMENT5 => source_segment5,
				                  P_IN_SEGMENT6 => source_segment6,
				                  P_IN_SEGMENT7 => source_segment7,
				                  P_IN_SEGMENT8 => source_segment8,
				                  P_IN_SEGMENT9 => source_segment9,
				                  P_IN_SEGMENT10 => source_segment10,
				                  P_IN_TRANSACTION_DATE => transaction_date,
								  P_IN_RETURN_DATE_TYPE => 'End Date'))			  
from (select distinct LEGACY_COA, TARGET_COA,source_segment1,source_segment2,source_segment3,source_segment4,source_segment5,
                    source_segment6,source_segment7,source_segment8,source_segment9,source_segment10, transaction_date
from SL_GL_USER_COA_MAPPING_STG
			 where batch_id = p_batch_id 
			   and attribute1 = 'Y'  
               and error_message is null
			   and substr(target_coa,1,instr(target_coa,'.',1,1)-1) is not null
               and target_coa is not null 
                    and COA_MAP_NAME = (select coa_map_name from SL_GL_COA_MAP_STG where COA_MAP_ID = lv_coa_mapid));  
				commit;
                exception when others then 
                v_error_msg := SQLERRM;

					commit;
			end; 
			-- End Comment on 29-Aug-2024 
			*/
--            insert into SL_GL_TBL_TIME_HIST (a,b) values ('4',sysdate);
--            commit;

-- Added below code on 29-Aug-2024 to get Target Coa and Insert Combination CCID 
begin
				FOR RECIDX IN cur_user_coa (p_batch_id,lv_coa_mapid,lv_src_system,lv_tgt_system)
				loop

				SL_COA_TRANSFORMATION_PKG.COA_MAIN_PRC (P_IN_SOURCE_SYSTEM => RECIDX.SOURCE_SYSTEM,
                                     P_IN_TARGET_SYSTEM => RECIDX.TARGET_SYSTEM,
                                     P_IN_SEGMENT1 => RECIDX.SOURCE_SEGMENT1,
                                     P_IN_SEGMENT2 => RECIDX.SOURCE_SEGMENT2,
                                     P_IN_SEGMENT3 => RECIDX.SOURCE_SEGMENT3,
                                     P_IN_SEGMENT4 => RECIDX.SOURCE_SEGMENT4,
                                     P_IN_SEGMENT5 => RECIDX.SOURCE_SEGMENT5,
                                     P_IN_SEGMENT6 => RECIDX.SOURCE_SEGMENT6,
                                     P_IN_SEGMENT7 => RECIDX.SOURCE_SEGMENT7,
                                     P_IN_SEGMENT8 => RECIDX.SOURCE_SEGMENT8,
                                     P_IN_SEGMENT9 => RECIDX.SOURCE_SEGMENT9,
                                     P_IN_SEGMENT10 => RECIDX.SOURCE_SEGMENT10,
                                     P_IN_TRANSACTION_DATE => RECIDX.transaction_date,
                                     P_OUT_TARGET_SYSTEM => LV_TARGET_SEGMENT,
                                     P_OUT_STATUS => LV_STATUS,
                                     P_OUT_MESSAGE => LV_MESSAGE);


                   UPDATE SL_GL_USER_COA_MAPPING_STG SET target_coa = nvl(LV_TARGET_SEGMENT, LV_MESSAGE)
					where rowid = RECIDX.IDENTIFIER;   
                  commit;
               end loop;
               --close cur_user_coa;
				commit;
end;
-- End Adding on 29-Aug-2024 

            begin
				update SL_GL_USER_COA_MAPPING_STG
				set TARGET_SEGMENT1 = substr(target_coa,1,instr(target_coa,'.',1,1)-1) ,
					TARGET_SEGMENT2 = substr(target_coa,instr(target_coa,'.',1,1)+1,instr(target_coa,'.',1,2)-instr(target_coa,'.',1,1)-1) ,
					TARGET_SEGMENT3 = substr(target_coa,instr(target_coa,'.',1,2)+1,instr(target_coa,'.',1,3)-instr(target_coa,'.',1,2)-1) ,
					TARGET_SEGMENT4 = substr(target_coa,instr(target_coa,'.',1,3)+1,instr(target_coa,'.',1,4)-instr(target_coa,'.',1,3)-1) ,
					TARGET_SEGMENT5 = substr(target_coa,instr(target_coa,'.',1,4)+1,instr(target_coa,'.',1,5)-instr(target_coa,'.',1,4)-1) ,
					TARGET_SEGMENT6 = substr(target_coa,instr(target_coa,'.',1,5)+1,instr(target_coa,'.',1,6)-instr(target_coa,'.',1,5)-1) ,
					TARGET_SEGMENT7 = substr(target_coa,instr(target_coa,'.',1,6)+1,instr(target_coa,'.',1,7)-instr(target_coa,'.',1,6)-1) ,
					TARGET_SEGMENT8 = --substr(target_coa,instr(target_coa,'.',1,7)+1,instr(target_coa,'.',1,8)-instr(target_coa,'.',1,7)-1) ,
					substr(target_coa,instr(target_coa,'.',1,7)+1),
					TARGET_SEGMENT9 = -- substr(target_coa,instr(target_coa,'.',1,8)+1) , -- commented on 19-Aug-2024
					(CASE WHEN instr(target_coa,'.',1,8) > 0 THEN
					substr(target_coa,instr(target_coa,'.',1,8)+1,instr(target_coa,'.',1,9)-instr(target_coa,'.',1,8)-1) 
					ELSE NULL END), -- added on 19-Aug-2024
					TARGET_SEGMENT10 = -- substr(target_coa,instr(target_coa,'.',1,9)+1,instr(target_coa,'.',1,10)-instr(target_coa,'.',1,9)-1) ,  -- commented on 19-Aug-2024
					(CASE WHEN instr(target_coa,'.',1,9) > 0 THEN
					substr(target_coa,instr(target_coa,'.',1,9)+1) 
					ELSE NULL END),  -- added on 19-Aug-2024
					LAST_UPDATE_DATE = sysdate
				where batch_id = p_batch_id 
                  and error_message is null
				  and substr(target_coa,1,instr(target_coa,'.',1,1)-1)  is not null
                  and COA_MAP_NAME = (select coa_map_name from SL_GL_COA_MAP_STG where COA_MAP_ID = lv_coa_mapid);
				commit;
			exception
				when others then
					dbms_output.put_line('Error with Query:  ' || SQLERRM);
			end;
--            insert into SL_GL_TBL_TIME_HIST (a,b) values ('5',sysdate);
--            commit;
            update
			(
			select user_coa.ERROR_MESSAGE,user_coa.LAST_UPDATE_DATE,
			   user_coa.batch_id, user_coa.target_coa tgt_coa
				  from SL_GL_USER_COA_MAPPING_STG user_coa
				where user_coa.batch_id = p_batch_id
                 and error_message is null
                 and COA_MAP_NAME = (select coa_map_name from SL_GL_COA_MAP_STG where COA_MAP_ID = lv_coa_mapid)
				 and substr(user_coa.target_coa,1,instr(user_coa.target_coa,'.',1,1)-1)  is null
			)
			set 
			   ERROR_MESSAGE = tgt_coa,
			   LAST_UPDATE_DATE = sysdate;


--            insert into SL_GL_TBL_TIME_HIST (a,b) values ('6',sysdate);
--            commit;
		end loop;
        update SL_GL_USER_COA_MAPPING_HDR_STG set status='Success' , last_update_date = sysdate 
        where HEADER_ID = p_batch_id;
        commit;
	end leg_coa_transformation; 


	PROCEDURE leg_coa_transformation_adfdi(p_batch_id IN number, p_user_name in varchar2) IS

		cursor cur_coa_map_id is 
			select distinct coa_map.coa_map_id, coa_map.target_system, coa_map.source_system
			  from SL_GL_COA_MAP_STG coa_map, SL_GL_ADFDI_COA_MAPPING_STG user_coa
			 where coa_map.COA_MAP_NAME = user_coa.COA_MAP_NAME 
			   and user_coa.batch_id = p_batch_id
               and error_message is null
               order by coa_map_id;

		Cursor cur_user_coa (c_batch_id number, c_coa_map_id number, c_source_system varchar2, c_target_system varchar2) is -- ADDED CURSOR ON 30-Aug-2024
		    SELECT ROWID IDENTIFIER, transaction_date,LEGACY_COA,SOURCE_SEGMENT1,SOURCE_SEGMENT2,SOURCE_SEGMENT3,SOURCE_SEGMENT4,SOURCE_SEGMENT5,
                SOURCE_SEGMENT6,SOURCE_SEGMENT7,SOURCE_SEGMENT8,SOURCE_SEGMENT9,SOURCE_SEGMENT10,
				c_source_system SOURCE_SYSTEM,c_target_system TARGET_SYSTEM, ACCOUNTING_DATE
			  FROM  SL_GL_ADFDI_COA_MAPPING_STG line
   			 where batch_id = c_batch_id and error_message is null
                 and COA_MAP_NAME = (select coa_map_name from SL_GL_COA_MAP_STG where COA_MAP_ID = c_coa_map_id);
	    type user_tgt_coa_type is table of cur_user_coa%rowtype;
        lv_tgt_coa user_tgt_coa_type;	   
/*
		cursor cur_leg_seg_value(cur_p_src_system varchar2, cur_p_tgt_system varchar2, cur_coa_mapid number) is		
			select tgt_coa.LEGACY_COA,SL_GL_COA_MAPPING_PKG.coa_mapping(cur_p_src_system,cur_p_tgt_system,
                tgt_coa.SOURCE_SEGMENT1	,
				tgt_coa.SOURCE_SEGMENT2,tgt_coa.SOURCE_SEGMENT3,tgt_coa.SOURCE_SEGMENT4,tgt_coa.SOURCE_SEGMENT5,
                tgt_coa.SOURCE_SEGMENT6,
				tgt_coa.SOURCE_SEGMENT7,tgt_coa.SOURCE_SEGMENT8,null,null) target_coa from 
                (select line.LEGACY_COA, line.SOURCE_SEGMENT1, line.SOURCE_SEGMENT2, line.SOURCE_SEGMENT3, 
					line.SOURCE_SEGMENT4, line.SOURCE_SEGMENT5, line.SOURCE_SEGMENT6, line.SOURCE_SEGMENT7, line.SOURCE_SEGMENT8
                from SL_GL_ADFDI_COA_MAPPING_STG line
               where line.batch_id = p_batch_id and line.target_coa is null and line.error_message is null
               and COA_MAP_NAME = (select coa_map_name from SL_GL_COA_MAP_STG where COA_MAP_ID = cur_coa_mapid)
				) tgt_coa;
*/
    cursor cur_leg_seg_value(cur_p_src_system varchar2, cur_p_tgt_system varchar2, cur_coa_mapid number) is	
        select tgt_coa.LEGACY_COA,SL_GL_COA_MAPPING_PKG.coa_mapping(cur_p_src_system,cur_p_tgt_system,
                tgt_coa.SOURCE_SEGMENT1	,
				tgt_coa.SOURCE_SEGMENT2,tgt_coa.SOURCE_SEGMENT3,tgt_coa.SOURCE_SEGMENT4,tgt_coa.SOURCE_SEGMENT5,
                tgt_coa.SOURCE_SEGMENT6,
				tgt_coa.SOURCE_SEGMENT7,tgt_coa.SOURCE_SEGMENT8,null,null,tgt_coa.TRANSACTION_DATE) target_coa from 
                SL_GL_ADFDI_COA_MAPPING_STG tgt_coa
                where tgt_coa.batch_id = p_batch_id and tgt_coa.target_coa is null and tgt_coa.error_message is null
               and COA_MAP_NAME = (select coa_map_name from SL_GL_COA_MAP_STG where COA_MAP_ID = cur_coa_mapid);

		type leg_seg_value_type is table of cur_leg_seg_value%rowtype;
        lv_leg_seg_value leg_seg_value_type;

		cursor cur_inserting_ccid_table is
			select distinct LEGACY_COA, TARGET_COA from SL_GL_ADFDI_COA_MAPPING_STG
			 where batch_id = p_batch_id 
			   and attribute1 = 'Y'  
               and error_message is null
			   and substr(target_coa,1,instr(target_coa,'.',1,1)-1) is not null;  

		type inserting_ccid_table_type is table of cur_inserting_ccid_table%rowtype;
        lv_inserting_ccid_table inserting_ccid_table_type;

		lv_coa_mapid number;
        lv_src_system varchar2(100);
        lv_tgt_system varchar2(100);
		lv_target_coa varchar2(1000);
        v_error_msg varchar2(500);
        LV_COA_MAP_CNT number;
        lv_error_msg varchar2(400);
        lv_error1 varchar2(30) := 'False';
        lv_error2 varchar2(30) := 'False';
		-- ADDED ON 30-AUG-2024
		LV_MESSAGE VARCHAR2(500);
		LV_STATUS VARCHAR2(50);
		LV_TARGET_SEGMENT VARCHAR2(300);
        -- END ADDING ON 30-AUG-2024

        cursor cur_line_table is select SOURCE_SEGMENT1,
        SOURCE_SEGMENT2,
        SOURCE_SEGMENT3,
        SOURCE_SEGMENT4,
        SOURCE_SEGMENT5,
        SOURCE_SEGMENT6,
        SOURCE_SEGMENT7,
        SOURCE_SEGMENT8,
        SOURCE_SEGMENT9,
        SOURCE_SEGMENT10,
        COA_MAP_NAME
        from SL_GL_ADFDI_COA_MAPPING_STG;

	begin 

         /*
		 -- Commented on 19-Aug-2024
		 update SL_GL_ADFDI_COA_MAPPING_STG set ERROR_MESSAGE = case when upper(COA_MAP_NAME) = upper('SuperLedger to Cloud') and (SOURCE_SEGMENT1 is null and SOURCE_SEGMENT8 is not null) then 
        'Source Segment 1 Required'
        when upper(COA_MAP_NAME) = upper('SuperLedger to Cloud') and (SOURCE_SEGMENT1 is not null and SOURCE_SEGMENT8 is null) then 
        'Reference 1 Required'
        when upper(COA_MAP_NAME) = upper('SuperLedger to Cloud') and (SOURCE_SEGMENT9 is not null or SOURCE_SEGMENT10 is not null) then 
        'Reference 2 and 3 not Required'
        when upper(COA_MAP_NAME) = upper('SuperLedger3 to Cloud') and (SOURCE_SEGMENT1 is null and SOURCE_SEGMENT8 is not null) then 
        'Source Segment 1 Required'
        when upper(COA_MAP_NAME) = upper('SuperLedger3 to Cloud') and (SOURCE_SEGMENT1 is not null and SOURCE_SEGMENT8 is null) then 
        'Reference 1 Required'
        when upper(COA_MAP_NAME) = upper('SuperLedger3 to Cloud') and (SOURCE_SEGMENT9 is not null or SOURCE_SEGMENT10 is not null) then 
        'Reference 2 and 3 not Required'
        when upper(COA_MAP_NAME) = upper('SuperLedger4 to Cloud') and (SOURCE_SEGMENT3 is not null or SOURCE_SEGMENT4 is not null
        or SOURCE_SEGMENT5 is not null or SOURCE_SEGMENT6 is not null or SOURCE_SEGMENT7 is not null or SOURCE_SEGMENT8 is not null
        or SOURCE_SEGMENT9 is not null or SOURCE_SEGMENT10 is not null) then 
        'Source Segment 3 to 7 and Reference 1 to 3 not Required'
        else null end
        where batch_id = p_batch_id; */
