--          commit;
--          
          update SL_GL_ADFDI_COA_MAPPING_STG a set ERROR_MESSAGE = lv_error_msg || ' -> ' || a.COA_MAP_NAME || ' :: COA Map Name value is invalid. Please verify.'
              where SL_GL_USER_COA_TRANSFORMATION_PKG.EXIT_COA_MAP_NAME(a.COA_MAP_NAME) = 0 and batch_id = p_batch_id;

		  -- Added on 30-Aug-2024 
          update SL_GL_ADFDI_COA_MAPPING_STG a set ERROR_MESSAGE = ERROR_MESSAGE || case when ACCOUNTING_DATE is null then ' -> Accounting Date Should have Value' else null end
		  where batch_id = p_batch_id;	  
          commit;     

		for lv_coa in cur_coa_map_id 
		loop
			lv_coa_mapid := lv_coa.coa_map_id;
			lv_tgt_system := lv_coa.target_system;
			lv_src_system := lv_coa.source_system;
--            insert into SL_GL_TBL_TIME_HIST (a,b) values ('1',sysdate);
--            commit;

/* Added comment on 29-Aug-2024
-- Below Codes are commented, because we going to use SL_SL_COA_TRANSFORMATION_PKGit will do the same process and capture some 
-- extra information and inserting into CCID Table.

			begin 
				UPDATE SL_GL_ADFDI_COA_MAPPING_STG line
				   SET TARGET_coa = SL_GL_USER_COA_TRANSFORMATION_PKG.ccid_match(LEGACY_COA,lv_coa_mapid,transaction_date), LAST_UPDATE_DATE = sysdate
				 where batch_id = p_batch_id and error_message is null
                 and COA_MAP_NAME = (select coa_map_name from SL_GL_COA_MAP_STG where COA_MAP_ID = lv_coa_mapid);
				   /*and exists 
					(select 1 from SL_GL_CCID_MAPPING_STG ccid_map
					  where ccid_map.coa_map_id = lv_coa_mapid and line.LEGACY_COA = ccid_map.source_segment);
				*-/commit;  -- added - on 30-Aug-2024
			exception 
				when others then
					dbms_output.put_line('Error with Query:  ' || SQLERRM);
			end;
