                    CREATION_DATE, LAST_UPDATE_DATE, ENABLE_FLAG,UI_FLAG,CREATED_BY,LAST_UPDATED_BY,
                    source_segment1,source_segment2,source_segment3,source_segment4,source_segment5,
                    source_segment6,source_segment7,source_segment8,source_segment9,source_segment10,
					start_date, end_date) -- added start_date and end_date on 19-Aug-2024
select SL_GL_CCID_VALUE_ID_MAPPING_S.nextval , lv_coa_mapid, LEGACY_COA,TARGET_COA,sysdate, sysdate, 'Y','N', p_user_name,p_user_name,source_segment1,source_segment2,source_segment3,source_segment4,source_segment5,
                    source_segment6,source_segment7,source_segment8,source_segment9,source_segment10,
