				                  P_IN_SEGMENT5 => source_segment5,
				                  P_IN_SEGMENT6 => source_segment6,
				                  P_IN_SEGMENT7 => source_segment7,
				                  P_IN_SEGMENT8 => source_segment8,
				                  P_IN_SEGMENT9 => source_segment9,
				                  P_IN_SEGMENT10 => source_segment10,
				                  P_IN_TRANSACTION_DATE => transaction_date,
								  P_IN_RETURN_DATE_TYPE => 'Start Date')),
					(SL_COA_TRANSFORMATION_PKG.COA_SEGMENT_VALUE_MAPPING_DATE_FNC (P_IN_SOURCE_SYSTEM => lv_src_system,
                                  P_IN_TARGET_SYSTEM => lv_tgt_system,
				                  P_IN_SEGMENT1 => source_segment1,
				                  P_IN_SEGMENT2 => source_segment2,
				                  P_IN_SEGMENT3 => source_segment3,
				                  P_IN_SEGMENT4 => source_segment4,
				                  P_IN_SEGMENT5 => source_segment5,
				                  P_IN_SEGMENT6 => source_segment6,
				                  P_IN_SEGMENT7 => source_segment7,
