                                     P_IN_SEGMENT3 => RECIDX.SOURCE_SEGMENT3,
                                     P_IN_SEGMENT4 => RECIDX.SOURCE_SEGMENT4,
                                     P_IN_SEGMENT5 => RECIDX.SOURCE_SEGMENT5,
                                     P_IN_SEGMENT6 => RECIDX.SOURCE_SEGMENT6,
                                     P_IN_SEGMENT7 => RECIDX.SOURCE_SEGMENT7,
                                     P_IN_SEGMENT8 => RECIDX.SOURCE_SEGMENT8,
                                     P_IN_SEGMENT9 => RECIDX.SOURCE_SEGMENT9,
