PROCEDURE transformation_one_prc ( 
        P_COA_MAP_NAME in varchar2,
        p_src_sgt1 IN varchar2,
        pp_src_sgt2 IN varchar2,
        p_src_sgt3 IN varchar2,
        p_src_sgt4 IN varchar2,
        p_src_sgt5 IN varchar2,
        p_src_sgt6 IN varchar2,
        p_src_sgt7 IN varchar2,
        p_src_sgt8 IN varchar2,
        p_src_sgt9 IN varchar2,
        p_src_sgt10 IN varchar2,
        p_user_name  IN varchar2,
		P_TRANSACTION_DATE IN DATE,
		p_out_trgt_sgt out varchar2
    )
	as
    LV_COA_MAP_ID number;
    lv_tgt_sgt varchar2(1000) := null;
    lv_target_system varchar2(200) := null;
    lv_source_system varchar2(200):= null ;
    lv_error_msg varchar2(1000) := null;
    LV_MESSAGE VARCHAR2(500);
	LV_STATUS VARCHAR2(50);
	LV_TARGET_SEGMENT VARCHAR2(300);
BEGIN

begin
        select coa_map_id, target_system, source_system into 
		LV_COA_MAP_ID, lv_target_system, lv_source_system 
		from SL_GL_COA_MAP_STG where upper(coa_map_name) = upper(p_coa_map_name);
    exception 
    WHEN OTHERS THEN 
         LV_COA_MAP_ID := null;
end;

begin

SL_COA_TRANSFORMATION_PKG.COA_MAIN_PRC (P_IN_SOURCE_SYSTEM => lv_source_system,
                                     P_IN_TARGET_SYSTEM => lv_target_system,
                                     P_IN_SEGMENT1 => p_src_sgt1,
                                     P_IN_SEGMENT2 => pp_src_sgt2,
                                     P_IN_SEGMENT3 => p_src_sgt3,
                                     P_IN_SEGMENT4 => p_src_sgt4,
                                     P_IN_SEGMENT5 => p_src_sgt5,
                                     P_IN_SEGMENT6 => p_src_sgt6,
                                     P_IN_SEGMENT7 => p_src_sgt7,
                                     P_IN_SEGMENT8 => p_src_sgt8,
                                     P_IN_SEGMENT9 => p_src_sgt9,
                                     P_IN_SEGMENT10 => p_src_sgt10,
                                     P_IN_TRANSACTION_DATE => P_TRANSACTION_DATE,
                                     P_OUT_TARGET_SYSTEM => LV_TARGET_SEGMENT,
                                     P_OUT_STATUS => LV_STATUS,
                                     P_OUT_MESSAGE => LV_MESSAGE);

	p_out_trgt_sgt := 	NVL(LV_TARGET_SEGMENT,LV_MESSAGE);						 
EXCEPTION WHEN OTHERS THEN 
dbms_output.put_line('Exception Error');
END;									 

END transformation_one_prc;


END SL_GL_USER_COA_TRANSFORMATION_PKG;

