    PROCEDURE update_party_stg_status (
        p_oic_instance_id  IN  VARCHAR2,
        p_party_id         IN  NUMBER,
        p_party_number     IN  VARCHAR2,
        p_process_status   IN  VARCHAR2 DEFAULT 'PROCESSED',
        p_status           OUT VARCHAR2,
        p_message          OUT VARCHAR2
    )
    IS
        l_row_count NUMBER := 0;
    BEGIN
        UPDATE TERAR_SEMARCHY_PARTY_STG
        SET    PROCESS_STATUS   = p_process_status,
               PartyId          = p_party_id,
               PartyNumber      = p_party_number,
               LAST_UPDATE_DATE = SYSDATE
        WHERE  OIC_INSTANCE_ID = p_oic_instance_id
          AND  PROCESS_STATUS IN ('NEW', 'ERROR');
        l_row_count := SQL%ROWCOUNT;
        IF l_row_count = 0 THEN
            p_status  := 'WARNING';
            p_message := 'No eligible records found to update for OIC_INSTANCE_ID: ' || p_oic_instance_id;
        ELSE
            COMMIT;
            p_status  := 'SUCCESS';
            p_message := l_row_count || ' record(s) updated successfully.';
        END IF;

        UPDATE TERAR_SEMARCHY_ACCOUNT_STG
        SET    PartyId          = p_party_id,
               LAST_UPDATE_DATE = SYSDATE
