    PROCEDURE check_overall_status (
              p_oic_instance_id IN VARCHAR2,
              p_overall_status  OUT VARCHAR2,
              p_status          OUT VARCHAR2,
              p_message         OUT VARCHAR2
              )
    AS
        v_total_count     NUMBER := 0;
        v_processed_count NUMBER := 0;
        v_tbl_total       NUMBER;
        v_tbl_processed   NUMBER;
    BEGIN

        SELECT COUNT(*),
               COUNT(CASE WHEN Process_status = 'PROCESSED' THEN 1 END)
          INTO v_tbl_total, v_tbl_processed
          FROM TERAR_SEMARCHY_PARTY_STG
         WHERE oic_instance_id = p_oic_instance_id;

        v_total_count     := v_total_count     + v_tbl_total;
        v_processed_count := v_processed_count + v_tbl_processed;

        SELECT COUNT(*),
               COUNT(CASE WHEN Process_status = 'PROCESSED' THEN 1 END)
          INTO v_tbl_total, v_tbl_processed
          FROM TERAR_SEMARCHY_ACCOUNT_STG
         WHERE oic_instance_id = p_oic_instance_id;

        v_total_count     := v_total_count     + v_tbl_total;
        v_processed_count := v_processed_count + v_tbl_processed;

        SELECT COUNT(*),
               COUNT(CASE WHEN Process_status = 'PROCESSED' THEN 1 END)
          INTO v_tbl_total, v_tbl_processed
          FROM TERAR_SEMARCHY_PARTYSITE_STG
         WHERE oic_instance_id = p_oic_instance_id;

        v_total_count     := v_total_count     + v_tbl_total;
        v_processed_count := v_processed_count + v_tbl_processed;

        SELECT COUNT(*),
               COUNT(CASE WHEN Process_status = 'PROCESSED' THEN 1 END)
          INTO v_tbl_total, v_tbl_processed
          FROM TERAR_SEMARCHY_ACCTSITE_STG
         WHERE oic_instance_id = p_oic_instance_id;

        v_total_count     := v_total_count     + v_tbl_total;
        v_processed_count := v_processed_count + v_tbl_processed;

        SELECT COUNT(*),
               COUNT(CASE WHEN Process_status = 'PROCESSED' THEN 1 END)
          INTO v_tbl_total, v_tbl_processed
          FROM TERAR_SEMARCHY_CONTACT_STG
         WHERE oic_instance_id = p_oic_instance_id;

        v_total_count     := v_total_count     + v_tbl_total;
        v_processed_count := v_processed_count + v_tbl_processed;

        IF v_total_count > 0 AND v_total_count = v_processed_count THEN
            p_overall_status := 'SUCCESS';
        ELSE
            p_overall_status := 'FAILED';
        END IF;

    EXCEPTION
        WHEN OTHERS THEN
            p_status  := 'ERROR';
            p_message := 'Error updating records: ' || SQLERRM;		

    END check_overall_status;	

END TERAR_SEMARCHY_CUSTOMER_PKG;

