  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TERDTP_PRICESPHERE_SRCRULE_PKG" 
IS
--**************************************************************************************************************************
  --     Script Name   :  TERDTP_PRICESPHERE_SRCRULE_PKG.pkb
  --     Created by    :  Sukhen Paul
  --     Creation date :  23-APR-2026
  --     Purpose       :  This Package is used to Update ATP Staging and Master Table after Processeing.
  --     Program History :
  --     Date                Version           Author               Description
  --     -----------------------------------------------------------------------------------------------------------------
  --     23-APR-2026          1.0             Sukhen Paul         Initial Version
--**************************************************************************************************************************

/* ********************************************************
   Wrapper Procedure for Batch Wise Processing   
 * ********************************************************/ 

    PROCEDURE WRAPPER_PROC(p_oic_instance_id  IN VARCHAR2) 
    IS

    CURSOR batch_cur(lc_request_id IN VARCHAR2)
    IS      
    SELECT  
          CEIL(RANK() OVER (ORDER BY ITEM asc)/50) row_num_batch 
         ,ROWID row_id 
         ,LINE_KEY   
         ,ITEM    
         ,ALLOCATION_PERCENTAGE    
         ,SUPPLIER_NUMBER
         ,OIC_INSTANCE_ID
      FROM TERDTP_PRICESPHERE_SOURCINGRULE_MASTER 
     WHERE 1=1
       AND OIC_INSTANCE_ID = P_OIC_INSTANCE_ID
       AND PROCESS_STATUS  = 'NEW';

    TYPE batch_tbl_type IS TABLE OF batch_cur%ROWTYPE INDEX BY BINARY_INTEGER;   
    batch_rec batch_tbl_type;      

    BEGIN 

       SAVEPOINT sp_wrp_proc;

       OPEN batch_cur(p_oic_instance_id);
       FETCH batch_cur BULK COLLECT INTO batch_rec;
       CLOSE batch_cur;

       IF (batch_rec.COUNT >= 1) THEN
          FORALL i IN 1..batch_rec.LAST    

          UPDATE TERDTP_PRICESPHERE_SOURCINGRULE_MASTER
             SET batch_number     = batch_rec(i).row_num_batch
           WHERE OIC_INSTANCE_ID  = batch_rec(i).oic_instance_id
             AND ROWID            = batch_rec(i).row_id;

       COMMIT;

       END IF;

    EXCEPTION
       WHEN OTHERS THEN	   
             ROLLBACK TO sp_wrp_proc;
          dbms_output.put_line('Exception in Wrapper Procedure: '||SQLERRM); 
          NULL;
    END WRAPPER_PROC; 

    PROCEDURE SUPPLIERNOTFOUND_STATUS_PROC(p_oic_instance_id_in IN terdtp_pricesphere_sourcingrule_master.oic_instance_id%TYPE
                                          ,p_line_key_in        IN terdtp_pricesphere_sourcingrule_master.line_key%TYPE
                                          ,p_error_desc         IN terdtp_pricesphere_sourcingrule_master.error_desc%TYPE
                                          ,p_batch_number       IN terdtp_pricesphere_sourcingrule_master.batch_number%TYPE)
    IS
      v_total_rows    NUMBER    := 0;
      v_rows          NUMBER    := 0;
      p_do_commit_in  BOOLEAN   := FALSE;
     BEGIN
         IF p_oic_instance_id_in IS NULL OR p_line_key_in IS NULL THEN
           RAISE_APPLICATION_ERROR(-20001, 'p_oic_instance_id_in and p_line_key_in cannot be NULL');
         END IF;

         SAVEPOINT sp_upd_proc;

         UPDATE TERDTP_PRICESPHERE_SOURCINGRULE_MASTER
            SET process_status  = 'ERROR'
               ,error_desc      =  p_error_desc
          WHERE process_status IN ('NEW','ERROR')
            AND oic_instance_id = p_oic_instance_id_in
            AND line_key        = p_line_key_in;

         UPDATE TERDTP_PRICESPHERE_SOURCINGRULE_MASTER
            SET process_status  = 'ERROR'
               ,error_desc      =  'Supplier Not Found in Same Batch'
          WHERE process_status IN ('NEW','ERROR')
            AND oic_instance_id = p_oic_instance_id_in
			AND error_desc     IS NULL
            AND batch_number    = p_batch_number;			
         v_rows := SQL%ROWCOUNT; v_total_rows := v_total_rows + v_rows;       

         IF p_do_commit_in THEN
           COMMIT;
         END IF;

      DBMS_OUTPUT.PUT_LINE('suppliernotfound_status_proc total rows updated = ' || v_total_rows);

    EXCEPTION
         WHEN OTHERS THEN
             ROLLBACK TO sp_upd_proc;
             DBMS_OUTPUT.PUT_LINE('suppliernotfound_status_proc failed: ' || SQLERRM);
             RAISE;
    END SUPPLIERNOTFOUND_STATUS_PROC;  

    PROCEDURE PRC_GET_SOURCINGRULE (
        P_OIC_INSTANCE_ID  IN  VARCHAR2,
        P_BATCH_NUMBER     IN  NUMBER,
        P_RESULT           OUT TYP_SOURCINGRULE_TAB,
        P_STATUS           OUT VARCHAR2,
        P_ERROR_MSG        OUT VARCHAR2
    )
    IS
        TYPE typ_cursor_rec IS RECORD (
            SOURCING_RULE_NAME   VARCHAR2(200),
            ITEM                 VARCHAR2(100),
            PROCESS_STATUS       VARCHAR2(240)
        );
        TYPE typ_cursor_tab IS TABLE OF typ_cursor_rec;
        C_BULK_LIMIT  CONSTANT PLS_INTEGER := 1000;
        v_update_count NUMBER := 0;

        CURSOR c_rules IS
            SELECT
                SOURCING_RULE_NAME,
                ITEM,
                PROCESS_STATUS
            FROM TERDTP_PRICESPHERE_SOURCINGRULE_MASTER
            WHERE OIC_INSTANCE_ID = P_OIC_INSTANCE_ID
              AND BATCH_NUMBER    = P_BATCH_NUMBER
              AND PROCESS_STATUS  = 'VALIDATED'
              AND ERROR_DESC IS NULL
            GROUP BY SOURCING_RULE_NAME, ITEM, PROCESS_STATUS;

        l_batch  typ_cursor_tab;
    BEGIN
        P_STATUS    := 'SUCCESS';
        P_ERROR_MSG := NULL;
        P_RESULT    := TYP_SOURCINGRULE_TAB();

        SAVEPOINT sp_get_srcrule;

/*        UPDATE TERDTP_PRICESPHERE_SOURCINGRULE_MASTER m
        SET (SOURCING_RULE_NAME, ERROR_DESC,PROCESS_STATUS) = (
            SELECT
                CASE
                    WHEN sub.alloc_valid = 0 THEN NULL
                    WHEN sub.supplier_count = 1
                    THEN 'Buy - ' || m.VENDOR_NAME
                    WHEN sub.item_has_transition = 1 AND m.END_DATE IS NULL
                    THEN 'Buy - ' || m.VENDOR_NAME
                    ELSE 'Buy - '
                         || SUBSTR(REPLACE(sub.vendor_rank1, ' ', ''), 1, 5)
                         || ' - '
                         || SUBSTR(REPLACE(sub.vendor_rank2, ' ', ''), 1, 5)
                         || CASE WHEN sub.item_has_transition = 1
                                 THEN ' - Transition'
                                 ELSE ' - Splits'
                            END
                END AS SOURCING_RULE_NAME,
                CASE WHEN sub.alloc_valid = 0
                     THEN 'Partial Record: Not Elligble for Sourcing Rule Integration'
                END AS ERROR_DESC,
                CASE WHEN sub.alloc_valid = 0
                     THEN 'INVALID'
                     ELSE 'VALIDATED'
                END    AS PROCESS_STATUS            
            FROM (
                SELECT
                    d.ITEM,
                    CASE
                        WHEN SUM(d.ALLOCATION_PERCENTAGE) = 100 THEN 1
                        WHEN MAX(d.supplier_alloc) = 100 THEN 1
                        WHEN COUNT(DISTINCT d.SUPPLIER_NUMBER) > 1
                             AND MAX(CASE WHEN d.END_DATE IS NOT NULL THEN 1 ELSE 0 END) = 1
                             AND MIN(d.ALLOCATION_PERCENTAGE) = 100 THEN 1
                        ELSE 0
                    END                                                       AS alloc_valid,
                    COUNT(DISTINCT d.SUPPLIER_NUMBER)                         AS supplier_count,
                    MAX(CASE WHEN d.END_DATE IS NOT NULL THEN 1 ELSE 0 END)  AS item_has_transition,
                    MAX(CASE WHEN d.supplier_rank = 1 THEN d.VENDOR_NAME END) AS vendor_rank1,
                    MAX(CASE WHEN d.supplier_rank = 2 THEN d.VENDOR_NAME END) AS vendor_rank2
                FROM (
                    SELECT
                        ITEM, SUPPLIER_NUMBER, VENDOR_NAME, END_DATE,
                        ALLOCATION_PERCENTAGE,
                        DENSE_RANK() OVER (PARTITION BY ITEM ORDER BY SUPPLIER_NUMBER) AS supplier_rank,
                        SUM(ALLOCATION_PERCENTAGE) OVER (PARTITION BY SUPPLIER_NUMBER) AS supplier_alloc
                    FROM (
                        SELECT DISTINCT
                            ITEM, SUPPLIER_NUMBER, VENDOR_NAME, END_DATE, ALLOCATION_PERCENTAGE
                        FROM TERDTP_PRICESPHERE_SOURCINGRULE_MASTER
                        WHERE OIC_INSTANCE_ID = P_OIC_INSTANCE_ID
                          AND BATCH_NUMBER    = P_BATCH_NUMBER
                          AND PROCESS_STATUS  = 'IN_PROGRESS'
                    )
                ) d
                GROUP BY d.ITEM
            ) sub
            WHERE sub.ITEM = m.ITEM
        )
        WHERE m.OIC_INSTANCE_ID = P_OIC_INSTANCE_ID
          AND m.BATCH_NUMBER    = P_BATCH_NUMBER
          AND m.PROCESS_STATUS  = 'IN_PROGRESS';*/

        UPDATE TERDTP_PRICESPHERE_SOURCINGRULE_MASTER m
        SET (SOURCING_RULE_NAME, ERROR_DESC, PROCESS_STATUS) = (
            SELECT
                CASE
                    WHEN sub.alloc_valid = 0 THEN NULL
                    WHEN sub.supplier_count = 1
                    THEN 'Buy - ' || m.VENDOR_NAME
                    WHEN sub.item_has_transition = 1
                    THEN 'Buy - '
                         || SUBSTR(REPLACE(sub.vendor_rank1, ' ', ''), 1, 5)
                         || ' - '
                         || SUBSTR(REPLACE(sub.vendor_rank2, ' ', ''), 1, 5)
                         || ' - Transition'
                    ELSE 'Buy - '
                         || SUBSTR(REPLACE(sub.vendor_rank1, ' ', ''), 1, 5)
                         || ' - '
                         || SUBSTR(REPLACE(sub.vendor_rank2, ' ', ''), 1, 5)
                         || ' - Splits'
                END AS SOURCING_RULE_NAME,
                CASE WHEN sub.alloc_valid = 0
                     THEN 'Partial Record: Not Elligble for Sourcing Rule Integration'
                END AS ERROR_DESC,
                CASE WHEN sub.alloc_valid = 0
                     THEN 'INVALID'
                     ELSE 'VALIDATED'
                END AS PROCESS_STATUS
            FROM (
                SELECT
                    d.ITEM,
                    CASE
                        WHEN SUM(d.ALLOCATION_PERCENTAGE) = 100 THEN 1
                        WHEN MAX(d.supplier_alloc) = 100 THEN 1
                        WHEN COUNT(DISTINCT d.SUPPLIER_NUMBER) > 1
                             AND MAX(CASE WHEN d.END_DATE IS NOT NULL THEN 1 ELSE 0 END) = 1
                             AND MIN(d.ALLOCATION_PERCENTAGE) = 100 THEN 1
                        ELSE 0
                    END AS alloc_valid,
                    COUNT(DISTINCT d.SUPPLIER_NUMBER) AS supplier_count,
                    MAX(CASE WHEN d.END_DATE IS NOT NULL THEN 1 ELSE 0 END) AS item_has_transition,
                    MAX(CASE WHEN d.supplier_rank = 1 THEN d.VENDOR_NAME END) AS vendor_rank1,
                    MAX(CASE WHEN d.supplier_rank = 2 THEN d.VENDOR_NAME END) AS vendor_rank2
                FROM (
                    SELECT
                        ITEM,
                        SUPPLIER_NUMBER,
                        VENDOR_NAME,
                        END_DATE,
                        ALLOCATION_PERCENTAGE,
                        DENSE_RANK() OVER (PARTITION BY ITEM ORDER BY SUPPLIER_NUMBER) AS supplier_rank,
                        SUM(ALLOCATION_PERCENTAGE) OVER (PARTITION BY SUPPLIER_NUMBER) AS supplier_alloc
                    FROM (
                        SELECT DISTINCT
                            ITEM,
                            SUPPLIER_NUMBER,
                            VENDOR_NAME,
                            END_DATE,
                            ALLOCATION_PERCENTAGE
                        FROM TERDTP_PRICESPHERE_SOURCINGRULE_MASTER
                        WHERE OIC_INSTANCE_ID  = P_OIC_INSTANCE_ID
                          AND BATCH_NUMBER     = P_BATCH_NUMBER
                          AND PROCESS_STATUS   = 'IN_PROGRESS'
                    )
                ) d
                GROUP BY d.ITEM
            ) sub
            WHERE sub.ITEM = m.ITEM
        )
        WHERE m.OIC_INSTANCE_ID = P_OIC_INSTANCE_ID
          AND m.BATCH_NUMBER    = P_BATCH_NUMBER
          AND m.PROCESS_STATUS  = 'IN_PROGRESS';		  

        COMMIT;
        v_update_count := SQL%ROWCOUNT;
        DBMS_OUTPUT.PUT_LINE('PRC_GET_SOURCINGRULE rows updated = ' || v_update_count);

        OPEN c_rules;
        LOOP
            FETCH c_rules BULK COLLECT INTO l_batch LIMIT C_BULK_LIMIT;
            EXIT WHEN l_batch.COUNT = 0;

            P_RESULT.EXTEND(l_batch.COUNT);
            FOR i IN 1 .. l_batch.COUNT LOOP
                P_RESULT(P_RESULT.COUNT - l_batch.COUNT + i) :=
                    TERDTP_TYPE_SOURCINGRULE_REC(
                        l_batch(i).SOURCING_RULE_NAME,
                        l_batch(i).ITEM,
                        l_batch(i).PROCESS_STATUS,
                        P_OIC_INSTANCE_ID,
						P_BATCH_NUMBER
                    );
            END LOOP;
        END LOOP;
        CLOSE c_rules;

    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK TO sp_get_srcrule;
            IF c_rules%ISOPEN THEN CLOSE c_rules; END IF;
            P_RESULT    := TYP_SOURCINGRULE_TAB();
            P_STATUS    := 'ERROR';
            P_ERROR_MSG := SUBSTR(SQLERRM, 1, 2000);
    END PRC_GET_SOURCINGRULE;

END TERDTP_PRICESPHERE_SRCRULE_PKG;

