  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TERDTP_RRCOMMON_OUTBOUND_PKG" AS
/**************************************************************************************************
  -- TER DTP to Rapid Response Outbound Utility Package Body
  -- Developer           : Vishnupriya 
  -- Description         : This Package Provide Utility to Rapid Response Outbound Service. 
  -- 
  -- Modification History
  -- Name                  Date          Version      JIRA reference 
  -- --------------------  -----------   -----------  ---------------------------------------------
  -- Vishnupriya           22-12-2025    1.0          Intial Release
  *************************************************************************************************/
gv_error VARCHAR2(1000) := NULL;
PROCEDURE TERDTP_FOLDERCREATION_PRC(
                p_date OUT VARCHAR2
                )
AS
  l_blob      BLOB;
  l_clob      CLOB;
  l_buffer    VARCHAR2(4000);
  l_amount    NUMBER := 4000;
  l_offset    NUMBER := 1;
  l_warning   NUMBER;
  l_context NUMBER := 0;
  l_date VARCHAR2(20) := TO_CHAR(SYSDATE, 'YYYYMMDD');
BEGIN
  -- Generate your custom file content into a CLOB variable (example)
  FOR rec IN (SELECT extractname, exportname FROM terdtp_filenames) LOOP
    l_clob := l_clob || rec.extractname || ',' || rec.exportname || UTL_TCP.CRLF;
  END LOOP;

  -- Convert CLOB to BLOB
  DBMS_LOB.CREATETEMPORARY(l_blob, TRUE);
  DBMS_LOB.CONVERTTOCLOB(
    dest_lob    => l_clob,
    src_blob     => l_blob, -- /Note: parameter names swapped in some versions
    amount      => DBMS_LOB.LOBMAXSIZE,
    dest_offset => l_offset,
    src_offset  => l_offset,
    blob_csid   => DBMS_LOB.DEFAULT_CSID,
    lang_context => l_context,
    warning     => l_warning
  );

  -- Upload the BLOB content to object storage
  DBMS_CLOUD.PUT_OBJECT(
    credential_name => 'TER_FUSION_INT_TO_TEREXT', -- Your credential name
    object_uri      => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Outbound/'|| l_date ||'/test1.csv', -- Your bucket URI and object name
    contents        => l_blob
  );

  -- Free the temporary LOBs
  DBMS_LOB.FREETEMPORARY(l_clob);
  DBMS_LOB.FREETEMPORARY(l_blob);
    
    p_date := l_date;
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(l_date,'TERDTP_FOLDERCREATION_PRC','ERROR',gv_error);
    COMMIT;
END;

