BEGIN
  WITH slot_plan_base AS (
      SELECT DISTINCT
          s_plan.slot_number,
          s_plan.partial_flag,
          s_plan.slot_status,
          s_plan.sales_order,
          s_plan.config_number,
          s_plan.promised_date,
          s_plan.schedule_date,
          s_plan.planning_organization
      FROM terext_slot_plan_dtls s_plan
      WHERE s_plan.slot_status IN ('Open', 'Identified', 'Booked')
  ),

  slot_ops_one AS (
      SELECT
          o.slot_number,
          MAX(o.planning_organization)
              KEEP (DENSE_RANK FIRST ORDER BY o.planning_organization) AS planning_organization
      FROM terext_slot_plan_ops_dtls o
      GROUP BY o.slot_number
  ),

  slot_so_lines AS (
      SELECT
          so.sales_order_num,
          so.part_number,
          SUM(so.quantity) AS quantity
      FROM TEREXT_SO_LINE_DTLS so
      GROUP BY
          so.sales_order_num,
          so.part_number
  ),

  slot_conf_lines AS (
      SELECT
          qc.config_number,
          qc.part_number,
          SUM(qc.quantity) AS quantity
      FROM TEREXT_QUOTE_CONFIG_DTLS qc
      GROUP BY
          qc.config_number,
          qc.part_number
  ),

  slot_def_lines AS (
      SELECT
          dc.config_number,
          dc.part_number,
          SUM(dc.quantity) AS quantity
      FROM TEREXT_SLOT_DEFAULT_CONFIG dc
      GROUP BY
          dc.config_number,
          dc.part_number
  ),

  slot_parts_lines AS (
      SELECT
          sp.slot_number,
          sp.part_number,
          SUM(sp.quantity) AS quantity
      FROM TEREXT_SLOT_PARTS sp
      GROUP BY
          sp.slot_number,
          sp.part_number
  ),

  slot_lines AS (
      SELECT
          p.slot_number,
          'Oracle Slot Partial Input' AS ordertype,
          sp.part_number,
          sp.quantity,
          p.promised_date AS old_demand_date,
          NVL(o.planning_organization, p.planning_organization) AS organization_code
      FROM slot_plan_base p
      LEFT JOIN slot_ops_one o
          ON o.slot_number = p.slot_number
      JOIN slot_parts_lines sp
          ON sp.slot_number = p.slot_number
      WHERE NVL(p.partial_flag, 'N') = 'Y'

      UNION ALL

      SELECT
          p.slot_number,
          'Oracle Slot Input' AS ordertype,
          so.part_number,
          so.quantity,
          p.schedule_date AS old_demand_date,
          NVL(o.planning_organization, p.planning_organization) AS organization_code
      FROM slot_plan_base p
      LEFT JOIN slot_ops_one o
          ON o.slot_number = p.slot_number
      JOIN slot_so_lines so
          ON so.sales_order_num = p.sales_order
      WHERE NVL(p.partial_flag, 'N') = 'N'
        AND p.slot_status = 'Booked'

      UNION ALL

      SELECT
          p.slot_number,
          'Oracle Slot Input' AS ordertype,
          qc.part_number,
          qc.quantity,
          p.schedule_date AS old_demand_date,
          NVL(o.planning_organization, p.planning_organization) AS organization_code
      FROM slot_plan_base p
      LEFT JOIN slot_ops_one o
          ON o.slot_number = p.slot_number
      JOIN slot_conf_lines qc
          ON qc.config_number = p.config_number
      WHERE NVL(p.partial_flag, 'N') = 'N'
        AND p.slot_status = 'Identified'

      UNION ALL

      SELECT
          p.slot_number,
          'Oracle Slot Input' AS ordertype,
          dc.part_number,
          dc.quantity,
          p.schedule_date AS old_demand_date,
          NVL(o.planning_organization, p.planning_organization) AS organization_code
      FROM slot_plan_base p
      LEFT JOIN slot_ops_one o
          ON o.slot_number = p.slot_number
      JOIN slot_def_lines dc
          ON dc.config_number = p.config_number
      WHERE NVL(p.partial_flag, 'N') = 'N'
        AND p.slot_status = 'Open'
  )

  SELECT
      ORDERNUMBER,
      ORDERTYPE,
      ORDER_LINE_NUM,
      PART_NUMBER,
      OLD_DEMAND_DATE,
      ORDERED_QUANTITY,
      ORGANIZATION_CODE_A,
      ORGANIZATION_CODE_B,
      STATUS
  BULK COLLECT INTO lv_ind_tbl
  FROM (
      /* =========================
         Sales Order + Forecast
         ========================= */
      SELECT DISTINCT
          CAST(NVL(TO_CHAR(ms_dem.sales_order_number), TO_CHAR(ms_dem.demand_id)) AS VARCHAR2(4000)) AS ordernumber,
          CAST(
              CASE
                  WHEN UPPER(lkp.meaning) = 'SALES ORDER' THEN 'SO'
                  WHEN UPPER(lkp.meaning) = 'FORECAST' THEN 'FCST'
                  ELSE NULL
              END
          AS VARCHAR2(4000)) AS ordertype,
          CAST(
              CASE
                  WHEN UPPER(lkp.meaning) = 'SALES ORDER' THEN TO_CHAR(ms_dem.so_line_num)
                  ELSE '1'
              END
          AS VARCHAR2(4000)) AS order_line_num,
          CAST(ms_items.item_name AS VARCHAR2(4000)) AS part_number,
          CAST(
              CASE
                  WHEN ms_dem.OLD_DEMAND_DATE IS NULL THEN NULL
                  WHEN REGEXP_LIKE(ms_dem.OLD_DEMAND_DATE, '^\d{8}$')
                      THEN ms_dem.OLD_DEMAND_DATE
                  WHEN REGEXP_LIKE(ms_dem.OLD_DEMAND_DATE, '^\d{4}-\d{2}-\d{2}$')
                      THEN TO_CHAR(TO_DATE(ms_dem.OLD_DEMAND_DATE, 'YYYY-MM-DD'), 'YYYYMMDD')
                  WHEN REGEXP_LIKE(ms_dem.OLD_DEMAND_DATE, '^\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}$')
                      THEN TO_CHAR(TO_DATE(ms_dem.OLD_DEMAND_DATE, 'YYYY-MM-DD HH24:MI:SS'), 'YYYYMMDD')
                  ELSE NULL
              END
          AS VARCHAR2(4000)) AS OLD_DEMAND_DATE,
          CAST(TO_CHAR(ms_dem.ordered_quantity) AS VARCHAR2(4000)) AS ordered_quantity,
          CAST(inv_org.organization_code AS VARCHAR2(4000)) AS organization_code_a,
          CAST(inv_org.organization_code AS VARCHAR2(4000)) AS organization_code_b,
          CAST(
              CASE
                  WHEN UPPER(lkp.meaning) = 'FORECAST' THEN 'CURRENT'
                  WHEN UPPER(lkp.meaning) = 'SALES ORDER' AND fl.source_order_number IS NULL THEN 'IGNORE'
                  WHEN fl.status_code NOT IN ('SHIPPED', 'CLOSED', 'CANCELED') THEN 'CURRENT'
                  WHEN fl.ship_flag = 'N' OR fl.request_ship_date IS NULL THEN 'IGNORE'
                  ELSE NULL
              END
          AS VARCHAR2(4000)) AS status
      FROM terdTp_msc_demands ms_dem
      JOIN termsc_system_items ms_items
        ON ms_dem.inventory_item_id = ms_items.inventory_item_id
      JOIN terdTp_msc_parameters inv_org
        ON ms_dem.organization_id = inv_org.organization_id
      JOIN terfnd_cmnlkp_vaues lkp
        ON lkp.lookupcode = TO_CHAR(ms_dem.origination_type)
       AND lkp.lookuptype = 'MSC_ORDER_TYPE'
      LEFT JOIN TEROM_FFILL_LINES fl
        ON UPPER(lkp.meaning) = 'SALES ORDER'
       AND TRIM(TO_CHAR(ms_dem.sales_order_number)) = TRIM(TO_CHAR(fl.source_order_number))
       AND TRIM(TO_CHAR(ms_dem.so_line_num)) = TRIM(TO_CHAR(fl.so_line_num))
      WHERE NVL(ms_dem.plan_id, -1) <> -1

      UNION ALL

      /* =========================
         Slot Planning
         ========================= */
      SELECT
          CAST(TO_CHAR(sl.slot_number) AS VARCHAR2(4000)) AS ordernumber,
          CAST(sl.ordertype AS VARCHAR2(4000)) AS ordertype,
          CAST(
              TO_CHAR(
                  ROW_NUMBER() OVER (
                      PARTITION BY sl.slot_number
                      ORDER BY sl.part_number, sl.quantity
                  )
              ) AS VARCHAR2(4000)
          ) AS order_line_num,
          CAST(sl.part_number AS VARCHAR2(4000)) AS part_number,
          CAST(TO_CHAR(sl.old_demand_date, 'YYYYMMDD') AS VARCHAR2(4000)) AS old_demand_date,
          CAST(sl.quantity AS VARCHAR2(4000)) AS ordered_quantity,
          CAST(sl.organization_code AS VARCHAR2(4000)) AS organization_code_a,
          CAST(sl.organization_code AS VARCHAR2(4000)) AS organization_code_b,
          CAST('CURRENT' AS VARCHAR2(4000)) AS status
      FROM slot_lines sl
  ) IndDemand
  WHERE NVL(ORDERTYPE, 'abc') IN ('SO', 'FCST', 'Oracle Slot Partial Input', 'Oracle Slot Input')
  ORDER BY IndDemand.ordernumber ASC;

--    EXCEPTION WHEN OTHERS THEN
--        gv_error := SUBSTR(SQLERRM,1,250);
--        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_INDEPENDENT_DATA_TRNSFM_PRC - Data Transformation','ERROR',gv_error);
--        COMMIT;

EXCEPTION
WHEN OTHERS THEN gv_error:= SUBSTR(SQLERRM, 1, 250);

INSERT INTO
  TERDTP_ERRORDTL_STG(RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
VALUES
  (
    p_date,
    'TERDTP_INDEPENDENT_DATA_TRNSFM_PRC - Data Transformation',
    'ERROR',
    gv_error
  );

COMMIT;

END;

-- Display the number of records fetched
DBMS_OUTPUT.PUT_LINE('Records fetched: ' || lv_ind_tbl.COUNT);

IF lv_ind_tbl.COUNT > 0 THEN FORALL i IN lv_ind_tbl.FIRST..lv_ind_tbl.LAST
INSERT INTO
  TERDTP_RR_IND_DEMANDORDER_STG(
    ORDER_NUMBER,
    ORDER_TYPE,
    ORDER_LINE_NUM,
    PART_NUMBER,
    USING_ASSEMBLY_DEMAND_DATE,
    ORDERED_QUANTITY,
    ORGANIZATION_CODE_A,
    ORGANIZATION_CODE_B,
    STATUS
  )
VALUES
  (
    lv_ind_tbl(i).ORDER_NUMBER,
    lv_ind_tbl(i).ORDER_TYPE,
    lv_ind_tbl(i).ORDER_LINE_NUM,
    lv_ind_tbl(i).PART_NUMBER,
    lv_ind_tbl(i).OLD_DEMAND_DATE,
    lv_ind_tbl(i).ORDERED_QUANTITY,
    lv_ind_tbl(i).ORGANIZATION_CODE_A,
    lv_ind_tbl(i).ORGANIZATION_CODE_B,
    lv_ind_tbl(i).STATUS
  );

DBMS_OUTPUT.PUT_LINE('Records inserted: ' || SQL % ROWCOUNT);



l_cnt:= SQL % ROWCOUNT;

COMMIT;

IF (lv_ind_tbl.COUNT = l_cnt) THEN DBMS_OUTPUT.PUT_LINE('Success. ');

