PROCEDURE TERDTP_SUPPLIER_TRNSFM_PRC (
        p_date                      IN VARCHAR2,
        p_rec_cnt                   OUT NUMBER
        ) 
AS

 l_cnt NUMBER := 0;

 TYPE TERDTP_SUP_OBJ IS RECORD (
 PARTNERNUMBER VARCHAR2(2000),
 PARTNERNAME   VARCHAR2(2000)
 );

 TYPE TERDTP_SUP_TAB IS TABLE OF TERDTP_SUP_OBJ;

 lv_sup_tbl  TERDTP_SUP_TAB;

BEGIN

BEGIN
    /* Purging the staging tables before insertion of BICC and BIP extracts */
    delete from TERPO_VENDOR_STG;
    delete from TERPO_SUPPLIER_STG;
    delete from TERDTP_RR_SUPPLIER_STG;
    commit;
EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_SUPPLIER_TRNSFM_PRC - Deletion','ERROR',gv_error);
        COMMIT;
END;

BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERPO_VENDOR_STG',   --TERPO_VENDOR_STG
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date||'/*supplierpvo*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'supplierpvo','TERDTP_SUPPLIER_TRNSFM_PRC - COPY_DATA','ERROR',gv_error);
    COMMIT;
END;

BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERPO_SUPPLIER_STG', --TERPO_SUPPLIER_STG  
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date||'/*globaltradingpartner*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'globaltradingpartner','TERDTP_SUPPLIER_TRNSFM_PRC - COPY_DATA','ERROR',gv_error);
    COMMIT;
END;

    BEGIN
        SELECT distinct
            sup.PARTNERNUMBER AS "SUPPLIER_NUMBER",
            sup.PARTNERNAME   AS "SUPPLIER_NAME"
        BULK COLLECT INTO lv_sup_tbl
        FROM
            TERPO_SUPPLIER_STG sup,
            TERPO_VENDOR_STG   vdr
        WHERE 1=1
            AND nvl(upper(vdr.VENDORTYPELOOKUP),'SUPPLIER') NOT IN ( 'EMPLOYEE', 'TAX AUTHORITY', 'INSURANCE', 'SERVICES' )
            AND sup.PARTNERNUMBER = vdr.VENDORNUMBER
        ORDER BY
            sup.PARTNERNAME ASC;
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_SUPPLIER_TRNSFM_PRC - Data Transformation','ERROR',gv_error);
        COMMIT;
    END;

    -- Display the number of records fetched
    DBMS_OUTPUT.PUT_LINE('Records fetched: ' || lv_sup_tbl.COUNT);

    IF lv_sup_tbl.COUNT > 0 THEN
        FORALL i IN lv_sup_tbl.FIRST .. lv_sup_tbl.LAST
            INSERT INTO TERDTP_RR_SUPPLIER_STG (
                VENDORNUMBER,
                VENDORNAME
            ) VALUES (
                lv_sup_tbl(i).PARTNERNUMBER,
                lv_sup_tbl(i).PARTNERNAME
            );
        -- Display the number of rows inserted (SQL%ROWCOUNT is special for FORALL)
        DBMS_OUTPUT.PUT_LINE('Records inserted: ' || SQL%ROWCOUNT);
        l_cnt := SQL%ROWCOUNT;
        COMMIT;

        IF (lv_sup_tbl.COUNT = l_cnt) THEN
            DBMS_OUTPUT.PUT_LINE('Success. ');
            BEGIN
                DBMS_CLOUD.BULK_MOVE(      
                      source_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      source_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*supplierpvo*',
                      target_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      target_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Archive/'||p_date||'/',
                      format                  =>  JSON_OBJECT ('logretention' value 7, 'logprefix' value 'BULKOP')
                );
            EXCEPTION WHEN OTHERS THEN
                gv_error := SUBSTR(SQLERRM,1,250);
                INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'supplierpvo','TERDTP_SUPPLIER_TRNSFM_PRC - Archive Processed Files','ERROR',gv_error);
                COMMIT;
            END;
            BEGIN
                DBMS_CLOUD.BULK_MOVE(      
                      source_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      source_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*globaltradingpartner*',
                      target_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      target_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Archive/'||p_date||'/',
                      format                  =>  JSON_OBJECT ('logretention' value 7, 'logprefix' value 'BULKOP')
                );
            EXCEPTION WHEN OTHERS THEN
                gv_error := SUBSTR(SQLERRM,1,250);
                INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'globaltradingpartner','TERDTP_SUPPLIER_TRNSFM_PRC - Archive Processed Files','ERROR',gv_error);
                COMMIT;
            END;
        ELSE
            DBMS_OUTPUT.PUT_LINE('Check the error logs. ');
            gv_error := SUBSTR(SQLERRM,1,250);
            INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_SUPPLIER_TRNSFM_PRC - No records found to insert','INFO',gv_error);
            COMMIT;
        END IF;

    END IF;
    p_rec_cnt := l_cnt;
    BEGIN
      DBMS_CLOUD.EXPORT_DATA(
        credential_name => 'TER_FUSION_INT_TO_TEREXT',
        file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Outbound/'|| p_date||'/OF_Supplier.csv',
        query           => 'SELECT * FROM TERDTP_RR_SUPPLIER_STG',
        format          => JSON_OBJECT('type' value 'csv','delimiter' value '|','maxfilesize' value '1048576000'));
    EXCEPTION WHEN OTHERS THEN
                gv_error := SUBSTR(SQLERRM,1,250);
                INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'OF_Supplier','TERDTP_SUPPLIER_TRNSFM_PRC - EXPORT_DATA','ERROR',gv_error);
                COMMIT;
    END;

EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_SUPPLIER_TRNSFM_PRC - Unknown Error','ERROR',gv_error);
    COMMIT;
END;

PROCEDURE TERDTP_PARTMSTR_TRNSFM_PRC (
        p_date                      IN VARCHAR2,
        p_rec_cnt                   OUT NUMBER
        ) 
AS

 l_cnt NUMBER := 0;

 TYPE TERDTP_PARTMSTR_OBJ IS RECORD (
    item_name							VARCHAR2(2000),
    ref_part_val                        VARCHAR2(2000),
    item_description 					VARCHAR2(2000),
	item_type							VARCHAR2(200),
    plan_calendar				        VARCHAR2(2000),
    safety_stock_qty                    NUMBER,
    fixed_days_supply					NUMBER,
    demand_fence_days					NUMBER,
    standard_cost   					NUMBER,
    uom_code							VARCHAR2(2000),
    organization_code					VARCHAR2(2000)
 );

 TYPE TERDTP_PARTMSTR_TAB IS TABLE OF TERDTP_PARTMSTR_OBJ;

 lv_partms_tbl  TERDTP_PARTMSTR_TAB;
 lv_org_code    VARCHAR2(2000);
 

BEGIN

BEGIN
    delete from TERMSC_STD_COSTS;
    delete from TERMSC_CSTINV_ORGS;
    delete from TERINV_INVENTORY_STG;
    delete from TERFND_CMNLKP_VAUES;
    delete from TERMSC_SYSTEM_ITEMS;
    delete from TERDTP_RR_PARTMSTR_STG;
    commit;
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_PARTMSTR_TRNSFM_PRC - Deletion','ERROR',gv_error);
    COMMIT;
END;

BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERMSC_STD_COSTS',   
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*fscmtopmodelam_scmextractam_cstbiccextractam_cststdcostdetailsextractpvo*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'cststdcostdetailsextractpvo','TERDTP_PARTMSTR_TRNSFM_PRC - COPY_DATA','ERROR',gv_error);
    COMMIT;
END;

BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERMSC_CSTINV_ORGS',   
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
