BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERMSC_SYSTEM_ITEMS',   
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*terdtp_msc_system_items*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'egpbiccextractam_itemextractpvo','TERDTP_PARTMSTR_TRNSFM_PRC - COPY_DATA','ERROR',gv_error);
    COMMIT;
END;
   
    BEGIN
    select distinct * BULK COLLECT INTO lv_partms_tbl from (
    SELECT distinct
            msc_inv.Item_Name,
            msc_inv.Item_Name as "part_value",
            nvl(REPLACE(REPLACE(msc_inv.description, CHR(10), ''), CHR(9), ''), 'No Description') AS "Description",
            decode(msc_inv.WIP_SUPPLY_TYPE,6,'Phantom',cmn_lkp2.meaning) as "item_type",
            'CAL-'||msc_inv.ORGANIZATION_CODE        AS "PlanningCalenar",
            msc_inv.safety_stock_qty  ,
            msc_inv.fixed_days_supply      ,
            msc_inv.demand_time_fence_days  ,            
            0                             AS "Standard_cost",
            msc_inv.uom_code              ,
            msc_inv.Organization_Code    
        FROM
            TERMSC_SYSTEM_ITEMS     msc_inv,
            TERFND_CMNLKP_VAUES cmn_lkp1,
            TERFND_CMNLKP_VAUES cmn_lkp2
	WHERE 1=1
              AND cmn_lkp1.lookuptype = 'EGP_WIP_SUP_TYPE'
              AND cmn_lkp1.lookupcode = msc_inv.WIP_SUPPLY_TYPE
              AND msc_inv.PLANNING_MAKE_BUY_CODE = cmn_lkp2.lookupcode
              AND cmn_lkp2.lookuptype = 'EGP_PLANNING_MAKE_BUY'
			  AND NOT EXISTS (
        SELECT
            nvl(a.totalcost, 0) AS "Standard Cost"
        FROM
            termsc_std_costs      a,
            TERINV_INVENTORY_STG b,
            TERDTP_RR_ORGCODE e,
            TERMSC_CSTINV_ORGS  cst_org
        WHERE
                1 = 1
            AND b.inventoryitemid = a.inventoryitemid
            AND b.itemnumber = msc_inv.item_name
            AND cst_org.costorgid = a.costorgid
            AND e.organizationid = cst_org.invorgid
            AND e.org_organizationcode = msc_inv.organization_code
            AND e.organizationid = b.organizationid
            AND cst_org.invorgid = b.organizationid
            AND nvl(a.effectiveenddate, sysdate+1) >= sysdate
            and a.STATUSCODE = 'PUBLISHED'
    )
   UNION
   SELECT distinct
            msc_inv.Item_Name,
            msc_inv.Item_Name as "part_value",
            nvl(REPLACE(REPLACE(msc_inv.description, CHR(10), ''), CHR(9), ''), 'No Description') AS "Description",
            decode(msc_inv.WIP_SUPPLY_TYPE,6,'Phantom',cmn_lkp2.meaning) as "item_type",
            'CAL-'||msc_inv.ORGANIZATION_CODE        AS "PlanningCalenar",
            msc_inv.safety_stock_qty  ,
            msc_inv.fixed_days_supply      ,
            msc_inv.demand_time_fence_days  ,           
            nvl(std_cst.totalcost,0) AS "Standard_cost",
            msc_inv.Uom_Code              ,
            msc_inv.Organization_Code     
        FROM
            TERMSC_SYSTEM_ITEMS     msc_inv,
            TERMSC_STD_COSTS        std_cst,
            TERINV_INVENTORY_STG     inv,
            TERFND_CMNLKP_VAUES cmn_lkp1,
            TERFND_CMNLKP_VAUES cmn_lkp2,
            TERDTP_RR_ORGCODE org_tbl,
            TERMSC_CSTINV_ORGS cst_org
        WHERE 1=1
              AND msc_inv.item_name = inv.ITEMNUMBER
              AND cmn_lkp1.lookuptype = 'EGP_WIP_SUP_TYPE'
              AND cmn_lkp1.lookupcode = inv.WipSupplyType
              AND msc_inv.planning_make_buy_code = cmn_lkp2.lookupcode
              AND cmn_lkp2.lookuptype = 'EGP_PLANNING_MAKE_BUY'
              AND std_cst.inventoryitemid = inv.inventoryitemid
              AND cst_org.costorgid = std_cst.costorgid
              AND org_tbl.organizationid = cst_org.invorgid
              AND org_tbl.org_organizationcode = msc_inv.organization_code
              AND org_tbl.organizationid = inv.organizationid
              AND cst_org.invorgid = inv.organizationid
              AND nvl(std_cst.effectiveenddate, sysdate+1) >= sysdate
              and std_cst.STATUSCODE = 'PUBLISHED'
			  ) comp_query
			  order by comp_query.item_name asc
			  ;
        
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_PARTMSTR_TRNSFM_PRC - Data Transformation','ERROR',gv_error);
        COMMIT;
    END;

    -- Display the number of records fetched
    DBMS_OUTPUT.PUT_LINE('Records fetched: ' || lv_partms_tbl.COUNT);

    IF lv_partms_tbl.COUNT > 0 THEN
        FORALL i IN lv_partms_tbl.FIRST .. lv_partms_tbl.LAST
