PROCEDURE TERDTP_WRH_LOC_TRNSFM_PRC (
        p_date                      IN VARCHAR2,
        p_rec_cnt                   OUT NUMBER
        )
AS
 TYPE TERDTP_WRH_OBJ IS RECORD (
 SECONDARY_INVENTORY_NAME  VARCHAR2(2000), 
 inventory_location_id     NUMBER,
 locator_name              VARCHAR2(4500)
 );

 TYPE TERDTP_WRH_TAB IS TABLE OF TERDTP_WRH_OBJ;

 lv_wrh_tbl  TERDTP_WRH_TAB;
BEGIN

    BEGIN
        delete from TERINV_SUBINV_LOCATOR_STG;
        delete from TERINV_WRH_SUBINV_STG;
        delete from TERDTP_RR_WRH_STG;
        commit;
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_WRH_LOC_TRNSFM_PRC - Deletion','ERROR',gv_error);
        COMMIT;
    END;

    BEGIN  
       DBMS_CLOUD.COPY_DATA(   
          table_name      => 'TERINV_WRH_SUBINV_STG',   --TERINV_WRH_SUBINV_STG
          credential_name => 'TER_FUSION_INT_TO_TEREXT',   
          file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*inventorylocatorpvo*.csv',
          format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
       );
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'inventorylocatorpvo','TERDTP_WRH_LOC_TRNSFM_PRC - COPY_DATA','ERROR',gv_error);
        COMMIT;
    END;
    
    BEGIN  
       DBMS_CLOUD.COPY_DATA(   
          table_name      => 'TERINV_SUBINV_LOCATOR_STG',   
          credential_name => 'TER_FUSION_INT_TO_TEREXT',   
          file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*inventorylocatorextractpvo*.csv',
          format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
       );
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'inventorylocatorextractpvo','TERDTP_WRH_LOC_TRNSFM_PRC - COPY_DATA','ERROR',gv_error);
        COMMIT;
    END;
    
    BEGIN
        SELECT distinct
            isi.SECONDARYINVENTORYNAME AS "SUBINVENTORY_NAME",
            iil.inventorylocationid    AS "INVENTORY_LOCATION_ID",
            iil.locatorname             AS "LOCATOR_NAME"
        BULK COLLECT
        INTO lv_wrh_tbl
        FROM
            TERINV_SUBINV_LOCATOR_STG iil,
            TERINV_WRH_SUBINV_STG  isi
        WHERE
                1 = 1
            AND iil.subinventorycode(+) = isi.SECONDARYINVENTORYNAME
            AND iil.subinventoryid(+) = isi.subinventoryid
            AND iil.organizationid(+) = isi.organizationid
        ORDER BY
            isi.SECONDARYINVENTORYNAME;    
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_WRH_LOC_TRNSFM_PRC - Data Transformation','ERROR',gv_error);
        COMMIT;
    END;

    -- Display the number of records fetched
    DBMS_OUTPUT.PUT_LINE('Records fetched: ' || lv_wrh_tbl.COUNT);

    IF lv_wrh_tbl.COUNT > 0 THEN
        FORALL i IN lv_wrh_tbl.FIRST .. lv_wrh_tbl.LAST
            INSERT INTO TERDTP_RR_WRH_STG (
                SECONDARY_INVENTORY_NAME,
                INVENTORY_LOCATION_ID,
                LOCATOR_NAME    
            ) VALUES (
                lv_wrh_tbl(i).SECONDARY_INVENTORY_NAME,
                lv_wrh_tbl(i).INVENTORY_LOCATION_ID,
                lv_wrh_tbl(i).LOCATOR_NAME
            );
            -- Display the number of rows inserted (SQL%ROWCOUNT is special for FORALL)
        DBMS_OUTPUT.PUT_LINE('Records inserted: ' || SQL%ROWCOUNT);
        p_rec_cnt := SQL%ROWCOUNT;
            COMMIT;

        IF (lv_wrh_tbl.COUNT = p_rec_cnt) THEN
            DBMS_OUTPUT.PUT_LINE('Success. ');
            BEGIN
                DBMS_CLOUD.BULK_MOVE(      
                      source_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      source_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*inventorylocatorpvo*',
                      target_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      target_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Archive/'||p_date||'/',
                      format                  =>  JSON_OBJECT ('logretention' value 7, 'logprefix' value 'BULKOP')
                );
            EXCEPTION WHEN OTHERS THEN
                gv_error := SUBSTR(SQLERRM,1,250);
                INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'inventorylocatorpvo','TERDTP_WRH_LOC_TRNSFM_PRC - Archive Processed Files','ERROR',gv_error);
                COMMIT;
            END;
            BEGIN
                DBMS_CLOUD.BULK_MOVE(      
                      source_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      source_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*inventorylocatorextractpvo*',
                      target_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      target_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Archive/'||p_date||'/',
                      format                  =>  JSON_OBJECT ('logretention' value 7, 'logprefix' value 'BULKOP')
