PROCEDURE TERDTP_CUSTOMER_TRNSFM_PRC (
        p_date                      IN VARCHAR2,
        p_rec_cnt                   OUT NUMBER
        )
AS
TYPE TERDTP_CUST_OBJ IS RECORD (
 PARTY_NUMBER VARCHAR2(2000),
 PARTY_NAME   VARCHAR2(2000)
 );

 TYPE TERDTP_CUST_TAB IS TABLE OF TERDTP_CUST_OBJ;

 lv_cust_tbl  TERDTP_CUST_TAB;
BEGIN
    BEGIN
        delete from TEROM_ORDER_ADDRESS;
        delete from TERAR_HZ_PARTIES;
        delete from TEROM_HEADERS_ALL;
        delete from TEROM_LINES_ALL;
        delete from TERMSC_PLAN_CUSTOMER;
        delete from TERDTP_RR_CUSTOMER_STG;
        commit;
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_CUSTOMER_TRNSFM_PRC - Deletion','ERROR',gv_error);
