          format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
       );
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'dootopam_header','TERDTP_CUSTOMER_TRNSFM_PRC - COPY_DATA','ERROR',gv_error);
        COMMIT;
    END;
    
    BEGIN  
       DBMS_CLOUD.COPY_DATA(   
          table_name      => 'TERAR_HZ_PARTIES',   --TERINV_WRH_SUBINV_STG
          credential_name => 'TER_FUSION_INT_TO_TEREXT',   
          file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*hzbiccextractam_partyextractpvo*.csv',
