        COMMIT;
    END;


    BEGIN
        SELECT * BULK COLLECT INTO lv_cust_tbl
        FROM (
            SELECT DISTINCT 
                mc.partner_number as partynumber,
                nvl(mc.partner_name, 'UNKNOWN') as partyname
            FROM 
                TERMSC_PLAN_CUSTOMER mc
            UNION 
            SELECT DISTINCT
                hp.partynumber,
                nvl(hp.partyname, 'UNKNOWN') as partyname
            FROM
                TEROM_HEADERS_ALL dh,
                TEROM_LINES_ALL  dl,
                TERAR_HZ_PARTIES HP 
            WHERE DH.SOLDTOPARTYID = HP.PARTYID 
            AND dh.headerid = dl.headerid
            and dl.canceledflag = 'N'
            UNION 
            SELECT DISTINCT
                hp.partynumber,
                nvl(hp.partyname, 'UNKNOWN') as partyname
            FROM
                TEROM_HEADERS_ALL   dh,
                TEROM_LINES_ALL     dl,
                TEROM_ORDER_ADDRESS da,
                TERAR_HZ_PARTIES    hp
            WHERE
                    dh.headerid = da.headerid
                AND da.partyid = hp.partyid
                AND dh.headerid = dl.headerid
                and dl.canceledflag = 'N'
                )qry
                order by qry.partynumber asc;
                
