PROCEDURE MAIN
AS
lv_rec_cnt NUMBER := 0;
lv_date    VARCHAR2(100) := NULL;
BEGIN
    TERDTP_FOLDERCREATION_PRC(lv_date);
    DBMS_OUTPUT.PUT_LINE('Record count: '||lv_date);
    TERDTP_WRH_LOC_TRNSFM_PRC(lv_date,lv_rec_cnt);
    DBMS_OUTPUT.PUT_LINE('Record count: '||lv_rec_cnt);
    LV_REC_CNT := 0;
    TERDTP_SUPPLIER_TRNSFM_PRC(lv_date,lv_rec_cnt);
    DBMS_OUTPUT.PUT_LINE('Record count: '||lv_rec_cnt);
    LV_REC_CNT := 0;
    TERDTP_CUSTOMER_TRNSFM_PRC(lv_date,lv_rec_cnt);
    DBMS_OUTPUT.PUT_LINE('Record count: '||lv_rec_cnt);
    TERDTP_ORG_CALENDAR_DATA_PRC(lv_date);
    TERDTP_CALENDAR_DATA_PRC(lv_date);
    BEGIN
        DBMS_CLOUD.DELETE_OBJECT(
        credential_name => 'TER_FUSION_INT_TO_TEREXT', -- Your credential name
        object_uri      => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Outbound/'||lv_date||'/test1.csv'
        );
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(lv_date,'MAIN - Unknown Error','ERROR',gv_error);
        COMMIT;
    END;
END;

