PROCEDURE TERDTP_CALENDAR_DATA_PRC(p_date IN VARCHAR2)
AS
BEGIN
DELETE FROM TER_DTP_CALENDAR_DATA;
COMMIT;
 BEGIN
   INSERT INTO TER_DTP_CALENDAR_DATA(LABEL,VALUE)
SELECT LABEL,VALUE
FROM(
SELECT 
       'RUNDATE' AS LABEL,
       TO_CHAR(SYSDATE, 'YYYYMMDD') AS VALUE
FROM DUAL

UNION ALL

SELECT 
       'WEEK' AS LABEL,
       TO_CHAR(TRUNC(start_date, 'IW') + (LEVEL - 1) * 7, 'YYYYMMDD') AS VALUE
FROM (
    SELECT
        TRUNC(TO_DATE(EXTRACT(YEAR FROM SYSDATE)-1 || '0101', 'YYYYMMDD'), 'IW') AS start_date,
        TRUNC(TO_DATE(EXTRACT(YEAR FROM SYSDATE)+10 || '1231', 'YYYYMMDD'), 'IW') AS end_date
    FROM DUAL
)
CONNECT BY (TRUNC(start_date, 'IW') + (LEVEL - 1) * 7) <= end_date

)
ORDER BY LABEL, VALUE;

 --RAISE_APPLICATION_ERROR(-20001, 'Error Occured during Execution');
EXCEPTION 
WHEN OTHERS THEN 
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'OF_CoreCalendarDate','Extracting Calendar Records','ERROR',gv_error);
    COMMIT;
END;
BEGIN
      DBMS_CLOUD.EXPORT_DATA(
        credential_name => 'TER_FUSION_INT_TO_TEREXT',
        file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Outbound/'||p_date||'/OF_CoreCalendarDate.csv',
        query           => 'SELECT * FROM TER_DTP_CALENDAR_DATA ORDER BY LABEL,VALUE ASC',
        format          => JSON_OBJECT('type' value 'csv','delimiter' value '|','maxfilesize' value '1048576000')
        );
    EXCEPTION WHEN OTHERS THEN 
  gv_error := SUBSTR(SQLERRM,1,250);
   INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'OF_CoreCalendarDate','Calendar Data Extract','ERROR',gv_error);
   COMMIT;
END;
    
END;


PROCEDURE TERDTP_ORG_CALENDAR_DATA_PRC(p_date IN VARCHAR2)
