   INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'OF_OrgCalendarDate','Organization Calendar Extract','ERROR',gv_error);
