PROCEDURE TERDTP_ONHAND_PRC(
  p_date   IN VARCHAR2
)
AS
  gv_error VARCHAR2(250);
  l_snt NUMBER := 0;
  l_org_code VARCHAR(500);

  TYPE TERDTP_ONHAND_DATA IS RECORD (
    Item_Name                 VARCHAR2(1000),
    Subinventory_Code         VARCHAR2(1000),
    Locator_Name              VARCHAR2(1000),
    Netting_Type              VARCHAR2(1000),
    TotalTransactionQuantity  NUMBER,
    ORGANIZATION_CODE         VARCHAR2(1000)
  );

  TYPE TERDTP_ONHAND_TAB IS TABLE OF TERDTP_ONHAND_DATA;

  lv_partms_tbl   TERDTP_ONHAND_TAB;                 
  --lv_success_tbl  TERDTP_ONHAND_TAB := TERDTP_ONHAND_TAB();
  --lv_error_tbl    TERDTP_ONHAND_TAB := TERDTP_ONHAND_TAB();

BEGIN
  BEGIN
  DELETE FROM TERMSC_SUPPLIES_DATA;
  DELETE FROM TERDTP_RR_ONHAND_QUANTITY;
  DELETE FROM TERDTP_RR_ORGCODE;
  DELETE FROM TERDTP_RR_ONHAND_RECORDS;
  --DELETE FROM TERDTP_RR_ONHAND_ERROR_RECORDS;
  DELETE FROM TERDTP_RR_SUBINV_NETTYPE;
  COMMIT;
  EXCEPTION
    WHEN OTHERS THEN
      gv_error := SUBSTR(SQLERRM, 1, 250);
      INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
      VALUES (p_date, 'TERDTP_ONHAND_PRC - Deletion', 'ERROR', gv_error);
      COMMIT;
  END;
  
BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERMSC_SUPPLIES_DATA',   
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*wpoh_orcl_ITEM*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'wpoh_orcl_ITEM BIP Report','TERDTP_ONHAND_PRC - COPY_DATA','ERROR',gv_error);
    COMMIT;
END;

BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERDTP_RR_SUBINV_NETTYPE',   
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*wpoh_orcl_Subinv*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'wpoh_orcl_Subinv BIP Report','TERDTP_ONHAND_PRC - COPY_DATA','ERROR',gv_error);
    COMMIT;
END;

BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERDTP_RR_ONHAND_QUANTITY',   
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*inventoryonhandpvo*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'inventoryonhandpvo','TERDTP_ONHAND_PRC - COPY_DATA','ERROR',gv_error);
    COMMIT;
END;

BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERDTP_RR_ORGCODE',   
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*inventoryorgparameterspvo*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'inventoryonhandpvo','TERDTP_ONHAND_PRC - COPY_DATA','ERROR',gv_error);
    COMMIT;
END;
BEGIN
    WITH onhand AS (
      SELECT
        o.ITEMBPEOORGANIZATIONID                     AS OrganizationId,
        o.ITEMBPEOITEMNUMBER                         AS ItemNumber,
        o.InventoryOnhandPEOSubinventoryCode         AS SubinventoryCode,
        o.InventoryOnhandPEOLocatorId                AS InventoryLocationId,
        SUM(o.InventoryOnhandPEOTransactionQuantity) AS TotalTransactionQuantity
      FROM TERDTP_RR_ONHAND_QUANTITY o
      GROUP BY
        o.ITEMBPEOORGANIZATIONID,
        o.ITEMBPEOITEMNUMBER,
        o.InventoryOnhandPEOSubinventoryCode,
        o.InventoryOnhandPEOLocatorId
    )
    SELECT DISTINCT
      ms.ITEM_NAME                                   AS Item_Name,
      oh.SubinventoryCode                             AS Subinventory_Code,
      loc.LocatorName                                 AS Locator_Name,
      CASE WHEN nt.NETTING_TYPE = 2 THEN 'NNET' ELSE 'NET' END AS Netting_Type,
      oh.TotalTransactionQuantity                     AS TotalTransactionQuantity,
      ms.ORGANIZATION_CODE                           AS ORGANIZATION_CODE
    BULK COLLECT INTO lv_partms_tbl
    FROM TERMSC_SUPPLIES_DATA tmi,
     TERmsc_system_items MS,
     TERDTP_RR_ORGCODE tis,
     onhand oh,
     TERINV_SUBINV_LOCATOR_STG loc,
     TERDTP_RR_SUBINV_NETTYPE nt,
     TERFND_CMNLKP_VAUES lkp
  WHERE tmi.INVENTORY_ITEM_ID = MS.INVENTORY_ITEM_ID(+)
  AND tmi.ORGANIZATION_ID = MS.ORGANIZATION_ID(+)
  AND tmi.PLAN_ID = MS.PLAN_ID(+)
  AND ms.ORGANIZATION_CODE = tis.ORG_ORGANIZATIONCODE(+)
  AND tis.ORGANIZATIONID = oh.OrganizationId(+)
  AND ms.ITEM_NAME = oh.ItemNumber(+)
  AND oh.InventoryLocationId = loc.InventoryLocationId(+)
  AND tmi.PLAN_ID = nt.PLAN_ID(+)
  AND tmi.ORGANIZATION_ID = nt.ORGANIZATION_ID(+)
  AND oh.SubinventoryCode = nt.SUB_INVENTORY_CODE(+)
  AND lkp.MEANING = MS.ORGANIZATION_CODE
  AND lkp.LOOKUPTYPE = 'TER_INT_RAPID_RESPONSE'
  AND tmi.ORDERTYPE = 18;
  /*
    FROM TERMSC_SUPPLIES_DATA tmi
    LEFT JOIN TERmsc_system_items MS
    ON tmi.INVENTORY_ITEM_ID=MS.INVENTORY_ITEM_ID
    AND tmi.ORGANIZATION_ID=MS.ORGANIZATION_ID
    AND TMI.ORDERTYPE=18
     AND tmi.PLAN_ID=MS.PLAN_ID
    LEFT JOIN TERDTP_RR_ORGCODE tis
     ON ms.ORGANIZATION_CODE = tis.ORG_ORGANIZATIONCODE
    LEFT JOIN onhand oh
      ON oh.OrganizationId = tis.ORGANIZATIONID
     AND oh.ItemNumber      = ms.ITEM_NAME
    LEFT JOIN TERINV_SUBINV_LOCATOR_STG loc
      ON loc.InventoryLocationId = oh.InventoryLocationId
    LEFT JOIN TERDTP_RR_SUBINV_NETTYPE nt
      ON nt.PLAN_ID            = tmi.PLAN_ID
     AND nt.ORGANIZATION_ID    = tmi.ORGANIZATION_ID
     AND nt.SUB_INVENTORY_CODE = oh.SubinventoryCode
     JOIN TERFND_CMNLKP_VAUES lkp
     ON lkp.MEANING = MS.ORGANIZATION_CODE
     AND lkp.LOOKUPTYPE = 'TER_INT_RAPID_RESPONSE';
     */
  EXCEPTION
    WHEN OTHERS THEN
      gv_error := SUBSTR(SQLERRM, 1, 250);
      INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
      VALUES (p_date, 'TERDTP_ONHAND_PRC - Data Transformation', 'ERROR', gv_error);
      COMMIT;
  END;
  
  IF lv_partms_tbl.COUNT > 0 THEN
    FORALL i IN 1 .. lv_partms_tbl.COUNT
      INSERT INTO TERDTP_RR_ONHAND_RECORDS (
        item_name,
        subinventory_code,
        locator_name,
        netting_type,
        totaltransactionquantity,
        organization_code
      )
      VALUES (
        lv_partms_tbl(i).Item_Name,
        lv_partms_tbl(i).Subinventory_Code,
        lv_partms_tbl(i).Locator_Name,
        lv_partms_tbl(i).Netting_Type,
        lv_partms_tbl(i).TotalTransactionQuantity,
        lv_partms_tbl(i).ORGANIZATION_CODE
      );
      -- Display the number of rows inserted (SQL%ROWCOUNT is special for FORALL)
        --DBMS_OUTPUT.PUT_LINE('Records inserted: ' || SQL%ROWCOUNT);
        --l_snt := SQL%ROWCOUNT;
      COMMIT;

       -- IF (lv_success_tbl.COUNT = l_snt) THEN
           -- DBMS_OUTPUT.PUT_LINE('Success. ');
           -- DBMS_OUTPUT.PUT_LINE(l_snt);
        --ELSE
            --DBMS_OUTPUT.PUT_LINE('Check the error logs. ');
           
          --  gv_error := SUBSTR(SQLERRM,1,250);
           -- INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_ONHAND_PRC - No records found to insert','ERROR',gv_error);
           -- COMMIT;
       -- END IF;
  END IF;
  /*
FOR rec in (SELECT lookupcode, meaning FROM TERFND_CMNLKP_VAUES WHERE lookuptype = 'TER_INT_RAPID_RESPONSE' and  enabledflag = 'Y'
 and nvl(startdateactive,SYSDATE) <= SYSDATE and nvl(enddateactive,SYSDATE+1) >= SYSDATE+1)
LOOP
l_org_code:=rec.meaning;
 DBMS_OUTPUT.PUT_LINE(l_org_code);
BEGIN
      DBMS_CLOUD.EXPORT_DATA(
        credential_name => 'TER_FUSION_INT_TO_TEREXT',
        file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Outbound/'|| p_date||'/OF_OnHand_'||rec.lookupcode||'.csv',
        query           => 'SELECT * FROM TERDTP_RR_ONHAND_RECORDS WHERE TotalTransactionQuantity IS NOT NULL AND ORGANIZATION_CODE='''||rec.meaning||'''',
        format          => JSON_OBJECT('type' value 'csv','delimiter' value '|','maxfilesize' value '1048576000'));
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'OF_OnHand','TERDTP_ONHAND_PRC - EXPORT_DATA','ERROR',gv_error);
        COMMIT;
    END;
    
    
BEGIN
      DBMS_CLOUD.EXPORT_DATA(
        credential_name => 'TER_FUSION_INT_TO_TEREXT',
        file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Error/'|| p_date||'/OF_OnHand_'||rec.lookupcode||'.csv',
        query           => 'SELECT * FROM TERDTP_RR_ONHAND_RECORDS WHERE TotalTransactionQuantity IS NULL AND ORGANIZATION_CODE='''||rec.meaning||'''',
        format          => JSON_OBJECT('type' value 'csv','delimiter' value '|','maxfilesize' value '1048576000'));
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'OF_OnHand','TERDTP_ONHAND_PRC - EXPORT_DATA','ERROR',gv_error);
        COMMIT;
END;
END LOOP;
*/

