PROCEDURE TERDTP_BOM_TRNSFM_PRC (
        p_date                      IN VARCHAR2,
        p_rec_cnt                   OUT NUMBER
        ) 
AS

 l_cnt NUMBER := 0;

 TYPE TERDTP_BOM_OBJ IS RECORD (
    ASS_ITEM_NAME						VARCHAR2(2000),
    COMP_ITEM_NAME                      VARCHAR2(2000),
    ITEM_TYPE        					VARCHAR2(2000),
	COMP_QTY							NUMBER,
    EFFECTIVEINDATE				        VARCHAR2(2000),
    EFFECTIVEOUTDATE                    VARCHAR2(2000),
    COMP_ORG_CODE			    		VARCHAR2(2000),
    ASS_ORG_CODE     					VARCHAR2(2000)
 );

 TYPE TERDTP_BOM_TAB IS TABLE OF TERDTP_BOM_OBJ;

 lv_bom_tbl  TERDTP_BOM_TAB;
 lv_org_code VARCHAR2(2000);

BEGIN

    BEGIN
        delete from TERINV_STRUCTURES_STG;
        delete from TERINV_COMPONENTS_STG;
        delete from TERDTP_RR_BOM_STG;
        commit;
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_BOM_TRNSFM_PRC- Deletion','ERROR',gv_error);
        COMMIT;
    END;
    
    BEGIN  
       DBMS_CLOUD.COPY_DATA(   
          table_name      => 'TERINV_STRUCTURES_STG',   
          credential_name => 'TER_FUSION_INT_TO_TEREXT',   
          file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*file_fscmtopmodelam_scmextractam_egpbiccextractam_structuresextractpvo*.csv',
          format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
       );
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'structuresextractpvo','TERDTP_BOM_TRNSFM_PRC - COPY_DATA','ERROR',gv_error);
        COMMIT;
    END;
    
    BEGIN  
       DBMS_CLOUD.COPY_DATA(   
          table_name      => 'TERINV_COMPONENTS_STG',   
          credential_name => 'TER_FUSION_INT_TO_TEREXT',   
          file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*file_fscmtopmodelam_scmextractam_egpbiccextractam_componentsextractpvo*.csv',
          format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
       );
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'componentsextractpvo','TERDTP_BOM_TRNSFM_PRC - COPY_DATA','ERROR',gv_error);
        COMMIT;
    END;
    
    BEGIN
        WITH cal AS (
          SELECT
              MIN(calendar_date) AS min_cal_date
            , MAX(calendar_date) AS max_cal_date
          FROM TERDTP_RR_ORG_CALENDAR
        )
        SELECT
            si_assy.itemnumber                                     AS assembly_item_number,
            si_comp.itemnumber                                     AS component_item_number,
            CASE si_comp.wipsupplytype
              WHEN 5 THEN 'OutsideProc'
              ELSE 'BOM'
            END AS Type,
            c.componentquantity,
            CASE
                WHEN to_char(c.effectivitydate, 'YYYYMMDD') IS NULL
                     OR to_char(c.effectivitydate, 'YYYYMMDD') < min_cal_date THEN
                    'PAST'
                WHEN to_char(c.effectivitydate, 'YYYYMMDD') > min_cal_date
                     AND to_char(c.effectivitydate, 'YYYYMMDD') < max_cal_date THEN
                    to_char(c.effectivitydate, 'YYYYMMDD') --TO_CHAR(c.EFFECTIVITYDATE,'YYYYMMDD')
                WHEN to_char(c.effectivitydate, 'YYYYMMDD') > max_cal_date THEN
                    'FUTURE' 
                ELSE
                    'FUTURE'
            END                                                    AS effectiveindate,
            CASE
                WHEN c.disabledate IS NULL
                     OR to_char(c.disabledate, 'YYYYMMDD') > max_cal_date THEN
                    'FUTURE'
                WHEN to_char(c.disabledate, 'YYYYMMDD') < max_cal_date THEN
                    to_char(c.disabledate, 'YYYYMMDD')
                ELSE
                    'FUTURE'
            END                                                    AS effectiveoutdate,
            comp_org.org_organizationcode                          AS componentsite,
            assy_org.org_organizationcode                          AS assemblysite
        BULK COLLECT INTO lv_bom_tbl
        FROM
            terinv_structures_stg s,
            terinv_components_stg c,
            terinv_inventory_stg  si_assy,
            terinv_inventory_stg  si_comp,
            terdtp_rr_orgcode     assy_org,
            terdtp_rr_orgcode     comp_org
            CROSS JOIN cal
        WHERE
                c.billsequenceid = s.billsequenceid
            AND si_assy.inventoryitemid = s.pk1value
            AND si_assy.organizationid = s.pk2value
            AND si_assy.organizationid = assy_org.organizationid
            AND si_comp.inventoryitemid = c.pk1value
            AND si_comp.organizationid = c.pk2value
            AND si_comp.organizationid = comp_org.organizationid
            AND si_comp.organizationid = si_assy.organizationid
            AND UPPER(s.ALTERNATEBOMDESIGNATOR) = 'PRIMARY'
            order by assembly_item_number asc;

    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_BOM_TRNSFM_PRC - Data Transformation','ERROR',gv_error);
        COMMIT;
    END;

    -- Display the number of records fetched
    DBMS_OUTPUT.PUT_LINE('Records fetched: ' || lv_bom_tbl.COUNT);

    IF lv_bom_tbl.COUNT > 0 THEN
        FORALL i IN lv_bom_tbl.FIRST .. lv_bom_tbl.LAST
            INSERT INTO TERDTP_RR_BOM_STG(
            ASSEMBLY_ITEMNAME	,
            COMPONENT_ITEMNAME  ,
            ITEM_TYPE        	,
            COMP_QTY			,
            EFFECTIVEINDATE		,
            EFFECTIVEOUTDATE    ,
            COMPONENT_ORGCODE	,
            ASSEMBLY_ORGCODE   
            )
            VALUES(
            lv_bom_tbl(i).ASS_ITEM_NAME		,
            lv_bom_tbl(i).COMP_ITEM_NAME       ,       
            lv_bom_tbl(i).ITEM_TYPE            ,
            lv_bom_tbl(i).COMP_QTY		        ,
            lv_bom_tbl(i).EffectiveInDate		,    
            lv_bom_tbl(i).EffectiveOutDate     ,       
            lv_bom_tbl(i).COMP_ORG_CODE	    ,
            lv_bom_tbl(i).ASS_ORG_CODE         
            );
    
    DBMS_OUTPUT.PUT_LINE('Records inserted: ' || SQL%ROWCOUNT);
        l_cnt := SQL%ROWCOUNT;
        COMMIT;

        IF (lv_bom_tbl.COUNT = l_cnt) THEN
            DBMS_OUTPUT.PUT_LINE('Success. ');
            BEGIN
                DBMS_CLOUD.BULK_MOVE(      
                      source_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      source_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*file_fscmtopmodelam_scmextractam_egpbiccextractam_structuresextractpvo*',
                      target_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      target_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Archive/'||p_date||'/',
                      format                  =>  JSON_OBJECT ('logretention' value 7, 'logprefix' value 'BULKOP')
                );
            EXCEPTION WHEN OTHERS THEN
                gv_error := SUBSTR(SQLERRM,1,250);
                INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'egpbiccextractam_structuresextractpvo','TERDTP_BOM_TRNSFM_PRC - Archive Processed Files','ERROR',gv_error);
                COMMIT;
            END;
            BEGIN
                DBMS_CLOUD.BULK_MOVE(      
                      source_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      source_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*file_fscmtopmodelam_scmextractam_egpbiccextractam_componentsextractpvo*',
                      target_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      target_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Archive/'||p_date||'/',
                      format                  =>  JSON_OBJECT ('logretention' value 7, 'logprefix' value 'BULKOP')
                );
            EXCEPTION WHEN OTHERS THEN
                gv_error := SUBSTR(SQLERRM,1,250);
                INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'egpbiccextractam_componentsextractpvo','TERDTP_BOM_TRNSFM_PRC - Archive Processed Files','ERROR',gv_error);
                COMMIT;
            END;
            
            ELSE
            DBMS_OUTPUT.PUT_LINE('Check the error logs. ');
            gv_error := SUBSTR(SQLERRM,1,250);
            INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_BOM_TRNSFM_PRC - No records found to insert','ERROR',gv_error);
            COMMIT;
        END IF;
        
    END IF;
    p_rec_cnt := l_cnt;
 
 FOR rec in (SELECT lookupcode, meaning FROM TERFND_CMNLKP_VAUES WHERE lookuptype = 'TER_INT_RAPID_RESPONSE' and  enabledflag = 'Y'
 and nvl(startdateactive,SYSDATE) <= SYSDATE and nvl(enddateactive,SYSDATE+1) >= SYSDATE)
