        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'OF_BOM','TERDTP_BOM_TRNSFM_PRC - EXPORT_DATA','ERROR',gv_error);
