PROCEDURE TERDTP_DEMANDORDER_TRNSFM_PRC (
        p_date                      IN VARCHAR2,
        p_rec_cnt                   OUT NUMBER
        ) 
AS

 l_cnt NUMBER := 0;

 TYPE TERDTP_DO_OBJ IS RECORD (
    ORDER_NUMBER						VARCHAR2(2000),
    ORDER_TYPE                          VARCHAR2(2000),
    CUSTOMER_NUMBER    					VARCHAR2(2000),
	ORG_CODE							VARCHAR2(2000)
 );

 TYPE TERDTP_DO_TAB IS TABLE OF TERDTP_DO_OBJ;

 lv_do_tbl  TERDTP_DO_TAB;
 lv_org_code VARCHAR2(2000);

BEGIN

    BEGIN
        delete from TERDTP_MSC_DEMANDS;
        delete from TERDTP_MSC_PARAMETERS;
        delete from TERDTP_RR_DEMANDORDER_STG;
        commit;
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_DEMANDORDER_TRNSFM_PRC- Deletion','ERROR',gv_error);
        COMMIT;
    END;
    
    BEGIN  
       DBMS_CLOUD.COPY_DATA(   
          table_name      => 'TERDTP_MSC_DEMANDS',   
          credential_name => 'TER_FUSION_INT_TO_TEREXT',   
          file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*DemandPlanningBIP*.csv',
          format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
       );
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'structuresextractpvo','TERDTP_DEMANDORDER_TRNSFM_PRC - COPY_DATA','ERROR',gv_error);
        COMMIT;
    END;
    
    BEGIN  
       DBMS_CLOUD.COPY_DATA(   
          table_name      => 'TERDTP_MSC_PARAMETERS',   
          credential_name => 'TER_FUSION_INT_TO_TEREXT',   
          file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*planningorganizationBIP*.csv',
          format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
       );
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'componentsextractpvo','TERDTP_DEMANDORDER_TRNSFM_PRC - COPY_DATA','ERROR',gv_error);
        COMMIT;
    END;
    
    BEGIN
        SELECT * BULK COLLECT INTO lv_do_tbl
        FROM
        (SELECT DISTINCT 
                CASE WHEN UPPER(lkp.meaning) = 'SALES ORDER' THEN 'SO'
                     WHEN UPPER(lkp.meaning) = 'FORECAST' THEN 'FCST'
                     ELSE NULL
                END as ORDERTYPE
                ,nvl(ms_dem.sales_order_number,ms_dem.demand_id) as ORDERNUMBER
                ,ms_cust.partner_number as CUSTOMERNUMBER
                ,inv_org.organization_code
            FROM
                TERDTP_MSC_DEMANDS ms_dem
                ,TERMSC_PLAN_CUSTOMER ms_cust
                ,TERDTP_MSC_PARAMETERS inv_org
                ,TERFND_CMNLKP_VAUES lkp
            WHERE 1=1
            AND ms_dem.customer_id = ms_cust.tp_id
            AND ms_dem.organization_id = inv_org.organization_id
            and lkp.lookupcode = ms_dem.origination_type
            and lkp.lookuptype = 'MSC_ORDER_TYPE'
        UNION 
        SELECT distinct
                decode(nvl(s_plan.partial_flag,'N'),'Y','Oracle Partial Slot Input','Oracle Slot Input') as ORDERTYPE
                ,s_plan.slot_number  as ORDERNUMBER
                ,s_plan.customer_id  as CUSTOMERNUMBER
                ,s_plan.planning_organization as organization_code
            FROM
                terext_slot_plan_dtls     s_plan
            WHERE 1=1
                and UPPER(s_plan.slot_status) NOT IN ('SHIPPED')
                )demand
            order by demand.ordernumber asc;

    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_DEMANDORDER_TRNSFM_PRC - Data Transformation','ERROR',gv_error);
        COMMIT;
    END;

    -- Display the number of records fetched
    DBMS_OUTPUT.PUT_LINE('Records fetched: ' || lv_do_tbl.COUNT);

    IF lv_do_tbl.COUNT > 0 THEN
        FORALL i IN lv_do_tbl.FIRST .. lv_do_tbl.LAST
            INSERT INTO TERDTP_RR_DEMANDORDER_STG(
            ORDER_TYPE      ,
            ORDER_NUMBER	,
            CUSTOMER_NUMBER ,
            ORG_CODE		
            )
            VALUES(
            lv_do_tbl(i).ORDER_TYPE         ,   
            lv_do_tbl(i).ORDER_NUMBER		,	
            lv_do_tbl(i).CUSTOMER_NUMBER    ,	
            lv_do_tbl(i).ORG_CODE				
            );
    
    DBMS_OUTPUT.PUT_LINE('Records inserted: ' || SQL%ROWCOUNT);
        l_cnt := SQL%ROWCOUNT;
        COMMIT;

        IF (lv_do_tbl.COUNT = l_cnt) THEN
            DBMS_OUTPUT.PUT_LINE('Success. ');
            BEGIN
                DBMS_CLOUD.BULK_MOVE(      
                      source_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      source_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*DemandPlanningBIP*',
                      target_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      target_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Archive/'||p_date||'/',
                      format                  =>  JSON_OBJECT ('logretention' value 7, 'logprefix' value 'BULKOP')
                );
            EXCEPTION WHEN OTHERS THEN
                gv_error := SUBSTR(SQLERRM,1,250);
                INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'DemandPlanningBIP','TERDTP_DEMANDORDER_TRNSFM_PRC - Archive Processed Files','ERROR',gv_error);
                COMMIT;
            END;
            BEGIN
                DBMS_CLOUD.BULK_MOVE(      
                      source_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      source_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*planningorganizationBIP*',
                      target_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      target_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Archive/'||p_date||'/',
                      format                  =>  JSON_OBJECT ('logretention' value 7, 'logprefix' value 'BULKOP')
                );
            EXCEPTION WHEN OTHERS THEN
                gv_error := SUBSTR(SQLERRM,1,250);
                INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'planningorganizationBIP','TERDTP_DEMANDORDER_TRNSFM_PRC - Archive Processed Files','ERROR',gv_error);
                COMMIT;
            END;
            
            ELSE
            DBMS_OUTPUT.PUT_LINE('Check the error logs. ');
            gv_error := SUBSTR(SQLERRM,1,250);
            INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_DEMANDORDER_TRNSFM_PRC - No records found to insert','ERROR',gv_error);
            COMMIT;
        END IF;
        
    END IF;
    p_rec_cnt := l_cnt;
 
    
    BEGIN
      DBMS_CLOUD.EXPORT_DATA(
        credential_name => 'TER_FUSION_INT_TO_TEREXT',
        file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Outbound/'|| p_date||'/OF_DemandOrder.csv',
        query           => 'SELECT * FROM TERDTP_RR_DEMANDORDER_STG',
        format          => JSON_OBJECT('type' value 'csv','delimiter' value '|','maxfilesize' value '1048576000'));
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'OF_BOM','TERDTP_DEMANDORDER_TRNSFM_PRC - EXPORT_DATA','ERROR',gv_error);
        COMMIT;
    END;


EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_DEMANDORDER_TRNSFM_PRC - Unknown Error','ERROR',gv_error);
    COMMIT;
END;



PROCEDURE TERDTP_PARTSOURCE_PRC (
  p_date                      IN VARCHAR2
)
AS
  gv_error VARCHAR2(250);
  l_cnt NUMBER := 0;
 
  TYPE TERDTP_PARTSOURCE_PRC_DATA IS RECORD (
    base_key VARCHAR2(2000),
    postprocessing_lead_time NUMBER,
    effectiveindate VARCHAR2(1000),
    effectiveoutdate VARCHAR2(1000),
    fixed_lead_time NUMBER,
    maximum_order_quantity NUMBER,
    minimum_order_quantity NUMBER,
    fixed_lot_multiplier NUMBER,
    part_name VARCHAR2(2000),
    PartSite_Value VARCHAR2(2000),
    planning_time_fence_days NUMBER,
    allocation_percent NUMBER,
    source_code VARCHAR2(200),
    PARTNER_Name VARCHAR2(2000),
    item_name VARCHAR2(2000),
    TRANSFERPARTSITE VARCHAR2(2000),
    SOURCEID VARCHAR2(2000)
  );
 
  TYPE TERDTP_PARTSOURCE_TAB IS TABLE OF TERDTP_PARTSOURCE_PRC_DATA;
 
  lv_partms_tbl   TERDTP_PARTSOURCE_TAB;                 

 
 
BEGIN

BEGIN
  DELETE FROM TERDTP_RR_PART_SOURCE_LEVEL;
  DELETE FROM TERDTP_RR_MSC_SOURCE;
  DELETE FROM TERDTP_RR_MSC_RECEIPT;
  DELETE FROM TERDTP_RR_MSC_ASSIGNMENT;
  DELETE FROM TERMSC_SYSTEM_ITEMS;
  COMMIT;
  EXCEPTION
    WHEN OTHERS THEN
      gv_error := SUBSTR(SQLERRM, 1, 250);
      INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
      VALUES (p_date, 'TERDTP_PARTSOURCE_PRC - Deletion', 'ERROR', gv_error);
      COMMIT;
  END;
  
BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERDTP_RR_MSC_SOURCE',   
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*TERDTP_Msc_Source*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_Msc_Source BIP Report','TERDTP_PARTSOURCE_PRC- COPY_DATA','ERROR',gv_error);
    COMMIT;
END;

BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERDTP_RR_MSC_RECEIPT',   
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*TERDTP_Msc_Receipt*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_Msc_Receipt BIP Report','TERDTP_PARTSOURCE_PRC - COPY_DATA','ERROR',gv_error);
    COMMIT;
END;

BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERDTP_RR_MSC_ASSIGNMENT',   
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*terdtp_msc_assignment*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_Msc_Assignment','TERDTP_PARTSOURCE_PRC - COPY_DATA','ERROR',gv_error);
    COMMIT;
END;

BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERMSC_SYSTEM_ITEMS',   
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*terdtp_msc_system_items*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'terdtp_msc_system_items','TERDTP_PARTSOURCE_PRC - COPY_DATA','ERROR',gv_error);
    COMMIT;
END;

BEGIN
WITH cal AS(
  SELECT
      MIN(calendar_date) AS min_cal_key,
      MAX(calendar_date) AS max_cal_key
  FROM TERDTP_RR_ORG_CALENDAR
),
base AS (
  SELECT
      ms.item_name as part_name,
      ms.organization_code,
      ms.postprocessing_lead_time,
      ms.fixed_lead_time,
      ms.fixed_lot_multiplier,
      ms.planning_time_fence_days,
      mss.allocation_percent,
      CASE mss.source_type
        WHEN 1 THEN 'Transfer'
        WHEN 2 THEN 'Make'
        WHEN 3 THEN 'Buy'
        ELSE 'NoSource'
      END AS Source_Code,
      mss.source_type,
      CASE
        WHEN mr.effective_date IS NULL
          OR mr.effective_date < cal.min_cal_key
          THEN 'PAST'
          WHEN mr.effective_date<= cal.max_cal_key
           THEN mr.effective_date
        ELSE 'FUTURE'
      END AS effectiveindate,
     CASE
        WHEN mr.disable_date IS NULL
          OR mr.disable_date > cal.max_cal_key
          THEN 'FUTURE'
        WHEN mr.disable_date < cal.min_cal_key
          THEN 'PAST'
        ELSE mr.disable_date
      END AS effectiveoutdate,
      CASE
        WHEN NVL(ms.fixed_order_quantity, 0) > 0 THEN ms.fixed_order_quantity
        ELSE ms.maximum_order_quantity
      END AS maximum_order_quantity,
      CASE
        WHEN NVL(ms.fixed_order_quantity, 0) > 0 THEN ms.fixed_order_quantity
        ELSE ms.minimum_order_quantity
      END AS minimum_order_quantity,
      CASE mss.source_type
        WHEN 1 THEN MAP.ORGANIZATION_CODE
        WHEN 2 THEN ms.organization_code
        WHEN 3 THEN ms.organization_code
        ELSE ms.organization_code
      END AS PartSite_Value,
      CASE mss.source_type
        WHEN 3 THEN mp.partnername
        ELSE NULL
      END AS PARTNER_NAME,
       ms.item_name,
      CASE mss.source_type
        WHEN 1 THEN MAS.ORGANIZATION_CODE
        WHEN 2 THEN ms.organization_code
        WHEN 3 THEN ms.organization_code
        ELSE NULL
      END AS TRANSFERPARTSITE,
      CASE mss.source_type
        WHEN 1 THEN 'None'|| '_' ||ms.organization_code
        WHEN 2 THEN 'None'|| '_' ||ms.organization_code
        WHEN 3 THEN mp.partnername||'_'||ms.organization_code
        ELSE 'None'||'_'||ms.organization_code
    END AS SOURCEID
  FROM TERmsc_system_items ms
  JOIN TERFND_CMNLKP_VAUES lkp
    ON lkp.meaning = ms.organization_code
   AND lkp.lookuptype = 'TER_INT_RAPID_RESPONSE'
  LEFT JOIN TERDTP_RR_msc_assignment ma
    ON ms.inventory_item_id = ma.inventory_item_id
   AND ms.organization_id   = ma.organization_id
  LEFT JOIN TERDTP_RR_msc_receipt mr
    ON ma.sourcing_rule_id  = mr.sourcing_rule_id
  LEFT JOIN TERDTP_RR_msc_source mss
    ON mr.sr_receipt_id     = mss.sr_receipt_id
  LEFT JOIN TERPO_SUPPLIER_STG mp
    ON mp.tpid = mss.source_partner_id
  LEFT JOIN TERDTP_MSC_PARAMETERS MAP
    ON MA.ORGANIZATION_ID=MAP.ORGANIZATION_ID
  LEFT JOIN TERDTP_MSC_PARAMETERS MAS
     ON MSS.ORGANIZATION_ID=MAS.ORGANIZATION_ID
  CROSS JOIN cal
  WHERE ms.plan_id = -1

)
SELECT DISTINCT
    item_name
    || '_' || organization_code
    || CASE WHEN PARTNER_NAME IS NOT NULL THEN '_'  || partner_name END
    || '_' || effectiveindate 
    || '_' || effectiveoutdate AS base_key,
    postprocessing_lead_time,
    effectiveindate,
    effectiveoutdate,
    fixed_lead_time,
    maximum_order_quantity,
    minimum_order_quantity,
    fixed_lot_multiplier,
    part_name,
    PartSite_Value,
    planning_time_fence_days,
    allocation_percent,
    source_code,
    PARTNER_Name,
    item_name,
    TRANSFERPARTSITE,
    SOURCEID
BULK COLLECT INTO lv_partms_tbl
FROM base;
  EXCEPTION
    WHEN OTHERS THEN
      gv_error := SUBSTR(SQLERRM, 1, 250);
      INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
      VALUES (p_date, 'TERDTP_PARTSOURCE_PRC - Data Transformation', 'ERROR', gv_error);
      COMMIT;
  END;
  IF lv_partms_tbl.COUNT > 0 THEN
    FORALL i IN 1 .. lv_partms_tbl.COUNT
      INSERT INTO TERDTP_RR_PART_SOURCE_LEVEL (
       base_key,
       postprocessing_lead_time,
       effectiveindate ,
       effectiveoutdate,
       fixed_lead_time ,
       maximum_order_quantity ,
       minimum_order_quantity ,
       fixed_lot_multiplier ,
       part_name,
       PartSite_Value,
       planning_time_fence_days ,
       allocation_percent ,
       source_code,
       PARTNER_Name,
       item_name,
       TRANSFERPARTSITE,
       SOURCEID
       )
      VALUES (
      lv_partms_tbl(i).base_key,
      lv_partms_tbl(i).postprocessing_lead_time,
      lv_partms_tbl(i).effectiveindate ,
      lv_partms_tbl(i).effectiveoutdate,
      lv_partms_tbl(i).fixed_lead_time ,
      lv_partms_tbl(i).maximum_order_quantity ,
      lv_partms_tbl(i).minimum_order_quantity ,
      lv_partms_tbl(i).fixed_lot_multiplier ,
      lv_partms_tbl(i).part_name,
      lv_partms_tbl(i).PartSite_Value,
      lv_partms_tbl(i).planning_time_fence_days ,
      lv_partms_tbl(i).allocation_percent ,
      lv_partms_tbl(i).source_code,
      lv_partms_tbl(i).PARTNER_Name,
      lv_partms_tbl(i).item_name,
      lv_partms_tbl(i).TRANSFERPARTSITE,
      lv_partms_tbl(i).SOURCEID
     );
  END IF;
   BEGIN
      DBMS_CLOUD.EXPORT_DATA(
        credential_name => 'TER_FUSION_INT_TO_TEREXT',
        file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Outbound/'|| p_date||'/OF_PartSource.csv',
        query           => 'SELECT * FROM TERDTP_RR_PART_SOURCE_LEVEL',
        format          => JSON_OBJECT('type' value 'csv','delimiter' value '|','maxfilesize' value '1048576000'));
    EXCEPTION WHEN OTHERS THEN
