PROCEDURE TERDTP_SUPPLYORDER_TRNSFM_PRC (
        p_date                      IN VARCHAR2,
        p_rec_cnt                   OUT NUMBER
        ) 
AS
l_cnt NUMBER := 0;

 TYPE TERDTP_SO_OBJ IS RECORD (
    ORDER_NUMBER						VARCHAR2(2000),
    ORG_CODE							VARCHAR2(2000),
    SUPPLIER_NUMBER    					VARCHAR2(2000),
    ORDER_TYPE                          VARCHAR2(2000)
 );

 TYPE TERDTP_SO_TAB IS TABLE OF TERDTP_SO_OBJ;

 lv_so_tbl  TERDTP_SO_TAB;
BEGIN

    BEGIN
        delete from TERDTP_RR_SUPPLYORDER_STG;
        commit;
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_SUPPLYORDER_TRNSFM_PRC- Deletion','ERROR',gv_error);
        COMMIT;
    END;
    
    BEGIN
        SELECT DISTINCT
                 ms.ordernumber
                ,mpo.organization_code
                ,mgtp.partnernumber
                ,CASE 
                    WHEN ms.FIRMTYPE = 2 AND ms.ordertype = 1 THEN 'PO'
                    WHEN ms.FIRMTYPE = 2 AND ms.ordertype = 2 THEN 'REQ'
                    WHEN ms.FIRMTYPE = 2 AND ms.ordertype = 3 THEN 'WO'
                    WHEN ms.FIRMTYPE = 1 AND ms.ordertype = 1 THEN 'POFIRM'
                    WHEN ms.FIRMTYPE = 1 AND ms.ordertype = 2 THEN 'REQFIRM'
                    WHEN ms.FIRMTYPE = 1 AND ms.ordertype = 3 THEN 'WOFIRM'
                   ELSE NULL
                   END AS order_type
        BULK COLLECT INTO lv_so_tbl
        from TERMSC_SUPPLIES_DATA ms
              ,TERDTP_MSC_PARAMETERS mpo
              ,TERPO_SUPPLIER_STG mgtp
        WHERE 1=1
            AND ms.supplierid = mgtp.tpid(+)
            AND ms.organization_id = mpo.organization_id
            AND ms.plan_id <> -1
            and ms.ordertype in (1,2,3);
    EXCEPTION WHEN OTHERS THEN
            gv_error := SUBSTR(SQLERRM,1,250);
            INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'Insertion','TERDTP_SUPPLYORDER_PRC - Transformation of data','ERROR',gv_error);
            COMMIT;
    END;
    
    -- Display the number of records fetched
    DBMS_OUTPUT.PUT_LINE('Records fetched: ' || lv_so_tbl.COUNT);

    IF lv_so_tbl.COUNT > 0 THEN
        FORALL i IN lv_so_tbl.FIRST .. lv_so_tbl.LAST
            INSERT INTO TERDTP_RR_SUPPLYORDER_STG(
            ORDER_NUMBER	,
            ORG_CODE	    ,
            SUPPLIER_NUMBER ,
            ORDER_TYPE      
            )
            VALUES(
            lv_so_tbl(i).ORDER_NUMBER         ,   
            lv_so_tbl(i).ORG_CODE		,	
            lv_so_tbl(i).SUPPLIER_NUMBER    ,	
            lv_so_tbl(i).ORDER_TYPE				
            );
    
    DBMS_OUTPUT.PUT_LINE('Records inserted: ' || SQL%ROWCOUNT);
        l_cnt := SQL%ROWCOUNT;
        COMMIT;

        IF (lv_so_tbl.COUNT = l_cnt) THEN
            DBMS_OUTPUT.PUT_LINE('Success. ');
                       
        ELSE
            DBMS_OUTPUT.PUT_LINE('Check the error logs. ');
            gv_error := SUBSTR(SQLERRM,1,250);
            INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_SUPPLYORDER_TRNSFM_PRC - No records found to insert','ERROR',gv_error);
            COMMIT;
        END IF;
        
    END IF;
    p_rec_cnt := l_cnt;
 
    
    BEGIN
      DBMS_CLOUD.EXPORT_DATA(
        credential_name => 'TER_FUSION_INT_TO_TEREXT',
        file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Outbound/'|| p_date||'/OF_SupplyOrder.csv',
        query           => 'SELECT * FROM TERDTP_RR_SUPPLYORDER_STG',
        format          => JSON_OBJECT('type' value 'csv','delimiter' value '|','maxfilesize' value '1048576000'));
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'OF_SupplyOrder','TERDTP_SUPPLYORDER_TRNSFM_PRC - EXPORT_DATA','ERROR',gv_error);
        COMMIT;
    END;
    
EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'OF_SupplyOrder','TERDTP_SUPPLYORDER_TRNSFM_PRC - EXPORT_DATA','ERROR',gv_error);
        COMMIT;
END TERDTP_SUPPLYORDER_TRNSFM_PRC;
        
PROCEDURE TERDTP_ALLOCATION_TRNSFM_PRC (
        p_date                      IN VARCHAR2,
        p_rec_cnt                   OUT NUMBER
        ) 
AS
l_cnt NUMBER := 0;
TYPE TERDTP_ALLOCATION_OBJ IS RECORD (
    ITEMNUMBER							VARCHAR2(2000),
	ORDERTYPE                           VARCHAR2(200),
    ORDERNUMBER 					    VARCHAR2(2000),
    MATERIAL_SEQ_NUMBER                 NUMBER,
	SCHEDULEDATE						VARCHAR2(200),
    ORIGQUANTITY				        NUMBER,
    STARTQUANTITY                       NUMBER,
    ORGANIZATION_CODE					VARCHAR2(2000),
    PARTSITE_ORGCODE					VARCHAR2(2000)
 );
TYPE TERDTP_ALLOCATION_TAB IS TABLE OF TERDTP_ALLOCATION_OBJ;
 lv_alloc_tbl  TERDTP_ALLOCATION_TAB;
 lv_org_code    VARCHAR2(2000);
BEGIN
BEGIN
    delete from TERDTP_WORK_ORDER_DATA;
    DELETE FROM TERDTP_RR_ALLOCATION_STG;
    commit;
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_ALLOCATION_TRNSFM_PRC - Deletion','ERROR',gv_error);
    COMMIT;
END;
BEGIN  
   DBMS_CLOUD.COPY_DATA(   
      table_name      => 'TERDTP_WORK_ORDER_DATA',   
      credential_name => 'TER_FUSION_INT_TO_TEREXT',   
      file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*workorderam_wooperationmaterialspvo*.csv',
      format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
   );
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'cststdcostdetailsextractpvo','TERDTP_ALLOCATION_TRNSFM_PRC - COPY_DATA','ERROR',gv_error);
    COMMIT;
END;
 BEGIN
    select distinct * BULK COLLECT INTO lv_alloc_tbl from(
    SELECT distinct
       MSC.ITEMNUMBER,
	   'WO' AS ORDERTYPE,
       MS.ORDERNUMBER,
       WOD.MATERIAL_SEQ_NUMBER, 
       MS.SCHEDULEDATE,
       MS.ORIGQUANTITY,
       ms.STARTQUANTITY,
       MP.ORGANIZATION_CODE,
       MP.ORGANIZATION_CODE AS ORGCODE
    FROM TERMSC_SUPPLIES_DATA MS,
    TERDTP_WORK_ORDER_DATA WOD, 
    TERINV_INVENTORY_STG MSC,
    TERDTP_MSC_PARAMETERS MP,
	TERFND_CMNLKP_VAUES lkp
    WHERE MS.ORDERTYPE=3 
    AND MS.ORDERNUMBER=WOD.WORK_ORDER_NUMBER
    AND MS.SUBINVENTORYCODE=WOD.SUBINVENTORY_CODE 
    AND WOD.MATERIAL_TYPE='COMPONENT'
    AND WOD.INVENTORY_ITEM_ID=MSC.INVENTORYITEMID 
    AND WOD.ORGANIZATION_ID=MSC.ORGANIZATIONID 
    AND MS.ORGANIZATION_ID=MP.ORGANIZATION_ID
	AND lkp.MEANING = MP.ORGANIZATION_CODE
    AND lkp.LOOKUPTYPE = 'TER_INT_RAPID_RESPONSE'
    )a
   ORDER BY a.ORDERNUMBER,a.MATERIAL_SEQ_NUMBER,a.SCHEDULEDATE,a.ORGANIZATION_CODE;
EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_PARTMSTR_ALLOCATION_PRC - Data Transformation','ERROR',gv_error);
        COMMIT;
    END;
   DBMS_OUTPUT.PUT_LINE('Records fetched: ' || lv_alloc_tbl.COUNT);
IF lv_alloc_tbl.COUNT > 0 THEN
        FORALL i IN lv_alloc_tbl.FIRST .. lv_alloc_tbl.LAST
            INSERT INTO TERDTP_RR_ALLOCATION_STG (
                 ITEMNUMBER,
				 ORDERTYPE,      
                 ORDERNUMBER, 
                 MATERIAL_SEQ_NUMBER,
	             SCHEDULEDATE,						
                 ORIGQUANTITY,				        
                 STARTQUANTITY,                      
                 ORGANIZATION_CODE,					
                 PARTSITE_ORGCODE					
            ) VALUES (
                lv_alloc_tbl(i).ITEMNUMBER,
                lv_alloc_tbl(i).ORDERTYPE,			        
                lv_alloc_tbl(i).ORDERNUMBER, 
                lv_alloc_tbl(i).MATERIAL_SEQ_NUMBER,
                lv_alloc_tbl(i).SCHEDULEDATE, 
                lv_alloc_tbl(i).ORIGQUANTITY,  		
                lv_alloc_tbl(i).STARTQUANTITY,
                lv_alloc_tbl(i).ORGANIZATION_CODE,
                lv_alloc_tbl(i).PARTSITE_ORGCODE                  	
            );
        DBMS_OUTPUT.PUT_LINE('Records inserted: ' || SQL%ROWCOUNT);
        l_cnt := SQL%ROWCOUNT;
        COMMIT;
       IF (lv_alloc_tbl.COUNT = l_cnt) THEN
            DBMS_OUTPUT.PUT_LINE('Success. ');
            BEGIN
                DBMS_CLOUD.BULK_MOVE(      
                      source_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      source_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*file_fscmtopmodelam_workorderam_wooperationmaterialspvo*',
                      target_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      target_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Archive/'||p_date||'/',
                      format                  =>  JSON_OBJECT ('logretention' value 7, 'logprefix' value 'BULKOP')
                );
            EXCEPTION WHEN OTHERS THEN
                gv_error := SUBSTR(SQLERRM,1,250);
                INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'file_fscmtopmodelam_workorderam_wooperationmaterialspvo','TERDTP_ALLOCATION_TRNSFM_PRC - Archive Processed Files','ERROR',gv_error);
                COMMIT;
            END;
        ELSE
            DBMS_OUTPUT.PUT_LINE('Check the error logs. ');
            gv_error := SUBSTR(SQLERRM,1,250);
            INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_ALLOCATION_TRNSFM_PRC - No records found to insert','ERROR',gv_error);
            COMMIT;
        END IF;
    END IF;
    p_rec_cnt := l_cnt;
    BEGIN
      DBMS_CLOUD.EXPORT_DATA(
        credential_name => 'TER_FUSION_INT_TO_TEREXT',
        file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Outbound/'|| p_date||'/OF_Allocation.csv',
        query           => 'SELECT * FROM TERDTP_RR_ALLOCATION_STG',
        format          => JSON_OBJECT('type' value 'csv','delimiter' value '|','maxfilesize' value '1048576000'));
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'OF_ALLOCATION','TERDTP_ALLOCATION_TRNSFM_PRC - EXPORT_DATA','ERROR',gv_error);
        COMMIT;
    END;
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM,1,250);
    INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_ALLOCATION_TRNSFM_PRC - Unknown Error','ERROR',gv_error);
    COMMIT;
END;

