    BEGIN  
       DBMS_CLOUD.COPY_DATA(   
          table_name      => 'TERPO_REQ_HEADERS_ALL',   
          credential_name => 'TER_FUSION_INT_TO_TEREXT',   
          file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*porbiccextractam_requisitionheaderextractpvo*.csv',
