    BEGIN  
       DBMS_CLOUD.COPY_DATA(   
          table_name      => 'TERPO_HEADERS_ALL',   
          credential_name => 'TER_FUSION_INT_TO_TEREXT',   
          file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date|| '/*pobiccextractam_purchasingdocumentheaderextractpvo*.csv',
          format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
       );
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'pobiccextractam_purchasingdocumentheaderextractpvo','TERDTP_SCHRECEIPTS_TRNSFM_PRC - COPY_DATA','ERROR',gv_error);
        COMMIT;
    END;
    
    BEGIN
    select * BULK COLLECT INTO lv_sr_tbl from
        (SELECT distinct
            CASE
                WHEN ms.ordertype = 1 THEN
                    'PO'
                WHEN ms.ordertype = 2 THEN
                    'REQ'
                WHEN ms.ordertype = 3 THEN
                    'WO'
                WHEN ms.ordertype = 94 THEN
                    'TransferOrder'
                ELSE
                    NULL
            END                AS ordertype,
             CASE
                WHEN ms.ordertype = 1 THEN substr(ms.ordernumber,
                                                      0,
                                                      instr(ms.ordernumber, '(') - 1)
                ELSE ms.ordernumber
                END as ordernumber,
                CASE
                    WHEN ms.ordertype = 3 THEN
                            '1'
                    WHEN ms.ordertype = 94 THEN
                            ms.to_line_number
                    ELSE
                        ms.purch_line_num
                END as line_num ,
            msi.item_name,
            ms.old_dock_date,
            ms.startquantity,
            CASE
                WHEN ms.ordertype = 1 THEN
                    (
                        SELECT
                            poh.documentstatus
                        FROM
                            TERpo_headers_all poh
                        WHERE
                                poh.segment1 = substr(ms.ordernumber,
                                                      0,
                                                      instr(ms.ordernumber, '(') - 1)
                            AND poh.reqbuid = iop.businessunitid
                            AND poh.documentstatus IN ('OPEN','PENDING APPROVAL')
                    )
                WHEN ms.ordertype = 2 THEN
                    (
                        SELECT
                            por.documentstatus AS req_status
                        FROM
                            TERpo_req_headers_all por
                        WHERE
                                por.requisitionnumber = ms.ordernumber
                            AND por.reqbuid = iop.businessunitid
                            AND por.documentstatus IN ('APPROVED','PENDING APPROVAL')
                    )
                WHEN ms.ordertype = 3 THEN
                    (
                        SELECT
                            wws.wosystemstatuscode AS order_status
                        FROM
                            TERMFG_work_orders_b wwo,
                            TERMFG_wo_status_b wws
                        WHERE
                                wwo.workordernumber = ms.ordernumber
                            AND wwo.organizationid = iop.organizationid
                            AND wwo.workorderstatusid = wws.wostatusid
                            AND wws.wosystemstatuscode IN ('UNRELEASED',
                            'ON_HOLD',
                            'RELEASED')
                    )
                WHEN ms.ordertype = 94 THEN (
                    SELECT
                        itol.status_lookup
                    FROM
                        TERINV_TO_HEADERS itoh,
                        TERINV_TO_LINES   itol
                    WHERE
                            itoh.header_id = itol.header_id
                            AND itoh.source_type_lookup IN ('INV')
                            AND itol.status_lookup IN ( 'OPEN' )
                            AND ms.ordernumber = itoh.header_number
                )
                ELSE
                    NULL
            END                AS status,
            iop.org_organizationcode,
            iop.org_organizationcode AS orgcode,
            ms.origquantity
        FROM
            TERMSC_SUPPLIES_DATA      ms,
            TERMSC_SYSTEM_ITEMS   	  msi,
            TERDTP_MSC_PARAMETERS     mp,
            TERDTP_RR_ORGCODE 		  iop
        WHERE
                ms.plan_id <> - 1
            AND ms.ordertype IN ( 1, 2, 3, 94 )
            AND ms.FIRMTYPE = 2
            AND ms.inventory_item_id = msi.inventory_item_id
            AND ms.organization_id = msi.organization_id
            and ms.plan_id = msi.plan_id
            AND ms.organization_id = mp.organization_id
            AND mp.organization_code = iop.org_organizationcode
         UNION 
         SELECT distinct
            CASE
                WHEN ms.ordertype = 1 THEN
                    'POFIRM'
                WHEN ms.ordertype = 2 THEN
                    'REQFIRM'
                WHEN ms.ordertype = 3 THEN
                    'WOFIRM'
                WHEN ms.ordertype = 5 and cmn_lkp.meaning = 'Buy' THEN
                'PlannedBuyFirm'
                WHEN ms.ordertype = 5 and cmn_lkp.meaning = 'Make' THEN
                'PlannedMakeFirm'
                WHEN ms.ordertype = 94 THEN
                    'TransferOrderFirm'
                ELSE
                    NULL
            END                AS ordertype,
            CASE
                WHEN ms.ordertype = 1 THEN substr(ms.ordernumber,
                                                      0,
                                                      instr(ms.ordernumber, '(') - 1)
                ELSE nvl(ms.ordernumber, ms.transaction_id)
                END as ordernumber,
                CASE
                    WHEN ms.ordertype IN (3,5) THEN
                            '1'
                    WHEN ms.ordertype = 94 THEN
                            ms.to_line_number
                    ELSE
                        ms.purch_line_num
                END as line_num ,
            msi.item_name,
            ms.firm_date,
            ms.startquantity,
            CASE
                WHEN ms.ordertype = 1 THEN
                    (
                        SELECT
                            poh.documentstatus
                        FROM
                            TERpo_headers_all poh
                        WHERE
                                poh.segment1 = substr(ms.ordernumber,
                                                      0,
                                                      instr(ms.ordernumber, '(') - 1)
                            AND poh.reqbuid = iop.businessunitid
                            AND poh.documentstatus IN ('OPEN','PENDING APPROVAL')
                    )
                WHEN ms.ordertype = 2 THEN
                    (
                        SELECT
                            por.documentstatus AS req_status
                        FROM
                            TERpo_req_headers_all por
                        WHERE
                                por.requisitionnumber = ms.ordernumber
                            AND por.reqbuid = iop.businessunitid
                            AND por.documentstatus IN ('APPROVED','PENDING APPROVAL')
                    )
                WHEN ms.ordertype = 3 THEN
                    (
                        SELECT
                            wws.wosystemstatuscode AS order_status
                        FROM
                            TERMFG_work_orders_b wwo,
                            TERMFG_wo_status_b wws
                        WHERE
                                wwo.workordernumber = ms.ordernumber
                            AND wwo.organizationid = iop.organizationid
                            AND wwo.workorderstatusid = wws.wostatusid
                            AND wws.wosystemstatuscode IN ('UNRELEASED',
                            'ON_HOLD',
                            'RELEASED')
                    )
                WHEN ms.ordertype = 5 and cmn_lkp.meaning = 'Buy' THEN
                'OPEN'
                WHEN ms.ordertype = 5 and cmn_lkp.meaning = 'Make' THEN
                'RELEASED'
                WHEN ms.ordertype = 94 THEN (
                    SELECT
                        itol.status_lookup
                    FROM
                        TERINV_TO_HEADERS itoh,
                        TERINV_TO_LINES   itol
                    WHERE
                            itoh.header_id = itol.header_id
                            AND itoh.source_type_lookup IN ('INV')
                            AND itol.status_lookup IN ( 'OPEN' )
                            AND ms.ordernumber = itoh.header_number
                )
                ELSE
                    NULL
            END                AS status,
            iop.org_organizationcode,
            iop.org_organizationcode AS orgcode,
            nvl(ms.origquantity,ms.startquantity)
        FROM
            TERMSC_SUPPLIES_DATA      ms,
            TERMSC_SYSTEM_ITEMS   	  msi,
            TERDTP_MSC_PARAMETERS     mp,
            TERDTP_RR_ORGCODE 		  iop,
            TERFND_CMNLKP_VAUES       cmn_lkp
        WHERE
                ms.plan_id <> - 1
            AND ms.ordertype IN ( 1, 2, 3, 5, 94 )
            AND ms.FIRMTYPE = 1
            AND ms.inventory_item_id = msi.inventory_item_id
            AND ms.organization_id = msi.organization_id
            and ms.plan_id = msi.plan_id
            AND PLANNING_MAKE_BUY_CODE = cmn_lkp.lookupcode
            AND cmn_lkp.lookuptype = 'EGP_PLANNING_MAKE_BUY'
            AND ms.organization_id = mp.organization_id
            AND mp.organization_code = iop.org_organizationcode)
            WHERE status is not null
         order by ordertype, ordernumber asc;
    EXCEPTION WHEN OTHERS THEN
            gv_error := SUBSTR(SQLERRM,1,250);
            INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'Insertion','TERDTP_SCHRECEIPTS_TRNSFM_PRC - Transformation of data','ERROR',gv_error);
            COMMIT;
    END;
    
    -- Display the number of records fetched
    DBMS_OUTPUT.PUT_LINE('Records fetched: ' || lv_sr_tbl.COUNT);

    IF lv_sr_tbl.COUNT > 0 THEN
        FORALL i IN lv_sr_tbl.FIRST .. lv_sr_tbl.LAST
            INSERT INTO TERDTP_RR_SCHRECEIPTS_STG(
            ORDER_TYPE		   ,
            ORDER_NUMBER       ,
            PURCH_LINE_NUM     ,
            ITEM_NAME          ,
            NEW_SCHEDULE_DATE  ,
            NEW_ORDER_QUANTITY ,
            ORDER_STATUS       ,
            ORG_CODE           ,
            ORGANIZATION_CODE  ,
            ORIGINAL_QTY 
            )
            VALUES(
            lv_sr_tbl(i).ORDER_TYPE		    ,
            lv_sr_tbl(i).ORDER_NUMBER       ,
            lv_sr_tbl(i).PURCH_LINE_NUM     ,
            lv_sr_tbl(i).ITEM_NAME          ,
            lv_sr_tbl(i).NEW_SCHEDULE_DATE  ,
            lv_sr_tbl(i).NEW_ORDER_QUANTITY ,
            lv_sr_tbl(i).ORDER_STATUS       ,
            lv_sr_tbl(i).ORG_CODE           ,
            lv_sr_tbl(i).ORGANIZATION_CODE  ,
            lv_sr_tbl(i).ORIGINAL_QTY       
            );
    
    DBMS_OUTPUT.PUT_LINE('Records inserted: ' || SQL%ROWCOUNT);
        l_cnt := SQL%ROWCOUNT;
        COMMIT;

        IF (lv_sr_tbl.COUNT = l_cnt) THEN
            DBMS_OUTPUT.PUT_LINE('Success. ');
            
