PROCEDURE TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC (
    p_date    IN  VARCHAR2,
    p_rec_cnt OUT NUMBER
)
AS
    l_cnt NUMBER := 0;
    
    TYPE TERDTP_SHIPHIST_OBJ IS RECORD (
        CUSTOMER_ID      NUMBER,
        CUSTOMER_NAME    VARCHAR2(2000),
        PART_NAME        VARCHAR2(2000),
        SITE_VALUE       VARCHAR2(2000),
        ACTUAL_SHIP_DATE VARCHAR2(2000),
        QUANTITY         NUMBER,
        REQUEST_DATE     VARCHAR2(2000),
        ORDER_ID         VARCHAR2(2000),
        LINE_NUM         VARCHAR2(2000),
        --ORDER_SITE       VARCHAR2(2000),
        UNIT_PRICE       NUMBER,
        U_DEMAND_CLASS   VARCHAR2(2000),
        UNIT_COST        NUMBER
    );

    TYPE TERDTP_SHIPHIST_TAB IS TABLE OF TERDTP_SHIPHIST_OBJ;

    lv_shiphist_tbl TERDTP_SHIPHIST_TAB;

BEGIN

    -- -----------------------------------------------------------------------
    -- Step 1 : Purge staging tables
    -- -----------------------------------------------------------------------
    BEGIN
        DELETE FROM TERMSC_ANALYTIC_CUST_FLAT_V_DYD;
        DELETE FROM TEROM_FFILL_LINES;
     --   DELETE FROM TERDTP_CST_STD_COSTS_STG;
        DELETE FROM TERDTP_RR_SHIPHISTORY_STG;
        DELETE FROM TERDTP_HEADERS_ALL;
        COMMIT;
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM, 1, 250);
        INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
        VALUES (p_date, 'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - Deletion', 'ERROR', gv_error);
        COMMIT;
    END;

    -- -----------------------------------------------------------------------
    -- Step 2a : Load MSC_DEMANDS BIP extract
    --           (TERDTP_MSC_DEMANDS may be shared; skip purge if shared)
    -- -----------------------------------------------------------------------
    BEGIN
        DELETE FROM TERDTP_MSC_DEMANDS;
        COMMIT;
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM, 1, 250);
        INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
        VALUES (p_date, 'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - Delete MSC_DEMANDS', 'ERROR', gv_error);
        COMMIT;
    END;

    BEGIN
        DBMS_CLOUD.COPY_DATA(
            table_name      => 'TERDTP_MSC_DEMANDS',
            credential_name => 'TER_FUSION_INT_TO_TEREXT',
            file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date ||'/*DemandPlanningBIP*.csv',
            format => JSON_OBJECT(
                'delimiter'       VALUE ',',
                'skipheaders'     VALUE '1',
                'timestampformat' VALUE 'YYYY-MM-DD HH24:MI:SS.FF6',
                'removequotes'    VALUE 'true'
            )
        );
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM, 1, 250);
        INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, FILE_NAME, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
        VALUES (p_date, 'shipHistoryDemandBIP',
                'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - COPY_DATA MSC_DEMANDS', 'ERROR', gv_error);
        COMMIT;
    END;
    
    BEGIN
        DBMS_CLOUD.COPY_DATA(
            table_name      => 'TERDTP_HEADERS_ALL',
            credential_name => 'TER_FUSION_INT_TO_TEREXT',
            file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date ||'/*terdtp_Header_datat*.csv',
            format => JSON_OBJECT(
                'delimiter'       VALUE ',',
                'skipheaders'     VALUE '1',
                'timestampformat' VALUE 'YYYY-MM-DD HH24:MI:SS.FF6',
                'removequotes'    VALUE 'true'
            )
        );
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM, 1, 250);
        INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, FILE_NAME, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
        VALUES (p_date, 'shipHistoryDemandBIP',
                'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - COPY_DATA MSC_DEMANDS', 'ERROR', gv_error);
        COMMIT;
    END;

    BEGIN
        DBMS_CLOUD.COPY_DATA(
            table_name      => 'TERMSC_ANALYTIC_CUST_FLAT_V_DYD',
            credential_name => 'TER_FUSION_INT_TO_TEREXT',
            file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'|| p_date || '/*file_fscmtopmodelam_mscanalyticstopam_planningcustomerpvo*.csv',
            format => JSON_OBJECT(
                'delimiter'       VALUE ',',
                'skipheaders'     VALUE '1',
                'timestampformat' VALUE 'YYYY-MM-DD HH24:MI:SS.FF6',
                'removequotes'    VALUE 'true'
            )
        );
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM, 1, 250);
        INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, FILE_NAME, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
        VALUES (p_date, 'analyticalCustFlatBIP',
                'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - COPY_DATA CUST_FLAT', 'ERROR', gv_error);
        COMMIT;
    END;

    BEGIN
        DBMS_CLOUD.COPY_DATA(
            table_name      => 'TEROM_FFILL_LINES',
            credential_name => 'TER_FUSION_INT_TO_TEREXT',
            file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'
                               || p_date || '/*file_fscmtopmodelam_dootopam_fulfillline*.csv',
            format => JSON_OBJECT(
                'delimiter'       VALUE ',',
                'skipheaders'     VALUE '1',
                'timestampformat' VALUE 'YYYY-MM-DD HH24:MI:SS.FF6',
                'removequotes'    VALUE 'true'
            )
        );
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM, 1, 250);
        INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, FILE_NAME, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
        VALUES (p_date, 'dooFulfillLinesBIP',
                'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - COPY_DATA DOO_FULFILL_LINES', 'ERROR', gv_error);
        COMMIT;
    END;
    BEGIN
    SELECT DISTINCT
       cust.CUSTOMERSPEOCUSTOMERID    AS customer_id,
       cust.CUSTOMERSPEOCUSTOMERNAME  AS customer_name,
       itm.ITEM_NAME           AS part_name,
       MAP.ORGANIZATION_CODE   AS site_value,
       TO_CHAR(TO_TIMESTAMP(ffl.ACTUAL_SHIP_DATE,'YYYY-MM-DD HH24:MI:SS:FF'),'YYYYMMDD') AS SHIPDATE,
       dem.COMPLETED_QUANTITY  AS quantity,
       dem.REQUEST_DATE   AS request_date,
       dem.SALES_ORDER_NUMBER  AS order_id,
       dem.SO_LINE_NUM         AS line_num,
      -- MAP.ORGANIZATION_CODE   AS order_site,
       dem.SELLING_PRICE       AS unit_price,
       dha.demandclasscodef  AS u_demand_class,
       cst.TOTALCOST          AS unit_cost  
BULK COLLECT INTO lv_shiphist_tbl
  FROM  TERDTP_MSC_DEMANDS dem,
       TERMSC_ANALYTIC_CUST_FLAT_V_DYD cust,
       TEROM_FFILL_LINES ffl,
       TERMSC_SYSTEM_ITEMS itm,
       TERMSC_STD_COSTS cst,
       TERDTP_MSC_PARAMETERS MAP,
       TERMSC_CSTINV_ORGS cinv,
        TERDTP_HEADERS_ALL dha,
       TERFND_CMNLKP_VAUES lkp
WHERE  dem.CUSTOMER_ID = cust.CUSTOMERSPEOCUSTOMERID(+)
AND    dem.SALES_ORDER_NUMBER = ffl.SOURCE_ORDER_NUMBER
AND    dem.SO_LINE_NUM = ffl.SO_LINE_NUM
AND    dem.INVENTORY_ITEM_ID = itm.INVENTORY_ITEM_ID
AND    dem.ORGANIZATION_ID = itm.ORGANIZATION_ID
AND    dem.ORGANIZATION_ID = MAP.ORGANIZATION_ID
AND    lkp.LOOKUPTYPE = 'TER_INT_RAPID_RESPONSE'
AND lkp.MEANING = MAP.ORGANIZATION_CODE
AND    ffl.INVENTORY_ITEM_ID = cst.INVENTORYITEMID(+)
AND    ffl.FULFILL_ORG_ID = cinv.invorgid(+)
AND   cinv.costorgid = cst.costorgid(+)
AND   SYSDATE BETWEEN CST.EFFECTIVESTARTDATE(+)  AND CST.EFFECTIVEENDDATE(+)
AND    CST.STATUSCODE(+)='PUBLISHED'
 AND NVL(dem.COMPLETED_QUANTITY, 0) > 0
 AND FFL.FULLFILL_HEADER_ID=DHA.HEADERID
 AND FFL.SOURCE_ORDER_NUMBER=DHA.ORDERNUMBER(+)
AND ffl.ACTUAL_SHIP_DATE >= TO_CHAR(TO_TIMESTAMP('20260401','YYYY-MM-DD')-7, 'YYYY-MM-DD') 
and dem.plan_id=-1
ORDER BY order_id, line_num;

    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM, 1, 250);
        INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
        VALUES (p_date, 'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - Data Transformation', 'ERROR', gv_error);
        COMMIT;
    END;

    DBMS_OUTPUT.PUT_LINE('Records fetched: ' || lv_shiphist_tbl.COUNT);
    -- -----------------------------------------------------------------------
    -- Step 4 : FORALL INSERT into output staging table
    -- -----------------------------------------------------------------------
    IF lv_shiphist_tbl.COUNT > 0 THEN

        FORALL i IN lv_shiphist_tbl.FIRST .. lv_shiphist_tbl.LAST
            INSERT INTO TERDTP_RR_SHIPHISTORY_STG (
                CUSTOMER_ID,
                CUSTOMER_NAME,
                PART_NAME,
                SITE_VALUE,
                ACTUAL_SHIP_DATE,
                QUANTITY,
                REQUEST_DATE,
                ORDER_ID,
                LINE_NUM,
                --ORDER_SITE,
                UNIT_PRICE,
                U_DEMAND_CLASS,
                UNIT_COST
            ) VALUES (
                lv_shiphist_tbl(i).CUSTOMER_ID,
                lv_shiphist_tbl(i).CUSTOMER_NAME,
                lv_shiphist_tbl(i).PART_NAME,
                lv_shiphist_tbl(i).SITE_VALUE,
                lv_shiphist_tbl(i).ACTUAL_SHIP_DATE,
                lv_shiphist_tbl(i).QUANTITY,
                lv_shiphist_tbl(i).REQUEST_DATE,
                lv_shiphist_tbl(i).ORDER_ID,
                lv_shiphist_tbl(i).LINE_NUM,
               -- lv_shiphist_tbl(i).ORDER_SITE,
                lv_shiphist_tbl(i).UNIT_PRICE,
                lv_shiphist_tbl(i).U_DEMAND_CLASS,
                lv_shiphist_tbl(i).UNIT_COST
            );
        DBMS_OUTPUT.PUT_LINE('Records inserted: ' || SQL%ROWCOUNT);
        l_cnt := SQL%ROWCOUNT;
        COMMIT;

        IF (lv_shiphist_tbl.COUNT = l_cnt) THEN
            DBMS_OUTPUT.PUT_LINE('Success.');
            -- -----------------------------------------------------------------
            -- Step 5 : Export pipe-delimited output file to Object Storage
            --          File name: OF_HistoricalDemandActual.csv
            -- -----------------------------------------------------------------
            BEGIN
                DBMS_CLOUD.EXPORT_DATA(
                    credential_name => 'TER_FUSION_INT_TO_TEREXT',
                    file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Outbound/'
                                       || p_date || '/OF_HistoricalDemandActual.csv',
                    query           => 'SELECT * FROM TERDTP_RR_SHIPHISTORY_STG ORDER BY ORDER_ID, LINE_NUM',
                    format => JSON_OBJECT(
                        'type'        VALUE 'csv',
                        'delimiter'   VALUE '|',
                        'maxfilesize' VALUE '1048576000'
                    )
                );
            EXCEPTION WHEN OTHERS THEN
                gv_error := SUBSTR(SQLERRM, 1, 250);
                INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, FILE_NAME, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
                VALUES (p_date, 'OF_HistoricalDemandActual',
                        'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - EXPORT_DATA', 'ERROR', gv_error);
                COMMIT;
            END;
            -- -----------------------------------------------------------------
            -- Step 6a : Archive MSC_DEMANDS source files
            -- -----------------------------------------------------------------
            
            BEGIN
                DBMS_CLOUD.BULK_MOVE(
                    source_credential_name => 'TER_FUSION_INT_TO_TEREXT',
                    source_location_uri    => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'
                                              || p_date ||'/*DemandPlanningBIP*.csv',
                    target_credential_name => 'TER_FUSION_INT_TO_TEREXT',
                    target_location_uri    => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Archive/'
                                              || p_date || '/',
                    format => JSON_OBJECT('logretention' VALUE 7, 'logprefix' VALUE 'BULKOP')
                );
            EXCEPTION WHEN OTHERS THEN
                gv_error := SUBSTR(SQLERRM, 1, 250);
                INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, FILE_NAME, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
                VALUES (p_date, 'DemandPlanningBIP',
                        'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - Archive Processed Files', 'ERROR', gv_error);
                COMMIT;
            END;
            -- -----------------------------------------------------------------
            -- Step 6b : Archive Customer flat source files
            -- -----------------------------------------------------------------
            BEGIN
                DBMS_CLOUD.BULK_MOVE(
                    source_credential_name => 'TER_FUSION_INT_TO_TEREXT',
                    source_location_uri    => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'
                                              || p_date || '/*file_fscmtopmodelam_mscanalyticstopam_planningcustomerpvo*.csv',
                    target_credential_name => 'TER_FUSION_INT_TO_TEREXT',
                    target_location_uri    => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Archive/'
                                              || p_date || '/',
                    format => JSON_OBJECT('logretention' VALUE 7, 'logprefix' VALUE 'BULKOP')
                );
            EXCEPTION WHEN OTHERS THEN
                gv_error := SUBSTR(SQLERRM, 1, 250);
                INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, FILE_NAME, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
                VALUES (p_date, 'file_fscmtopmodelam_mscanalyticstopam_planningcustomerpvo',
                        'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - Archive Processed Files', 'ERROR', gv_error);
                COMMIT;
            END;
            -- -----------------------------------------------------------------
            -- Step 6c : Archive DOO Fulfill Lines source files
            -- -----------------------------------------------------------------
            BEGIN
                DBMS_CLOUD.BULK_MOVE(
                    source_credential_name => 'TER_FUSION_INT_TO_TEREXT',
                    source_location_uri    => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'
                                              || p_date || '/*file_fscmtopmodelam_dootopam_fulfillline*.csv',
                    target_credential_name => 'TER_FUSION_INT_TO_TEREXT',
                    target_location_uri    => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Archive/'
                                              || p_date || '/',
                    format => JSON_OBJECT('logretention' VALUE 7, 'logprefix' VALUE 'BULKOP')
                );
            EXCEPTION WHEN OTHERS THEN
                gv_error := SUBSTR(SQLERRM, 1, 250);
                INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, FILE_NAME, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
                VALUES (p_date, 'file_fscmtopmodelam_dootopam_fulfillline',
                        'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - Archive Processed Files', 'ERROR', gv_error);
                COMMIT;
            END;
            
        ELSE
            DBMS_OUTPUT.PUT_LINE('Check the error logs.');
            gv_error := 'Record count mismatch: fetched=' || lv_shiphist_tbl.COUNT || ' inserted=' || l_cnt;
            INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
            VALUES (p_date,
                    'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - Record Count Mismatch', 'ERROR', gv_error);
            COMMIT;
        END IF;
    ELSE
        DBMS_OUTPUT.PUT_LINE('No records found for the previous week. Check source data.');
        gv_error := 'No records extracted for run date: ' || p_date;
        INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
        VALUES (p_date,
                'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - No Records Found', 'WARNING', gv_error);
        COMMIT;
    END IF;
   p_rec_cnt := l_cnt;
EXCEPTION WHEN OTHERS THEN
    gv_error := SUBSTR(SQLERRM, 1, 250);
    INSERT INTO TERDTP_ERRORDTL_STG (RUN_DATE, MSG_STAGE, MESSAGE_TYPE, MSG_TEXT)
    VALUES (p_date, 'TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC - Unknown Error', 'ERROR', gv_error);
    COMMIT;
END TERDTP_INT147_SHIPHISTORY_TRNSFM_PRC;


PROCEDURE TERDTP_PLANORDER_TRNSFM_PRC (
        p_date                      IN VARCHAR2,
        p_rec_cnt                   OUT NUMBER
        ) 
AS
l_cnt NUMBER := 0;

 TYPE TERDTP_PLANORDR_OBJ IS RECORD (
    ORGANIZATION_CODE           VARCHAR2(2000),
    ITEM_NAME                   VARCHAR2(2000),
    NEW_WIP_START_DATE          VARCHAR2(2000),
    NEED_BY_DATE                VARCHAR2(2000),
    NEW_ORDER_QUANTITY          NUMBER
 );

 TYPE TERDTP_PLANORDR_TAB IS TABLE OF TERDTP_PLANORDR_OBJ;

 lv_planordr_tbl  TERDTP_PLANORDR_TAB;
BEGIN

    BEGIN
        delete from TERDTP_RR_PLANORDER_STG;
        commit;
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_PLANORDER_TRNSFM_PRC- Deletion','ERROR',gv_error);
        COMMIT;
    END;
    
    
    BEGIN
        SELECT 
            mp.organization_code,
            msi.item_name,
            ms.new_wip_start_date,
            ms.need_by_date,
            ms.startquantity
        BULK COLLECT INTO lv_planordr_tbl
        FROM
            termsc_supplies_data  ms,
            termsc_system_items   msi,
            terdtp_msc_parameters mp
        WHERE
                ms.inventory_item_id = msi.inventory_item_id
            AND ms.organization_id = msi.organization_id
            AND ms.plan_id = msi.plan_id
            AND msi.organization_id = mp.organization_id
            AND ms.plan_id <> - 1
            AND ms.ordertype = 5
            AND ms.firmtype = 2
            order by mp.organization_code, msi.item_name asc;
    EXCEPTION WHEN OTHERS THEN
            gv_error := SUBSTR(SQLERRM,1,250);
            INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'Insertion','TERDTP_PLANORDER_TRNSFM_PRC - Transformation of data','ERROR',gv_error);
            COMMIT;
    END;
    
    -- Display the number of records fetched
    DBMS_OUTPUT.PUT_LINE('Records fetched: ' || lv_planordr_tbl.COUNT);

    IF lv_planordr_tbl.COUNT > 0 THEN
        FORALL i IN lv_planordr_tbl.FIRST .. lv_planordr_tbl.LAST
            INSERT INTO TERDTP_RR_PLANORDER_STG(
            ORGANIZATION_CODE  ,
            ITEM_NAME          ,
            NEW_WIP_START_DATE ,
            NEED_BY_DATE       ,
            NEW_ORDER_QUANTITY 
            )
            VALUES(
            lv_planordr_tbl(i).ORGANIZATION_CODE  ,
            lv_planordr_tbl(i).ITEM_NAME          ,
            lv_planordr_tbl(i).NEW_WIP_START_DATE ,
            lv_planordr_tbl(i).NEED_BY_DATE       ,
            lv_planordr_tbl(i).NEW_ORDER_QUANTITY 
            );
    
    DBMS_OUTPUT.PUT_LINE('Records inserted: ' || SQL%ROWCOUNT);
        l_cnt := SQL%ROWCOUNT;
        COMMIT;

        IF (lv_planordr_tbl.COUNT = l_cnt) THEN
            DBMS_OUTPUT.PUT_LINE('Success. ');
                       
        ELSE
            DBMS_OUTPUT.PUT_LINE('Check the error logs. ');
            gv_error := SUBSTR(SQLERRM,1,250);
            INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'TERDTP_PLANORDER_TRNSFM_PRC - No records found to insert','ERROR',gv_error);
            COMMIT;
        END IF;
        
    END IF;
    p_rec_cnt := l_cnt;
 
    
    BEGIN
      DBMS_CLOUD.EXPORT_DATA(
        credential_name => 'TER_FUSION_INT_TO_TEREXT',
        file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Outbound/'|| p_date||'/OF_BaselinePlannedOrder.csv',
        query           => 'SELECT * FROM TERDTP_RR_PLANORDER_STG',
        format          => JSON_OBJECT('type' value 'csv','delimiter' value '|','maxfilesize' value '1048576000'));
    EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'OF_BaselinePlannedOrder','TERDTP_PLANORDER_TRNSFM_PRC - EXPORT_DATA','ERROR',gv_error);
        COMMIT;
    END;
    
EXCEPTION WHEN OTHERS THEN
        gv_error := SUBSTR(SQLERRM,1,250);
        INSERT INTO TERDTP_ERRORDTL_STG(RUN_DATE,FILE_NAME,MSG_STAGE,MESSAGE_TYPE,MSG_TEXT) VALUES(p_date,'OF_BaselinePlannedOrder','TERDTP_PLANORDER_TRNSFM_PRC - EXPORT_DATA','ERROR',gv_error);
        COMMIT;
END TERDTP_PLANORDER_TRNSFM_PRC;

PROCEDURE SLOTPLANNING_VALIDATION(
        p_date                      IN VARCHAR2
       
        ) 
AS
BEGIN
delete from TERSLOT_CATRGORY_DATA;
delete from TERSLOT_PARTY_SITES;
delete from TERSLOT_EGP_ASSIGNMENT;
commit;
    BEGIN  
       DBMS_CLOUD.COPY_DATA(   
         table_name      => 'TERSLOT_CATRGORY_DATA',  
         credential_name => 'TER_FUSION_INT_TO_TEREXT',   
         file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*file_fscmtopmodelam_catalogam_catalogcategoryassignp1*.csv',
         format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
         );
    EXCEPTION WHEN OTHERS THEN
        NULL;
    END;
    BEGIN
        DBMS_CLOUD.BULK_MOVE(      
          source_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
          source_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*file_fscmtopmodelam_catalogam_catalogcategoryassignp1*.csv',
          target_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
          target_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Archive/'||p_date||'/',
          format                  =>  JSON_OBJECT ('logretention' value 7, 'logprefix' value 'BULKOP')
          );
     EXCEPTION WHEN OTHERS THEN
         NULL;
     END;
    
    BEGIN  
       DBMS_CLOUD.COPY_DATA(   
          table_name      => 'TERSLOT_PARTY_SITES',  
          credential_name => 'TER_FUSION_INT_TO_TEREXT',   
          file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*file_fscmtopmodelam_finextractam_hzbiccextractam_partysiteextractpvo*.csv',
          format => json_object('delimiter' value ',', 'skipheaders' value '1', 'timestampformat' value 'YYYY-MM-DD HH24:MI:SS.FF6', 'removequotes' value 'true')   
       );
     EXCEPTION WHEN OTHERS THEN
    DBMS_OUTPUT.PUT_LINE(SUBSTR(SQLERRM,1,250));
            
     END;
     
    BEGIN
                DBMS_CLOUD.BULK_MOVE(      
                      source_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      source_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*file_fscmtopmodelam_finextractam_hzbiccextractam_partysiteextractpvo*.csv',
                      target_credential_name  => 'TER_FUSION_INT_TO_TEREXT',
                      target_location_uri     => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Archive/'||p_date||'/',
                      format                  =>  JSON_OBJECT ('logretention' value 7, 'logprefix' value 'BULKOP')
                );
    EXCEPTION WHEN OTHERS THEN
         NULL;
    END;
    
    BEGIN  
       DBMS_CLOUD.COPY_DATA(   
          table_name      => 'TERSLOT_EGP_ASSIGNMENT',  
          credential_name => 'TER_FUSION_INT_TO_TEREXT',   
          file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/idzdhlnqyhdp/b/fusion-pass-app-dev-bucket/o/Rapid_Response/Stage/'||p_date||'/*file_fscmtopmodelam_scmextractam_egpbiccextractam_itemcatassignmentsextractpvo*.csv',
