--  DDL for Package Body TEREPM_FX_EXCHANGERATES_PERIODNAME_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TEREPM_FX_EXCHANGERATES_PERIODNAME_PKG" AS

  PROCEDURE FIND_PERIOD_NAME(P_OUT OUT VARCHAR2) AS
  BEGIN
    -- TODO: Implementation required for PROCEDURE TEREPM_FX_EXCHANGERATES_PERIODNAME_PKG.FIND_PERIOD_NAME
    WITH cur_period AS (
  SELECT MAX(p.start_date) AS start_date
  FROM   gl_periods p
  WHERE  p.period_set_name = 'Terayne_445'
    AND  TRUNC(SYSDATE) BETWEEN p.start_date AND p.end_date
),
prev_period AS (
  SELECT p.period_name
  FROM   gl_periods p
  CROSS JOIN cur_period c
  WHERE  p.period_set_name = 'Terayne_445'
    AND  p.end_date = (
      SELECT MAX(p2.end_date)
      FROM   gl_periods p2
      WHERE  p2.period_set_name = 'Terayne_445'
        AND  p2.end_date < c.start_date
    )
)
SELECT TO_CHAR(
         TO_DATE(
           LPAD(SUBSTR(period_name, 1, INSTR(period_name, '-') - 1), 2, '0')
           || '-' ||
           SUBSTR(period_name, INSTR(period_name, '-') + 1),
           'MM-RR'
         ),
         'fmMon-RR',
         'NLS_DATE_LANGUAGE=ENGLISH'
       ) AS period_name_mon_yy INTO P_0UT
FROM prev_period;
  END FIND_PERIOD_NAME;

END TEREPM_FX_EXCHANGERATES_PERIODNAME_PKG;

