  PROCEDURE TEREPM_DERIVE_PERIOD_PRC(
                P_INPUT_STRING IN VARCHAR2,
                P_PERIOD_NAME OUT VARCHAR2
                ) AS
  BEGIN
    -- TODO: Implementation required for PROCEDURE TEREPM_SUCCESSFACTOR_TO_EPBCS_PKG.TEREPM_DERIVE_PERIOD_PRC
    SELECT TO_CHAR(
             TO_DATE(P_INPUT_STRING, 'MMDDYYYY'),
             'Mon-YY',
             'NLS_DATE_LANGUAGE=ENGLISH'
           )
      INTO P_PERIOD_NAME
      FROM dual;

  END TEREPM_DERIVE_PERIOD_PRC;

END TEREPM_SUCCESSFACTOR_TO_EPBCS_PKG;

