--  DDL for Package Body TEREXT_COMMON_ATTACHMENT_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TEREXT_COMMON_ATTACHMENT_PKG" 
IS
   PROCEDURE upload_doc (p_attachment_name IN VARCHAR2
                        ,p_attachment_category IN VARCHAR2
                        ,p_attachment_file IN BLOB
                        ,p_id  IN NUMBER
                        ,p_part_number    IN VARCHAR2
                        ,p_source IN VARCHAR2
                        ,p_config_num IN VARCHAR2)
   IS
      l_seq_id   NUMBER := TEREXT_ATTACHMENT_SEQ.NEXTVAL;
   BEGIN
      INSERT INTO terext_common_attachment (attachment_id
                                 ,attachment_name
                                 ,attachment_category
                                 ,attachment_file
                                 ,id
                                 ,part_number
                                 ,source
                                 ,config_num
                                 ,created_by
                                 ,creation_date
                                 ,last_updated_by
                                 ,last_update_date)
           VALUES (l_seq_id                                                                                                    --document_id
                  ,p_attachment_name                                                                                           --document_name
                  ,p_attachment_category                                                                                   --document_category
                  ,p_attachment_file                                                                                           --document_type
                  ,p_id                                                                                               --description
                  ,p_part_number                                                                                          --document_file
                  ,p_source
                  ,p_config_num
                  ,-1                                                                                                --created_by
                  ,SYSDATE                                                                                                   --creation_date
                  ,-1                                                                                           --last_updated_by
                  ,SYSDATE                                                                                                --last_update_date
                  );

      COMMIT;


      apex_json.open_object;
      apex_json.write ('p_primarykey'
                      ,l_seq_id);
      apex_json.write ('p_err_msg'
                      ,'File Uploaded Successfully');
      apex_json.write ('p_status'
                      ,'S');
      apex_json.close_object;
   EXCEPTION
      WHEN OTHERS THEN
         DBMS_OUTPUT.put_line ('Error > ' || SQLCODE || SQLERRM);
         apex_json.open_object;
         apex_json.write ('p_err_code'
                         ,'E');
         apex_json.write ('p_err_msg'
                         ,'API Error - ' || SQLERRM);
         apex_json.write ('p_primarykey'
                         ,l_seq_id);
         apex_json.close_object;
   END upload_doc;

END TEREXT_COMMON_ATTACHMENT_PKG;

