--  DDL for Package Body TEREXT_OM_REST_SERVICE_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TEREXT_OM_REST_SERVICE_PKG" 
is 
	procedure get_url
	is 
	begin
		g_url :='https://terfusionapp-icbkjb-dev1.fa.ocs.oraclecloud.com';
		/*select tlv.description
		  into g_rr_url
		  from tereo_lookup_types tlt,
			   tereo_lookup_value tlv 
		 where tlt.lookup_name ='RAPIDRESPONSE_SETUP'
		   and tlt.LOOKUP_ID = tlv.LOOKUP_ID
		   and tlv.enabled_flag ='Y'
		   and tlv.LOOKUP_VALUE = 'RR_URL_DEV';
		*/
	end get_url;
	
	procedure get_cred_web_service
	is 
	begin
		g_cred_web_service:='TER_SRV_ERP_CONVERSION';
		/*select tlv.description
		  into g_cred_rest_service
		  from tereo_lookup_types tlt,
			   tereo_lookup_value tlv 
		 where tlt.lookup_name ='RAPIDRESPONSE_SETUP'
		   and tlt.LOOKUP_ID = tlv.LOOKUP_ID
		   and tlv.enabled_flag ='Y'
		   and tlv.LOOKUP_VALUE = 'RR_CRED_REST_SERVICE';
		*/
	end get_cred_web_service;
	
	
	
	procedure get_sales_order
	is 
		l_error_message varchar2(4000);
		l_debug_message varchar2(240);
		l_procedure_name   varchar2(30) :='get_sales_order';
		l_clob clob;
		l_query_param varchar2(4000);
		l_count number;
		l_exists_count number;
		
		TYPE doo_headers_tab_type IS TABLE OF TEREXT_DOO_HEADERS%ROWTYPE INDEX BY BINARY_INTEGER;
		
		v_doo_headers_ins_tab_type doo_headers_tab_type;
		v_doo_headers_upd_tab_type doo_headers_tab_type;
		
		idx_ins BINARY_INTEGER := 0;
		idx_upd BINARY_INTEGER := 0;
		l_header_id number;
		
	begin 
		l_debug_message:=g_pkg_name||'.'||l_procedure_name||' Starts>>>>';
		
		/*apex_web_service.g_request_headers.DELETE;       -- Clear previous headers
		apex_web_service.g_request_headers (1).name := 'Content-Type';
		apex_web_service.g_request_headers (1).VALUE := 'application/vnd.oracle.adf.resourcecollection+json';*/
		
		apex_web_service.set_request_headers(
        p_name_01 => 'Content-Type',
        p_value_01 => 'application/json'
        );
		
		l_query_param:='';
		
		--dbms_output.put_line(g_url||g_om_api);
		--dbms_output.put_line(g_om_api);
		
		l_clob:=APEX_WEB_SERVICE.MAKE_REST_REQUEST (p_url 					=>g_url||g_om_api,
													p_http_method           => 'GET',  -- or 'POST', 'PUT', 'DELETE'
													p_credential_static_id  => g_cred_web_service,    -- if secured
													p_body                  =>null
													);
		
		dbms_output.put_line(apex_web_service.g_status_code);
		
		--dbms_output.put_line('get_plan:l_count->'||substr(l_clob,1,8000));
		
		APEX_JSON.PARSE(p_source => l_clob);
		
		l_count :=APEX_JSON.GET_COUNT(p_path => 'items');
		
		--dbms_output.put_line('l_count-> '||l_count);
		
		FOR i IN 1 .. l_count LOOP
            
            l_header_id:= APEX_JSON.get_varchar2('items[%d].HeaderId', i);
            
             select count(*)
              into l_exists_count
              from TEREXT_DOO_HEADERS 
             where header_id = l_header_id;
             
            If l_exists_count = 0
            then
             
                idx_ins:=idx_ins+1;                
                v_doo_headers_ins_tab_type(idx_ins).header_id :=l_header_id;
                v_doo_headers_ins_tab_type(idx_ins).ORDER_NUMBER :=APEX_JSON.get_varchar2('items[%d].OrderNumber', i);
                v_doo_headers_ins_tab_type(idx_ins).SOLD_TO_CUSTOMER_ID :=APEX_JSON.get_varchar2('items[%d].BuyingPartyId', i);
                v_doo_headers_ins_tab_type(idx_ins).CUSTOMER_PO_NUMBER :=APEX_JSON.get_varchar2('items[%d].CustomerPONumber', i);
                v_doo_headers_ins_tab_type(idx_ins).TRANSACTIONAL_CURRENCY_CODE :=APEX_JSON.get_varchar2('items[%d].TransactionalCurrencyCode', i);
                v_doo_headers_ins_tab_type(idx_ins).CERATED_BY :=-1;
                v_doo_headers_ins_tab_type(idx_ins).CREATION_DATE :=sysdate;
                v_doo_headers_ins_tab_type(idx_ins).LAST_UPDATE_BY :=-1;
                v_doo_headers_ins_tab_type(idx_ins).LAST_UPDATED_DATE :=sysdate;
                v_doo_headers_ins_tab_type(idx_ins).LAST_UDATE_LOGIN_ID :=-1;
            else 
                idx_upd:=idx_upd+1;                
                v_doo_headers_upd_tab_type(idx_upd).header_id :=l_header_id;
                v_doo_headers_upd_tab_type(idx_upd).ORDER_NUMBER :=APEX_JSON.get_varchar2('items[%d].OrderNumber', i);
                v_doo_headers_upd_tab_type(idx_upd).SOLD_TO_CUSTOMER_ID :=APEX_JSON.get_varchar2('items[%d].BuyingPartyId', i);
                v_doo_headers_upd_tab_type(idx_upd).CUSTOMER_PO_NUMBER :=APEX_JSON.get_varchar2('items[%d].CustomerPONumber', i);
                v_doo_headers_upd_tab_type(idx_upd).TRANSACTIONAL_CURRENCY_CODE :=APEX_JSON.get_varchar2('items[%d].TransactionalCurrencyCode', i);
                --v_doo_headers_upd_tab_type(idx_upd).CERATED_BY :=-1;
                --v_doo_headers_upd_tab_type(idx_upd).CREATION_DATE :=sysdate;
                v_doo_headers_upd_tab_type(idx_upd).LAST_UPDATE_BY :=-1;
                v_doo_headers_upd_tab_type(idx_upd).LAST_UPDATED_DATE :=sysdate;
                v_doo_headers_upd_tab_type(idx_upd).LAST_UDATE_LOGIN_ID :=-1;
            end if;
            
		END LOOP;
		
		dbms_output.put_line('Ins Array Count-> '||v_doo_headers_ins_tab_type.count);
		
		FORALL i IN v_doo_headers_ins_tab_type.FIRST..v_doo_headers_ins_tab_type.LAST
            INSERT INTO TEREXT_DOO_HEADERS VALUES v_doo_headers_ins_tab_type(i);
		
		dbms_output.put_line('Upd Array Count-> '||v_doo_headers_upd_tab_type.count);
		
		FORALL i IN v_doo_headers_upd_tab_type.FIRST..v_doo_headers_upd_tab_type.LAST
            UPDATE TEREXT_DOO_HEADERS 
               set ORDER_NUMBER = v_doo_headers_upd_tab_type(i).ORDER_NUMBER,
                   SOLD_TO_CUSTOMER_ID=v_doo_headers_upd_tab_type(i).SOLD_TO_CUSTOMER_ID,
                   CUSTOMER_PO_NUMBER=v_doo_headers_upd_tab_type(i).CUSTOMER_PO_NUMBER,
                   TRANSACTIONAL_CURRENCY_CODE=v_doo_headers_upd_tab_type(i).TRANSACTIONAL_CURRENCY_CODE,
                   LAST_UPDATE_BY=v_doo_headers_upd_tab_type(i).LAST_UPDATE_BY,
                   LAST_UPDATED_DATE=v_doo_headers_upd_tab_type(i).LAST_UPDATED_DATE,
                   LAST_UDATE_LOGIN_ID=v_doo_headers_upd_tab_type(i).LAST_UDATE_LOGIN_ID
             where header_id = v_doo_headers_upd_tab_type(i).header_id;
             
		
		
		
        commit;
		
		l_debug_message:=g_pkg_name||'.'||l_procedure_name||' end<<<<<<';
	exception 
	when others then 
		l_error_message :=substr(sqlerrm,1,3000)||'=>stage:'||l_debug_message;
		dbms_output.put_line(l_error_message);
	end get_sales_order;
	
	begin	
		get_url;
		get_cred_web_service;
		
end TEREXT_OM_REST_SERVICE_PKG;

