  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TERGL_11I_COA_TARGETMAP_PKG" AS   
FUNCTION get_target_coa_11i (
        p_in_coa IN VARCHAR2
        ) RETURN VARCHAR
IS 
l_tgt_coa VARCHAR2(1000);
BEGIN    
select target_segment INTO l_tgt_coa 
from SL_GL_CCID_MAPPING_STG where 1=1
and enable_flag='Y'
and coa_map_name='11i to Fusion'
and source_segment=p_in_coa
;
RETURN l_tgt_coa;
EXCEPTION
WHEN OTHERS THEN 
RETURN null;
end get_target_coa_11i;

PROCEDURE TERGL_11i_COA_TARGETMAP_PRC_V(
    p_batch_id  NUMBER,
    p_sub_batch_id NUMBER,
    p_map_name  VARCHAR2
)
IS
CURSOR get_11i_raw_stg IS 
select rowid row_id,
source_segment1,
source_segment2,
source_segment3,
source_segment4,
source_segment5,
source_segment6,
source_segment7,
source_segment8,
source_segment9,
source_segment10
--, source_segment1||'.' ||source_segment2||'.'||source_segment3||'.'||source_segment4||'.'||source_segment5||'.....' legacy_coa
, get_target_coa_11i(source_segment1||'.' ||source_segment2||'.'||source_segment3||'.'||source_segment4||'.'||source_segment5||'.'||source_segment6||'.'||source_segment7||'.'||source_segment8||'.'||source_segment9||'.'||source_segment10) target_coa
from TER_RTR_ORACLE_11I_RAW_STG 
where batch_id=p_batch_id
and sub_batch_id=p_sub_batch_id
and status_code='NEW'
;

TYPE typ_11i_raw_stg_details IS TABLE OF get_11i_raw_stg%rowtype INDEX BY BINARY_INTEGER;
tab_11i_raw_stg_details    typ_11i_raw_stg_details;

l_target_coa VARCHAR2(1000);

BEGIN
        OPEN get_11i_raw_stg;
        LOOP 
        FETCH get_11i_raw_stg BULK COLLECT INTO tab_11i_raw_stg_details LIMIT 1000;
        EXIT WHEN tab_11i_raw_stg_details.COUNT = 0;
       -- CLOSE get_11i_raw_stg; 

        IF tab_11i_raw_stg_details.count > 0 THEN

         FORALL i IN tab_11i_raw_stg_details.first..tab_11i_raw_stg_details.last --SAVE EXCEPTIONS
                    UPDATE TER_RTR_ORACLE_11I_RAW_STG 
                        SET
                    TARGET_SEGMENT1  = REGEXP_SUBSTR(tab_11i_raw_stg_details(i).target_coa, '[^.]+',1),
                    TARGET_SEGMENT2  = REGEXP_SUBSTR(tab_11i_raw_stg_details(i).target_coa, '[^.]+',1,2),
                    TARGET_SEGMENT3  = REGEXP_SUBSTR(tab_11i_raw_stg_details(i).target_coa, '[^.]+',1,3),
                    TARGET_SEGMENT4  = REGEXP_SUBSTR(tab_11i_raw_stg_details(i).target_coa, '[^.]+',1,4),
                    TARGET_SEGMENT5  = REGEXP_SUBSTR(tab_11i_raw_stg_details(i).target_coa, '[^.]+',1,5),
                    TARGET_SEGMENT6  = REGEXP_SUBSTR(tab_11i_raw_stg_details(i).target_coa, '[^.]+',1,6),
                    TARGET_SEGMENT7  = REGEXP_SUBSTR(tab_11i_raw_stg_details(i).target_coa, '[^.]+',1,7),
                    TARGET_SEGMENT8  = REGEXP_SUBSTR(tab_11i_raw_stg_details(i).target_coa, '[^.]+',1,8),
                    TARGET_SEGMENT9  = REGEXP_SUBSTR(tab_11i_raw_stg_details(i).target_coa, '[^.]+',1,9),
                    TARGET_SEGMENT10 = REGEXP_SUBSTR(tab_11i_raw_stg_details(i).target_coa, '[^.]+',1,10)

                  WHERE batch_id = p_batch_id
                  AND sub_batch_id= p_sub_batch_id
                  AND rowid= tab_11i_raw_stg_details(i).row_id
                  ;



        END IF;

        END LOOP;
         CLOSE get_11i_raw_stg; 
        COMMIT;

EXCEPTION 
WHEN OTHERS THEN 
ROLLBACK ;
null;
END;





END TERGL_11i_COA_TARGETMAP_PKG;

