        EXIT WHEN tab_nav_raw_stg_details.COUNT = 0;
       -- CLOSE get_ax_raw_stg; 

        IF tab_nav_raw_stg_details.count > 0 THEN

         FORALL i IN tab_nav_raw_stg_details.first..tab_nav_raw_stg_details.last --SAVE EXCEPTIONS
                    UPDATE TER_RTR_NAVISION_RAW_STG 
                        SET
                    TARGET_SEGMENT1  = REGEXP_SUBSTR(tab_nav_raw_stg_details(i).target_coa, '[^.]+',1),
                    TARGET_SEGMENT2  = REGEXP_SUBSTR(tab_nav_raw_stg_details(i).target_coa, '[^.]+',1,2),
                    TARGET_SEGMENT3  = REGEXP_SUBSTR(tab_nav_raw_stg_details(i).target_coa, '[^.]+',1,3),
                    TARGET_SEGMENT4  = REGEXP_SUBSTR(tab_nav_raw_stg_details(i).target_coa, '[^.]+',1,4),
                    TARGET_SEGMENT5  = REGEXP_SUBSTR(tab_nav_raw_stg_details(i).target_coa, '[^.]+',1,5),
                    TARGET_SEGMENT6  = REGEXP_SUBSTR(tab_nav_raw_stg_details(i).target_coa, '[^.]+',1,6),
                    TARGET_SEGMENT7  = REGEXP_SUBSTR(tab_nav_raw_stg_details(i).target_coa, '[^.]+',1,7),
                    TARGET_SEGMENT8  = REGEXP_SUBSTR(tab_nav_raw_stg_details(i).target_coa, '[^.]+',1,8),
                    TARGET_SEGMENT9  = REGEXP_SUBSTR(tab_nav_raw_stg_details(i).target_coa, '[^.]+',1,9),
                    TARGET_SEGMENT10 = REGEXP_SUBSTR(tab_nav_raw_stg_details(i).target_coa, '[^.]+',1,10)

                  WHERE batch_id = p_batch_id
                  AND sub_batch_id= p_sub_batch_id
                  AND rowid= tab_nav_raw_stg_details(i).row_id
                  ;



        END IF;

        END LOOP;
         CLOSE get_nav_raw_stg; 
        COMMIT;

EXCEPTION 
WHEN OTHERS THEN 
ROLLBACK ;
null;
END;


END TERGL_COA_TARGETMAP_PKG;

