  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TERHCM_WORKER_INBOUND_PKG" AS
/************************************************************************
  -- TER SuccessFactor/Thrive To Oracle Employee Inbound Utility Package Body
  -- Developer           : Vishnupriya 
  -- Description         : This Package Provide Utility to Employee Inbound Service. 
  -- 
  -- Modification History
  -- Name                  Date          Version      JIRA reference 
  -- --------------------  -----------   -----------  ---------------------------------------------
  -- Vishnupriya           05-11-2025    1.0          Intial Release
  ************************************************************************/
    PROCEDURE TERHCM_UPSERT_WORKERFILEMASTER_PRC (
        p_file_uid                   IN OUT NUMBER,
        p_file_path                  VARCHAR2,
        p_source_system              VARCHAR2,
        p_request_id                 NUMBER,
        p_ucm_content_id             VARCHAR2,
        p_imported_status            VARCHAR2,
        p_loaded_status              VARCHAR2,
        p_skipped_status             VARCHAR2,
        p_validated_status           VARCHAR2,
        p_import_lines_success_count NUMBER,
        p_import_lines_error_count   NUMBER,
        p_import_lines_total_count   NUMBER,
        p_import_success_count       NUMBER,
        p_import_error_count         NUMBER,
        p_line_held_count            NUMBER,
        p_line_loaded_count          NUMBER,
        p_line_unprocessed_count     NUMBER,
        p_line_error_count           NUMBER,
        p_unprocessed_count          NUMBER,
        p_validated_count            NUMBER,
        p_loaded_count               NUMBER,
        p_rollback_error_count       NUMBER,
        p_error_count                NUMBER,
        p_skipped_count              NUMBER,
        p_corrected_count            NUMBER
    ) AS
    BEGIN
        IF p_file_uid IS NULL THEN
            INSERT INTO TERHCM_WORKERFILEMASTER_SFTHRIVE_STG (
                file_path,
                source_system,
                file_date,
                request_id,
                ucm_content_id,
                imported_status,
                loaded_status,
                skipped_status,
                validated_status,
                import_lines_success_count,
                import_lines_error_count,
                import_lines_total_count,
                import_success_count,
                import_error_count,
                line_held_count,
                line_loaded_count,
                line_unprocessed_count,
                line_error_count,
                unprocessed_count,
                validated_count,
                loaded_count,
                rollback_error_count,
                error_count,
                skipped_count,
                corrected_count
            ) VALUES (
                p_file_path,
                p_source_system,
                sysdate,
                p_request_id,
                p_ucm_content_id,
                p_imported_status,
                p_loaded_status,
                p_skipped_status,
                p_validated_status,
                p_import_lines_success_count,
                p_import_lines_error_count,
                p_import_lines_total_count,
                p_import_success_count,
                p_import_error_count,
                p_line_held_count,
                p_line_loaded_count,
                p_line_unprocessed_count,
                p_line_error_count,
                p_unprocessed_count,
                p_validated_count,
                p_loaded_count,
                p_rollback_error_count,
                p_error_count,
                p_skipped_count,
                p_corrected_count
            ) RETURNING file_uid INTO p_file_uid;

        ELSE
            UPDATE TERHCM_WORKERFILEMASTER_SFTHRIVE_STG
            SET
                request_id = nvl(p_request_id, request_id),
                ucm_content_id = nvl(p_ucm_content_id, ucm_content_id),
                imported_status = nvl(p_imported_status, imported_status),
                loaded_status = nvl(p_loaded_status, loaded_status),
                skipped_status = nvl(p_skipped_status, skipped_status),
                validated_status = nvl(p_validated_status, validated_status),
                import_lines_success_count = nvl(p_import_lines_success_count, import_lines_success_count),
                import_lines_error_count = nvl(p_import_lines_error_count, import_lines_error_count),
                import_lines_total_count = nvl(p_import_lines_total_count, import_lines_total_count),
                import_success_count = nvl(p_import_success_count, import_success_count),
                import_error_count = nvl(p_import_error_count, import_error_count),
                line_held_count = nvl(p_line_held_count, line_held_count),
                line_loaded_count = nvl(p_line_loaded_count, line_loaded_count),
                line_unprocessed_count = nvl(p_line_unprocessed_count, line_unprocessed_count),
                line_error_count = nvl(p_line_error_count, line_error_count),
                unprocessed_count = nvl(p_unprocessed_count, unprocessed_count),
                validated_count = nvl(p_validated_count, validated_count),
                loaded_count = nvl(p_loaded_count, loaded_count),
                rollback_error_count = nvl(p_rollback_error_count, rollback_error_count),
                error_count = nvl(p_error_count, error_count),
                skipped_count = nvl(p_skipped_count, skipped_count),
                corrected_count = nvl(p_corrected_count, corrected_count)
            WHERE
                file_uid = p_file_uid;

        END IF;

        COMMIT;
    END;

    PROCEDURE TERHCM_INSERT_WORKEREMPRAW_PRC (
        p_employees TERHCM_WORKER_EMP_RAW_TAB
    ) AS
    BEGIN
        FOR i IN 1..p_employees.count LOOP
            IF p_employees(i).raw_rec_uid IS NULL THEN
                INSERT INTO TERHCM_WORKEREMPRAW_SFTHRIVE_STG (
                    file_uid,
                    action_code,
                    person_number,
                    person_start_date,
                    person_effective_start_date,
                    email_address,
                    first_name,
                    middle_names,
                    last_name,
                    termination_date,
                    legal_employer_name,
                    cost_center,
                    assignment_effective_start_date,
                    grade_level,
                    job_code,
                    location_code,
                    department_code,
                    worker_type,
                    manager_person_number,
                    business_unit_code,
                    known_as,
                    mail_stop
                ) VALUES (
                    p_employees(i).file_uid,
                    p_employees(i).action_code,
                    p_employees(i).person_number,
                    p_employees(i).person_start_date,
                    p_employees(i).person_effective_start_date,
                    p_employees(i).email_address,
                    p_employees(i).first_name,
                    p_employees(i).middle_names,
                    p_employees(i).last_name,
                    p_employees(i).termination_date,
                    p_employees(i).legal_employer_name,
                    p_employees(i).cost_center,
                    p_employees(i).assignment_effective_start_date,
                    p_employees(i).grade_level,
                    p_employees(i).job_code,
                    p_employees(i).location_code,
                    p_employees(i).department_code,
                    p_employees(i).worker_type,
                    p_employees(i).manager_person_number,
                    p_employees(i).business_unit_code,
                    p_employees(i).known_as,
                    p_employees(i).mail_stop
                );

            ELSE
                UPDATE TERHCM_WORKEREMPRAW_SFTHRIVE_STG
                SET
                    imported_status = p_employees(i).imported_status,
                    validated_loaded_status = p_employees(i).validated_loaded_status,
                    message_type = p_employees(i).message_type,
                    msg_text = p_employees(i).msg_text
                WHERE
                    raw_rec_uid = p_employees(i).raw_rec_uid;

            END IF;
        END LOOP;
    END;

      PROCEDURE TERHCM_UPDATE_WORKER_HDL_ALL_PRC (
        p_file_uid IN NUMBER
    ) AS
    BEGIN
    
        BEGIN
            UPDATE TERHCM_WORKEREMPRAW_SFTHRIVE_STG
            SET IMPORTED_STATUS = NULL, VALIDATED_LOADED_STATUS = NULL, MESSAGE_TYPE = NULL, MSG_TEXT = NULL
            WHERE file_uid = p_file_uid
            AND nvl(VALIDATED_LOADED_STATUS,'LOADED_ERROR') = 'LOADED_ERROR';
            
            IF (SQL%ROWCOUNT >= 1) THEN
                BEGIN
                    UPDATE TERHCM_WORKERFILEMASTER_SFTHRIVE_STG
                    SET IMPORTED_STATUS = NULL, LOADED_STATUS = NULL
                    WHERE file_uid = p_file_uid;
                    
                    COMMIT;
                EXCEPTION 
                    WHEN NO_DATA_FOUND THEN
                        NULL;
                    WHEN OTHERS THEN
                        NULL;
                END;
                BEGIN
                    DELETE FROM TERHCM_WORKER_HDL_SFTHRIVE_STG WHERE FILE_UID = p_file_uid;
                    DELETE FROM TERHCM_WORKER_NAME_SFTHRIVE_STG WHERE FILE_UID = p_file_uid;
                    DELETE FROM TERHCM_WORKER_EMAIL_SFTHRIVE_STG WHERE FILE_UID = p_file_uid;
                    DELETE FROM TERHCM_WORKER_REL_SFTHRIVE_STG WHERE FILE_UID = p_file_uid;
                    DELETE FROM TERHCM_WORKER_TERMS_SFTHRIVE_STG WHERE FILE_UID = p_file_uid;
                    DELETE FROM TERHCM_WORKER_ASG_SFTHRIVE_STG WHERE FILE_UID = p_file_uid;
                    DELETE FROM TERHCM_WORKER_ASG_SUP_SFTHRIVE_STG WHERE FILE_UID = p_file_uid;
                EXCEPTION 
                    WHEN NO_DATA_FOUND THEN
                        NULL;
                    WHEN OTHERS THEN
                        NULL;
                END;
            END IF;
        EXCEPTION 
            WHEN NO_DATA_FOUND THEN
                NULL;
            WHEN OTHERS THEN
                NULL;
        END;

    END;

