PROCEDURE TERHCM_SELECT_SUP_TERMS_PRC (
        p_file_uid       IN NUMBER,
        p_work_terms     OUT TERHCM_WORKER_TERMS_TAB
    ) AS
    BEGIN
        
        SELECT
            TERHCM_WORKER_TERMS_OBJ(file_uid, raw_rec_uid, worker_uid, worker_rel_uid, worker_term_uid,
                                                  action_code, source_system_owner, source_system_id, effective_start_date, effective_end_date
                                                  ,
                                                  effective_sequence, effective_latest_change, assignment_number, assignment_status_type_code
                                                  , business_unit_short_code,
                                                  period_of_service_id, legal_employer_name, system_person_type, reason_code, assignment_name
                                                  ,
                                                  person_type_code, assignment_type, notice_period, primary_work_terms_flag, freeze_start_date
                                                  ,
                                                  freeze_until_date, worker_type, date_start, mail_stop, source_ref_table_name, source_ref001,
                                                  source_ref002, source_ref003, source_ref004, source_ref005, source_ref006,
                                                  source_ref007, source_ref008, source_ref009, source_ref010)
        BULK COLLECT
        INTO p_work_terms
        FROM
            TERHCM_WORKER_TERMS_SFTHRIVE_STG t
        WHERE
            t.file_uid = p_file_uid
            AND EXISTS (
            SELECT
                'Y'
            FROM
                terhcm_workerempraw_sfthrive_stg e
            WHERE
                    t.file_uid = e.file_uid
                AND e.validated_loaded_status = 'LOADED_SUCCESS'
                AND t.SOURCE_SYSTEM_ID = 'TERM_' || e.person_number
        );

    END;
    
