    PROCEDURE TERHCM_VALIDATE_LEGAL_ENTITY_PRC (
        p_file_uid       IN NUMBER,
        p_legal_entities IN OUT TERHCM_GENERIC_VALIDATION_TAB,
        p_invalid_les    OUT VARCHAR2
    ) AS
    BEGIN
--        SELECT
--            LISTAGG(DISTINCT legal_employer_name, ',')
--        INTO p_invalid_les
--        FROM
        UPDATE TERHCM_WORKEREMPRAW_SFTHRIVE_STG
        SET
            imported_status = 'VALIDATION_FAILED_AT_OIC',
            message_type = 'INVALID_LE',
            msg_text = 'INVALID_LE'
        WHERE
                file_uid = p_file_uid
            AND imported_status IS NULL
            AND NOT EXISTS (
                SELECT
                    'Y'
                FROM
                    TABLE ( p_legal_entities ) jobs
                WHERE
                        1 = 1
                    AND condition_field1 = legal_employer_name
                    --AND TO_DATE(condition_field2, 'YYYY-MM-DD') >= TO_DATE(person_effective_start_date, 'YYYY/MM/DD')
                    --AND TO_DATE(condition_field3, 'YYYY-MM-DD') <= TO_DATE(person_effective_start_date, 'YYYY/MM/DD')
            );

        COMMIT;
    END;

    PROCEDURE TERHCM_VALIDATE_JOB_CODES_PRC (
        p_file_uid     IN NUMBER,
        p_jobs         IN OUT TERHCM_GENERIC_VALIDATION_TAB,
        p_invalid_jobs OUT VARCHAR2
    ) AS
    BEGIN
        UPDATE TERHCM_WORKEREMPRAW_SFTHRIVE_STG
        SET
            imported_status = 'VALIDATION_FAILED_AT_OIC',
            message_type = 'INVALID_JOB_LEVEL',
            msg_text = 'INVALID_JOB_LEVEL'
        WHERE
                file_uid = p_file_uid
            AND imported_status IS NULL
            AND NOT EXISTS (
                SELECT
                    'Y'
                FROM
                    TABLE ( p_jobs ) jobs
                WHERE
                        1 = 1
                    AND condition_field1 = job_code
                    AND TO_DATE(condition_field2, 'YYYY-MM-DD') <= TO_DATE(assignment_effective_start_date, 'YYYY/MM/DD')
                    AND TO_DATE(condition_field3, 'YYYY-MM-DD') >= TO_DATE(assignment_effective_start_date, 'YYYY/MM/DD')
            );

        COMMIT;
    END;

	PROCEDURE TERHCM_VALIDATE_DEPARTMENT_PRC (
        p_file_uid     IN NUMBER,
        p_dept         IN OUT TERHCM_GENERIC_VALIDATION_TAB,
        p_invalid_dept OUT VARCHAR2
    ) AS
    BEGIN
        UPDATE TERHCM_WORKEREMPRAW_SFTHRIVE_STG
        SET
            imported_status = 'VALIDATION_FAILED_AT_OIC',
            message_type = 'INVALID_DEPT',
            msg_text = 'INVALID_DEPT'
        WHERE
                file_uid = p_file_uid
            AND imported_status IS NULL
            AND NOT EXISTS (
                SELECT
                    'Y'
                FROM
                    TABLE ( p_dept ) dept
                WHERE
                        1 = 1
                    AND condition_field1 = department_code
                    AND TO_DATE(condition_field2, 'YYYY-MM-DD') <= TO_DATE(assignment_effective_start_date, 'YYYY/MM/DD')
                    AND TO_DATE(condition_field3, 'YYYY-MM-DD') >= TO_DATE(assignment_effective_start_date, 'YYYY/MM/DD')
            );

        COMMIT;
    END;

    PROCEDURE TERHCM_VALIDATE_LOC_PRC (
        p_file_uid     IN NUMBER,
        p_locations    IN OUT TERHCM_GENERIC_VALIDATION_TAB,
        p_invalid_locs OUT VARCHAR2
