            );

        COMMIT;
    END;

    PROCEDURE TERHCM_VALIDATE_COA_PRC (
        p_file_uid                    IN NUMBER,
        p_code_combinations           IN TERHCM_GENERIC_VALIDATION_TAB,
        p_le_bu_to_o_unit_acc_num_map IN TERHCM_GENERIC_VALIDATION_TAB,
        p_emp_expense_account_map     OUT TERHCM_GENERIC_VALIDATION_TAB,
        p_status                      OUT VARCHAR2
    ) AS
        l_def_exp_acc VARCHAR2(500);
    BEGIN
        p_emp_expense_account_map := TERHCM_GENERIC_VALIDATION_TAB();
        FOR rec IN (
            SELECT
                file_uid,
                raw_rec_uid,
                action_code,
                person_number,
                person_start_date,
                email_address,
                first_name,
                middle_names,
                last_name,
                termination_date,
                legal_employer_name,
                cost_center,
                assignment_effective_start_date,
                grade_level,
                job_code,
                location_code,
                department_code,
                worker_type,
                manager_person_number,
                business_unit_code
            FROM
                TERHCM_WORKEREMPRAW_SFTHRIVE_STG
            WHERE
                file_uid = p_file_uid
        ) LOOP
            l_def_exp_acc := NULL;
            BEGIN
                SELECT
                    gcc.condition_field1
                    || '-'
                    || gcc.condition_field2
                    || '-'
                    || gcc.condition_field3
                    || '-'
                    || gcc.condition_field4
                    || '-'
                    || gcc.condition_field5
                    || '-'
                    || gcc.condition_field6
                    || '-'
                    || gcc.condition_field7
                    || '-'
                    || gcc.condition_field8
                    || '-'
                    || gcc.condition_field9
                    || '-'
                INTO l_def_exp_acc
                FROM
                    TABLE ( p_code_combinations ) gcc
                WHERE
                        condition_field1 = rec.legal_employer_name
                    AND EXISTS (
                        SELECT
                            'Y'
                        FROM
                            TABLE ( p_le_bu_to_o_unit_acc_num_map ) acc
                        WHERE
                                rec.legal_employer_name
                                || '-'
                                || rec.business_unit_code = acc.condition_field1 --checking lookup code existance 
                            AND gcc.condition_field2 = acc.condition_field2 -- comparing operating Unit with Lookup Tag
                            AND condition_field4 = acc.condition_field3  -- Comparing Account Number with lookup description
                    )
                    AND condition_field3 = rec.cost_center --comparing cost center  
                    AND condition_field5 = rec.location_code
                    AND condition_field6 = '000000'
                    AND condition_field7 = '000'
                    AND condition_field8 = '0000'
                    AND condition_field9 = '0000';

            EXCEPTION
                WHEN no_data_found THEN
                    l_def_exp_acc := NULL;
            END;

            p_emp_expense_account_map.extend(1);
            IF ( l_def_exp_acc != NULL ) THEN
                p_emp_expense_account_map(p_emp_expense_account_map.last).condition_field1 := rec.raw_rec_uid;
                p_emp_expense_account_map(p_emp_expense_account_map.last).result_field1 := rec.raw_rec_uid;
            ELSE
                p_status := 'F';
            END IF;

        END LOOP;

    END;

    PROCEDURE TERHCM_UPDATE_EMP_LOAD_STATUS_PRC (
        p_file_uid                   IN OUT NUMBER,
        p_request_id                 NUMBER,
        p_ucm_content_id             VARCHAR2,
        p_imported_status            VARCHAR2,
        p_loaded_status              VARCHAR2,
        p_skipped_status             VARCHAR2,
        p_validated_status           VARCHAR2,
        p_import_lines_success_count NUMBER,
        p_import_lines_error_count   NUMBER,
        p_import_lines_total_count   NUMBER,
        p_import_success_count       NUMBER,
        p_import_error_count         NUMBER,
        p_line_held_count            NUMBER,
        p_line_loaded_count          NUMBER,
        p_line_unprocessed_count     NUMBER,
        p_line_error_count           NUMBER,
        p_unprocessed_count          NUMBER,
        p_validated_count            NUMBER,
        p_loaded_count               NUMBER,
        p_rollback_error_count       NUMBER,
        p_error_count                NUMBER,
        p_skipped_count              NUMBER,
        p_corrected_count            NUMBER,
        p_emp_rec_status             TERHCM_GENERIC_VALIDATION_TAB
    ) AS
        p_emp TERHCM_WORKER_EMP_RAW_TAB := TERHCM_WORKER_EMP_RAW_TAB();
    BEGIN
        TERHCM_WORKER_INBOUND_PKG.TERHCM_UPSERT_WORKERFILEMASTER_PRC(p_file_uid, NULL, NULL, p_request_id, p_ucm_content_id,
                                                                  p_imported_status, p_loaded_status, p_skipped_status, p_validated_status
                                                                  , p_import_lines_success_count,
                                                                  p_import_lines_error_count, p_import_lines_total_count, p_import_success_count
                                                                  , p_import_error_count, p_line_held_count,
                                                                  p_line_loaded_count, p_line_unprocessed_count, p_line_error_count, p_unprocessed_count
                                                                  , p_validated_count,
                                                                  p_loaded_count, p_rollback_error_count, p_error_count, p_skipped_count
                                                                  , p_corrected_count);

        BEGIN
            SELECT
                TERHCM_WORKER_EMP_RAW_OBJ(p_file_uid, raw_rec_uid, NULL, NULL, NULL,
                                                     NULL, NULL, NULL, NULL, NULL,
                                                     NULL, NULL, NULL, NULL, NULL,
                                                     NULL, NULL, NULL, NULL, NULL,
                                                     NULL, NULL, NULL, imported_status, validated_loaded_status, message_type, msg_text)
            BULK COLLECT
            INTO p_emp
            FROM
                (
                    SELECT
                        (
                            SELECT
                                raw_rec_uid
                            FROM
                                TERHCM_WORKEREMPRAW_SFTHRIVE_STG
                            WHERE
                                    file_uid = p_file_uid
                                AND condition_field3 = person_number
                                AND rownum = 1
                        )                raw_rec_uid,
                        condition_field1 message_type,
                        condition_field2 msg_text,
                        condition_field3 person_number,
                        condition_field4 imported_status,
                        condition_field5 validated_loaded_status
                    FROM
                        TABLE ( p_emp_rec_status )
                );

            TERHCM_WORKER_INBOUND_PKG.TERHCM_INSERT_WORKEREMPRAW_PRC(p_emp);
            COMMIT;
        END;

    END;

    PROCEDURE TERHCM_VALIDATE_COST_CENTER_PRC (
        p_file_uid            IN NUMBER,
        p_cost_centers        IN OUT TERHCM_GENERIC_VALIDATION_TAB,
        p_invalid_cost_ceners OUT VARCHAR2
    ) AS
    BEGIN
        UPDATE TERHCM_WORKEREMPRAW_SFTHRIVE_STG
        SET
            imported_status = 'VALIDATION_FAILED_AT_OIC',
            message_type = 'INVALID_COST_CENTER',
            msg_text = 'INVALID_COST_CENTER'
        WHERE
                file_uid = p_file_uid
            AND imported_status IS NULL
            AND NOT EXISTS (
                SELECT
                    'Y'
                FROM
                    TABLE ( p_cost_centers ) cc
                WHERE
                        1 = 1
                    AND condition_field1 = cost_center
            );

        COMMIT;
    END;

END TERHCM_WORKER_INBOUND_PKG;

