--  DDL for Package Body TERMFG_SCAN_PICK_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TERMFG_SCAN_PICK_PKG" AS

    PROCEDURE update_pick_staging (
        p_wo                 IN termfg_workorder_pick_stg.work_order_number%TYPE,
        p_warehouse_code     IN termfg_workorder_pick_stg.warehouse_code%TYPE,
        p_slot_number        IN termfg_workorder_pick_stg.slot_number%TYPE,
        p_pick_slip_num      IN termfg_workorder_pick_stg.pick_slip_number%TYPE,
        p_scan_station       IN termfg_workorder_pick_stg.scan_station%TYPE,
        p_work_order         IN termfg_workorder_slot_scan_stg.work_order%TYPE,
        p_movement_request   IN termfg_workorder_slot_scan_stg.movement_request%TYPE,
        o_rows_step1         OUT NUMBER,
        o_rows_step2         OUT NUMBER,
        o_rows_step3         OUT NUMBER,
        o_rows_step3_summary OUT NUMBER,
        o_rows_step4         OUT NUMBER,
        p_do_commit          IN BOOLEAN DEFAULT TRUE
    ) IS
    BEGIN
        IF p_wo IS NULL THEN
            raise_application_error(-20001, 'WO IS REQUIRED');
        END IF;
        IF p_warehouse_code IS NULL THEN
            raise_application_error(-20002, 'WAREHOUSE_CODE IS REQUIRED');
        END IF;
    -- 1) UPDATE SLOT ASSIGNMENT (BY WO + WAREHOUSE)
        UPDATE termfg_workorder_pick_stg
        SET
            slot_assigned = 'Yes',
            slot_number = p_slot_number,
            slot_status = 'In Process',
            scan_station = p_scan_station
        WHERE
                work_order_number = p_wo
            AND warehouse_code = p_warehouse_code
            AND pick_status = 'Confirmed'
            AND ( slot_status <> 'Bin Dropped'
                  OR slot_status IS NULL );

        o_rows_step1 := SQL%rowcount;
    -- 2) UPDATE SCAN + ASSIGNMENT TIMESTAMPS (BY WO + WAREHOUSE + PICK SLIP)
        UPDATE termfg_workorder_pick_stg
        SET
            component_scan_time_stamp = systimestamp,
            slot_assignment_time_stamp = systimestamp + INTERVAL '1' SECOND,
            slot_status = 'In Process-Awaiting Bin Drop',
            updated_by = p_scan_station,
            updated_date = systimestamp
        WHERE
                work_order_number = p_wo
            AND warehouse_code = p_warehouse_code
            AND pick_status = 'Confirmed'
            AND TRIM(to_char(pick_slip_number)) IN (
                SELECT
                    TRIM(regexp_substr(p_pick_slip_num, '[^,]+', 1, level))
                FROM
                    dual
                CONNECT BY
                    regexp_substr(p_pick_slip_num, '[^,]+', 1, level) IS NOT NULL
            )
            AND ( slot_status <> 'Bin Dropped'
                  OR slot_status IS NULL );

        o_rows_step2 := SQL%rowcount;
    -- 3A) (COMMENTED) SCAN STATION ON PICK — if re-enabled, include WAREHOUSE_CODE
        o_rows_step3 := 0;
    -- 3B) UPDATE SCAN STATION IN SUMMARY TABLE (BY WO + WAREHOUSE)
        UPDATE termfg_workorder_summary_stg
        SET
            scan_station = p_scan_station,
            last_updated_date = systimestamp,
            last_updated_by = p_scan_station
        WHERE
                work_order_number = p_wo
            AND warehouse_code = p_warehouse_code;

        o_rows_step3_summary := SQL%rowcount;
    -- 4) UPDATE SLOT TABLE (UNCHANGED KEY: SLOT_NUMBER)
        UPDATE termfg_workorder_slot_scan_stg
        SET
            work_order = p_work_order,
            movement_request = p_movement_request,
            slot_status = 'Engaged',
            first_pick_slip_scan_time_stamp =
                CASE
                    WHEN work_order IS NULL THEN
                        systimestamp
                    ELSE
                        first_pick_slip_scan_time_stamp
                END
        WHERE
            slot_number = p_slot_number;

        o_rows_step4 := SQL%rowcount;
        IF p_do_commit THEN
            COMMIT;
        END IF;
    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            RAISE;
    END update_pick_staging;

    PROCEDURE update_bin_drop (
        p_wo                  IN termfg_workorder_pick_stg.work_order_number%TYPE,
        p_warehouse_code      IN termfg_workorder_pick_stg.warehouse_code%TYPE,
        p_pick_slip_num       IN termfg_workorder_pick_stg.pick_slip_number%TYPE,
        p_scanned_bin_number  IN termfg_workorder_pick_stg.scanned_bin_number%TYPE,
        p_slot_status         IN termfg_workorder_pick_stg.slot_status%TYPE,
        p_slot_number         IN termfg_workorder_slot_scan_stg.slot_number%TYPE,
        p_pick_slip_csv_value IN VARCHAR2,
        p_pick_line_csv_value IN VARCHAR2,
        o_rows_pick           OUT NUMBER,
        o_rows_slot_scan      OUT NUMBER,
        p_do_commit           IN BOOLEAN DEFAULT TRUE
    ) IS
    BEGIN
        IF p_wo IS NULL THEN
            raise_application_error(-20001, 'WO IS REQUIRED');
        END IF;
        IF p_warehouse_code IS NULL THEN
            raise_application_error(-20002, 'WAREHOUSE_CODE IS REQUIRED');
        END IF;
    -- 1) PICK STG UPDATE (BY WO + WAREHOUSE + PICK SLIP)
        UPDATE termfg_workorder_pick_stg
        SET
            scanned_bin_number = p_scanned_bin_number,
            slot_status = p_slot_status,
            final_bin_drop_time_stamp = systimestamp,
            updated_date = systimestamp
        WHERE
                work_order_number = p_wo
            AND warehouse_code = p_warehouse_code
            AND pick_status = 'Confirmed'
            AND TRIM(to_char(pick_slip_number)) IN (
                SELECT
                    TRIM(regexp_substr(p_pick_slip_num, '[^,]+', 1, level))
                FROM
                    dual
                CONNECT BY
                    regexp_substr(p_pick_slip_num, '[^,]+', 1, level) IS NOT NULL
            )
            AND TRIM(to_char(picking_line_number)) IN (
                SELECT
                    TRIM(regexp_substr(p_pick_line_csv_value, '[^,]+', 1, level))
                FROM
                    dual
                CONNECT BY
                    regexp_substr(p_pick_line_csv_value, '[^,]+', 1, level) IS NOT NULL
            )
            AND ( slot_status <> 'Bin Dropped'
                  OR slot_status IS NULL );

        o_rows_pick := SQL%rowcount;
    -- 2) SLOT SCAN STG UPDATE (BY SLOT_NUMBER)
        UPDATE termfg_workorder_slot_scan_stg
        SET
            pick_slip =
                CASE
                    WHEN pick_slip IS NULL
                         OR TRIM(pick_slip) IS NULL THEN
                        p_pick_slip_csv_value
                    WHEN p_pick_slip_csv_value IS NULL
                         OR TRIM(p_pick_slip_csv_value) IS NULL THEN
                        pick_slip
                    ELSE
                        pick_slip
                        || ','
                        || p_pick_slip_csv_value
                END,
            pick_slip_line_number =
                CASE
                    WHEN pick_slip_line_number IS NULL
                         OR TRIM(pick_slip_line_number) IS NULL THEN
                        p_pick_line_csv_value
                    WHEN p_pick_line_csv_value IS NULL
                         OR TRIM(p_pick_line_csv_value) IS NULL THEN
                        pick_slip_line_number
                    ELSE
                        pick_slip_line_number
                        || ','
                        || p_pick_line_csv_value
                END,
            count_of_pick_slips = nvl(count_of_pick_slips, 0) + 1
        WHERE
            slot_number = p_slot_number;

        o_rows_slot_scan := SQL%rowcount;
        IF p_do_commit THEN
            COMMIT;
        END IF;
    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            RAISE;
    END update_bin_drop;

    PROCEDURE termfg_upset_processid_prc (
        porg            NUMBER,
        pworkorderid    VARCHAR2,
        pprocessid      NUMBER,
        pchildprocessid NUMBER
    ) AS
        l_str   LONG DEFAULT pworkorderid || ',';
        l_n     NUMBER;
        vnumber NUMBER;
    BEGIN
        LOOP
            l_n := instr(l_str, ',');
            EXIT WHEN ( nvl(l_n, 0) = 0 );
            vnumber := ltrim(rtrim(substr(l_str, 1, l_n - 1)));

            UPDATE termfg_workorder_summary_stg
            SET
                process_id = pprocessid,
                update_required_flag = 'Y',
                child_process_id = pchildprocessid
            WHERE
                work_order_id IN ( vnumber )
                AND organization_id = porg;

            COMMIT;
            l_str := substr(l_str, l_n + 1);
        END LOOP;
    EXCEPTION
        WHEN OTHERS THEN
            dbms_output.put_line(sqlcode
                                 || '- 2 -'
                                 || sqlerrm);
            ROLLBACK;
    END termfg_upset_processid_prc;

    PROCEDURE termfg_pickslip_truncate_prc (
        p_dummy VARCHAR2
    ) AS
    BEGIN

--DELETE FROM TERMFG_WORKORDER_PICK_STG;
        COMMIT;
    EXCEPTION
        WHEN OTHERS THEN
            dbms_output.put_line(sqlcode
                                 || '- 2 -'
                                 || sqlerrm);
    END termfg_pickslip_truncate_prc;

END termfg_scan_pick_pkg;

