  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TERPO_BPA_ATP_PKG" IS

  PROCEDURE stg_status_proc(
    p_oic_instance_id_in     IN terpo_bpa_hdr_stg.oic_instance_id%TYPE,
    p_process_set_status_in  IN terpo_bpa_hdr_stg.process_status%TYPE,
