  BEGIN
    IF p_oic_instance_id_in IS NULL THEN
      RAISE_APPLICATION_ERROR(-20001, 'p_oic_instance_id_in cannot be NULL');
    END IF;

    SAVEPOINT sp_stg_status;

    UPDATE terpo_bpa_hdr_stg h
    SET    h.process_status   = p_process_set_status_in,
           h.last_update_date = SYSDATE
    WHERE  h.process_status   = p_process_whr_status_in
    AND    h.oic_instance_id  = p_oic_instance_id_in;
    v_rows := SQL%ROWCOUNT; v_total_rows := v_total_rows + v_rows;

    UPDATE terpo_bpa_line_stg l
    SET    l.process_status   = p_process_set_status_in,
           l.last_update_date = SYSDATE
    WHERE  l.process_status   = p_process_whr_status_in
    AND    l.oic_instance_id  = p_oic_instance_id_in;
    v_rows := SQL%ROWCOUNT; v_total_rows := v_total_rows + v_rows;

    UPDATE terpo_bpa_lineloc_stg s
    SET    s.process_status   = p_process_set_status_in,
           s.last_update_date = SYSDATE
    WHERE  s.process_status   = p_process_whr_status_in
