    v_rows := SQL%ROWCOUNT; v_total_rows := v_total_rows + v_rows;

    UPDATE terpo_bpa_attr_values_stg a
    SET    a.process_status   = p_process_set_status_in,
           a.last_update_date = SYSDATE
    WHERE  a.process_status   = p_process_whr_status_in
    AND    a.oic_instance_id  = p_oic_instance_id_in;
    v_rows := SQL%ROWCOUNT; v_total_rows := v_total_rows + v_rows;

