    WHERE  t.process_status   = p_process_whr_status_in
    AND    t.oic_instance_id  = p_oic_instance_id_in;
    v_rows := SQL%ROWCOUNT; v_total_rows := v_total_rows + v_rows;

    DBMS_OUTPUT.PUT_LINE('stg_status_proc rows updated = ' || v_total_rows);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK TO sp_stg_status;
      RAISE;
  END stg_status_proc;

