    SET    s.process_status   = p_process_set_status_in,
           s.last_update_date = SYSDATE
    WHERE  s.interface_request_id = p_load_request_id_in
    AND    s.oic_instance_id      = p_oic_instance_id_in
    AND    EXISTS (
      SELECT 1 FROM terpo_bpa_line_stg l
      WHERE  l.interface_request_id = p_load_request_id_in
