    AND    a.oic_instance_id      = p_oic_instance_id_in
    AND    EXISTS (
      SELECT 1 FROM terpo_bpa_line_stg l
      WHERE  l.interface_request_id = p_load_request_id_in
      AND    l.oic_instance_id      = p_oic_instance_id_in
      AND    l.header_key           = p_header_key_in
      AND    l.line_key             = a.line_key
