  PROCEDURE cancel_stg_row_proc(
    p_cancel_key_in      IN terpo_bpa_cancel_stg.cancel_key%TYPE,
    p_process_status_in  IN terpo_bpa_cancel_stg.process_status%TYPE,
    p_error_desc_in      IN terpo_bpa_cancel_stg.error_desc%TYPE DEFAULT NULL
  ) IS
  BEGIN
