   PROCEDURE suppliernotfound_status_proc(p_oic_instance_id_in IN terpo_pricesphere_hdr_master.oic_instance_id%TYPE
                                         ,p_header_key_in      IN terpo_pricesphere_hdr_master.header_key%TYPE)
   IS
     v_total_rows    NUMBER    := 0;
     v_rows          NUMBER    := 0;
     p_do_commit_in  BOOLEAN   := FALSE;
    BEGIN
        IF p_oic_instance_id_in IS NULL OR p_header_key_in IS NULL THEN
          RAISE_APPLICATION_ERROR(-20001, 'p_oic_instance_id_in and p_header_key_in cannot be NULL');
        END IF;

        SAVEPOINT sp_upd_proc;

        UPDATE terpo_pricesphere_hdr_master
           SET process_status  = 'ERROR'
         WHERE process_status <> 'VALIDATED'
           AND oic_instance_id = p_oic_instance_id_in
           AND header_key      = p_header_key_in;
        v_rows := SQL%ROWCOUNT; v_total_rows := v_total_rows + v_rows;

        UPDATE terpo_pricesphere_line_master
           SET process_status  = 'ERROR'
         WHERE process_status <> 'VALIDATED'
           AND oic_instance_id = p_oic_instance_id_in
           AND header_key      = p_header_key_in;
        v_rows := SQL%ROWCOUNT; v_total_rows := v_total_rows + v_rows;        

        UPDATE terpo_pricesphere_lineloc_master pll
           SET process_status  = 'ERROR'
         WHERE process_status <> 'VALIDATED'
           AND oic_instance_id = p_oic_instance_id_in
           AND EXISTS (SELECT 1 FROM terpo_pricesphere_line_master pl
                               WHERE oic_instance_id = p_oic_instance_id_in
                                 AND process_status  = 'ERROR'
                                 AND pll.line_key    = pl.line_key
                                 AND pl.header_key   = p_header_key_in);
        v_rows := SQL%ROWCOUNT; v_total_rows := v_total_rows + v_rows;        

        UPDATE terpo_pricesphere_attr_values_master pll
           SET process_status  = 'ERROR'
         WHERE process_status <> 'VALIDATED'
           AND oic_instance_id = p_oic_instance_id_in
           AND EXISTS (SELECT 1 FROM terpo_pricesphere_line_master pl
