   PROCEDURE stg_recon_proc(p_process_set_status_in        IN terpo_pricesphere_hdr_stg.process_status%TYPE
                           ,p_header_key_in                IN terpo_pricesphere_hdr_stg.header_key%TYPE
                           ,p_oic_instance_id_in           IN terpo_pricesphere_hdr_stg.oic_instance_id%TYPE  
                           ,p_load_request_id_in           IN terpo_pricesphere_hdr_stg.interface_request_id%TYPE)                 
   IS
     v_total_rows    NUMBER    := 0;
     v_rows          NUMBER    := 0;
     p_do_commit_in  BOOLEAN   := FALSE;
    BEGIN
        IF p_load_request_id_in IS NULL THEN
          RAISE_APPLICATION_ERROR(-20001, 'p_load_request_id_in cannot be NULL');
        END IF;

        SAVEPOINT sp_upd_proc;   

        UPDATE terpo_pricesphere_hdr_stg
           SET process_status = p_process_set_status_in
         WHERE interface_request_id = p_load_request_id_in
           AND oic_instance_id      = p_oic_instance_id_in
           AND header_key           = p_header_key_in;
        v_rows := SQL%ROWCOUNT; v_total_rows := v_total_rows + v_rows;

        UPDATE terpo_pricesphere_line_stg
           SET process_status = p_process_set_status_in
         WHERE interface_request_id = p_load_request_id_in
           AND oic_instance_id      = p_oic_instance_id_in
           AND header_key           = p_header_key_in;
        v_rows := SQL%ROWCOUNT; v_total_rows := v_total_rows + v_rows;

        UPDATE terpo_pricesphere_lineloc_stg pll
           SET process_status = p_process_set_status_in
         WHERE interface_request_id = p_load_request_id_in
           AND oic_instance_id      = p_oic_instance_id_in
           AND EXISTS (SELECT 1 
                         FROM terpo_pricesphere_line_stg pl
                        WHERE 1=1
                          AND pl.interface_request_id = p_load_request_id_in
                          AND pl.oic_instance_id      = p_oic_instance_id_in
                          AND header_key              = p_header_key_in
                          AND pl.line_key             = pll.line_key);
        v_rows := SQL%ROWCOUNT; v_total_rows := v_total_rows + v_rows;

        UPDATE terpo_pricesphere_attr_values_stg pll
           SET process_status = p_process_set_status_in
         WHERE interface_request_id = p_load_request_id_in
           AND oic_instance_id      = p_oic_instance_id_in
           AND EXISTS (SELECT 1 
                         FROM terpo_pricesphere_line_stg pl
                        WHERE 1=1
                          AND pl.interface_request_id = p_load_request_id_in
                          AND pl.oic_instance_id      = p_oic_instance_id_in
                          AND header_key              = p_header_key_in
                          AND pl.line_key             = pll.line_key);
        v_rows := SQL%ROWCOUNT; v_total_rows := v_total_rows + v_rows;

        UPDATE terpo_pricesphere_attr_tlp_stg pll
           SET process_status = p_process_set_status_in
         WHERE interface_request_id = p_load_request_id_in
           AND oic_instance_id      = p_oic_instance_id_in
           AND EXISTS (SELECT 1 
                         FROM terpo_pricesphere_line_stg pl
                        WHERE 1=1
                          AND pl.interface_request_id = p_load_request_id_in
                          AND pl.oic_instance_id      = p_oic_instance_id_in
