--------------------------------------------------------
--  DDL for Package Body TERPO_PRICESPHERE_HDR_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TERPO_PRICESPHERE_HDR_PKG" AS
  FUNCTION get_rows
    RETURN terpo_pricesphere_hdr_tab
    PIPELINED
  IS
  BEGIN
    FOR r IN (
      SELECT header_key, action_code, batch_id
      FROM   terpo_pricesphere_hdr_stg
    ) LOOP
      PIPE ROW (
        terpo_pricesphere_hdr_row(
          r.header_key,
          r.action_code,
          r.batch_id
        )
      );
    END LOOP;

    RETURN;
  END get_rows;
END terpo_pricesphere_hdr_pkg;

/
--------------------------------------------------------
--  DDL for Package Body TERSLOT_APPROVE_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TERSLOT_APPROVE_PKG" AS    


   CURSOR cur_cr_partial_dtls (
        p_data BLOB
    ) IS
    SELECT
        config_number,
        part_number,
        part_description,
        quantity,
        promisedate,
        comments
    FROM
        JSON_TABLE 
		( p_data FORMAT JSON, '$[*]' --'$'  -- If payload is an array, change to '$[*]'
            COLUMNS (
                config_number VARCHAR2  PATH '$.config_number',
                part_number VARCHAR2  PATH '$.part_number',
                part_description VARCHAR2  PATH '$.part_description',
                quantity NUMBER  PATH '$.quantity',
                promisedate TIMESTAMP  PATH '$.promise_date',
                comments VARCHAR2 PATH '$.comments'
            )
        )
		;
		
	TYPE partials_tab_type IS TABLE OF cur_cr_partial_dtls%rowtype;
    l_partials_tab   partials_tab_type; 
    
     CURSOR cur_cr_refurb_dtls (
        p_data BLOB
    ) IS
    SELECT
        config_number,
        part_number,
        part_description,
        quantity,
        promisedate,
        shipfromsite,
        comments
    FROM
        JSON_TABLE 
		( p_data FORMAT JSON, '$[*]' --'$'  -- If payload is an array, change to '$[*]'
            COLUMNS (
                config_number VARCHAR2  PATH '$.config_number',
                part_number VARCHAR2  PATH '$.part_number',
                part_description VARCHAR2  PATH '$.part_description',
                quantity NUMBER  PATH '$.quantity',
                promisedate TIMESTAMP  PATH '$.promise_date',
                shipfromsite  VARCHAR2  PATH '$.ship_from_site',
                comments VARCHAR2 PATH '$.comments'
            )
        )
		;
		
	TYPE refurb_tab_type IS TABLE OF cur_cr_refurb_dtls%rowtype;
    l_refurb_tab   refurb_tab_type; 
		

	--get customer detials 
    FUNCTION get_customer_id_f (
            p_in_cust_name IN VARCHAR2,
            p_in_cust_site IN VARCHAR2   
            ) RETURN VARCHAR
    IS 
    l_customer_id VARCHAR2(30);
    BEGIN    
    
    IF ( p_in_cust_name IS NULL OR p_in_cust_site IS NULL ) THEN 
              l_customer_id := NULL;
      ELSE  
         select customer_id INTO l_customer_id 
		 from terext_slot_customer_dtls 
         where customer_name = p_in_cust_name and 
          customer_site =p_in_cust_site
          ;
    END IF;  
    
    RETURN l_customer_id;
    EXCEPTION
    WHEN OTHERS THEN 
    RETURN null;
    end get_customer_id_f;
	

   PROCEDURE cr_approve (
        p_in_crnum   VARCHAR2,
        p_in_action  VARCHAR2,
        p_in_user    VARCHAR2,
        p_in_partial_flag VARCHAR2,
        p_in_partial_body BLOB DEFAULT NULL,
        p_out_status OUT VARCHAR2,
        p_out_msg    OUT VARCHAR2
    )
    IS
    l_customer_id NUMBER;
    --check cr status 
     CURSOR cur_cr_dtls (l_cr_num VARCHAR2)
      IS
         SELECT   COUNT(*)
             FROM TEREXT_SLOT_CR_DTLS
            WHERE CR_NUMBER=l_cr_num 
            AND request_status = 'Submitted'
         ;   

     --get cr details
     CURSOR cur_get_cr_dtls (l_cr_num VARCHAR2) IS
     SELECT * 
     FROM TEREXT_SLOT_CR_DTLS
            WHERE CR_NUMBER=l_cr_num 
            AND request_status = 'Submitted';               
    cr_rec   cur_get_cr_dtls%ROWTYPE;             

      l_count NUMBER;   
    BEGIN
    dbms_output.put_line('cr_approve Procedure START');
    --insert into test_slot_log(col1,col2,col3,col4) values('1','START-'||p_in_user,p_in_crnum,p_in_action);
    OPEN cur_cr_dtls(p_in_crnum);    
    LOOP
        FETCH cur_cr_dtls INTO l_count;        
        EXIT WHEN cur_cr_dtls%NOTFOUND;
    END LOOP;    
    CLOSE cur_cr_dtls;
    dbms_output.put_line('cr count-'||l_count);
     --insert into test_slot_log(col1,col2,col3,col4) values('2','l_count-'||l_count,p_in_crnum,p_in_action);

    IF (l_count != 1) THEN
    p_out_status :='Error';
    p_out_msg    :='No Active CR';
    RETURN;    
    END IF;
   
    --reject CR START
	
	
    IF (p_in_action ='Reject') THEN
    UPDATE TEREXT_SLOT_CR_DTLS 
      SET request_status='Rejected',
          updated_by=p_in_user,
          updated_date=sysdate
      WHERE cr_number=p_in_crnum
      ;
    p_out_status := 'Success';
    p_out_msg    := 'CR Status Updated To Reject';
    
        dbms_output.put_line('CR Status Updated To Reject-'||p_in_crnum);
    -- insert into test_slot_log(col1,col2,col3,col4) values('3','p_out_status-'||p_out_status,p_in_crnum,p_in_action);

    COMMIT;
    RETURN;
    END IF;
   --reject CR END


    OPEN cur_get_cr_dtls(p_in_crnum);    
    LOOP
     
       --insert into test_slot_log(col1,col2,col3,col4) values('3','APPROVE',p_in_crnum,p_in_action);

        FETCH cur_get_cr_dtls INTO cr_rec;
       --insert into test_slot_log(col1,col2,col3,col4) values('4','cr_rec.count-',p_in_crnum,'cr_rec.new_slot_status-'||cr_rec.new_slot_status);

		--update by balaji to get the data from the customer table
			   /*  select CUSTOMER_ID INTO l_customer_id from terext_slot_customer_dtls 
		where CUSTOMER_NAME = cr_rec.new_customer_name and 
		CUSTOMER_SITE =cr_rec.new_customer_site;
		*/
        EXIT WHEN cur_get_cr_dtls%NOTFOUND; 
		
        l_customer_id := get_customer_id_f (cr_rec.new_customer_name,cr_rec.new_customer_site);

        IF    cr_rec.new_slot_status='Booked'     THEN
           --update slot hdr table 
           UPDATE TEREXT_SLOT_PLAN_DTLS  SET 
                   customer=cr_rec.new_customer_name,
                   customer_id=l_customer_id,
                   customer_site_id=cr_rec.new_customer_site,
                   config_number=cr_rec.new_config_number,
                   slot_status=cr_rec.new_slot_status,                   
                   sales_order=cr_rec.new_sales_order,
                   promised_date=cr_rec.new_promised_date,
                   pd_qtr=cr_rec.new_pd_qtr,                 
                   --operation_comments=operation_comments||'-'||cr_rec.operation_comments,
                  -- marketing_comments=marketing_comments||'-'||cr_rec.marketing_comments,
                   updated_by=p_in_user,
                   updated_date=sysdate                   
           WHERE slot_number=cr_rec.slot_number
           ;
          
          MERGE INTO terext_slot_plan_ops_dtls target1
			USING (
				SELECT slot_number,
					   slot_type,
					   sales_order,
					   planning_organization,
					   manufacture,
					   manufacture_site,
					   operation_comments,
					   created_by,
					   created_date,
					   updated_by,
					   updated_date
				  FROM terext_slot_plan_dtls
				 WHERE slot_number = cr_rec.slot_number
			) source1
			ON (target1.slot_number = source1.slot_number)
			WHEN MATCHED THEN
				UPDATE
				   SET target1.sales_order         = cr_rec.new_sales_order,
					   target1.operations_comments = operations_comments || '-' || cr_rec.operation_comments,
					   target1.updated_by          = p_in_user,
					   target1.updated_date        = SYSDATE
			WHEN NOT MATCHED THEN
				INSERT (
					slot_number,
					slot_type,
					sales_order,
					planning_organization,
					mfr,
					mfr_site,
					operations_comments,
					created_by,
					created_date,
					updated_by,
					updated_date
				)
				VALUES (
					source1.slot_number,
					source1.slot_type,
					--source1.sales_order,
					cr_rec.new_sales_order,
					source1.planning_organization,
					source1.manufacture,
					source1.manufacture_site,
					--source1.operation_comments,
					source1.operation_comments || '-' ||cr_rec.operation_comments,
					source1.created_by,
					source1.created_date,
					--source1.updated_by,
					p_in_user,
					--source1.updated_date
					SYSDATE
				);

           --update mkting tables
           MERGE INTO terext_slot_plan_mkt_dtls target1
			USING (
				SELECT slot_number,
					   slot_type,
					   sales_order,
					   customer_id,
					   customer_site_id,
					   marketing_comments,
					   created_by,
					   created_date,
					   updated_by,
					   updated_date,
					   config_number,
					   promised_date
				  FROM terext_slot_plan_dtls
				 WHERE slot_number = cr_rec.slot_number
			) source1
			ON (target1.slot_number = source1.slot_number)
			WHEN MATCHED THEN
				UPDATE
				   SET target1.forecast_name     = cr_rec.new_forecast_name,
					   target1.config_number     = cr_rec.new_config_number,     ---CHECK
					   target1.request_number    = cr_rec.cr_number,
					   target1.s_number          = cr_rec.new_sales_order,       ---CHECK
					   target1.customer_id       = l_customer_id,                          ---CHECK
					   target1.customer_site_id  = cr_rec.new_customer_site,     ---CHECK HDR
					   target1.marketing_comments = marketing_comments || '-' || cr_rec.marketing_comments,
					   target1.updated_by        = p_in_user,
					   target1.updated_date      = SYSDATE
			WHEN NOT MATCHED THEN
				INSERT (
					slot_number,
					slot_type,
					s_number,
					customer_id,
					customer_site_id,
					marketing_comments,
					created_by,
					created_date,
					updated_by,
					updated_date,
					config_number,
					--insert fields from CR
					forecast_name,
					request_number,
					promise_date
				)
				VALUES (
					source1.slot_number,
					source1.slot_type,
					--source1.sales_order,
					cr_rec.new_sales_order,
					source1.customer_id,
					--source1.customer_site_id,
					cr_rec.new_customer_site,
					source1.marketing_comments|| '-' || cr_rec.marketing_comments,
					source1.created_by,
					source1.created_date,
					--source1.updated_by,
					p_in_user,
					--source1.updated_date,
					sysdate,
					--source1.config_number
					cr_rec.new_config_number,
					--insert fields from CR
					cr_rec.new_forecast_name,
					cr_rec.cr_number,
					source1.promised_date
					
				);
          
		
        ELSIF (cr_rec.new_slot_status='Identified') THEN-- AND cr_rec.new_config_number is not null) THEN 
        --update slot hdr table           
           UPDATE TEREXT_SLOT_PLAN_DTLS  SET 
                   customer=cr_rec.new_customer_name,
                   customer_id=l_customer_id,
                   customer_site_id=cr_rec.new_customer_site,
                  config_number=COALESCE(cr_rec.new_config_number,config_number),
                   slot_status=cr_rec.new_slot_status,                   
                   sales_order=NULL,
                   promised_date=cr_rec.new_promised_date,
                   pd_qtr=cr_rec.new_pd_qtr,                 
                   --operation_comments=operation_comments||'-'||cr_rec.operation_comments,
                   --marketing_comments=marketing_comments||'-'||cr_rec.marketing_comments,
                   updated_by=p_in_user,
                   updated_date=sysdate                   
           WHERE slot_number=cr_rec.slot_number
           ;
		   
		   --
		   MERGE INTO terext_slot_plan_ops_dtls target1
			USING (
				SELECT slot_number,
					   slot_type,
					   sales_order,
					   planning_organization,
					   manufacture,
					   manufacture_site,
					   operation_comments,
					   created_by,
					   created_date,
					   updated_by,
					   updated_date
				  FROM terext_slot_plan_dtls
				 WHERE slot_number = cr_rec.slot_number
			) source1
			ON (target1.slot_number = source1.slot_number)
			WHEN MATCHED THEN
				UPDATE
				   SET target1.sales_order         = NULL,--cr_rec.new_sales_order,
					   target1.operations_comments = operations_comments || '-' || cr_rec.operation_comments,
					   target1.updated_by          = p_in_user,
					   target1.updated_date        = SYSDATE
			WHEN NOT MATCHED THEN
				INSERT (
					slot_number,
					slot_type,
					sales_order,
					planning_organization,
					mfr,
					mfr_site,
					operations_comments,
					created_by,
					created_date,
					updated_by,
					updated_date
				)
				VALUES (
					source1.slot_number,
					source1.slot_type,
					--source1.sales_order,
					--cr_rec.new_sales_order,
					NULL,
					source1.planning_organization,
					source1.manufacture,
					source1.manufacture_site,
					--source1.operation_comments,
					source1.operation_comments || '-' || cr_rec.operation_comments,--cr_rec.operation_comments,
					source1.created_by,
					source1.created_date,
					--source1.updated_by,
					p_in_user,
					--source1.updated_date
					SYSDATE
				);
		  
		 MERGE INTO terext_slot_plan_mkt_dtls target1
			USING (
				SELECT slot_number,
					   slot_type,
					   sales_order,
					   customer_id,
					   customer_site_id,
					   marketing_comments,
					   created_by,
					   created_date,
					   updated_by,
					   updated_date,
					   config_number
				  FROM terext_slot_plan_dtls
				 WHERE slot_number = cr_rec.slot_number
			) source1
			ON (target1.slot_number = source1.slot_number)
			WHEN MATCHED THEN
				UPDATE
				   SET target1.forecast_name     = cr_rec.new_forecast_name,
					   target1.config_number     = COALESCE(cr_rec.new_config_number,target1.config_number),--cr_rec.new_config_number,     ---CHECK
					   target1.request_number    = cr_rec.cr_number,
					   target1.s_number          = null,--cr_rec.new_sales_order,       ---CHECK
					   target1.customer_id       = l_customer_id,                          ---CHECK
					   target1.customer_site_id  = cr_rec.new_customer_site,     ---CHECK HDR
					   target1.marketing_comments = marketing_comments || '-' || cr_rec.marketing_comments,
					   target1.updated_by        = p_in_user,
					   target1.updated_date      = SYSDATE
			WHEN NOT MATCHED THEN
				INSERT (
					slot_number,
					slot_type,
					s_number,
					customer_id,
					customer_site_id,
					marketing_comments,
					created_by,
					created_date,
					updated_by,
					updated_date,
					config_number,
					--insert fields from CR
					forecast_name,
					request_number,
					promise_date
				)
				VALUES (
					source1.slot_number,
					source1.slot_type,
					--source1.sales_order,
					cr_rec.new_sales_order,
					source1.customer_id,
					--source1.customer_site_id,
					cr_rec.new_customer_site,
					source1.marketing_comments|| '-' || cr_rec.marketing_comments,
					source1.created_by,
					source1.created_date,
					--source1.updated_by,
					p_in_user,
					--source1.updated_date,
					sysdate,
					--source1.config_number
					cr_rec.new_config_number,
					--insert fields from CR
					cr_rec.new_forecast_name,
					cr_rec.cr_number,
					cr_rec.new_promised_date
					
				);
		
        ELSIF cr_rec.new_slot_status='Open' THEN 
           --update slot hdr table           
           UPDATE TEREXT_SLOT_PLAN_DTLS  SET 
                   customer=NULL,
                   customer_id=NULL,
                   customer_site_id=NULL,
                   config_number=COALESCE(cr_rec.new_config_number,config_number),
                   slot_status='Open',                   
                   sales_order=NULL,
                   promised_date=cr_rec.new_promised_date,
                   pd_qtr=cr_rec.new_pd_qtr,                 
                   --operation_comments=operation_comments||'-'||cr_rec.operation_comments,
                   --marketing_comments=marketing_comments||'-'||cr_rec.marketing_comments,
                   updated_by=p_in_user,
                   updated_date=sysdate                   
           WHERE slot_number=cr_rec.slot_number
           ;

            --update operations table
            UPDATE TEREXT_SLOT_PLAN_OPS_DTLS SET 
                  -- slot_status=cr_rec.new_slot_status,
                   sales_order=NULL,      --check
                   operations_comments=operations_comments||'-'||cr_rec.operation_comments,
                   updated_by=p_in_user,
                   updated_date=sysdate                   
             WHERE slot_number=cr_rec.slot_number
           ;       

            --update mkting tables
           UPDATE TEREXT_SLOT_PLAN_MKT_DTLS SET 
                   forecast_name=cr_rec.new_forecast_name,
--                   new_slot_status=cr_rec.new_slot_status,
                   s_number=NULL, 
                  -- config_number=cr_rec.new_config_number,
                   --config_number=COALESCE(cr_rec.new_config_number,config_number),
                   request_number=cr_rec.cr_number,
                   promise_date=cr_rec.new_promised_date,
                   customer_id=NULL,
                   customer_site_id=NULL,
                   updated_by=p_in_user,
                   updated_date=sysdate                   
             WHERE slot_number=cr_rec.slot_number
           ;       
           --finance check 
          UPDATE TEREXT_SLOT_PLAN_FIN_DTLS SET
                sales_order=NULL,    --CHECK    
               -- slot_status='Open',  
                updated_by=p_in_user,
                updated_date=sysdate                   
           WHERE slot_number=cr_rec.slot_number
           ;     
           
       
        END IF;
		
		 
		--updated partial details 
		IF p_in_partial_flag = 'Y' THEN 
		
			OPEN cur_cr_partial_dtls(p_in_partial_body);
			FETCH cur_cr_partial_dtls BULK COLLECT INTO l_partials_tab;
			CLOSE cur_cr_partial_dtls;
			
			IF l_partials_tab.COUNT >=1 THEN 
			
				delete from TEREXT_SLOT_PARTS where slot_number=cr_rec.slot_number;
				
				FOR i IN l_partials_tab.first..l_partials_tab.last
				LOOP 
				 insert into TEREXT_SLOT_PARTS(slot_number,part_number,part_description,quantity,promise_date,comments,config_num) 
				 values(cr_rec.slot_number,l_partials_tab(i).part_number,l_partials_tab(i).part_description,l_partials_tab(i).quantity
				 ,l_partials_tab(i).promisedate,l_partials_tab(i).comments,cr_rec.new_config_number);
		 
				END LOOP;
				
				l_partials_tab.delete; 
	   
				UPDATE TEREXT_SLOT_PLAN_DTLS  SET partial_flag='Y' WHERE slot_number=cr_rec.slot_number;
			
			END IF;
		
		END IF; --End of IF  p_in_partial_flag = 'Y'
		--update CR status  
		UPDATE TEREXT_SLOT_CR_DTLS SET 
          request_status='Approved',
          updated_by=p_in_user,
          updated_date=sysdate
        WHERE cr_number=p_in_crnum;

    END LOOP;
    CLOSE cur_get_cr_dtls;
    COMMIT;
    p_out_status := 'Success';
    p_out_msg    := 'CR Approved Succesfully!';
    EXCEPTION 
    WHEN OTHERS THEN 
    ROLLBACK;
    p_out_status := 'Error';
    p_out_msg    := 'Exception is -'|| SUBSTR(SQLERRM,1,100);
   -- insert into test_slot_log(col1,col2,col3,col4) values('44','OTHERS',p_in_crnum,null);
    --DBMS_OUTPUT.PUT_LINE('Error backtrace:');
    --DBMS_OUTPUT.PUT_LINE(DBMS_UTILITY.FORMAT_ERROR_BACKTRACE());
    commit;
    END;
    
	PROCEDURE cr_bulk_data_process(
        p_in_filename     VARCHAR2
--        ,
--        p_out_status OUT VARCHAR2
    )
    IS
    CURSOR get_cr_dtls  
    IS
    select * from TEREXT_SLOT_CR_BULK_UPLOAD_CSV where status='New' and filename=p_in_filename
    --and action=p_action
    ;
    cr_dtls_rec   get_cr_dtls%ROWTYPE;         
    l_status  VARCHAR2(10);
    l_msg     VARCHAR2(200);
    BEGIN
    --insert into test_one(sno,desci) values(1,p_in_filename);
    OPEN get_cr_dtls;
     LOOP
       
     FETCH get_cr_dtls INTO cr_dtls_rec;
      EXIT WHEN get_cr_dtls%NOTFOUND; 
      cr_approve(cr_dtls_rec.cr_number,cr_dtls_rec.action,cr_dtls_rec.username,'N',NULL,l_status,l_msg);
      --END IF;
      update TEREXT_SLOT_CR_BULK_UPLOAD_CSV set status=l_status,error_msg=l_msg where cr_number=cr_dtls_rec.cr_number;      
     END LOOP; 
     CLOSE get_cr_dtls;
     COMMIT; 
    --p_out_status:='Success';
    apex_json.open_object;
        apex_json.write('p_err_code', 'Success');
        apex_json.write('p_err_msg', 'Processed Succesfully');
        --apex_json.write('slot_number', rec_mkt_data.slot_number);
        apex_json.close_object;
    

        
    EXCEPTION 
    WHEN OTHERS THEN 
    ROLLBACK;
 apex_json.open_object;
        apex_json.write('p_err_code', 'Success');
        apex_json.write('p_err_msg', 'Error Message');
        --apex_json.write('slot_number', rec_mkt_data.slot_number);
        apex_json.close_object;
    END cr_bulk_data_process;
    
    
   PROCEDURE cr_refurb_dtls (
        p_in_slotnum     VARCHAR2,
        p_in_refurb_flag VARCHAR2,
        p_in_refurb_body BLOB DEFAULT NULL,
        p_out_status OUT VARCHAR2,
        p_out_msg    OUT VARCHAR2
    )
    IS
    BEGIN 
    insert into test_slot_log(col1,col2,col3) values('cr_refurb_dtls',p_in_slotnum,p_in_refurb_flag);
    IF p_in_refurb_flag = 'Y' THEN 
		OPEN cur_cr_refurb_dtls(p_in_refurb_body);
        FETCH cur_cr_refurb_dtls BULK COLLECT INTO l_refurb_tab;
        CLOSE cur_cr_refurb_dtls;
		
		IF l_refurb_tab.COUNT >=1 THEN 
		delete from TEREXT_SLOT_PARTS_REFURB where slot_number=p_in_slotnum;
		FOR i IN l_refurb_tab.first..l_refurb_tab.last
		LOOP 
	--	 null;
         insert into TEREXT_SLOT_PARTS_REFURB(slot_number,part_number,part_description,quantity,promise_date,comments,ship_from_site) 
		 values(p_in_slotnum,l_refurb_tab(i).part_number,l_refurb_tab(i).part_description,l_refurb_tab(i).quantity
         ,l_refurb_tab(i).promisedate,l_refurb_tab(i).comments,l_refurb_tab(i).shipfromsite);
         --*/
        END LOOP;
        l_refurb_tab.delete;
	   --partial flag to Y 
	     UPDATE TEREXT_SLOT_PLAN_DTLS  SET refurb_flag='Y' WHERE slot_number=p_in_slotnum;
		END IF; --End of l_refurb_tab.COUNT >=1
		
    END IF;  --End of p_in_refurb_flag = 'Y' 
    p_out_status := 'Success';
    p_out_msg    := 'CR Refurb Details Updated Succesfully!';
    COMMIT;
    EXCEPTION 
    WHEN OTHERS THEN 
    ROLLBACK;
    p_out_status := 'Error2';
    --p_out_msg    := SUBSTR(SQLERRM(),1,100);
    p_out_msg    := 'Backtrace: ' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE;
    END;
    
END terslot_approve_pkg;

