--| Date        Who                Ver     Change Description
--| ----------- ----------         ---    ------------------------------|
--| 19-JAN-2026 Balaji Umapathy    1.0     Initial version
--| 28-JAN-2026 Balaji Umapathy    1.1     Initial version

CURSOR cur_cr_data (
        p_data BLOB
    ) IS
    SELECT
        forecastname,
        slotstatus,
        customername,
        customersite,
        confignum,
        salesorder,
        changereason,
        mktcomments,
        created_by,
        raised_by,
		created_date,
		request_date,
		request_qtr,
		slotnumber,
        promise_date,
        pd_qtr
    FROM
        JSON_TABLE 
		( p_data FORMAT JSON, '$'  -- If payload is an array, change to '$[*]'
            COLUMNS (
                forecastname VARCHAR2 PATH '$.forecastname',
                slotstatus VARCHAR2 PATH '$.slotstatus',
                customername VARCHAR2  PATH '$.customername',
                customersite VARCHAR2  PATH '$.customersite',
                confignum VARCHAR2  PATH '$.confignum',
                salesorder VARCHAR2 PATH '$.salesorder',
                changereason VARCHAR2  PATH '$.changereason',
                mktcomments VARCHAR2  PATH '$.mktcomments',
                created_by VARCHAR2  PATH '$.created_by',
                raised_by VARCHAR2 PATH '$.raised_by',
				 created_date VARCHAR2 PATH '$.created_date',
				  request_date VARCHAR2 PATH '$.request_date',
				  request_qtr VARCHAR2 PATH '$.request_qtr',
				  slotnumber VARCHAR2 PATH '$.slotnumber',
                  promise_date VARCHAR2 PATH '$.promise_date',
                   pd_qtr VARCHAR2 PATH '$.pd_qtr'
            )
        )
		;

    rec_cr_data         cur_cr_data%rowtype;
---start cursor finance page
    CURSOR cur_data_fin (
        p_data BLOB
    ) IS
    SELECT
        finance_id,
        slot_id,
        slot_number,
        slot_type,
        customer,
        revenue_risk,
        system_count_adj,
        revenue_adj,
        cogs_adj,
        revenue_qtr,
        source,
        pd_qtr,
        slot_status,
        system,
        sales_order,
        platform,
        adjustment_comment,
        finance_comments,
        created_by,
        created_date,
        updated_by,
        updated_date
    FROM
        JSON_TABLE ( p_data FORMAT JSON, '$'
            COLUMNS (
                finance_id NUMBER PATH '$.finance_id',
                slot_id NUMBER PATH '$.slot_id',
                slot_number VARCHAR2 PATH '$.slot_number',
                slot_type VARCHAR2 PATH '$.slot_type',
                customer VARCHAR2 PATH '$.customer',
                revenue_risk VARCHAR2 PATH '$.revenue_risk',
                system_count_adj NUMBER PATH '$.system_count_adj',
                revenue_adj NUMBER PATH '$.revenue_adj',
                cogs_adj NUMBER PATH '$.cogs_adj',
                revenue_qtr VARCHAR2 PATH '$.revenue_qtr',
                source VARCHAR2 PATH '$.source',
                pd_qtr VARCHAR2 PATH '$.pd_qtr',
                slot_status VARCHAR2 PATH '$.slot_status',
                system VARCHAR2 PATH '$.system',
                sales_order VARCHAR2 PATH '$.sales_order',
                platform VARCHAR2 PATH '$.platform',
                adjustment_comment VARCHAR2 PATH '$.adjustment_comment',
                finance_comments VARCHAR2 PATH '$.finance_comments',
                created_by VARCHAR2 PATH '$.created_by',
                created_date TIMESTAMP PATH '$.created_date',
                updated_by VARCHAR2 PATH '$.updated_by',
                updated_date TIMESTAMP PATH '$.updated_date'
            )
        );

    rec_data             cur_data_fin%rowtype;
    l_err_code           VARCHAR2(1);
    l_err_msg            VARCHAR2(2000);
    l_primarykey         NUMBER;
    v_primarykey         VARCHAR2(2000);
---end cursor finance page

    CURSOR cur_ops_data_slot (
        p_data BLOB
    ) IS
    SELECT
        slot_number,
        slot_type,
        slot_status,
        mrp_qtr,
        pd_qtr,
        promised_date,
        scheduled_date,
        updated_date_ts,
        config_num,
        planning_organization,
        mfr,
        mfr_site,
        operations_comments,
        created_by,
        updated_by
    FROM
        JSON_TABLE ( p_data FORMAT JSON, '$'   -- If payload is an array, change to '$[*]'
            COLUMNS (
                slot_number VARCHAR2 ( 250 ) PATH '$.slotNumber',
                slot_type VARCHAR2 ( 200 ) PATH '$.slotType',
                slot_status VARCHAR2 ( 50 ) PATH '$.slotStatus',
                mrp_qtr VARCHAR2 ( 30 ) PATH '$.mrpQtr',
                pd_qtr VARCHAR2 ( 50 ) PATH '$.pdQtr',
                promised_date VARCHAR2 ( 50 ) PATH '$.promisedDate',
                scheduled_date VARCHAR2 ( 50 ) PATH '$.scheduledDate',
                updated_date_ts TIMESTAMP PATH '$.updatedDate',
                config_num VARCHAR2 ( 50 ) PATH '$.configNumber',
                planning_organization VARCHAR2 ( 200 ) PATH '$.planningOrganization',
                mfr VARCHAR2 ( 200 ) PATH '$.manufacture',
                mfr_site VARCHAR2 ( 200 ) PATH '$.manufactureSite',
                operations_comments VARCHAR2 ( 4000 ) PATH '$.operationComments',
                created_by VARCHAR2 ( 200 ) PATH '$.createdBy',
                updated_by VARCHAR2 ( 200 ) PATH '$.updatedBy'
            )
        );

    rec_ops_data         cur_ops_data_slot%rowtype;
    l_operation_err_code VARCHAR2(50);
    l_operation_err_msg  VARCHAR2(2000);
    
    CURSOR cur_mkt_data_slot (
        p_data BLOB
    ) IS
    SELECT
        config_number,
        scheduled_date_s,
        marketing_comments,
        created_by,
        updated_by,
        updated_date_ts,
        slot_type,
        promise_date_s,
        slot_number,
        revenue_risk
    FROM
        JSON_TABLE ( p_data FORMAT JSON, '$'  -- If payload is an array, change to '$[*]'
            COLUMNS (
                config_number VARCHAR2 ( 50 ) PATH '$.configNumber',
                scheduled_date_s VARCHAR2 ( 50 ) PATH '$.scheduledDate',
                marketing_comments VARCHAR2 ( 4000 ) PATH '$.marketingComments',
                created_by VARCHAR2 ( 200 ) PATH '$.createdBy',
                updated_by VARCHAR2 ( 200 ) PATH '$.updatedBy',
                updated_date_ts TIMESTAMP PATH '$.updatedDate',
                slot_type VARCHAR2 ( 200 ) PATH '$.slotType',
                promise_date_s VARCHAR2 ( 50 ) PATH '$.promisedDate',
                slot_number VARCHAR2 ( 250 ) PATH '$.slotNumber',
                revenue_risk VARCHAR2 PATH '$.revenueRisk'
            )
        );

    rec_mkt_data         cur_mkt_data_slot%rowtype;
    l_marketing_err_code VARCHAR2(20);
    l_marketing_err_msg  VARCHAR2(2000);

    PROCEDURE terslot_delete_prc (
        p_slot_number   IN VARCHAR2,
        o_status        OUT VARCHAR2,
        o_error_message OUT VARCHAR2
    ) IS
        v_count NUMBER;
    BEGIN
        SELECT
            COUNT(*)
        INTO v_count
        FROM
            terext_slot_plan_dtls
        WHERE
            slot_number = p_slot_number;

        IF v_count > 0 THEN
            DELETE FROM terext_slot_parts
            WHERE
                slot_number = p_slot_number;

            DELETE FROM terext_slot_plan_ops_dtls
            WHERE
                slot_number = p_slot_number;

            DELETE FROM terext_slot_plan_mkt_dtls
            WHERE
                slot_number = p_slot_number;

            DELETE FROM terext_slot_plan_fin_dtls
            WHERE
                slot_number = p_slot_number;

            DELETE FROM terext_slot_plan_dtls
            WHERE
                slot_number = p_slot_number;

            COMMIT;
            o_status := 'Success';
            o_error_message := 'Slot data deleted successfully for SLOT_NUMBER = ' || p_slot_number;
        ELSIF v_count = 0 THEN
            o_error_message := 'No data found for SLOT_NUMBER = ' || p_slot_number;
            o_status := 'Failed';
            RETURN;
        ELSE
            o_error_message := 'Unknown Error = ' || p_slot_number;
            o_status := 'Failed';
        END IF;

    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            o_status := 'Error';
            o_error_message := sqlerrm;
    END terslot_delete_prc;

---finance page procedure begins        
    PROCEDURE process_data (
        p_method     IN VARCHAR2,
        p_primarykey IN VARCHAR2,
        p_data       IN BLOB
    ) IS
    BEGIN
        IF p_method = 'POST' THEN
            post_data(p_primarykey, p_data);
        ELSIF p_method = 'PUT' THEN
            put_data(p_primarykey, p_data);
        END IF;
    END process_data;

    PROCEDURE post_data (
        p_primarykey IN VARCHAR2,
        p_data       IN BLOB
    ) IS
        l_seq_id NUMBER := slot_finance_ext_seq.nextval;
        l_count  NUMBER;
    BEGIN
        OPEN cur_data_fin(p_data);
        FETCH cur_data_fin INTO rec_data;
        CLOSE cur_data_fin;
        INSERT INTO terext_slot_plan_fin_dtls (
            finance_id,
--            slot_id,
            slot_number,
            slot_type,
            customer,
            revenue_risk,
            system_count_adj,
            revenue_adj,
            cogs_adj,
            revenue_qtr,
            source,
            pd_qtr,
            slot_status,
            system,
            sales_order,
            platform,
            adjustment_comment,
            finance_comments,
            created_by,
            created_date,
            updated_by,
            updated_date
        ) VALUES (
            l_seq_id,
--            rec_data.slot_id,
            rec_data.slot_number,
            rec_data.slot_type,
            rec_data.customer,
            rec_data.revenue_risk,
            rec_data.system_count_adj,
            rec_data.revenue_adj,
            rec_data.cogs_adj,
            rec_data.revenue_qtr,
            'Extension',
            rec_data.pd_qtr,
            rec_data.slot_status,
            rec_data.system,
            rec_data.sales_order,
            rec_data.platform,
            rec_data.adjustment_comment,
            rec_data.finance_comments,
            rec_data.created_by,
            rec_data.created_date,
            rec_data.updated_by,
            rec_data.updated_date
        );

        l_primarykey := l_seq_id;
        COMMIT;
        l_err_code := 'S';
        l_err_msg := 'Information Saved Successfully';
        apex_json.open_object;
        apex_json.write('p_err_code', l_err_code);
        apex_json.write('p_err_msg', l_err_msg);
        apex_json.write('p_primarykey', l_primarykey);
        apex_json.close_object;
    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            l_err_code := 'E';
            l_err_msg := 'API Error - ' || sqlerrm;
            apex_json.open_object;
            apex_json.write('p_err_code', l_err_code);
            apex_json.write('p_err_msg', l_err_msg);
            apex_json.write('p_primarykey', l_primarykey);
            apex_json.close_object;
    END post_data;

    PROCEDURE put_data (
        p_primarykey IN VARCHAR2,
        p_data       IN BLOB
    ) IS
    BEGIN
        OPEN cur_data_fin(p_data);
        FETCH cur_data_fin INTO rec_data;
        CLOSE cur_data_fin;
        UPDATE terext_slot_plan_fin_dtls
        SET
            revenue_risk = rec_data.revenue_risk,
            system_count_adj = rec_data.system_count_adj,
            revenue_adj = rec_data.revenue_adj,
            cogs_adj = rec_data.cogs_adj,
            revenue_qtr = rec_data.revenue_qtr,
            source = 'Extension',
            adjustment_comment = rec_data.adjustment_comment,
            finance_comments = rec_data.finance_comments,
            updated_by = rec_data.updated_by,
            updated_date = rec_data.updated_date
        WHERE
            slot_number = p_primarykey;

        v_primarykey := p_primarykey;
        COMMIT;
        l_err_code := 'S';
        l_err_msg := 'Information Saved Successfully';
        apex_json.open_object;
        apex_json.write('p_err_code', l_err_code);
        apex_json.write('p_err_msg', l_err_msg);
        apex_json.write('p_primarykey', v_primarykey);
        apex_json.close_object;
    EXCEPTION
        WHEN OTHERS THEN
            l_err_code := 'E';
            l_err_msg := 'API UPDATE Error - ' || sqlerrm;
            dbms_output.put_line('Error > '
                                 || sqlcode
                                 || sqlerrm);
            apex_json.open_object;
            apex_json.write('p_err_code', l_err_code);
            apex_json.write('p_err_msg', l_err_msg);
            apex_json.write('p_primarykey', l_primarykey);
            apex_json.close_object;
    END put_data;

---finance page procedure ends  

    PROCEDURE operation_process_data (
        p_method IN VARCHAR2,
        p_data   IN BLOB
    ) IS
    BEGIN
        IF p_method = 'POST' THEN
            operation_post_data(p_data);
        ELSIF p_method = 'PUT' THEN
            operation_put_data(p_data);
        ELSE
            l_operation_err_code := 'Error';
            l_operation_err_msg := 'Unsupported method: ' || p_method;
            apex_json.open_object;
            apex_json.write('p_err_code', l_operation_err_code);
            apex_json.write('p_err_msg', l_operation_err_msg);
            apex_json.close_object;
        END IF;
    END operation_process_data;


/* POST = upsert into PLAN + insert-only into OPS */
    PROCEDURE operation_post_data (
        p_data IN BLOB
    ) IS
    BEGIN
        OPEN cur_ops_data_slot(p_data);
        FETCH cur_ops_data_slot INTO rec_ops_data;
        CLOSE cur_ops_data_slot;

    -- OPS insert (audit trail)
        INSERT INTO terext_slot_plan_ops_dtls (
            planning_organization,
            mfr,
            mfr_site,
            operations_comments,
            created_by,
            updated_by,
            updated_date,
            slot_type,
            slot_number
        ) VALUES (
            rec_ops_data.planning_organization,
            rec_ops_data.mfr,
            rec_ops_data.mfr_site,
            rec_ops_data.operations_comments,
            rec_ops_data.created_by,
            rec_ops_data.updated_by,
            CAST(rec_ops_data.updated_date_ts AS DATE),
            rec_ops_data.slot_type,
            rec_ops_data.slot_number
        );

    -- PLAN upsert
        MERGE INTO terext_slot_plan_dtls t
        USING (
            SELECT
                rec_ops_data.slot_number                   AS slot_number,
                rec_ops_data.pd_qtr                        AS pd_qtr,
                rec_ops_data.slot_type                     AS slot_type,
                rec_ops_data.slot_status                   AS slot_status,
                rec_ops_data.mrp_qtr                       AS mrp_qtr,
                CASE
                    WHEN rec_ops_data.promised_date IS NULL THEN
                        NULL
                    ELSE
                        TO_DATE(substr(rec_ops_data.promised_date, 1, 10),
                                'YYYY-MM-DD')
                END                                        AS promised_date,
                CASE
                    WHEN rec_ops_data.scheduled_date IS NULL THEN
                        NULL
                    ELSE
                        TO_DATE(substr(rec_ops_data.scheduled_date, 1, 10),
                                'YYYY-MM-DD')
                END                                        AS schedule_date,
                /*TO_NUMBER(nullif(TRIM(rec_ops_data.config_num),
                                 ''))                                       AS config_number,*/ --commented by veera 15-apr-26
                  nullif(TRIM(rec_ops_data.config_num),
                                 '')                                       AS config_number,                 
                                 
                                                 
                rec_ops_data.planning_organization         AS planning_organization,
                rec_ops_data.mfr                           AS manufacture,
                rec_ops_data.mfr_site                      AS manufacture_site,
                rec_ops_data.operations_comments           AS operation_comments,
                rec_ops_data.updated_by                    AS updated_by,
                CAST(rec_ops_data.updated_date_ts AS DATE) AS updated_date
            FROM
                dual
        ) s ON ( t.slot_number = s.slot_number )
        WHEN MATCHED THEN UPDATE
        SET t.pd_qtr = s.pd_qtr,
            t.slot_type = s.slot_type,
            t.slot_status = s.slot_status,
            t.mrp_qtr = s.mrp_qtr,
            t.promised_date = s.promised_date,
            t.schedule_date = s.schedule_date,
            t.config_number = s.config_number,
            t.planning_organization = s.planning_organization,
            t.manufacture = s.manufacture,
            t.manufacture_site = s.manufacture_site,
            t.operation_comments = s.operation_comments,
            t.updated_by = s.updated_by,
            t.updated_date = s.updated_date
        WHEN NOT MATCHED THEN
        INSERT (
            slot_number,
            pd_qtr,
            slot_type,
            slot_status,
            mrp_qtr,
            promised_date,
            schedule_date,
            config_number,
            planning_organization,
            manufacture,
            manufacture_site,
            operation_comments,
            updated_by,
            updated_date )
        VALUES
            ( s.slot_number,
              s.pd_qtr,
              s.slot_type,
              s.slot_status,
              s.mrp_qtr,
              s.promised_date,
              s.schedule_date,
              s.config_number,
              s.planning_organization,
              s.manufacture,
              s.manufacture_site,
              s.operation_comments,
              s.updated_by,
              s.updated_date );

        MERGE INTO terext_slot_plan_mkt_dtls x
        USING (
            SELECT
                rec_ops_data.slot_number AS slot_number,
                rec_ops_data.slot_type   AS slot_type
            FROM
                dual
        ) s2 ON ( x.slot_number = s2.slot_number )
        WHEN MATCHED THEN UPDATE
        SET x.slot_type = s2.slot_type;

        COMMIT;
        l_operation_err_code := 'Success';
        l_operation_err_msg := 'Operation Changes Saved Successfully';
        apex_json.open_object;
        apex_json.write('p_err_code', l_operation_err_code);
        apex_json.write('p_err_msg', l_operation_err_msg);
        apex_json.write('slot_number', rec_ops_data.slot_number);
        apex_json.close_object;
    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            l_operation_err_code := 'Error';
            l_operation_err_msg := 'API Error - ' || sqlerrm;
            apex_json.open_object;
            apex_json.write('p_err_code', l_operation_err_code);
            apex_json.write('p_err_msg', l_operation_err_msg);
            apex_json.write('slot_number', rec_ops_data.slot_number);
            apex_json.close_object;
    END operation_post_data;

    PROCEDURE operation_put_data (
        p_data IN BLOB
    ) IS
    BEGIN
        OPEN cur_ops_data_slot(p_data);
        FETCH cur_ops_data_slot INTO rec_ops_data;
        CLOSE cur_ops_data_slot;
        UPDATE terext_slot_plan_ops_dtls o
        SET
            o.planning_organization = rec_ops_data.planning_organization,
            o.operations_comments = rec_ops_data.operations_comments,
            o.slot_type = rec_ops_data.slot_type,
            o.mfr = rec_ops_data.mfr,
            o.mfr_site = rec_ops_data.mfr_site,
            o.updated_by = rec_ops_data.updated_by,
            o.updated_date = CAST(rec_ops_data.updated_date_ts AS DATE)
        WHERE
            o.slot_number = rec_ops_data.slot_number;

        UPDATE terext_slot_plan_dtls t
        SET
            t.planning_organization = rec_ops_data.planning_organization,
            t.operation_comments = rec_ops_data.operations_comments,
            t.slot_type = rec_ops_data.slot_type,
            t.manufacture = rec_ops_data.mfr,
            t.manufacture_site = rec_ops_data.mfr_site,
            t.promised_date =
                CASE
                    WHEN rec_ops_data.promised_date IS NULL THEN
                        NULL
                    ELSE
                        TO_DATE(substr(rec_ops_data.promised_date, 1, 10),
                                'YYYY-MM-DD')
                END,
            t.schedule_date =
                CASE
                    WHEN rec_ops_data.scheduled_date IS NULL THEN
                        NULL
                    ELSE
                        TO_DATE(substr(rec_ops_data.scheduled_date, 1, 10),
                                'YYYY-MM-DD')
                END,
            t.mrp_qtr = rec_ops_data.mrp_qtr,
            t.pd_qtr = rec_ops_data.pd_qtr,
           /* t.config_number = TO_NUMBER(nullif(TRIM(rec_ops_data.config_num),
                                               '')), */                         --commented by veera 15-Apr-26
            t.config_number = nullif(TRIM(rec_ops_data.config_num),
                                               ''),
            t.updated_by = rec_ops_data.updated_by,
            t.updated_date = CAST(rec_ops_data.updated_date_ts AS DATE)
        WHERE
            t.slot_number = rec_ops_data.slot_number;

        MERGE INTO terext_slot_plan_mkt_dtls x
        USING (
            SELECT
                rec_ops_data.slot_number AS slot_number,
                rec_ops_data.slot_type   AS slot_type
            FROM
                dual
        ) s2 ON ( x.slot_number = s2.slot_number )
        WHEN MATCHED THEN UPDATE
        SET x.slot_type = s2.slot_type;

        COMMIT;
        l_operation_err_code := 'Success';
        l_operation_err_msg := 'Operation Changes Saved Successfully';
        apex_json.open_object;
        apex_json.write('p_err_code', l_operation_err_code);
        apex_json.write('p_err_msg', l_operation_err_msg);
        apex_json.write('slot_number', rec_ops_data.slot_number);
        apex_json.close_object;
    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            l_operation_err_code := 'Error';
            l_operation_err_msg := 'API UPDATE Error - ' || sqlerrm;
            apex_json.open_object;
            apex_json.write('p_err_code', l_operation_err_code);
            apex_json.write('p_err_msg', l_operation_err_msg);
            apex_json.write('slot_number', rec_ops_data.slot_number);
            apex_json.close_object;
    END operation_put_data;

