            apex_json.write('p_err_msg', l_marketing_err_msg);
            apex_json.write('slot_number', rec_mkt_data.slot_number);
            apex_json.close_object;
    END marketing_put_data;
    
    
    PROCEDURE cr_post_data (
        p_data IN BLOB
    )
	
	is
	
	
	l_cr_err_code           VARCHAR2(10);
    l_cr_err_msg            VARCHAR2(1000);
	
	BEGIN 
	
    OPEN cur_cr_data(p_data);
    FETCH cur_cr_data INTO rec_cr_data;
    CLOSE cur_cr_data;

    -- Insert into cr details 
    INSERT INTO terext_slot_cr_dtls (
        slot_number,
        new_forecast_name,
        new_slot_status,
        new_customer_name,
        new_customer_site,
        new_config_number,
        new_sales_order,
        new_promised_date,
        change_reason,
        marketing_comments,
        request_status,
        request_date,
        request_qtr,
        created_by,
        raised_by,
        created_date,
        new_pd_qtr
    ) VALUES(
    rec_cr_data.slotnumber,
	rec_cr_data.forecastname,
	rec_cr_data.slotstatus,
	rec_cr_data.customername,
	rec_cr_data.customersite,
	rec_cr_data.confignum,
	rec_cr_data.salesorder,
	to_date(rec_cr_data.promise_date,'YYYY-MM-DD'),--sysdate, 
	rec_cr_data.changereason,
	rec_cr_data.mktcomments,
	'Submitted',
	to_date(rec_cr_data.request_date,'YYYY-MM-DD'),
	rec_cr_data.request_qtr,
	rec_cr_data.created_by,
	rec_cr_data.raised_by,
	to_date(rec_cr_data.created_date,'YYYY-MM-DD'),
    rec_cr_data.pd_qtr
	);	
		
  COMMIT;
        l_cr_err_code := 'Success';
        l_cr_err_msg := 'CR Data Saved Successfully';
        apex_json.open_object;
        apex_json.write('p_err_code', l_cr_err_code);
        apex_json.write('p_err_msg', l_cr_err_msg);
        --apex_json.write('slot_number', rec_mkt_data.slot_number);
        apex_json.close_object;
    EXCEPTION 
		WHEN OTHERS THEN
            ROLLBACK;
            l_cr_err_code := 'Error';
            l_cr_err_msg := 'API Insert Error - ' || SUBSTR(sqlerrm,1,1000);
            apex_json.open_object;
            apex_json.write('p_err_code', l_cr_err_code);
            apex_json.write('p_err_msg', l_cr_err_msg);
            --apex_json.write('slot_number', rec_mkt_data.slot_number);
            apex_json.close_object;
	
	END;
	

END terslot_common_util_pkg;

