--------------------------------------------------------
--  DDL for Package Body TERSLOT_MANAGE_CONFIG_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TERSLOT_MANAGE_CONFIG_PKG" AS

    PROCEDURE update_default_config_details (
        p_body_text IN CLOB,
        p_status    OUT VARCHAR2,
        p_message   OUT VARCHAR2
    ) AS

        l_json_array     json_array_t;
        l_json_obj       json_object_t;
        l_config_number  VARCHAR2(100);
        l_default_config VARCHAR2(50);
        l_effective_from VARCHAR2(50);
        l_updated_by     VARCHAR2(100);
        l_update_count   NUMBER := 0;
    BEGIN
        l_json_array := json_array_t.parse(p_body_text);
        FOR i IN 0..l_json_array.get_size - 1 LOOP
            l_json_obj := json_object_t(l_json_array.get(i));
            l_config_number := l_json_obj.get_string('config_number');
            l_default_config := l_json_obj.get_string('default_config');
            l_effective_from := l_json_obj.get_string('effective_from');
            l_updated_by := l_json_obj.get_string('updated_by');
            UPDATE terext_slot_manage_config_dtls
            SET
                default_config =
                    CASE
                        WHEN l_default_config = 'Yes' THEN
                            'Default'
                        ELSE
                            NULL
                    END,
                effective_from = TO_DATE(l_effective_from, 'YYYY-MM-DD'),
                updated_by = l_updated_by,
                updated_date = sysdate
            WHERE
                config_number = l_config_number;

            l_update_count := l_update_count + SQL%rowcount;
        END LOOP;

        COMMIT;
        p_status := 'SUCCESS';
        p_message := l_update_count || ' record(s) updated successfully.';
    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            p_status := 'ERROR';
            p_message := sqlerrm;
    END update_default_config_details;

    PROCEDURE update_manage_config_details (
        p_body_text IN CLOB,
        p_status    OUT VARCHAR2,
        p_message   OUT VARCHAR2
    ) AS

        l_json                   json_object_t;
        l_header                 json_object_t;
        l_lines                  json_array_t;
        l_delete_lines           json_array_t;
        l_line                   json_object_t;
        l_delete_line            json_object_t;
        l_operation              VARCHAR2(50);
        l_config_number          VARCHAR2(100);
        l_original_config_number VARCHAR2(100);
        l_platform               VARCHAR2(200);
        l_system                 VARCHAR2(200);
        l_slot_type              VARCHAR2(200);
        l_created_by             VARCHAR2(200);
        l_updated_by             VARCHAR2(200);
        l_part_number            VARCHAR2(200);
        l_part_description       VARCHAR2(500);
        l_quantity               NUMBER;
        l_line_created_by        VARCHAR2(200);
        l_line_updated_by        VARCHAR2(200);
        l_record_count           NUMBER := 0;
        l_delete_count           NUMBER := 0;
    BEGIN
        l_json := json_object_t.parse(p_body_text);
        l_operation := l_json.get_string('operation');
        l_header := l_json.get_object('header');
        l_lines := l_json.get_array('lines');
        l_config_number := l_header.get_string('config_number');
        IF upper(l_operation) = 'CREATE' THEN
            l_platform := l_header.get_string('platform');
            l_system := l_header.get_string('system');
            l_slot_type := l_header.get_string('slot_type');
            l_created_by := l_header.get_string('created_by');
            INSERT INTO terext_slot_manage_config_dtls (
                config_number,
                platform,
                system,
                slot_type,
                created_by,
                created_date
            ) VALUES (
                l_config_number,
                l_platform,
                l_system,
                l_slot_type,
                l_created_by,
                sysdate
            );

            FOR i IN 0..l_lines.get_size - 1 LOOP
                l_line := json_object_t(l_lines.get(i));
                l_part_number := l_line.get_string('part_number');
                l_part_description := l_line.get_string('part_description');
                l_quantity := l_line.get_number('quantity');
                l_line_created_by := l_line.get_string('created_by');
                INSERT INTO terext_slot_default_config (
                    config_number,
                    part_number,
                    part_description,
                    quantity,
                    created_by,
                    created_date
                ) VALUES (
                    l_config_number,
                    l_part_number,
                    l_part_description,
                    l_quantity,
                    l_line_created_by,
                    sysdate
                );

                l_record_count := l_record_count + 1;
            END LOOP;

            COMMIT;
            p_status := 'SUCCESS';
            p_message := 'Configuration created with '
                         || l_record_count
                         || ' line(s).';
        ELSIF upper(l_operation) = 'EDIT' THEN
            l_config_number := l_header.get_string('config_number');
            l_original_config_number := l_header.get_string('original_config_number');
            l_updated_by := l_header.get_string('updated_by');
            UPDATE terext_slot_manage_config_dtls
            SET
                config_number = l_config_number,
                updated_by = l_updated_by,
                updated_date = sysdate
            WHERE
                config_number = l_original_config_number;

            IF l_json.has('delete_lines') THEN
                l_delete_lines := l_json.get_array('delete_lines');
                FOR j IN 0..l_delete_lines.get_size - 1 LOOP
                    l_delete_line := json_object_t(l_delete_lines.get(j));
                    l_part_number := l_delete_line.get_string('part_number');
                    DELETE FROM terext_slot_default_config
                    WHERE
                            part_number = l_part_number
                        AND config_number = l_original_config_number;

                    l_delete_count := l_delete_count + SQL%rowcount;
                END LOOP;

            END IF;

            FOR i IN 0..l_lines.get_size - 1 LOOP
                l_line := json_object_t(l_lines.get(i));
                l_part_number := l_line.get_string('part_number');
                l_part_description := l_line.get_string('part_description');
                l_quantity := l_line.get_number('quantity');
                l_line_updated_by := l_line.get_string('updated_by');
                UPDATE terext_slot_default_config
                SET
                    config_number = l_config_number,
                    quantity = l_quantity,
                    updated_by = l_line_updated_by,
                    updated_date = sysdate
                WHERE
                        part_number = l_part_number
                    AND config_number = l_original_config_number;

                IF SQL%rowcount = 0 THEN
                    INSERT INTO terext_slot_default_config (
                        part_number,
                        part_description,
                        config_number,
                        quantity,
                        created_by,
                        created_date
                    ) VALUES (
                        l_part_number,
                        l_part_description,
                        l_config_number,
                        l_quantity,
                        l_line_updated_by,
                        sysdate
                    );

                END IF;

                l_record_count := l_record_count + SQL%rowcount;
            END LOOP;

            COMMIT;
            p_status := 'SUCCESS';
            p_message := l_record_count
                         || ' record(s) updated, '
                         || l_delete_count
                         || ' record(s) deleted.';
        ELSE
            p_status := 'ERROR';
            p_message := 'Invalid operation: '
                         || l_operation
                         || '. Expected CREATE or EDIT.';
        END IF;

    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            p_status := 'ERROR';
            p_message := sqlerrm;
    END update_manage_config_details;

    PROCEDURE manage_config_validate_csv (
        p_filename IN VARCHAR2
    ) IS
    BEGIN
  -----------------------------------------------------------------
  -- STEP 1: Build multi-column error messages and mark INVALID
  -----------------------------------------------------------------
        UPDATE terext_slot_manage_config_bulk_upload_csv c
        SET
            status = 'INVALID',
            error_msg = rtrim(
                CASE
                    WHEN NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terext_slot_platform_dtls e
                        WHERE
                            e.platform = c.platform
                    ) THEN
                        'PLATFORM not found; '
                END
                ||
                CASE
                    WHEN NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terext_slot_system_dtls d
                        WHERE
                                d.system = c.system
                            AND d.platform = c.platform
                    ) THEN
                        'SYSTEM not found; '
                END
                ||
                CASE
                    WHEN NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terext_slot_type g
                        WHERE
                            g.name = c.slot_type
                    ) THEN
                        'SLOT TYPE not found; '
                END
                ||
                CASE
                    WHEN NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terext_slot_item_structure_config a
                        WHERE
                            a.part_number = c.part_number
                    ) THEN
                        'PART NUMBER not found; '
                END
                ||
                CASE
                    WHEN NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terext_slot_item_structure_config b
                        WHERE
                                b.part_description = c.part_description
                            AND b.part_number = c.part_number
                    ) THEN
                        'PART DESCRIPTION not found; '
                END
                ||
                CASE
                    WHEN EXISTS(
                        SELECT
                            1
                        FROM
                            terext_slot_manage_config_dtls f
                        WHERE
                            f.config_number = c.config_number
                    ) THEN
                        'CONFIG NUMBER already exists; '
                END
            )
        WHERE
                filename = p_filename
            AND ( NOT EXISTS (
                SELECT
                    1
                FROM
                    terext_slot_platform_dtls e
                WHERE
                    e.platform = c.platform
            )
                      OR NOT EXISTS (
                SELECT
                    1
                FROM
                    terext_slot_system_dtls d
                WHERE
                        d.system = c.system
                    AND d.platform = c.platform
            )
                      OR NOT EXISTS (
                SELECT
                    1
                FROM
                    terext_slot_type g
                WHERE
                    g.name = c.slot_type
            )
                      OR NOT EXISTS (
                SELECT
                    1
                FROM
                    terext_slot_item_structure_config a
                WHERE
                    a.part_number = c.part_number
            )
                      OR NOT EXISTS (
                SELECT
                    1
                FROM
                    terext_slot_item_structure_config b
                WHERE
                        b.part_description = c.part_description
                    AND b.part_number = c.part_number
            )
                      OR EXISTS (
                SELECT
                    1
                FROM
                    terext_slot_manage_config_dtls f
                WHERE
                    f.config_number = c.config_number
            ) );

  -----------------------------------------------------------------
  -- STEP 2: Mark remaining records as VALID
  -----------------------------------------------------------------
        UPDATE terext_slot_manage_config_bulk_upload_csv
        SET
            status = 'VALID',
            error_msg = NULL
        WHERE
                filename = p_filename
            AND status IS NULL;

    END manage_config_validate_csv;

    PROCEDURE bulk_upload_insert_from_json (
        p_payload   IN CLOB,
        p_cfg_rows  OUT NUMBER,
        p_part_rows OUT NUMBER
    ) IS
    BEGIN
        p_cfg_rows := 0;
        p_part_rows := 0;
        INSERT INTO terext_slot_manage_config_dtls (
            config_number,
            platform,
            system,
            slot_type,
            created_by
        )
            SELECT
                jt.config_number,
                jt.platform,
                jt.system,
                jt.slot_type,
                jt.created_by
            FROM
                    JSON_TABLE ( p_payload, '$.configPayload[*]'
                        COLUMNS (
                            config_number VARCHAR2 ( 4000 ) PATH '$.CONFIG_NUMBER',
                            platform VARCHAR2 ( 4000 ) PATH '$.PLATFORM',
                            system VARCHAR2 ( 4000 ) PATH '$.SYSTEM',
                            slot_type VARCHAR2 ( 4000 ) PATH '$.SLOT_TYPE',
                            created_by VARCHAR2 ( 250 ) PATH '$.CREATED_BY'
                        )
                    )
                jt;

        p_cfg_rows := SQL%rowcount;
        INSERT INTO terext_slot_default_config (
            config_number,
            part_description,
            part_number,
            quantity,
            created_by
        )
            SELECT
                jt.config_number,
                jt.part_description,
                jt.part_number,
                jt.quantity,
                jt.created_by
            FROM
                    JSON_TABLE ( p_payload, '$.partsPayload[*]'
                        COLUMNS (
                            config_number VARCHAR2 ( 4000 ) PATH '$.CONFIG_NUMBER',
                            part_number VARCHAR2 ( 4000 ) PATH '$.PART_NUMBER',
                            part_description VARCHAR2 ( 4000 ) PATH '$.PART_DESCRIPTION',
                            quantity NUMBER PATH '$.QUANTITY',
                            created_by VARCHAR2 ( 250 ) PATH '$.CREATED_BY'
                        )
                    )
                jt;

        p_part_rows := SQL%rowcount;
        IF
            p_cfg_rows = 0
            AND p_part_rows = 0
        THEN
            raise_application_error(-20010, 'No rows inserted (payload empty or paths missing).');
        END IF;

    EXCEPTION
        WHEN OTHERS THEN
    -- Prefer NOT to ROLLBACK here unless you want to cancel the caller’s whole transaction.
            RAISE;
    END bulk_upload_insert_from_json;

    PROCEDURE default_config_scheduler_prc (
        p_updated_by IN VARCHAR2 DEFAULT 'SCHEDULER_JOB',
        p_do_commit  IN BOOLEAN DEFAULT TRUE
    ) IS
    BEGIN
        UPDATE terext_slot_manage_config_dtls t
        SET
            t.default_config =
                CASE
                    WHEN t.effective_from = (
                            SELECT
                                MAX(x.effective_from)
                            FROM
                                terext_slot_manage_config_dtls x
                            WHERE
                                    x.platform = t.platform
                                AND x.system = t.system
                                AND x.slot_type = t.slot_type
                                AND x.effective_from <= systimestamp
                        )
                         AND decode(t.created_date,
                                    (
                                                 SELECT
                                                     MAX(x.created_date)
                                                 FROM
                                                     terext_slot_manage_config_dtls x
                                                 WHERE
                                                         x.platform = t.platform
                                                     AND x.system = t.system
                                                     AND x.slot_type = t.slot_type
                                                     AND x.effective_from <= systimestamp
                                                     AND x.effective_from =(
                                                         SELECT
                                                             MAX(y.effective_from)
                                                         FROM
                                                             terext_slot_manage_config_dtls y
                                                         WHERE
                                                                 y.platform = t.platform
                                                             AND y.system = t.system
                                                             AND y.slot_type = t.slot_type
                                                             AND y.effective_from <= systimestamp
                                                     )
                                             ),
                                    1,
                                    0) = 1 THEN
                        'Default'
                    WHEN t.default_config = 'Default'
                         AND NOT ( t.effective_from = (
                            SELECT
                                MAX(x.effective_from)
                            FROM
                                terext_slot_manage_config_dtls x
                            WHERE
                                    x.platform = t.platform
                                AND x.system = t.system
                                AND x.slot_type = t.slot_type
                                AND x.effective_from <= systimestamp
                        )
                                   AND decode(t.created_date,
                                              (
                                                           SELECT
                                                               MAX(x.created_date)
                                                           FROM
                                                               terext_slot_manage_config_dtls x
                                                           WHERE
                                                                   x.platform = t.platform
                                                               AND x.system = t.system
                                                               AND x.slot_type = t.slot_type
                                                               AND x.effective_from <= systimestamp
                                                               AND x.effective_from =(
                                                                   SELECT
                                                                       MAX(y.effective_from)
                                                                   FROM
                                                                       terext_slot_manage_config_dtls y
                                                                   WHERE
                                                                           y.platform = t.platform
                                                                       AND y.system = t.system
                                                                       AND y.slot_type = t.slot_type
                                                                       AND y.effective_from <= systimestamp
                                                               )
                                                       ),
                                              1,
                                              0) = 1 ) THEN
                        NULL
                    ELSE
                        t.default_config
                END,
            t.updated_by = p_updated_by,
            t.updated_date = sysdate
        WHERE
            ( t.effective_from = (
                    SELECT
                        MAX(x.effective_from)
                    FROM
                        terext_slot_manage_config_dtls x
                    WHERE
                            x.platform = t.platform
                        AND x.system = t.system
                        AND x.slot_type = t.slot_type
                        AND x.effective_from <= systimestamp
                )
              AND decode(t.created_date,
                         (
                                  SELECT
                                      MAX(x.created_date)
                                  FROM
                                      terext_slot_manage_config_dtls x
                                  WHERE
                                          x.platform = t.platform
                                      AND x.system = t.system
                                      AND x.slot_type = t.slot_type
                                      AND x.effective_from <= systimestamp
                                      AND x.effective_from =(
                                          SELECT
                                              MAX(y.effective_from)
                                          FROM
                                              terext_slot_manage_config_dtls y
                                          WHERE
                                                  y.platform = t.platform
                                              AND y.system = t.system
                                              AND y.slot_type = t.slot_type
                                              AND y.effective_from <= systimestamp
                                      )
                              ),
                         1,
                         0) = 1 )
            OR ( t.default_config = 'Default'
                 AND NOT ( t.effective_from = (
                    SELECT
                        MAX(x.effective_from)
                    FROM
                        terext_slot_manage_config_dtls x
                    WHERE
                            x.platform = t.platform
                        AND x.system = t.system
                        AND x.slot_type = t.slot_type
                        AND x.effective_from <= systimestamp
                )
                           AND decode(t.created_date,
                                      (
                                               SELECT
                                                   MAX(x.created_date)
                                               FROM
                                                   terext_slot_manage_config_dtls x
                                               WHERE
                                                       x.platform = t.platform
                                                   AND x.system = t.system
                                                   AND x.slot_type = t.slot_type
                                                   AND x.effective_from <= systimestamp
                                                   AND x.effective_from =(
                                                       SELECT
                                                           MAX(y.effective_from)
                                                       FROM
                                                           terext_slot_manage_config_dtls y
                                                       WHERE
                                                               y.platform = t.platform
                                                           AND y.system = t.system
                                                           AND y.slot_type = t.slot_type
                                                           AND y.effective_from <= systimestamp
                                                   )
                                           ),
                                      1,
                                      0) = 1 ) );

        IF p_do_commit THEN
            COMMIT;
        END IF;
    EXCEPTION
        WHEN OTHERS THEN
            IF p_do_commit THEN
                ROLLBACK;
            END IF;
            RAISE;
    END default_config_scheduler_prc;

END terslot_manage_config_pkg;

