--  DDL for Package Body TERSLOT_OPERATION_TABLE_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TERSLOT_OPERATION_TABLE_PKG" AS 

CURSOR cur_data_slot (
    p_data BLOB
) IS
SELECT
    slot_number,
    slot_type,
