        slot_number            VARCHAR2(250)  PATH '$.slotNumber',
        slot_type              VARCHAR2(200)  PATH '$.slotType',
        slot_status            VARCHAR2(50)   PATH '$.slotStatus',
        mrp_qtr                VARCHAR2(30)   PATH '$.mrpQtr',
        pd_qtr                 VARCHAR2(50)   PATH '$.pdQtr',
        promised_date          VARCHAR2(50)   PATH '$.promisedDate',
        scheduled_date         VARCHAR2(50)   PATH '$.scheduledDate',
        updated_date_ts        TIMESTAMP      PATH '$.updatedDate',
        config_num             VARCHAR2(50)   PATH '$.configNumber',
        planning_organization  VARCHAR2(200)  PATH '$.planningOrganization',
        mfr                    VARCHAR2(200)  PATH '$.manufacture',
        mfr_site               VARCHAR2(200)  PATH '$.manufactureSite',
        operations_comments    VARCHAR2(4000) PATH '$.operationComments',
        created_by             VARCHAR2(200)  PATH '$.createdBy',
        updated_by             VARCHAR2(200)  PATH '$.updatedBy'
    )
);

rec_data   cur_data_slot%ROWTYPE;
l_err_code VARCHAR2(1);
l_err_msg  VARCHAR2(2000);

--cursor queries to add partials and refurb details in ops/mkt page

