		( p_data FORMAT JSON, '$[*]' --'$'  -- If payload is an array, change to '$[*]'
            COLUMNS (
					Part_Number            VARCHAR2  PATH '$.part_number',
					Part_Description       VARCHAR2  PATH '$.part_description',
					Quantity               VARCHAR2  PATH '$.quantity',
					Promise_Date           TIMESTAMP PATH '$.promise_date',
