                Comments               VARCHAR2  PATH '$.comments',
                source                 VARCHAR2  PATH '$.source',
                ship_from_site         VARCHAR2  PATH '$.ship_from_site'
                
                
            )
        );
	TYPE refurb_tab_type IS TABLE OF cur_refurb_dtls%rowtype;
    l_refurb_tab   refurb_tab_type; 


PROCEDURE process_data (
    p_method IN VARCHAR2,
    p_data   IN BLOB
) IS
BEGIN
    IF p_method = 'POST' THEN
        post_data(p_data);
    ELSIF p_method = 'PUT' THEN
        put_data(p_data);
    ELSE
        l_err_code := 'E';
        l_err_msg  := 'Unsupported method: ' || p_method;

        apex_json.open_object;
        apex_json.write('p_err_code', l_err_code);
        apex_json.write('p_err_msg',  l_err_msg);
        apex_json.close_object;
    END IF;
END process_data;


/* POST = upsert into PLAN + insert-only into OPS */
PROCEDURE post_data (
    p_data IN BLOB
) IS
BEGIN
    OPEN cur_data_slot(p_data);
    FETCH cur_data_slot INTO rec_data;
    CLOSE cur_data_slot;

    -- OPS insert (audit trail)
    INSERT INTO terext_slot_plan_ops_dtls (
        planning_organization,
        mfr,
        mfr_site,
        operations_comments,
        created_by,
        updated_by,
        updated_date,
        slot_type,
        slot_number
    ) VALUES (
        rec_data.planning_organization,
        rec_data.mfr,
        rec_data.mfr_site,
        rec_data.operations_comments,
        rec_data.created_by,
        rec_data.updated_by,
        CAST(rec_data.updated_date_ts AS DATE),
        rec_data.slot_type,
        rec_data.slot_number
    );

    -- PLAN upsert
    MERGE INTO terext_slot_plan_dtls t
    USING (
        SELECT
            rec_data.slot_number AS slot_number,
            rec_data.pd_qtr AS pd_qtr,
            rec_data.slot_type AS slot_type,
            rec_data.slot_status AS slot_status,
            rec_data.mrp_qtr AS mrp_qtr,
            CASE
                WHEN rec_data.promised_date IS NULL THEN NULL
                ELSE TO_DATE(SUBSTR(rec_data.promised_date, 1, 10), 'YYYY-MM-DD')
            END AS promised_date,
            CASE
                WHEN rec_data.scheduled_date IS NULL THEN NULL
                ELSE TO_DATE(SUBSTR(rec_data.scheduled_date, 1, 10), 'YYYY-MM-DD')
            END AS schedule_date,
            TO_NUMBER(NULLIF(TRIM(rec_data.config_num), '')) AS config_number,
            rec_data.planning_organization AS planning_organization,
            rec_data.mfr AS manufacture,
            rec_data.mfr_site AS manufacture_site,
            rec_data.operations_comments AS operation_comments,
            rec_data.updated_by AS updated_by,
            CAST(rec_data.updated_date_ts AS DATE) AS updated_date
        FROM dual
    ) s
    ON (t.slot_number = s.slot_number)
    WHEN MATCHED THEN
        UPDATE SET
            t.pd_qtr                = s.pd_qtr,
            t.slot_type             = s.slot_type,
            t.slot_status           = s.slot_status,
            t.mrp_qtr               = s.mrp_qtr,
            t.promised_date         = s.promised_date,
            t.schedule_date         = s.schedule_date,
            t.config_number         = s.config_number,
            t.planning_organization = s.planning_organization,
            t.manufacture           = s.manufacture,
            t.manufacture_site      = s.manufacture_site,
            t.operation_comments    = s.operation_comments,
            t.updated_by            = s.updated_by,
            t.updated_date          = s.updated_date
    WHEN NOT MATCHED THEN
        INSERT (
            slot_number,
            pd_qtr,
            slot_type,
            slot_status,
            mrp_qtr,
            promised_date,
            schedule_date,
            config_number,
            planning_organization,
            manufacture,
            manufacture_site,
            operation_comments,
            updated_by,
            updated_date
        )
        VALUES (
            s.slot_number,
            s.pd_qtr,
            s.slot_type,
            s.slot_status,
            s.mrp_qtr,
            s.promised_date,
            s.schedule_date,
            s.config_number,
            s.planning_organization,
            s.manufacture,
            s.manufacture_site,
            s.operation_comments,
            s.updated_by,
            s.updated_date
        );

    COMMIT;
    l_err_code := 'S';
    l_err_msg  := 'Information Saved Successfully';

    apex_json.open_object;
    apex_json.write('p_err_code',   l_err_code);
    apex_json.write('p_err_msg',    l_err_msg);
    apex_json.write('slot_number',  rec_data.slot_number);
    apex_json.close_object;

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        l_err_code := 'E';
        l_err_msg  := 'API Error - ' || SQLERRM;

        apex_json.open_object;
        apex_json.write('p_err_code',  l_err_code);
        apex_json.write('p_err_msg',   l_err_msg);
        apex_json.write('slot_number', rec_data.slot_number);
        apex_json.close_object;
END post_data;


/* PUT = update OPS + update PLAN */
PROCEDURE put_data (
    p_data IN BLOB
) IS
BEGIN
    OPEN cur_data_slot(p_data);
    FETCH cur_data_slot INTO rec_data;
    CLOSE cur_data_slot;

    UPDATE terext_slot_plan_ops_dtls o
    SET
        o.planning_organization = rec_data.planning_organization,
        o.operations_comments   = rec_data.operations_comments,
        o.slot_type             = rec_data.slot_type,
        o.mfr                   = rec_data.mfr,
        o.mfr_site              = rec_data.mfr_site,
        o.updated_by            = rec_data.updated_by,
        o.updated_date          = CAST(rec_data.updated_date_ts AS DATE)
    WHERE o.slot_number = rec_data.slot_number;

    UPDATE terext_slot_plan_dtls t
    SET
        t.planning_organization = rec_data.planning_organization,
        t.operation_comments    = rec_data.operations_comments,
        t.slot_type             = rec_data.slot_type,
        t.manufacture           = rec_data.mfr,
        t.manufacture_site      = rec_data.mfr_site,
        t.promised_date         = CASE
                                      WHEN rec_data.promised_date IS NULL THEN NULL
                                      ELSE TO_DATE(SUBSTR(rec_data.promised_date, 1, 10), 'YYYY-MM-DD')
                                  END,
        t.schedule_date         = CASE
                                      WHEN rec_data.scheduled_date IS NULL THEN NULL
                                      ELSE TO_DATE(SUBSTR(rec_data.scheduled_date, 1, 10), 'YYYY-MM-DD')
                                  END,
        t.mrp_qtr               = rec_data.mrp_qtr,
        t.pd_qtr                = rec_data.pd_qtr,
        t.config_number         = TO_NUMBER(NULLIF(TRIM(rec_data.config_num), '')),
        t.updated_by            = rec_data.updated_by,
        t.updated_date          = CAST(rec_data.updated_date_ts AS DATE)
    WHERE t.slot_number = rec_data.slot_number;

    COMMIT;
    l_err_code := 'S';
    l_err_msg  := 'Information Saved Successfully';

    apex_json.open_object;
    apex_json.write('p_err_code',   l_err_code);
    apex_json.write('p_err_msg',    l_err_msg);
    apex_json.write('slot_number',  rec_data.slot_number);
    apex_json.close_object;

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        l_err_code := 'E';
        l_err_msg  := 'API UPDATE Error - ' || SQLERRM;

        apex_json.open_object;
        apex_json.write('p_err_code',  l_err_code);
        apex_json.write('p_err_msg',   l_err_msg);
        apex_json.write('slot_number', rec_data.slot_number);
        apex_json.close_object;
END put_data;

--procs to add partials and refurb details in ops and mkt page 

--procedure to add partials table for both ops and mkt     
PROCEDURE ops_partials_dtls (
        p_in_slotnum      VARCHAR2,
		p_in_refnum       VARCHAR2,
        p_in_partial_flag VARCHAR2,
		p_in_source       VARCHAR2,
        p_in_user         VARCHAR2,
        p_in_partial_body BLOB DEFAULT NULL,
        p_out_status OUT  VARCHAR2,
        p_out_msg    OUT  VARCHAR2
    )
    IS 
    BEGIN 
	
    insert into test_slot_log(col1,col2,col3,col4) values('1','START-ops_partials_dtls-'||p_in_slotnum,p_in_refnum,p_in_partial_flag);

        IF p_in_partial_flag = 'Y' THEN    
	  
            OPEN cur_partial_dtls(p_in_partial_body);
            FETCH cur_partial_dtls BULK COLLECT INTO l_partial_tab;
            CLOSE cur_partial_dtls;
            
            
            IF l_partial_tab.COUNT >=1 THEN 
            insert into test_slot_log(col1,col2,col3,col4) values('2','ops_partials_dtls-',null,null);

			   --Loading partials Data into a temp table 
               FOR i IN l_partial_tab.FIRST..l_partial_tab.LAST
                    LOOP 
            insert into test_slot_log(col1,col2,col3,col4) values('3','Insert Partial Details Into Temp Table',null,null);

                     INSERT INTO 
                     TEREXT_SLOT_PARTS_TEMP
                       (
					     part_number,
						 part_description,
						 quantity,
						 Promise_Date,
						 Partial_Approved,
						 comments,source,
						 slotnum,
						 refnum,
						 created_by,
						 created_date,
						 itemtype
						) 
						 VALUES
						 (
						 l_partial_tab(i).part_number,
						 l_partial_tab(i).part_description,
						 l_partial_tab(i).quantity,
						 l_partial_tab(i).Promise_Date,               
						 l_partial_tab(i).Partial_Approved,
						 l_partial_tab(i).comments,
						 l_partial_tab(i).source,
						 p_in_slotnum,
						 p_in_refnum,
						 p_in_user,
						 sysdate,
						 'PARTIAL'
						 ); 
                    END LOOP;
					
             IF p_in_source='Operation' THEN 
			 insert into test_slot_log(col1,col2,col3,col4) values('4','Add Partial Details For Operation Page',null,null);

			 --If partials details are already there then update the details else insert the details
				 MERGE INTO TEREXT_SLOT_PARTS target2
				 USING(
				 SELECT        
						part_number,
						part_description,
						quantity,
						Promise_Date,
						Partial_Approved,
						comments,
						source,
						slotnum,
					    refnum,
						created_by,
						created_date
						FROM TEREXT_SLOT_PARTS_TEMP   
						WHERE itemtype='PARTIAL'
					  ) source2
					  ON (
					      1=1
						  AND target2.slot_number = source2.slotnum 
						  AND target2.config_num  = source2.refnum 
						  AND target2.part_number = source2.part_number
						  AND target2.quantity    = source2.quantity
						  )
					WHEN MATCHED THEN
					UPDATE
						   SET target2.promise_date    = source2.promise_date,
							   target2.comments        = source2.comments,   
							   target2.updated_by      = p_in_user,
							   target2.updated_date    = SYSDATE     
					WHEN NOT MATCHED THEN
					INSERT 
					 (
					  slot_number,
					  part_number,
					  part_description,
					  quantity,
					  promise_date,
					  comments,
					  created_by,
					  created_date,
                      config_num
					  )                
					values(
					 source2.slotnum,
					 source2.part_number,
					 source2.part_description,
					 source2.quantity,
					 source2.Promise_Date,
					 source2.comments,
					 p_in_user,
					 sysdate,
                     source2.refnum
					  );     
					  
             END IF; --END of p_in_source='Operation'
             
             
			 IF p_in_source='Marketing' THEN 
			 insert into test_slot_log(col1,col2,col3,col4) values('5','Add Partial Details For Marketing Page',null,null);

			 --If partials details are already there then update the details else insert the details
             MERGE INTO TEREXT_SLOT_PARTS target2
             USING(
             SELECT        
                    part_number,
                    part_description,
                    quantity,
                    Promise_Date,
                    Partial_Approved,
                    comments,
                    source,
                    slotnum,
                    refnum,
					created_by,
					created_date
                    FROM TEREXT_SLOT_PARTS_TEMP
					WHERE itemtype='PARTIAL'
                   ) source2
                  ON ( 1=1
				      AND target2.slot_number = source2.slotnum 
					  AND target2.config_num  = source2.refnum 
                      AND target2.part_number = source2.part_number
                      AND target2.quantity    = source2.quantity
                      )
                 WHEN MATCHED THEN
                 UPDATE
                       SET target2.partial_approved = source2.Partial_Approved,
                           target2.comments         = source2.comments,   
                           target2.updated_by       = p_in_user,
                           target2.updated_date     = SYSDATE                           
                   ;          
             END IF; --END of p_in_source='Operation'
             
             --drop data from  temp table 
             DELETE FROM TEREXT_SLOT_PARTS_TEMP WHERE itemtype='PARTIAL';
             insert into test_slot_log(col1,col2,col3,col4) values('6','Deleted Data From Temp Table',null,null);

			 
			 UPDATE TEREXT_SLOT_PLAN_DTLS  SET partial_flag='Y' WHERE slot_number=p_in_slotnum;
			 
			 p_out_status := 'Success';
             p_out_msg    := 'Partial Details Inserted/Updated Succesfully.';
			
            END IF; --END of l_partial_tab.COUNT >=1            
            
		ELSE 
            p_out_status := 'Success';
            p_out_msg    := 'No change In Partial Details.';
        END IF;
       
       COMMIT;
    EXCEPTION 
	WHEN OTHERS THEN
    ROLLBACK;
    p_out_status := 'Error';
    p_out_msg    := 'Exception is -'|| SUBSTR(SQLERRM,1,100);
        
    END;
 	
PROCEDURE ops_refurb_dtls (
        p_in_slotnum      VARCHAR2,
		p_in_refnum       VARCHAR2,
        p_in_refurb_flag  VARCHAR2,
        p_in_source       VARCHAR2,
        p_in_user         VARCHAR2,
        p_in_refurb_body  BLOB DEFAULT NULL,
