    )
    IS
    BEGIN 
	    insert into test_slot_log(col1,col2,col3,col4) values('1','START-ops_refurb_dtls-'||p_in_slotnum,p_in_refnum,p_in_refurb_flag);

     IF p_in_refurb_flag = 'Y' THEN 
