        IF l_refurb_tab.count>=1 THEN 
			            insert into test_slot_log(col1,col2,col3,col4) values('3','Insert refurb Details Into Temp Table',null,null);

			 --Loading refurb Data into a temp table 
             FOR i IN l_refurb_tab.first..l_refurb_tab.last
                LOOP 
                    --load data into temp table 
                     INSERT INTO TEREXT_SLOT_PARTS_TEMP
                     (
