                      l_refurb_tab(i).Promise_Date,
                      l_refurb_tab(i).refurb_Approved,
					  l_refurb_tab(i).comments,
					  l_refurb_tab(i).source,
					  p_in_slotnum,
					  p_in_refnum,
					  p_in_user,
					  sysdate,
					  'REFURB',
                      l_refurb_tab(i).ship_from_site
					  ); 
                END LOOP;
                
         IF p_in_source = 'Operation' THEN 
		 			 insert into test_slot_log(col1,col2,col3,col4) values('4','Add refurb Details For Operation Page',null,null);

             --If refurb details are already there then update the details else insert the details
			 MERGE INTO TEREXT_SLOT_PARTS_REFURB target2
             USING(
             SELECT        
                    part_number,
                    part_description,
                    quantity,
                    Promise_Date,
                    refurb_approved,
                    comments,
                    source,
                    slotnum,
                    refnum,
					created_by,
                    created_date,
                    ship_from_site
                    FROM  TEREXT_SLOT_PARTS_TEMP
                    WHERE itemtype='REFURB'
                   ) source2
                  ON  (
				      1=1
				      AND target2.slot_number = source2.slotnum 
					  AND target2.config_num  = source2.refnum 
                      AND target2.part_number = source2.part_number
                      AND target2.quantity    = source2.quantity
                       )
                 WHEN MATCHED THEN
                 UPDATE
                       SET target2.promise_date    = source2.promise_date,
                           target2.comments        = source2.comments,   
                           target2.updated_by      = p_in_user,
                           target2.updated_date    = SYSDATE,
                           target2.ship_from_site  = source2.ship_from_site
                           
                 WHEN NOT MATCHED THEN
                INSERT 
                 (slot_number,
                  part_number,
                  part_description,
                  quantity,
                  promise_date,
                  comments,
                  created_by,
                  created_date,
                  ship_from_site,
                  config_num
                  )                
		        values(
                 source2.slotnum,
                 source2.part_number,
                 source2.part_description,
                 source2.quantity,
                 source2.Promise_Date,
                 source2.comments,
                 p_in_user,
                 sysdate,
                 source2.ship_from_site,
                 source2.refnum
                  );          
         END IF; --END of p_in_source='Operation'
         
		 IF p_in_source = 'Marketing' THEN 
		insert into test_slot_log(col1,col2,col3,col4) values('4','Add refurb Details For Marketing Page',null,null);

             MERGE INTO TEREXT_SLOT_PARTS_REFURB target2
             USING(
             SELECT        
                    part_number,
                    part_description,
                    quantity,
                    Promise_Date,
                    refurb_Approved,
                    comments,
                    source,
                    slotnum,
                    refnum,
					created_by,
					created_date					
                    FROM TEREXT_SLOT_PARTS_TEMP
                    WHERE itemtype='REFURB'
                  ) source2
                  ON (
				      1=1
					  AND target2.slot_number = source2.slotnum 
					  AND target2.config_num  = source2.refnum 
                      AND target2.part_number = source2.part_number
                      AND target2.quantity    = source2.quantity
                      )
                WHEN MATCHED THEN                
				UPDATE
                       SET target2.refurb_approved = source2.refurb_approved,
                           target2.comments        = source2.comments,   
                           target2.updated_by      = p_in_user,
                           target2.updated_date    = SYSDATE  
				;
				
             END IF; --END of p_in_source='Marketing'
			 
         DELETE FROM TEREXT_SLOT_PARTS_TEMP WHERE itemtype='REFURB';
		  insert into test_slot_log(col1,col2,col3,col4) values('5','Deleted data from temp table ',null,null);
		 UPDATE TEREXT_SLOT_PLAN_DTLS  SET refurb_flag='Y' WHERE slot_number=p_in_slotnum;

        END IF; --End Of l_refurb_tab.count>=1 
 	  

      p_out_status := 'Success';
      p_out_msg    := 'refurb Details Inserted/Updated Succesfully.';
	  
     ELSE
      p_out_status := 'Success';
      p_out_msg    := 'No change In Refurb Details.';
	  
    END IF;--END OF p_in_refurb_flag = 'Y'
    COMMIT;
    EXCEPTION 
	WHEN OTHERS THEN
    ROLLBACK;
    p_out_status := 'Error';
    p_out_msg    := 'Exception is -'|| SUBSTR(SQLERRM,1,100);
    END;
       

END;

/
--------------------------------------------------------
--  DDL for Package Body TERSLOT_TABLE_API
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TERSLOT_TABLE_API" AS

   /* **********************************************************************************************
   TYPE                Procedure
   NAME                delete_tmp_recs
   DESCRIPTION         This procedure will data from temp table 
   INPUT PARAMETERS    
   OUTPUT PARAMETERS
   ********************************************************************************************** */

    PROCEDURE delete_tmp_recs IS
        PRAGMA autonomous_transaction;
    BEGIN
        DELETE FROM terext_bulk_slot_nums_temp;

        COMMIT;
    EXCEPTION
        WHEN OTHERS THEN
            NULL;
    END;

   /* **********************************************************************************************
   TYPE                FUNCTION
   NAME                chk_new_slot_num_f
   DESCRIPTION         Function will validate the generated slot data  
   INPUT PARAMETERS    
   OUTPUT PARAMETERS
   ********************************************************************************************** */
    FUNCTION chk_new_slot_num_f (
        p_in_new_slot_num IN VARCHAR2,
        p_in_prefix       IN VARCHAR2
    ) RETURN VARCHAR IS
        l_cnt          NUMBER;
        l_cnt2         NUMBER;
        l_new_slotnum2 VARCHAR2(50);
    BEGIN
        l_new_slotnum2 := p_in_new_slot_num;
        LOOP    
               --validate with current data
            SELECT
                COUNT(*)
            INTO l_cnt
            FROM
                terext_bulk_slot_nums_temp
            WHERE
                slot_number = p_in_prefix || l_new_slotnum2;

                             --validate with exisisting data
            SELECT
                COUNT(*)
            INTO l_cnt2
            FROM
                terext_slot_plan_dtls
            WHERE
                slot_number = p_in_prefix || l_new_slotnum2;

                             --check duplicate or not 
            IF ( l_cnt >= 1 OR l_cnt2 >= 1 ) THEN
                SELECT
                    CASE
                        WHEN instr(p_in_prefix || l_new_slotnum2, p_in_prefix) = 1 THEN
                            TO_NUMBER(regexp_replace(substr(p_in_prefix || l_new_slotnum2,
                                                            length(p_in_prefix) + 1),
                                                     '[^0-9]',
                                                     '')) + 1
                    END
                INTO l_new_slotnum2
                FROM
                    dual;

            END IF;

            EXIT WHEN (
                l_cnt = 0
                AND l_cnt2 = 0
            );
        END LOOP;
              --Insert record into Temp Table 
        INSERT INTO terext_bulk_slot_nums_temp ( slot_number ) VALUES ( p_in_prefix || l_new_slotnum2 );

        RETURN p_in_prefix || l_new_slotnum2;
    EXCEPTION
        WHEN OTHERS THEN
            RETURN NULL;
    END chk_new_slot_num_f;

   /* **********************************************************************************************
   TYPE                FUNCTION
   NAME                get_slot_num_f
   DESCRIPTION         Function used to generate the slot number   
   INPUT PARAMETERS    
   OUTPUT PARAMETERS
   ********************************************************************************************** */
    FUNCTION get_slot_num_f (
        p_in_plaftform IN VARCHAR2,
        p_in_slotnum   IN VARCHAR2
    ) RETURN VARCHAR IS

        l_prefix        VARCHAR2(40);
        l_cur_slotnum   VARCHAR2(50);
        l_new_slotnum   VARCHAR2(50);
        l_valid_slotnum VARCHAR2(50);
    BEGIN
        IF p_in_slotnum IS NULL THEN
            SELECT
                prefix
            INTO l_prefix
            FROM
                terext_slot_platform_prefix_dtls
            WHERE
                platform = p_in_plaftform;

            SELECT
                slot_number
            INTO l_cur_slotnum
            FROM
                terext_slot_plan_dtls
            WHERE
                slot_id = (
                    SELECT
                        MAX(slot_id)
                    FROM
                        terext_slot_plan_dtls
                    WHERE
                            platform = p_in_plaftform
                        AND slot_number LIKE l_prefix || '%'
                );

            SELECT
                CASE
                    WHEN instr(l_cur_slotnum, l_prefix) = 1 THEN
                        TO_NUMBER(regexp_replace(substr(l_cur_slotnum,
                                                        length(l_prefix) + 1),
                                                 '[^0-9]',
                                                 '')) + 1
                END
            INTO l_new_slotnum
            FROM
                dual;

       --now validate the generated new slot number with exisisting data 
            l_valid_slotnum := chk_new_slot_num_f(l_new_slotnum, l_prefix);
        END IF;

        RETURN l_valid_slotnum;
    EXCEPTION
        WHEN OTHERS THEN
            RETURN NULL;
    END get_slot_num_f;

    PROCEDURE plan_dtls_tbl_action_from_json (
        p_body     IN CLOB,
        p_status   OUT VARCHAR2,
        p_message  OUT VARCHAR2,
        p_rows_out OUT NUMBER
    ) IS

        TYPE t_row IS RECORD (
                slot_number           VARCHAR2(200),
                pd_qtr                VARCHAR2(100),
                platform              VARCHAR2(50),
                system                VARCHAR2(200),
                slot_type             VARCHAR2(200),
                slot_status           VARCHAR2(200),
                demand_class          VARCHAR2(200),
                config_number         VARCHAR2(200),
                schedule_date         DATE,
                promised_date         DATE,
                mrp_qtr               VARCHAR2(100),
                created_by            VARCHAR2(50),
                planning_organization VARCHAR2(200),
                manufacture           VARCHAR2(200),
                manufacture_site      VARCHAR2(200),
                operation_comments    VARCHAR2(4000),
                marketing_comments    VARCHAR2(4000)
        );
        TYPE t_row_tab IS
            TABLE OF t_row INDEX BY PLS_INTEGER;
        l_rows      t_row_tab;
        l_has_items NUMBER;
    BEGIN
        p_rows_out := 0;
        p_status := 'SUCCESS';
        p_message := NULL;
        SELECT
            CASE
                WHEN JSON_EXISTS ( p_body, '$.ITEMS[*]' ) THEN
                    1
                ELSE
                    0
            END
        INTO l_has_items
        FROM
            dual;

        IF l_has_items = 1 THEN
            SELECT
                jt.slot_number,
                jt.pd_qtr,
                jt.platform,
                jt.system,
                jt.slot_type,
                jt.slot_status,
                jt.demand_class,
                jt.config_number,
                CASE
                    WHEN jt.schedule_date_str IS NOT NULL
                         AND REGEXP_LIKE ( jt.schedule_date_str,
                                           '^\d{4}-\d{2}-\d{2}$' ) THEN
                        TO_DATE(jt.schedule_date_str, 'YYYY-MM-DD')
                    ELSE
                        NULL
                END AS schedule_date,
                CASE
                    WHEN jt.promised_date_str IS NOT NULL
                         AND REGEXP_LIKE ( jt.promised_date_str,
                                           '^\d{4}-\d{2}-\d{2}$' ) THEN
                        TO_DATE(jt.promised_date_str, 'YYYY-MM-DD')
                    ELSE
                        NULL
                END AS promised_date,
                jt.mrp_qtr,
                jt.created_by,
                jt.planning_organization,
                jt.manufacture,
                jt.manufacture_site,
                jt.operation_comments,
                jt.marketing_comments
            BULK COLLECT
            INTO l_rows
            FROM
                    JSON_TABLE ( p_body FORMAT JSON, '$.ITEMS[*]'
                        COLUMNS (
                            slot_number VARCHAR2 ( 200 ) PATH '$.SLOT_NUMBER' NULL ON ERROR,
                            pd_qtr VARCHAR2 ( 100 ) PATH '$.PD_QTR' NULL ON ERROR,
                            platform VARCHAR2 ( 50 ) PATH '$.PLATFORM' NULL ON ERROR,
                            system VARCHAR2 ( 200 ) PATH '$.SYSTEM' NULL ON ERROR,
                            slot_type VARCHAR2 ( 200 ) PATH '$.SLOT_TYPE' NULL ON ERROR,
                            slot_status VARCHAR2 ( 200 ) PATH '$.SLOT_STATUS' NULL ON ERROR,
                            demand_class VARCHAR2 ( 200 ) PATH '$.DEMAND_CLASS' NULL ON ERROR,
                            config_number VARCHAR2 ( 200 ) PATH '$.CONFIG_NUMBER' NULL ON ERROR,
                            schedule_date_str VARCHAR2 ( 10 ) PATH '$.SCHEDULE_DATE' NULL ON ERROR,
                            promised_date_str VARCHAR2 ( 10 ) PATH '$.PROMISED_DATE' NULL ON ERROR,
                            mrp_qtr VARCHAR2 ( 100 ) PATH '$.MRP_QTR' NULL ON ERROR,
                            created_by VARCHAR2 ( 50 ) PATH '$.CREATED_BY' NULL ON ERROR,
                            planning_organization VARCHAR2 ( 200 ) PATH '$.PLANNING_ORGANIZATION' NULL ON ERROR,
                            manufacture VARCHAR2 ( 200 ) PATH '$.MANUFACTURE' NULL ON ERROR,
                            manufacture_site VARCHAR2 ( 200 ) PATH '$.MANUFACTURE_SITE' NULL ON ERROR,
                            operation_comments VARCHAR2 ( 4000 ) PATH '$.OPERATION_COMMENTS' NULL ON ERROR,
                            marketing_comments VARCHAR2 ( 4000 ) PATH '$.MARKETING_COMMENTS' NULL ON ERROR
                        )
                    )
                jt;

        ELSE
            SELECT
                jt.slot_number,
                jt.pd_qtr,
                jt.platform,
                jt.system,
                jt.slot_type,
                jt.slot_status,
                jt.demand_class,
                jt.config_number,
                jt.schedule_date,
                jt.promised_date,
                jt.mrp_qtr,
                jt.created_by,
                jt.planning_organization,
                jt.manufacture,
                jt.manufacture_site,
                jt.operation_comments,
                jt.marketing_comments
            BULK COLLECT
            INTO l_rows
            FROM
                    JSON_TABLE ( p_body, 
                                                                        --'$'
                     '$[*]'
                        COLUMNS (
                            slot_number VARCHAR2 ( 200 ) PATH '$.SLOT_NUMBER',
                            pd_qtr VARCHAR2 ( 100 ) PATH '$.PD_QTR',
                            platform VARCHAR2 ( 50 ) PATH '$.PLATFORM',
                            system VARCHAR2 ( 200 ) PATH '$.SYSTEM',
                            slot_type VARCHAR2 ( 200 ) PATH '$.SLOT_TYPE',
                            slot_status VARCHAR2 ( 200 ) PATH '$.SLOT_STATUS',
                            demand_class VARCHAR2 ( 200 ) PATH '$.DEMAND_CLASS',
                            config_number VARCHAR2 ( 200 ) PATH '$.CONFIG_NUMBER',
                            schedule_date DATE PATH '$.SCHEDULE_DATE',
                            promised_date DATE PATH '$.PROMISED_DATE',
                            mrp_qtr VARCHAR2 ( 100 ) PATH '$.MRP_QTR',
                            created_by VARCHAR2 ( 50 ) PATH '$.CREATED_BY',
                            planning_organization VARCHAR2 ( 200 ) PATH '$.PLANNING_ORGANIZATION',
                            manufacture VARCHAR2 ( 200 ) PATH '$.MANUFACTURE',
                            manufacture_site VARCHAR2 ( 200 ) PATH '$.MANUFACTURE_SITE',
                            operation_comments VARCHAR2 ( 4000 ) PATH '$.OPERATION_COMMENTS',
                            marketing_comments VARCHAR2 ( 4000 ) PATH '$.MARKETING_COMMENTS'
                        )
                    )
                jt;

        END IF;

        IF l_rows.count = 0 THEN
            p_status := 'SUCCESS';
            p_message := 'No rows found in payload.';
            RETURN;
        END IF;

        IF l_has_items = 1 THEN
            FOR i IN 1..l_rows.count LOOP
                l_rows(i).slot_number := terslot_generate_slotnum_seq(l_rows(i).platform);
            END LOOP;

            FORALL i IN 1..l_rows.count
                INSERT INTO terext_slot_plan_dtls (
                    slot_number,
                    pd_qtr,
                    platform,
                    system,
                    slot_type,
                    slot_status,
                    demand_class,
                    config_number,
                    schedule_date,
                    promised_date,
                    mrp_qtr,
                    created_by,
                    planning_organization,
                    manufacture,
                    manufacture_site,
                    operation_comments,
                    marketing_comments
                ) VALUES (
                    l_rows(i).slot_number,
                    l_rows(i).pd_qtr,
                    l_rows(i).platform,
                    l_rows(i).system,
                    l_rows(i).slot_type,
                    l_rows(i).slot_status,
                    l_rows(i).demand_class,
                    l_rows(i).config_number,
                    l_rows(i).schedule_date,
                    l_rows(i).promised_date,
                    l_rows(i).mrp_qtr,
                    l_rows(i).created_by,
                    l_rows(i).planning_organization,
                    l_rows(i).manufacture,
                    l_rows(i).manufacture_site,
                    l_rows(i).operation_comments,
                    l_rows(i).marketing_comments
                );

        ELSE

                             --load all the slot_numbers in temp table 
            FOR i IN 1..l_rows.count LOOP
                IF l_rows(i).slot_number IS NOT NULL THEN
                    BEGIN
                        INSERT INTO terext_bulk_slot_nums_temp ( slot_number ) VALUES ( l_rows(i).slot_number );

                    EXCEPTION
                        WHEN OTHERS THEN
                            NULL;
                    END;

                END IF;
            END LOOP;

            FOR i IN 1..l_rows.count LOOP
            --l_rows(i).slot_number := terslot_generate_slotnum_seq(l_rows(i).platform);
                l_rows(i).slot_number := nvl(l_rows(i).slot_number, get_slot_num_f(l_rows(i).platform, l_rows(i).slot_number));
            END LOOP;

            FORALL i IN 1..l_rows.count
                INSERT INTO terext_slot_plan_dtls (
                    slot_number,
                    pd_qtr,
                    platform,
                    system,
                    slot_type,
                    slot_status,
                    demand_class,
                    config_number,
                    schedule_date,
                    promised_date,
                    mrp_qtr,
                    created_by,
                    planning_organization,
                    manufacture,
                    manufacture_site,
                    operation_comments,
                    marketing_comments,
                    source
                ) VALUES (
                    l_rows(i).slot_number,
                    l_rows(i).pd_qtr,
                    l_rows(i).platform,
                    l_rows(i).system,
                    l_rows(i).slot_type,
                    l_rows(i).slot_status,
                    l_rows(i).demand_class,
                    l_rows(i).config_number,
                    l_rows(i).schedule_date,
                    l_rows(i).promised_date,
                    l_rows(i).mrp_qtr,
                    l_rows(i).created_by,
                                                          --'VEERA-TEST',
                    l_rows(i).planning_organization,
                    l_rows(i).manufacture,
                    l_rows(i).manufacture_site,
                    l_rows(i).operation_comments,
                    l_rows(i).marketing_comments,
                    'BULK_IMPORT'
                );

        END IF;

        p_rows_out := SQL%rowcount;
        COMMIT;
                             --delete records from Temp Table
        delete_tmp_recs();
        p_status := 'SUCCESS';
        p_message := 'Inserted '
                     || p_rows_out
                     || ' row(s).';
    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            p_rows_out := 0;
            p_status := 'ERROR';
            p_message := substr('SQLCODE='
                                || sqlcode
                                || '; SQLERRM='
                                || sqlerrm
                                || '; BT='
                                || dbms_utility.format_error_backtrace, 1, 4000);

            RETURN;
    END plan_dtls_tbl_action_from_json;

    PROCEDURE create_slot_json_action (
        p_body     IN CLOB,
        p_status   OUT VARCHAR2,
        p_message  OUT VARCHAR2,
        p_rows_out OUT NUMBER
    ) IS

        TYPE t_row IS RECORD (
                slot_number           VARCHAR2(100),
                pd_qtr                VARCHAR2(10),
                platform              VARCHAR2(100),
                system_name           VARCHAR2(200),
                slot_type             VARCHAR2(50),
                slot_status           VARCHAR2(50),
                demand_class          VARCHAR2(200),
                config_number         VARCHAR2(100),
                schedule_date         DATE,
                promised_date         DATE,
                mrp_qtr               VARCHAR2(10),
                created_by            VARCHAR2(200),
                planning_organization VARCHAR2(100),
                manufacture           VARCHAR2(200),
                manufacture_site      VARCHAR2(400),
                operation_comments    VARCHAR2(4000),
                marketing_comments    VARCHAR2(4000)
        );
        TYPE t_row_tab IS
            TABLE OF t_row;
        l_rows t_row_tab;
    BEGIN
        p_status := 'ERROR';
        p_message := NULL;
        p_rows_out := 0;
        IF p_body IS NULL OR NOT json_exists(p_body, '$[0]') THEN
            p_message := 'Invalid payload: expected root array with one object at $[0].';
            RETURN;
        END IF;

        SELECT
            jt.slot_number,
            jt.pd_qtr,
            jt.platform,
            jt.system_name,
            jt.slot_type,
            jt.slot_status,
            jt.demand_class,
            jt.config_number,
            CASE
                WHEN jt.schedule_date_str IS NULL THEN
                    NULL
                ELSE
                    TO_DATE(jt.schedule_date_str, 'YYYY-MM-DD')
            END,
            CASE
                WHEN jt.promised_date_str IS NULL THEN
                    NULL
                ELSE
                    TO_DATE(jt.promised_date_str, 'YYYY-MM-DD')
            END,
            jt.mrp_qtr,
            jt.created_by,
            jt.planning_organization,
            jt.manufacture,
            jt.manufacture_site,
            jt.operation_comments,
            jt.marketing_comments
        BULK COLLECT
        INTO l_rows
        FROM
                JSON_TABLE ( p_body, '$[*]'
                    COLUMNS
                        slot_number VARCHAR2 ( 100 ) PATH '$.SLOT_NUMBER' NULL ON ERROR,
                        pd_qtr VARCHAR2 ( 10 ) PATH '$.PD_QTR',
                        platform VARCHAR2 ( 100 ) PATH '$.PLATFORM',
                        system_name VARCHAR2 ( 200 ) PATH '$.SYSTEM',
                        slot_type VARCHAR2 ( 50 ) PATH '$.SLOT_TYPE',
                        slot_status VARCHAR2 ( 50 ) PATH '$.SLOT_STATUS',
                        demand_class VARCHAR2 ( 200 ) PATH '$.DEMAND_CLASS',
                        config_number VARCHAR2 ( 100 ) PATH '$.CONFIG_NUMBER' NULL ON ERROR,
                        schedule_date_str VARCHAR2 ( 20 ) PATH '$.SCHEDULE_DATE' NULL ON ERROR,
                        promised_date_str VARCHAR2 ( 20 ) PATH '$.PROMISED_DATE' NULL ON ERROR,
                        mrp_qtr VARCHAR2 ( 10 ) PATH '$.MRP_QTR',
                        created_by VARCHAR2 ( 200 ) PATH '$.CREATED_BY',
                        planning_organization VARCHAR2 ( 100 ) PATH '$.PLANNING_ORGANIZATION',
                        manufacture VARCHAR2 ( 200 ) PATH '$.MANUFACTURE',
                        manufacture_site VARCHAR2 ( 400 ) PATH '$.MANUFACTURE_SITE',
                        operation_comments VARCHAR2 ( 4000 ) PATH '$.OPERATION_COMMENTS' NULL ON ERROR,
                        marketing_comments VARCHAR2 ( 4000 ) PATH '$.MARKETING_COMMENTS' NULL ON ERROR
                )
            jt;

        IF l_rows.count != 1 THEN
            p_message := 'Invalid payload: expected exactly 1 object, got '
                         || l_rows.count
                         || '.';
            RETURN;
        END IF;

    -- Generate custom slot number based on platform
        FOR i IN 1..l_rows.count LOOP
            --l_rows(i).slot_number := terslot_generate_slotnum_seq(l_rows(i).platform); commented by veera to assign user defined slot num
            l_rows(i).slot_number := nvl(l_rows(i).slot_number, terslot_generate_slotnum_seq(l_rows(i).platform));
        END LOOP;

        FORALL i IN 1..l_rows.count
            INSERT INTO terext_slot_plan_dtls (
                slot_number,
                pd_qtr,
                platform,
                system,
                slot_type,
                slot_status,
                demand_class,
                config_number,
                schedule_date,
                promised_date,
                mrp_qtr,
                created_by,
                planning_organization,
                manufacture,
                manufacture_site,
                operation_comments,
                marketing_comments
            ) VALUES (
                l_rows(i).slot_number,
                l_rows(i).pd_qtr,
                l_rows(i).platform,
                l_rows(i).system_name,
                l_rows(i).slot_type,
                l_rows(i).slot_status,
                l_rows(i).demand_class,
                l_rows(i).config_number,
                l_rows(i).schedule_date,
                l_rows(i).promised_date,
                l_rows(i).mrp_qtr,
                l_rows(i).created_by,
                l_rows(i).planning_organization,
                l_rows(i).manufacture,
                l_rows(i).manufacture_site,
                l_rows(i).operation_comments,
                l_rows(i).marketing_comments
            );

        p_rows_out := l_rows.count;
        p_status := 'SUCCESS';
        p_message := 'Inserted '
                     || p_rows_out
                     || ' row(s).';
        COMMIT;
    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            p_status := 'ERROR';
            p_message := substr(sqlerrm, 1, 200);
            p_rows_out := 0;
    END create_slot_json_action;

    PROCEDURE terslot_validate_csv (
        p_filename IN VARCHAR2
    ) IS
    BEGIN
  -----------------------------------------------------------------
  -- STEP 1: Build multi-column error messages and mark INVALID
  -----------------------------------------------------------------
        UPDATE terext_slot_bulk_upload_csv c
        SET
            status = 'INVALID',
            error_msg = rtrim(
                CASE
                    WHEN NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terext_slot_platform_dtls e
                        WHERE
                            e.platform = c.platform
                    ) THEN
                        'PLATFORM not found; '
                END
                ||
                CASE
                    WHEN NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terext_slot_system_dtls d
                        WHERE
                                d.system = c.system
                            AND d.platform = c.platform
                    ) THEN
                        'SYSTEM not found; '
                END
                ||
                CASE
                    WHEN NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terext_slot_demand_class_dtls s
                        WHERE
                            s.demandclass = c.demand_class
                    ) THEN
                        'DEMAND CLASS not found; '
                END
                ||
                CASE
                    WHEN NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terext_slot_planning_org_dtls p
                        WHERE
                                p.orgname = c.planning_organization
                            AND p.system = c.system
                    ) THEN
                        'PLANNING ORGANIZATION not found; '
                END
                ||
                CASE
                    WHEN NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terext_slot_type g
                        WHERE
                            g.name = c.slot_type
                    ) THEN
                        'SLOT TYPE not found; '
                END
                ||
                CASE
                    WHEN NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terpo_vendor_stg a
                        WHERE
                            a.partyname = c.manufacture
                    ) THEN
                        'MANUFACTURE not found; '
                END
                ||
                CASE
                    WHEN NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terpo_vendorsites_stg b
                        WHERE
                                b.vendorsitecode = c.manufacture_site
                            AND b.vendorid =(
                                SELECT DISTINCT
                                    vendorid
                                FROM
                                    terpo_vendor_stg
                                WHERE
                                    partyname = c.manufacture
                            )
                    ) THEN
                        'MANUFACTURE SITE not found; '
                END
                ||
                CASE
                    WHEN EXISTS(
                        SELECT
                            1
                        FROM
                            terext_slot_plan_dtls f
                        WHERE
                            f.slot_number = c.slot_number
                    ) THEN
                        'SLOT NUMBER already exists; '
                END
            )
        WHERE
                filename = p_filename
            AND ( NOT EXISTS (
                SELECT
                    1
                FROM
                    terext_slot_platform_dtls e
                WHERE
                    e.platform = c.platform
            )
                      OR NOT EXISTS (
                SELECT
                    1
                FROM
                    terext_slot_system_dtls d
                WHERE
                        d.system = c.system
                    AND d.platform = c.platform
            )
                      OR NOT EXISTS (
                SELECT
                    1
                FROM
                    terext_slot_demand_class_dtls s
                WHERE
                    s.demandclass = c.demand_class
            )
                      OR NOT EXISTS (
                SELECT
                    1
                FROM
                    terext_slot_planning_org_dtls p
                WHERE
                        p.orgname = c.planning_organization
                    AND p.system = c.system
            )
                      OR NOT EXISTS (
                SELECT
                    1
                FROM
                    terext_slot_type g
                WHERE
                    g.name = c.slot_type
            )
                      OR NOT EXISTS (
                SELECT
                    1
                FROM
                    terpo_vendor_stg a
                WHERE
                    a.partyname = c.manufacture
            )
                      OR NOT EXISTS (
                SELECT
                    1
                FROM
                    terpo_vendorsites_stg b
                WHERE
                    b.vendorsitecode = c.manufacture_site
            )
                      OR EXISTS (
                SELECT
                    1
                FROM
                    terext_slot_plan_dtls f
                WHERE
                    f.slot_number = c.slot_number
            ) );

  ------------------------------------------------                            -----------------
  -- STEP 2: Mark remaining records as VALID
  -----------------------------------------------------------------
        UPDATE terext_slot_bulk_upload_csv
        SET
            status = 'VALID',
            error_msg = NULL
        WHERE
                filename = p_filename
            AND status IS NULL;

    END terslot_validate_csv;

    PROCEDURE terext_slot_bulk_update_from_json (
        p_body     IN CLOB,
        p_status   OUT VARCHAR2,
        p_message  OUT VARCHAR2,
        p_rows_out OUT NUMBER
    ) IS
        l_has_items NUMBER;
        l_cnt       PLS_INTEGER := 0;
    BEGIN
        p_rows_out := 0;
        p_status := 'SUCCESS';
        p_message := NULL;
        SELECT
            CASE
                WHEN JSON_EXISTS (
                    JSON(
                        p_body
                    ), '$.ITEMS[*]' ) THEN
                    1
                ELSE
                    0
            END
        INTO l_has_items
        FROM
            dual;

        IF l_has_items = 1 THEN
            FOR r IN (
                SELECT
                    jt.slot_number,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.SLOT_TYPE' ) THEN
                            1
                        ELSE
                            0
                    END AS has_slot_type,
                    jt.slot_type,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.PLANNING_ORGANIZATION' ) THEN
                            1
                        ELSE
                            0
                    END AS has_planning_organization,
                    jt.planning_organization,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.MANUFACTURE' ) THEN
                            1
                        ELSE
                            0
                    END AS has_manufacture,
                    jt.manufacture,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.MANUFACTURE_SITE' ) THEN
                            1
                        ELSE
                            0
                    END AS has_manufacture_site,
                    jt.manufacture_site,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.SCHEDULE_DATE' ) THEN
                            1
                        ELSE
                            0
                    END AS has_schedule_date,
                    CASE
                        WHEN jt.schedule_date_str IS NOT NULL
                             AND REGEXP_LIKE ( TRIM(jt.schedule_date_str),
                                               '^\d{4}-\d{2}-\d{2}$' ) THEN
                            TO_DATE(TRIM(jt.schedule_date_str),
                                    'YYYY-MM-DD')
                        WHEN jt.schedule_date_str IS NOT NULL
                             AND length(TRIM(jt.schedule_date_str)) >= 10
                             AND REGEXP_LIKE ( substr(TRIM(jt.schedule_date_str),
                                                      1,
                                                      10),
                                               '^\d{4}-\d{2}-\d{2}$' ) THEN
                            TO_DATE(substr(TRIM(jt.schedule_date_str),
                                           1,
                                           10),
                                    'YYYY-MM-DD')
                    END AS schedule_date,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.PROMISED_DATE' ) THEN
                            1
                        ELSE
                            0
                    END AS has_promised_date,
                    CASE
                        WHEN jt.promised_date_str IS NOT NULL
                             AND REGEXP_LIKE ( TRIM(jt.promised_date_str),
                                               '^\d{4}-\d{2}-\d{2}$' ) THEN
                            TO_DATE(TRIM(jt.promised_date_str),
                                    'YYYY-MM-DD')
                        WHEN jt.promised_date_str IS NOT NULL
                             AND length(TRIM(jt.promised_date_str)) >= 10
                             AND REGEXP_LIKE ( substr(TRIM(jt.promised_date_str),
                                                      1,
                                                      10),
                                               '^\d{4}-\d{2}-\d{2}$' ) THEN
                            TO_DATE(substr(TRIM(jt.promised_date_str),
                                           1,
                                           10),
                                    'YYYY-MM-DD')
                    END AS promised_date,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.PD_QTR' ) THEN
                            1
                        ELSE
                            0
                    END AS has_pd_qtr,
                    jt.pd_qtr,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.MRP_QTR' ) THEN
                            1
                        ELSE
                            0
                    END AS has_mrp_qtr,
                    jt.mrp_qtr,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.UPDATED_BY' ) THEN
                            1
                        ELSE
                            0
                    END AS has_updated_by,
                    jt.updated_by
                FROM
                        JSON_TABLE (
                            JSON(
                                p_body
                            ), '$.ITEMS[*]'
                            COLUMNS (
                                item JSON PATH '$',
                                slot_number VARCHAR2 ( 200 ) PATH '$.SLOT_NUMBER',
                                slot_type VARCHAR2 ( 200 ) PATH '$.SLOT_TYPE',
                                planning_organization VARCHAR2 ( 200 ) PATH '$.PLANNING_ORGANIZATION',
                                manufacture VARCHAR2 ( 200 ) PATH '$.MANUFACTURE',
                                manufacture_site VARCHAR2 ( 200 ) PATH '$.MANUFACTURE_SITE',
                                schedule_date_str VARCHAR2 ( 100 ) PATH '$.SCHEDULE_DATE',
                                promised_date_str VARCHAR2 ( 100 ) PATH '$.PROMISED_DATE',
                                pd_qtr VARCHAR2 ( 100 ) PATH '$.PD_QTR',
                                mrp_qtr VARCHAR2 ( 100 ) PATH '$.MRP_QTR',
                                updated_by VARCHAR2 ( 256 ) PATH '$.UPDATED_BY'
                            )
                        )
                    jt
                WHERE
                    jt.slot_number IS NOT NULL
            ) LOOP
                UPDATE terext_slot_plan_dtls t
                SET
                    t.slot_type =
                        CASE
                            WHEN r.has_slot_type = 1
                                 AND r.slot_type IS NOT NULL THEN
                                r.slot_type
                            ELSE
                                t.slot_type
                        END,
                    t.planning_organization =
                        CASE
                            WHEN r.has_planning_organization = 1
                                 AND r.planning_organization IS NOT NULL THEN
                                r.planning_organization
                            ELSE
                                t.planning_organization
                        END,
                    t.manufacture =
                        CASE
                            WHEN r.has_manufacture = 1
                                 AND r.manufacture IS NOT NULL THEN
                                r.manufacture
                            ELSE
                                t.manufacture
                        END,
                    t.manufacture_site =
                        CASE
                            WHEN r.has_manufacture_site = 1
                                 AND r.manufacture_site IS NOT NULL THEN
                                r.manufacture_site
                            ELSE
                                t.manufacture_site
                        END,
                    t.schedule_date =
                        CASE
                            WHEN r.has_schedule_date = 1
                                 AND r.schedule_date IS NOT NULL THEN
                                r.schedule_date
                            ELSE
                                t.schedule_date
                        END,
                    t.promised_date =
                        CASE
                            WHEN r.has_promised_date = 1
                                 AND r.promised_date IS NOT NULL THEN
                                r.promised_date
                            ELSE
                                t.promised_date
                        END,
                    t.pd_qtr =
                        CASE
                            WHEN r.has_pd_qtr = 1
                                 AND r.pd_qtr IS NOT NULL THEN
                                r.pd_qtr
                            ELSE
                                t.pd_qtr
                        END,
                    t.mrp_qtr =
                        CASE
                            WHEN r.has_mrp_qtr = 1
                                 AND r.mrp_qtr IS NOT NULL THEN
                                r.mrp_qtr
                            ELSE
                                t.mrp_qtr
                        END,
                    t.updated_by =
                        CASE
                            WHEN r.has_updated_by = 1
                                 AND r.updated_by IS NOT NULL THEN
                                r.updated_by
                            ELSE
                                t.updated_by
                        END,
                    t.updated_date = sysdate
                WHERE
                    t.slot_number = r.slot_number;

                l_cnt := l_cnt + SQL%rowcount;
            END LOOP;
        ELSE
            FOR r IN (
                SELECT
                    jt.slot_number,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.SLOT_TYPE' ) THEN
                            1
                        ELSE
                            0
                    END AS has_slot_type,
                    jt.slot_type,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.PLANNING_ORGANIZATION' ) THEN
                            1
                        ELSE
                            0
                    END AS has_planning_organization,
                    jt.planning_organization,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.MANUFACTURE' ) THEN
                            1
                        ELSE
                            0
                    END AS has_manufacture,
                    jt.manufacture,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.MANUFACTURE_SITE' ) THEN
                            1
                        ELSE
                            0
                    END AS has_manufacture_site,
                    jt.manufacture_site,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.SCHEDULE_DATE' ) THEN
                            1
                        ELSE
                            0
                    END AS has_schedule_date,
                    CASE
                        WHEN jt.schedule_date_str IS NOT NULL
                             AND REGEXP_LIKE ( TRIM(jt.schedule_date_str),
                                               '^\d{4}-\d{2}-\d{2}$' ) THEN
                            TO_DATE(TRIM(jt.schedule_date_str),
                                    'YYYY-MM-DD')
                        WHEN jt.schedule_date_str IS NOT NULL
                             AND length(TRIM(jt.schedule_date_str)) >= 10
                             AND REGEXP_LIKE ( substr(TRIM(jt.schedule_date_str),
                                                      1,
                                                      10),
                                               '^\d{4}-\d{2}-\d{2}$' ) THEN
                            TO_DATE(substr(TRIM(jt.schedule_date_str),
                                           1,
                                           10),
                                    'YYYY-MM-DD')
                    END AS schedule_date,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.PROMISED_DATE' ) THEN
                            1
                        ELSE
                            0
                    END AS has_promised_date,
                    CASE
                        WHEN jt.promised_date_str IS NOT NULL
                             AND REGEXP_LIKE ( TRIM(jt.promised_date_str),
                                               '^\d{4}-\d{2}-\d{2}$' ) THEN
                            TO_DATE(TRIM(jt.promised_date_str),
                                    'YYYY-MM-DD')
                        WHEN jt.promised_date_str IS NOT NULL
                             AND length(TRIM(jt.promised_date_str)) >= 10
                             AND REGEXP_LIKE ( substr(TRIM(jt.promised_date_str),
                                                      1,
                                                      10),
                                               '^\d{4}-\d{2}-\d{2}$' ) THEN
                            TO_DATE(substr(TRIM(jt.promised_date_str),
                                           1,
                                           10),
                                    'YYYY-MM-DD')
                    END AS promised_date,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.PD_QTR' ) THEN
                            1
                        ELSE
                            0
                    END AS has_pd_qtr,
                    jt.pd_qtr,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.MRP_QTR' ) THEN
                            1
                        ELSE
                            0
                    END AS has_mrp_qtr,
                    jt.mrp_qtr,
                    CASE
                        WHEN JSON_EXISTS ( jt.item, '$.UPDATED_BY' ) THEN
                            1
                        ELSE
                            0
                    END AS has_updated_by,
                    jt.updated_by
                FROM
                        JSON_TABLE (
                            JSON(
                                p_body
                            ), '$[*]'
                            COLUMNS (
                                item JSON PATH '$',
                                slot_number VARCHAR2 ( 200 ) PATH '$.SLOT_NUMBER',
                                slot_type VARCHAR2 ( 200 ) PATH '$.SLOT_TYPE',
                                planning_organization VARCHAR2 ( 200 ) PATH '$.PLANNING_ORGANIZATION',
                                manufacture VARCHAR2 ( 200 ) PATH '$.MANUFACTURE',
                                manufacture_site VARCHAR2 ( 200 ) PATH '$.MANUFACTURE_SITE',
                                schedule_date_str VARCHAR2 ( 100 ) PATH '$.SCHEDULE_DATE',
                                promised_date_str VARCHAR2 ( 100 ) PATH '$.PROMISED_DATE',
                                pd_qtr VARCHAR2 ( 100 ) PATH '$.PD_QTR',
                                mrp_qtr VARCHAR2 ( 100 ) PATH '$.MRP_QTR',
                                updated_by VARCHAR2 ( 256 ) PATH '$.UPDATED_BY'
                            )
                        )
                    jt
                WHERE
                    jt.slot_number IS NOT NULL
            ) LOOP
                UPDATE terext_slot_plan_dtls t
                SET
                    t.slot_type =
                        CASE
                            WHEN r.has_slot_type = 1
                                 AND r.slot_type IS NOT NULL THEN
                                r.slot_type
                            ELSE
                                t.slot_type
                        END,
                    t.planning_organization =
                        CASE
                            WHEN r.has_planning_organization = 1
                                 AND r.planning_organization IS NOT NULL THEN
                                r.planning_organization
                            ELSE
                                t.planning_organization
                        END,
                    t.manufacture =
                        CASE
                            WHEN r.has_manufacture = 1
                                 AND r.manufacture IS NOT NULL THEN
                                r.manufacture
                            ELSE
                                t.manufacture
                        END,
                    t.manufacture_site =
                        CASE
                            WHEN r.has_manufacture_site = 1
                                 AND r.manufacture_site IS NOT NULL THEN
                                r.manufacture_site
                            ELSE
                                t.manufacture_site
                        END,
                    t.schedule_date =
                        CASE
                            WHEN r.has_schedule_date = 1
                                 AND r.schedule_date IS NOT NULL THEN
                                r.schedule_date
                            ELSE
                                t.schedule_date
                        END,
                    t.promised_date =
                        CASE
                            WHEN r.has_promised_date = 1
                                 AND r.promised_date IS NOT NULL THEN
                                r.promised_date
                            ELSE
                                t.promised_date
                        END,
                    t.pd_qtr =
                        CASE
                            WHEN r.has_pd_qtr = 1
                                 AND r.pd_qtr IS NOT NULL THEN
                                r.pd_qtr
                            ELSE
                                t.pd_qtr
                        END,
                    t.mrp_qtr =
                        CASE
                            WHEN r.has_mrp_qtr = 1
                                 AND r.mrp_qtr IS NOT NULL THEN
                                r.mrp_qtr
                            ELSE
                                t.mrp_qtr
                        END,
                    t.updated_by =
                        CASE
                            WHEN r.has_updated_by = 1
                                 AND r.updated_by IS NOT NULL THEN
                                r.updated_by
                            ELSE
                                t.updated_by
                        END,
                    t.updated_date = sysdate
                WHERE
                    t.slot_number = r.slot_number;

                l_cnt := l_cnt + SQL%rowcount;
            END LOOP;
        END IF;

        p_rows_out := l_cnt;
        IF p_rows_out = 0 THEN
            p_message := 'No rows updated (no matching SLOT_NUMBER in table, or empty payload).';
        ELSE
            p_message := 'Updated '
                         || p_rows_out
                         || ' row(s).';
        END IF;

        COMMIT;
    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            p_rows_out := 0;
            p_status := 'ERROR';
            p_message := substr('SQLCODE='
                                || sqlcode
                                || '; SQLERRM='
                                || sqlerrm
                                || '; BT='
                                || dbms_utility.format_error_backtrace, 1, 4000);

    END terext_slot_bulk_update_from_json;

    PROCEDURE terslot_bulk_update_validate_csv (
        p_filename IN VARCHAR2
    ) IS
    BEGIN
        UPDATE terext_slot_bulk_upload_csv c
        SET
            status = 'INVALID',
            error_msg = rtrim(
                CASE
                    WHEN c.slot_number IS NULL THEN
                        'SLOT NUMBER is required; '
                    WHEN NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terext_slot_plan_dtls f
                        WHERE
                            f.slot_number = c.slot_number
                    ) THEN
                        'SLOT NUMBER does not exist; '
                END
                ||
                CASE
                    WHEN c.slot_type IS NOT NULL
                         AND NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terext_slot_type g
                        WHERE
                            g.name = c.slot_type
                    ) THEN
                        'SLOT TYPE not found; '
                END
                ||
                CASE
                    WHEN c.planning_organization IS NOT NULL
                         AND NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terext_slot_planning_org_dtls p
                        WHERE
                                p.orgname = c.planning_organization
                            AND p.system =(
                                SELECT
                                    f.system
                                FROM
                                    terext_slot_plan_dtls f
                                WHERE
                                    f.slot_number = c.slot_number
                            )
                    ) THEN
                        'PLANNING ORGANIZATION not found for Slot System; '
                END
                ||
                CASE
                    WHEN c.manufacture IS NOT NULL
                         AND NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terpo_vendor_stg a
                        WHERE
                            a.partyname = c.manufacture
                    ) THEN
                        'MANUFACTURE not found; '
                END
                ||
                CASE
                    WHEN c.manufacture_site IS NOT NULL
                         AND NOT EXISTS(
                        SELECT
                            1
                        FROM
                            terpo_vendorsites_stg b
                        WHERE
                                b.vendorsitecode = c.manufacture_site
                            AND b.vendorid =(
                                SELECT
                                    vendorid
                                FROM
                                    terpo_vendor_stg
                                WHERE
                                    partyname = c.manufacture
                                FETCH FIRST 1 ROW ONLY
                            )
                    ) THEN
                        'MANUFACTURE SITE not found; '
                END, '; ')
        WHERE
                c.filename = p_filename
            AND ( c.slot_number IS NULL
                  OR NOT EXISTS (
                SELECT
                    1
                FROM
                    terext_slot_plan_dtls f
                WHERE
                    f.slot_number = c.slot_number
            )
                  OR ( c.slot_type IS NOT NULL
                       AND NOT EXISTS (
                SELECT
                    1
                FROM
                    terext_slot_type g
                WHERE
                    g.name = c.slot_type
            ) )
                  OR ( c.planning_organization IS NOT NULL
                       AND NOT EXISTS (
                SELECT
                    1
                FROM
                    terext_slot_planning_org_dtls p
                WHERE
                        p.orgname = c.planning_organization
                    AND p.system = (
                        SELECT
                            f.system
                        FROM
                            terext_slot_plan_dtls f
                        WHERE
                            f.slot_number = c.slot_number
                    )
            ) )
                  OR ( c.manufacture IS NOT NULL
                       AND NOT EXISTS (
                SELECT
                    1
                FROM
                    terpo_vendor_stg a
                WHERE
                    a.partyname = c.manufacture
            ) )
                  OR ( c.manufacture_site IS NOT NULL
                       AND NOT EXISTS (
                SELECT
                    1
                FROM
                    terpo_vendorsites_stg b
                WHERE
                        b.vendorsitecode = c.manufacture_site
                    AND b.vendorid = (
                        SELECT
                            vendorid
                        FROM
                            terpo_vendor_stg
                        WHERE
                            partyname = c.manufacture
                        FETCH FIRST 1 ROW ONLY
                    )
            ) ) );

        UPDATE terext_slot_bulk_upload_csv
        SET
            status = 'VALID',
            error_msg = NULL
        WHERE
                filename = p_filename
            AND status IS NULL;

    END terslot_bulk_update_validate_csv;

END terslot_table_api;

/
--------------------------------------------------------
--  DDL for Package Body TERSLOT_VEERA_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TERSLOT_VEERA_PKG" AS   
--Operation Marketing

--cursor query to get the partials details for ops and mkt 
CURSOR cur_partial_dtls (
        p_data BLOB
						) IS
    SELECT        
        part_number,
        part_description,
        quantity,
        Promise_Date,
        Partial_Approved,
        comments,
        source
    FROM
        JSON_TABLE 
		( p_data FORMAT JSON, '$[*]' --'$'  -- If payload is an array, change to '$[*]'
            COLUMNS (
					Part_Number            VARCHAR2  PATH '$.part_number',
					Part_Description       VARCHAR2  PATH '$.part_description',
					Quantity               VARCHAR2  PATH '$.quantity',
					Promise_Date           TIMESTAMP PATH '$.promise_date',
					Partial_Approved       VARCHAR2  PATH '$.partial_approved',
					Comments               VARCHAR2  PATH '$.comments',
					source                 VARCHAR2  PATH '$.source'
					)
                    

        );
	TYPE partial_tab_type IS TABLE OF cur_partial_dtls%rowtype;
    l_partial_tab   partial_tab_type; 
    
--cursor query to get the refurb details for ops and mkt 
	
    CURSOR cur_refurb_dtls (
							p_data BLOB
							) IS    
		
    SELECT        
        part_number,
        part_description,
        quantity,
        Promise_Date,
        refurb_Approved,
        comments,
        source,
        ship_from_site
    FROM
        JSON_TABLE 
		( p_data FORMAT JSON, '$[*]' --'$'  -- If payload is an array, change to '$[*]'
            COLUMNS (
                Part_Number            VARCHAR2  PATH '$.part_number',
                Part_Description       VARCHAR2  PATH '$.part_description',
                Quantity               VARCHAR2  PATH '$.quantity',
                Promise_Date           TIMESTAMP PATH '$.promise_date',
                Refurb_Approved        VARCHAR2  PATH '$.refurb_approved',
                Comments               VARCHAR2  PATH '$.comments',
                source                 VARCHAR2  PATH '$.source',
                ship_from_site         VARCHAR2  PATH '$.ship_from_site'
                
                
            )
        );
	TYPE refurb_tab_type IS TABLE OF cur_refurb_dtls%rowtype;
    l_refurb_tab   refurb_tab_type; 

--procedure to add partials table for both ops and mkt     
PROCEDURE ops_partials_dtls (
        p_in_slotnum      VARCHAR2,
		p_in_refnum       VARCHAR2,
        p_in_partial_flag VARCHAR2,
		p_in_source       VARCHAR2,
        p_in_user         VARCHAR2,
        p_in_partial_body BLOB DEFAULT NULL,
        p_out_status OUT  VARCHAR2,
        p_out_msg    OUT  VARCHAR2
    )
    IS 
    BEGIN 
	
    insert into test_slot_log(col1,col2,col3,col4) values('1','START-ops_partials_dtls-'||p_in_slotnum,p_in_refnum,p_in_partial_flag);

        IF p_in_partial_flag = 'Y' THEN    
	  
            OPEN cur_partial_dtls(p_in_partial_body);
            FETCH cur_partial_dtls BULK COLLECT INTO l_partial_tab;
            CLOSE cur_partial_dtls;
            
            
            IF l_partial_tab.COUNT >=1 THEN 
            insert into test_slot_log(col1,col2,col3,col4) values('2','ops_partials_dtls-',null,null);

			   --Loading partials Data into a temp table 
               FOR i IN l_partial_tab.FIRST..l_partial_tab.LAST
                    LOOP 
            insert into test_slot_log(col1,col2,col3,col4) values('3','Insert Partial Details Into Temp Table',null,null);

                     INSERT INTO 
                     TEREXT_SLOT_PARTS_TEMP
                       (
					     part_number,
						 part_description,
						 quantity,
						 Promise_Date,
						 Partial_Approved,
						 comments,source,
						 slotnum,
						 refnum,
						 created_by,
						 created_date,
						 itemtype
						) 
						 VALUES
						 (
						 l_partial_tab(i).part_number,
						 l_partial_tab(i).part_description,
						 l_partial_tab(i).quantity,
						 l_partial_tab(i).Promise_Date,               
						 l_partial_tab(i).Partial_Approved,
						 l_partial_tab(i).comments,
						 l_partial_tab(i).source,
						 p_in_slotnum,
						 p_in_refnum,
						 p_in_user,
						 sysdate,
						 'PARTIAL'
						 ); 
                    END LOOP;
					
             IF p_in_source='Operation' THEN 
			 insert into test_slot_log(col1,col2,col3,col4) values('4','Add Partial Details For Operation Page',null,null);

			 --If partials details are already there then update the details else insert the details
				 MERGE INTO TEREXT_SLOT_PARTS target2
				 USING(
				 SELECT        
						part_number,
						part_description,
						quantity,
						Promise_Date,
						Partial_Approved,
						comments,
						source,
						slotnum,
					    refnum,
						created_by,
						created_date
						FROM TEREXT_SLOT_PARTS_TEMP   
						WHERE itemtype='PARTIAL'
					  ) source2
					  ON (
					      1=1
						  AND target2.slot_number = source2.slotnum 
						  AND target2.config_num  = source2.refnum 
						  AND target2.part_number = source2.part_number
						  AND target2.quantity    = source2.quantity
						  )
					WHEN MATCHED THEN
					UPDATE
						   SET target2.promise_date    = source2.promise_date,
							   target2.comments        = source2.comments,   
							   target2.updated_by      = p_in_user,
							   target2.updated_date    = SYSDATE     
					WHEN NOT MATCHED THEN
					INSERT 
					 (
					  slot_number,
					  part_number,
					  part_description,
					  quantity,
					  promise_date,
					  comments,
					  created_by,
					  created_date,
                      config_num
					  )                
					values(
					 source2.slotnum,
					 source2.part_number,
					 source2.part_description,
					 source2.quantity,
					 source2.Promise_Date,
					 source2.comments,
					 p_in_user,
					 sysdate,
                     source2.refnum
					  );     
					  
             END IF; --END of p_in_source='Operation'
             
             
			 IF p_in_source='Marketing' THEN 
			 insert into test_slot_log(col1,col2,col3,col4) values('5','Add Partial Details For Marketing Page',null,null);

			 --If partials details are already there then update the details else insert the details
             MERGE INTO TEREXT_SLOT_PARTS target2
             USING(
             SELECT        
                    part_number,
                    part_description,
                    quantity,
                    Promise_Date,
                    Partial_Approved,
                    comments,
                    source,
                    slotnum,
                    refnum,
					created_by,
					created_date
                    FROM TEREXT_SLOT_PARTS_TEMP
					WHERE itemtype='PARTIAL'
                   ) source2
                  ON ( 1=1
				      AND target2.slot_number = source2.slotnum 
					  AND target2.config_num  = source2.refnum 
                      AND target2.part_number = source2.part_number
                      AND target2.quantity    = source2.quantity
                      )
                 WHEN MATCHED THEN
                 UPDATE
                       SET target2.partial_approved = source2.Partial_Approved,
                           target2.comments         = source2.comments,   
                           target2.updated_by       = p_in_user,
                           target2.updated_date     = SYSDATE                           
                   ;          
             END IF; --END of p_in_source='Operation'
             
             --drop data from  temp table 
             DELETE FROM TEREXT_SLOT_PARTS_TEMP WHERE itemtype='PARTIAL';
             insert into test_slot_log(col1,col2,col3,col4) values('6','Deleted Data From Temp Table',null,null);

			 
			 UPDATE TEREXT_SLOT_PLAN_DTLS  SET partial_flag='Y' WHERE slot_number=p_in_slotnum;
			 
			 p_out_status := 'Success';
             p_out_msg    := 'Partial Details Inserted/Updated Succesfully.';
			
            END IF; --END of l_partial_tab.COUNT >=1            
            
		ELSE 
            p_out_status := 'Success';
            p_out_msg    := 'No change In Partial Details.';
        END IF;
       
       COMMIT;
    EXCEPTION 
	WHEN OTHERS THEN
    ROLLBACK;
    p_out_status := 'Error';
    p_out_msg    := 'Exception is -'|| SUBSTR(SQLERRM,1,100);
        
    END;
 	
PROCEDURE ops_refurb_dtls (
        p_in_slotnum      VARCHAR2,
		p_in_refnum       VARCHAR2,
        p_in_refurb_flag  VARCHAR2,
        p_in_source       VARCHAR2,
        p_in_user         VARCHAR2,
