					  AND target2.config_num  = source2.refnum 
                      AND target2.part_number = source2.part_number
                      AND target2.quantity    = source2.quantity
                       )
                 WHEN MATCHED THEN
                 UPDATE
                       SET target2.promise_date    = source2.promise_date,
                           target2.comments        = source2.comments,   
                           target2.updated_by      = p_in_user,
                           target2.updated_date    = SYSDATE,
                           target2.ship_from_site  = source2.ship_from_site
                           
                 WHEN NOT MATCHED THEN
                INSERT 
                 (slot_number,
                  part_number,
                  part_description,
                  quantity,
                  promise_date,
                  comments,
                  created_by,
                  created_date,
                  ship_from_site,
                  config_num
                  )                
		        values(
                 source2.slotnum,
                 source2.part_number,
                 source2.part_description,
                 source2.quantity,
                 source2.Promise_Date,
                 source2.comments,
                 p_in_user,
                 sysdate,
                 source2.ship_from_site,
                 source2.refnum
                  );          
         END IF; --END of p_in_source='Operation'
         
		 IF p_in_source = 'Marketing' THEN 
		insert into test_slot_log(col1,col2,col3,col4) values('4','Add refurb Details For Marketing Page',null,null);

             MERGE INTO TEREXT_SLOT_PARTS_REFURB target2
             USING(
             SELECT        
                    part_number,
                    part_description,
                    quantity,
                    Promise_Date,
                    refurb_Approved,
                    comments,
                    source,
                    slotnum,
                    refnum,
					created_by,
					created_date					
                    FROM TEREXT_SLOT_PARTS_TEMP
                    WHERE itemtype='REFURB'
                  ) source2
                  ON (
				      1=1
					  AND target2.slot_number = source2.slotnum 
					  AND target2.config_num  = source2.refnum 
                      AND target2.part_number = source2.part_number
                      AND target2.quantity    = source2.quantity
                      )
                WHEN MATCHED THEN                
				UPDATE
                       SET target2.refurb_approved = source2.refurb_approved,
                           target2.comments        = source2.comments,   
                           target2.updated_by      = p_in_user,
                           target2.updated_date    = SYSDATE  
				;
				
             END IF; --END of p_in_source='Marketing'
			 
         DELETE FROM TEREXT_SLOT_PARTS_TEMP WHERE itemtype='REFURB';
		  insert into test_slot_log(col1,col2,col3,col4) values('5','Deleted data from temp table ',null,null);
		 UPDATE TEREXT_SLOT_PLAN_DTLS  SET refurb_flag='Y' WHERE slot_number=p_in_slotnum;

        END IF; --End Of l_refurb_tab.count>=1 
 	  

      p_out_status := 'Success';
      p_out_msg    := 'refurb Details Inserted/Updated Succesfully.';
	  
     ELSE
      p_out_status := 'Success';
      p_out_msg    := 'No change In Refurb Details.';
	  
    END IF;--END OF p_in_refurb_flag = 'Y'
    COMMIT;
    EXCEPTION 
	WHEN OTHERS THEN
    ROLLBACK;
    p_out_status := 'Error';
    p_out_msg    := 'Exception is -'|| SUBSTR(SQLERRM,1,100);
    END;
       

END terslot_veera_pkg;

/
--------------------------------------------------------
--  DDL for Package Body TER_AP_INV_APPROVAL_ROUTING_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TER_AP_INV_APPROVAL_ROUTING_PKG" AS

   gc_enabled CONSTANT flag_vc1 := 'Y';

   gc_null_acct_key CONSTANT VARCHAR2(20) := '#NULL_ACCT#';

   TYPE t_sum_by_natural_acct IS TABLE OF NUMBER INDEX BY VARCHAR2(4000);

   FUNCTION nvl_flag(p VARCHAR2) RETURN flag_vc1 IS
   BEGIN
      RETURN NVL(UPPER(SUBSTR(p, 1, 1)), 'N');
   END;

   FUNCTION cnt_headers(p IN ter_rtr_ap_approval_header_nt) RETURN PLS_INTEGER IS
   BEGIN
      IF p IS NULL THEN
         RETURN 0;
      END IF;
      RETURN p.COUNT;
   END cnt_headers;

   FUNCTION cnt_lines(p IN ter_rtr_ap_approval_line_nt) RETURN PLS_INTEGER IS
   BEGIN
      IF p IS NULL THEN
         RETURN 0;
      END IF;
      RETURN p.COUNT;
   END cnt_lines;

   FUNCTION cnt_hier(p IN ter_rtr_ap_approval_hier_nt) RETURN PLS_INTEGER IS
   BEGIN
      IF p IS NULL THEN
         RETURN 0;
      END IF;
      RETURN p.COUNT;
   END cnt_hier;

   FUNCTION cnt_signlim(p IN ter_rtr_ap_approval_signlimit_nt) RETURN PLS_INTEGER IS
   BEGIN
      IF p IS NULL THEN
         RETURN 0;
      END IF;
      RETURN p.COUNT;
   END cnt_signlim;

   FUNCTION cnt_sigovr(p IN ter_rtr_ap_approval_sigovr_nt) RETURN PLS_INTEGER IS
   BEGIN
      IF p IS NULL THEN
         RETURN 0;
      END IF;
      RETURN p.COUNT;
   END cnt_sigovr;

   FUNCTION lookup_limits_for_user(
      p_username IN VARCHAR2,
      p_grade    IN VARCHAR2,
      p_limits   IN ter_rtr_ap_approval_signlimit_nt
   ) RETURN ter_rtr_ap_approval_signlimit_ot IS
      l_empty ter_rtr_ap_approval_signlimit_ot := ter_rtr_ap_approval_signlimit_ot(
                                                    NULL, NULL, NULL, NULL, NULL, NULL);
      i       PLS_INTEGER;
   BEGIN
      FOR i IN 1 .. cnt_signlim(p_limits) LOOP
         IF nvl_flag(p_limits(i).enabled_flag) = gc_enabled THEN
            IF p_grade IS NOT NULL
               AND p_limits(i).grade_name IS NOT NULL
               AND UPPER(TRIM(p_limits(i).grade_name)) = UPPER(TRIM(p_grade))
            THEN
               RETURN p_limits(i);
            END IF;
         END IF;
      END LOOP;

      FOR i IN 1 .. cnt_signlim(p_limits) LOOP
         IF nvl_flag(p_limits(i).enabled_flag) = gc_enabled THEN
            IF p_username IS NOT NULL
               AND UPPER(TRIM(p_limits(i).lookup_code)) = UPPER(TRIM(p_username))
            THEN
               RETURN p_limits(i);
            END IF;
         END IF;
      END LOOP;

      RETURN l_empty;
   END lookup_limits_for_user;

   FUNCTION primary_expense_limit(
      p_username IN VARCHAR2,
      p_grade    IN VARCHAR2,
      p_limits   IN ter_rtr_ap_approval_signlimit_nt
   ) RETURN NUMBER IS
      l_lim ter_rtr_ap_approval_signlimit_ot;
   BEGIN
      l_lim := lookup_limits_for_user(p_username, p_grade, p_limits);
      RETURN NVL(l_lim.expense_limit, -1);
   END primary_expense_limit;

   FUNCTION cnt_lines_for_invoice(
      p_lines      IN ter_rtr_ap_approval_line_nt,
      p_invoice_id IN NUMBER
   ) RETURN PLS_INTEGER IS
      j PLS_INTEGER;
      n PLS_INTEGER := 0;
   BEGIN
      FOR j IN 1 .. cnt_lines(p_lines) LOOP
         IF NVL(p_lines(j).invoice_id, -1) = NVL(p_invoice_id, -1) THEN
            n := n + 1;
         END IF;
      END LOOP;
      RETURN n;
   END cnt_lines_for_invoice;
   /** OIC often omits ENABLED_FLAG on overrides; NULL means row is active. */
   FUNCTION override_row_active(p_enabled IN VARCHAR2) RETURN BOOLEAN IS
   BEGIN
      IF p_enabled IS NULL THEN
         RETURN TRUE;
      END IF;
      RETURN nvl_flag(p_enabled) = gc_enabled;
   END override_row_active;


   /**
    * Exception lookup only (no primary EXP fallback). NULL if no enabled row for approver + account.
    */
   FUNCTION exception_override_for_account(
      p_approver_email  IN VARCHAR2,
      p_natural_account IN VARCHAR2,
      p_ovr             IN ter_rtr_ap_approval_sigovr_nt
   ) RETURN NUMBER IS
      j      PLS_INTEGER;
      l_best NUMBER := NULL;
      l_nat  VARCHAR2(4000);
      l_cand NUMBER;
   BEGIN
      l_nat := NULLIF(TRIM(p_natural_account), '');

      FOR j IN 1 .. cnt_sigovr(p_ovr) LOOP
         IF NOT override_row_active(p_ovr(j).enabled_flag) THEN
            GOTO next_ovr;
         END IF;
         IF UPPER(TRIM(p_ovr(j).approver_email)) != UPPER(TRIM(p_approver_email)) THEN
            GOTO next_ovr;
         END IF;
         IF p_ovr(j).override_account_number IS NULL THEN
            GOTO next_ovr;
         END IF;
         IF l_nat IS NULL THEN
            GOTO next_ovr;
         END IF;
         IF TRIM(p_ovr(j).override_account_number) != l_nat THEN
            GOTO next_ovr;
         END IF;

         l_cand :=
            NVL(p_ovr(j).override_purchase_limit, NVL(p_ovr(j).override_inventory_limit, p_ovr(j).purchase_limit));
         IF l_cand IS NOT NULL
            AND (l_best IS NULL OR l_cand > l_best)
         THEN
            l_best := l_cand;
         END IF;

         <<next_ovr>>
         NULL;
      END LOOP;

      RETURN l_best;
   END exception_override_for_account;

   /** Each account bucket must have an exception row and sum <= override limit. */
   FUNCTION approver_covers_lines_exception_only(
      p_approver_email IN VARCHAR2,
      p_invoice_id     IN NUMBER,
      p_lines          IN ter_rtr_ap_approval_line_nt,
      p_ovr            IN ter_rtr_ap_approval_sigovr_nt
   ) RETURN BOOLEAN IS
      j        PLS_INTEGER;
      l_exc    NUMBER;
      l_sum    t_sum_by_natural_acct;
      l_key    VARCHAR2(4000);
      l_nat    VARCHAR2(4000);
      l_bucket NUMBER;
   BEGIN
      FOR j IN 1 .. cnt_lines(p_lines) LOOP
         IF NVL(p_lines(j).invoice_id, -1) != NVL(p_invoice_id, -1) THEN
            GOTO next_line_in;
         END IF;

         IF TRIM(p_lines(j).natural_account) IS NULL THEN
            l_key := gc_null_acct_key;
         ELSE
            l_key := TRIM(p_lines(j).natural_account);
         END IF;

         IF l_sum.EXISTS(l_key) THEN
            l_sum(l_key) := l_sum(l_key) + NVL(p_lines(j).line_amount, 0);
         ELSE
            l_sum(l_key) := NVL(p_lines(j).line_amount, 0);
         END IF;

         <<next_line_in>>
         NULL;
      END LOOP;

      l_key := l_sum.FIRST;
      WHILE l_key IS NOT NULL LOOP
         l_bucket := l_sum(l_key);
         IF l_key = gc_null_acct_key THEN
            l_nat := NULL;
         ELSE
            l_nat := l_key;
         END IF;

         l_exc := exception_override_for_account(p_approver_email, l_nat, p_ovr);

         IF l_exc IS NULL THEN
            RETURN FALSE;
         END IF;

         IF NVL(l_bucket, 0) > NVL(l_exc, -1) THEN
            RETURN FALSE;
         END IF;

         l_key := l_sum.NEXT(l_key);
      END LOOP;

      RETURN TRUE;
   END approver_covers_lines_exception_only;

   FUNCTION max_hierarchy_level(p_hier IN ter_rtr_ap_approval_hier_nt) RETURN NUMBER IS
      i PLS_INTEGER;
      m NUMBER := 0;
   BEGIN
      FOR i IN 1 .. cnt_hier(p_hier) LOOP
         m := GREATEST(m, NVL(p_hier(i).hierarchy_level, 0));
      END LOOP;
      RETURN m;
   END max_hierarchy_level;

   FUNCTION first_approver_by_exception_lines(
      p_invoice_id  IN NUMBER,
      p_hdr         IN ter_rtr_ap_approval_header_ot,
      p_lines       IN ter_rtr_ap_approval_line_nt,
      p_hierarchy   IN ter_rtr_ap_approval_hier_nt,
      p_ovr         IN ter_rtr_ap_approval_sigovr_nt
   ) RETURN VARCHAR2 IS
      l_lvl PLS_INTEGER;
      l_h   PLS_INTEGER;
      l_req VARCHAR2(512);
      l_max NUMBER;
   BEGIN
      IF cnt_lines_for_invoice(p_lines, p_invoice_id) = 0 THEN
         RETURN NULL;
      END IF;

      l_req := TRIM(p_hdr.requester_email);

      IF approver_covers_lines_exception_only(
            l_req,
            p_invoice_id,
            p_lines,
            p_ovr)
      THEN
         RETURN l_req;
      END IF;

      l_max := NVL(max_hierarchy_level(p_hierarchy), 0);

      FOR l_lvl IN 1 .. l_max LOOP
         FOR l_h IN 1 .. cnt_hier(p_hierarchy) LOOP
            IF NVL(p_hierarchy(l_h).hierarchy_level, -1) != l_lvl THEN
               GOTO next_hier_row;
            END IF;

            l_req := TRIM(p_hierarchy(l_h).manager_username);

            IF approver_covers_lines_exception_only(
                  l_req,
                  p_invoice_id,
                  p_lines,
                  p_ovr)
            THEN
               RETURN l_req;
            END IF;

            <<next_hier_row>>
            NULL;
         END LOOP;
      END LOOP;

      RETURN NULL;
   END first_approver_by_exception_lines;

   /** Primary signing limit vs header total (no line / exception logic). */
   FUNCTION first_approver_by_header_sign(
      p_hdr_amt     IN NUMBER,
      p_hdr         IN ter_rtr_ap_approval_header_ot,
      p_hierarchy   IN ter_rtr_ap_approval_hier_nt,
      p_sign_limits IN ter_rtr_ap_approval_signlimit_nt
   ) RETURN VARCHAR2 IS
      l_lvl PLS_INTEGER;
      l_h   PLS_INTEGER;
      l_req VARCHAR2(512);
      l_pri NUMBER;
      l_max NUMBER;
   BEGIN
      l_req := TRIM(p_hdr.requester_email);
      l_pri := primary_expense_limit(l_req, p_hdr.requester_grade, p_sign_limits);

      IF l_pri >= NVL(p_hdr_amt, 0) THEN
         RETURN l_req;
      END IF;

      l_max := NVL(max_hierarchy_level(p_hierarchy), 0);

      FOR l_lvl IN 1 .. l_max LOOP
         FOR l_h IN 1 .. cnt_hier(p_hierarchy) LOOP
            IF NVL(p_hierarchy(l_h).hierarchy_level, -1) != l_lvl THEN
               GOTO next_hier_row_hd;
            END IF;

            l_req := TRIM(p_hierarchy(l_h).manager_username);
            l_pri :=
               primary_expense_limit(
                  l_req,
                  p_hierarchy(l_h).manager_grade,
                  p_sign_limits);

            IF l_pri >= NVL(p_hdr_amt, 0) THEN
               RETURN l_req;
            END IF;

            <<next_hier_row_hd>>
            NULL;
         END LOOP;
      END LOOP;

      RETURN NULL;
   END first_approver_by_header_sign;

   PROCEDURE derive_routing_attribute_3 (
      p_headers         IN ter_rtr_ap_approval_header_nt,
      p_lines           IN ter_rtr_ap_approval_line_nt,
      p_hierarchy       IN ter_rtr_ap_approval_hier_nt,
      p_sign_limits     IN ter_rtr_ap_approval_signlimit_nt,
      p_limit_overrides IN ter_rtr_ap_approval_sigovr_nt DEFAULT ter_rtr_ap_approval_sigovr_nt(),
      p_ra3_results       OUT NOCOPY ter_rtr_ap_approval_ra3_nt
   ) IS
      i          PLS_INTEGER;
      l_row      ter_rtr_ap_approval_ra3_ot;
      l_pick     VARCHAR2(512);
      gc_mgr     CONSTANT VARCHAR2(30) := 'SUCCESS_MANAGER';
      gc_req     CONSTANT VARCHAR2(30) := 'SUCCESS_REQUESTER';
      gc_warn    CONSTANT VARCHAR2(30) := 'WARNING';
   BEGIN
      p_ra3_results := ter_rtr_ap_approval_ra3_nt();

      FOR i IN 1 .. cnt_headers(p_headers) LOOP
         l_pick :=
            first_approver_by_exception_lines(
               p_headers(i).invoice_id,
               p_headers(i),
               p_lines,
               p_hierarchy,
               p_limit_overrides);

         IF l_pick IS NULL THEN
            l_pick :=
               first_approver_by_header_sign(
                  NVL(p_headers(i).invoice_amount, 0),
                  p_headers(i),
                  p_hierarchy,
                  p_sign_limits);
         END IF;

         IF l_pick IS NULL THEN
            l_row :=
               ter_rtr_ap_approval_ra3_ot(
                  invoice_id      => p_headers(i).invoice_id,
                  routing_attr3   => NULL,
                  status_code     => gc_warn,
                  status_message  =>
                     'No exception-line approver and no header EXP approver for invoice amount.');
         ELSIF UPPER(TRIM(l_pick)) = UPPER(TRIM(p_headers(i).requester_email))
         THEN
            l_row :=
               ter_rtr_ap_approval_ra3_ot(
                  invoice_id      => p_headers(i).invoice_id,
                  routing_attr3   => NULL,
                  status_code     => gc_req,
                  status_message  => NULL);
         ELSE
            l_row :=
               ter_rtr_ap_approval_ra3_ot(
                  invoice_id      => p_headers(i).invoice_id,
                  routing_attr3   => l_pick,
                  status_code     => gc_mgr,
                  status_message  => NULL);
         END IF;

         p_ra3_results.EXTEND;
         p_ra3_results(p_ra3_results.LAST) := l_row;
      END LOOP;
   END derive_routing_attribute_3;

END ter_ap_inv_approval_routing_pkg;

/
--------------------------------------------------------
--  DDL for Package Body TER_EMAIL_TEMPLATES_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TER_EMAIL_TEMPLATES_PKG" IS
  
  PROCEDURE get_email_data_prc (
      p_in_email_template                   IN    VARCHAR2,
      p_in_interfaceid                      IN    VARCHAR2,
      p_in_batchid                             IN    VARCHAR2,
      p_in_source_directory                    IN    VARCHAR2,
      p_in_source_filepattern                  IN    VARCHAR2,
      p_in_instanceid                          IN    VARCHAR2,
      p_in_filename                            IN    VARCHAR2,
      p_in_send_email                          IN    VARCHAR2,
      p_in_metadata_read_sts                   IN    VARCHAR2,
      p_in_file_read_sts                       IN    VARCHAR2,
      p_in_file_format_sts                     IN    VARCHAR2,
      p_in_src_data_validation_sts             IN    VARCHAR2,
      p_in_src_data_transform_sts              IN    VARCHAR2,
      p_in_fbdi_hdl_file_write_sts             IN    VARCHAR2,
      p_in_fbdi_hdl_file_zip_sts               IN    VARCHAR2,
      p_in_fbdi_hdl_get_prop_file_sts          IN    VARCHAR2,
      p_in_fbdi_hdl_prop_write_sts             IN    VARCHAR2,
      p_in_fbdi_hdl_file_archive_sts           IN    VARCHAR2,
      p_in_erp_zip_file_name                   IN    VARCHAR2,
      p_in_ucm_upload_sts                      IN    VARCHAR2,
      p_in_loadint_ess_jobid                   IN    VARCHAR2,
      p_in_loadint_ess_jobstatus               IN    VARCHAR2,
      p_in_baseimport_ess_jobid                IN    VARCHAR2,
      p_in_baseimport_ess_jobstatus            IN    VARCHAR2,
      p_in_total_rowcount                      IN    VARCHAR2,
      p_in_mw_error_rowcount                   IN    VARCHAR2,
      p_in_cloud_error_rowcount                IN    VARCHAR2,
      p_in_success_rowcount                    IN    VARCHAR2,
      p_in_integration_status                  IN    VARCHAR2,
      p_in_error_code                          IN    VARCHAR2,
      p_in_error_message                       IN    VARCHAR2,
      p_in_attribute1                          IN    VARCHAR2,
      p_in_attribute2                          IN    VARCHAR2,
      p_in_attribute3                          IN    VARCHAR2,
      p_in_attribute4                          IN    VARCHAR2,
      p_in_attribute5                          IN    VARCHAR2,
      p_in_attribute6                          IN    VARCHAR2,
      p_in_attribute7                          IN    VARCHAR2,
      p_in_attribute8                          IN    VARCHAR2,
      p_in_attribute9                          IN    VARCHAR2,
      p_in_attribute10                         IN    VARCHAR2,
      p_in_Success_Mes                         IN    VARCHAR2,
      p_out_email_subject                   OUT   CLOB,
      p_out_email_body                      OUT   CLOB
   ) IS
    BEGIN
      IF NVL(p_in_send_email, 'Y') = 'Y' THEN
           --FTP error notifications
           IF p_in_email_template = 'INT_METADATA_NOT_FOUND' THEN
               p_out_email_subject := 'Batch #p_in_batchid - Job has Failed';
               p_out_email_body := '<p>Batch #p_in_batchid has failed to execute because metadata for the interface was not found.</p>      
                                <p>Expected metadata - Source SFTP directory, File Name pattern and child integration URI path.</p>
                                <p>#p_in_error_message</p>'
               ;
           ELSIF p_in_email_template = 'INT_NO_FILE_FOUND' THEN
               p_out_email_subject := 'OIC Instance #p_in_instanceid - Job has Failed';
               p_out_email_body := '<p>OIC Instance #p_in_instanceid has failed during file transfer process from SFTP server, since no source files were present for processing.</p>
                                <p>Expected SFTP directory - #p_in_source_directory</p>
                                <p>Expected File Pattern: #p_in_source_filepattern</p>
                                <p>#p_in_error_message</p>'
               ;
           ELSIF p_in_email_template = 'INT_EMPTY_FILE' THEN
               p_out_email_subject := 'OIC Instance #p_in_instanceid - Job has Completed';
               p_out_email_body := '<p>OIC Instance #p_in_instanceid has completed, no data source files available for processing.</p>
                                <p>Source File: #p_in_filename</p>
                                <p>#p_in_error_message</p>'
               ;
           ELSIF p_in_email_template = 'INT_FBDI_WRITE_FAULT' THEN
               p_out_email_subject := 'Batch #p_in_batchid - Job has Failed';
               p_out_email_body := '<p>The interface failed during FBDI file creation in middleware.</p>
                                <p>Review middleware instance ID: #p_in_instanceid for more details. Please resolve errors and execute the integration again.</p>
                                <p>#p_in_error_message</p>'
               ;
           ELSIF p_in_email_template = 'INT_VAL_FAULT' THEN
               p_out_email_subject := 'OIC Instance #p_in_instanceid - Job has Failed';
               p_out_email_body := '<p>OIC Instance #p_in_instanceid has failed to process file internally. Below are the possible reason(s) for the failure:</p>
                                <p>1. The source file might be missing one or more fields and not conforming to the specified schema.</p>
                                <p>2. Review middleware instance ID: #p_in_instanceid for more details. Please resolve errors and execute the integration again.</p>
                                <p>#p_in_error_message</p>'
               ;
           --Zip FBDI and UCM Scope notifications
           ELSIF p_in_email_template = 'INT_ZIP_FBDI_FAILED' THEN
               p_out_email_subject := 'Batch #p_in_batchid - Job has Failed';
               p_out_email_body := '<p>Batch #p_in_batchid has failed during FBDI Zip file generation.</p>
                                <p>Review middleware instance ID: #p_in_instanceid for more details. Please resolve errors and execute the integration again.</p>
                                <p>#p_in_error_message</p>'
               ;
           ELSIF p_in_email_template = 'INT_ZIP_FAULT' THEN
               p_out_email_subject := 'Batch #p_in_batchid - Job has Failed';
               p_out_email_body := '<p>Batch #p_in_batchid has failed during FBDI Zip file generation with below error. Review middleware instance ID: #p_in_instanceid for more details. Please resolve errors and execute the integration again.</p>
                                <p>Error message: #p_in_error_message</p>'
               ;
            ELSIF p_in_email_template = 'INT_SUCCESS' THEN
               p_out_email_subject := 'Batch #p_in_batchid - Completed';
               p_out_email_body := '<p>Batch #p_in_batchid has completed with #p_status status.</p>
                                <p>The file has been successfully transfered to the FTP</p>
                                '
               ;
               ELSIF p_in_email_template = 'INT2_SUCCESS' THEN
               p_out_email_subject := 'Batch #p_in_batchid - Completed';
               p_out_email_body := '<p>Batch #p_in_batchid has completed.</p>
                                <p>The file has been successfully archived at SFTP.</p>
                                '
               ;
            ELSIF p_in_email_template = 'INT_LOADINT_ESS_NOTSUCCESS' THEN
               p_out_email_subject := 'Batch #p_in_batchid - Load Interface ESS job has failed';
               p_out_email_body := '<p>The interface load for batch #p_in_batchid has completed with #p_in_loadint_ess_jobstatus status.</p>
                                <p>Review ESS job request ID: #p_in_loadint_ess_jobid for more details and attached log file contains the records (if any) that have failed validation in Oracle.</p>   
                                <p>#p_in_error_message</p>'
                ;
           ELSIF p_in_email_template = 'INT_BASEIMPORT_ESS_NOTSUCCESS' THEN
               p_out_email_subject := 'Batch #p_in_batchid - Completed with errors';
               p_out_email_body := '<p>Batch #p_in_batchid has completed with #p_in_baseimport_ess_jobstatus status.</p>
                                <p>Review Base Import ESS Job with request ID: #p_in_baseimport_ess_jobid. Please find the attached file with the error transaction details</p>
                                <p>Review middleware instance ID: #p_in_instanceid for more details.</p>
                                <table border="1" cellspacing="0">
                                <tbody>
                                  <tr>
                                    <td bgcolor="#80d4ff" width="70%"><strong>Total</strong></td>
