               p_out_email_body := '<html><body style="font-family:Arial,sans-serif;background-color:#f4f4f9;color:#333;margin:20px;"><h2 style="text-align:center;color:#4CAF50;margin-bottom:20px;">Worker HCM Interface Execution Summary</h2><br/><h3 style="text-align:center;color:#4CAF50;margin-bottom:20px;">File uid:#p_in_batchid<br/>UCM Content ID:#p_in_attribute3<br/>Path:#p_in_attribute4</h3><table border="1" cellpadding="10" cellspacing="0" width="100%" style="max-width:600px;margin:0 auto;border-collapse:collapse;text-align:center;"><thead><tr><th style="background-color:#4CAF50;color:#fff;">Count Type</th><th style="background-color:#4CAF50;color:#fff;">Count</th></tr></thead><tbody><tr><td style="background-color:#fff3cd;">Requested</td><td style="background-color:#fff3cd;">#p_in_attribute5</td></tr><tr><td style="background-color:#d4edda;">Loaded Successfully</td><td style="background-color:#d4edda;">#p_in_attribute6</td></tr><tr><td style="background-color:#f8d7da;">Errored Out</td><td style="background-color:#f8d7da;">#p_in_attribute7</td></tr></tbody></table><p style="text-align:center;font-size:12px;color:#666;margin-top:20px;">For any further details, please contact the support team.</p></body></html>'

