               ,attribute7  = NVL(p_in_attribute7,attribute7)
               ,attribute8  = NVL(p_in_attribute8,attribute8)
               ,attribute9  = NVL(p_in_attribute9,attribute8)
               ,attribute10 = NVL(p_in_attribute10,attribute10)
            WHERE interface_id = p_in_interfaceid
              AND batch_id = p_in_batchid;
        ELSE
        --update for call from the common callback service

            UPDATE TER_CMN_INT_INSTANCE_TRACK_T
            SET
              metadata_read_sts             = NVL(p_in_metadata_read_sts,metadata_read_sts)
             ,file_read_sts                 = NVL(p_in_file_read_sts,file_read_sts)
             ,file_format_sts               = NVL(p_in_file_format_sts,file_format_sts)
             ,src_data_validation_sts       = NVL(p_in_src_data_validation_sts,src_data_validation_sts)
             ,src_data_transform_sts        = NVL(p_in_src_data_transform_sts,src_data_transform_sts)
