          --   ,fbdi_hdl_get_prop_file_sts    = NVL(p_in_fbdi_hdl_get_prop_file_sts,fbdi_hdl_get_prop_file_sts)
          --   ,fbdi_hdl_prop_write_sts       = NVL(p_in_fbdi_hdl_prop_write_sts,fbdi_hdl_prop_write_sts)
          --    ,fbdi_hdl_file_archive_sts     = NVL(p_in_fbdi_hdl_file_archive_sts,fbdi_hdl_file_archive_sts)
          --   ,erp_zip_file_name             = NVL(p_in_erp_zip_file_name,erp_zip_file_name)
             ,ucm_upload_sts                = NVL(p_in_ucm_upload_sts,ucm_upload_sts)
             ,LOADINT_ESS_JOBSTATUS              = NVL(p_in_loadint_ess_jobstatus,LOADINT_ESS_JOBSTATUS)
             ,BASEIMPORT_ESS_JOBSTATUS            = NVL(p_in_baseimport_ess_jobstatus,BASEIMPORT_ESS_JOBSTATUS)
             ,BASEIMPORT_ESS_JOBID             = NVL(p_in_baseimport_ess_jobid,BASEIMPORT_ESS_JOBID)
             ,RUN_TIME = SYSDATE
             ,attribute1  = NVL(p_in_attribute1,attribute1)
             ,attribute2  = NVL(p_in_attribute2,attribute2)
             ,attribute3  = NVL(p_in_attribute3,attribute3)
             ,attribute4  = NVL(p_in_attribute4,attribute4)
             ,attribute5  = NVL(p_in_attribute5,attribute5)
             ,attribute6  = NVL(p_in_attribute6,attribute6)
             ,attribute7  = NVL(p_in_attribute7,attribute7)
             ,attribute8  = NVL(p_in_attribute8,attribute8)
             ,attribute9  = NVL(p_in_attribute9,attribute8)
             ,attribute10 = NVL(p_in_attribute10,attribute10)
            WHERE LOADINT_ESS_JOBID = p_in_loadint_ess_jobid;
    END IF;

    EXCEPTION
        WHEN OTHERS THEN
            p_out_email_subject := 'Exception while generating the subject.';
            p_out_email_body := 'Exception while generating the body.';
    END get_email_data_prc;

END TER_EMAIL_TEMPLATES_PKG;

