--  DDL for Package Body TER_PKG_SLOT_BICC_VALIDATE
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."TER_PKG_SLOT_BICC_VALIDATE" AS

  c_err_prefix CONSTANT VARCHAR2(200) :=
    'Respective Data is not available in BICC extract';

  ---------------------------------------------------------------------------
  -- TEREXT_SLOT_PLAN_DTLS (section 4.2)
  -- BICC: TERAR_HZ_PARTIES (partyname,partynumber,partytype),
  --       TERSLOT_PARTY_SITE (party_site_name/party_site_number)
  --       TERSLOT_CATRGORY_DATA (category_sets_tlcategorysetname), TERINV_INVENTORY_STG (itemnumber),
  --       TERFND_CMNLKP_VAUES (lookupcode,description ..where lookuptype='ORA_DOO_DEMAND_CLASS')
  ---------------------------------------------------------------------------
  PROCEDURE p_validate_slot_plan_dtls IS
  BEGIN
  EXECUTE IMMEDIATE 'TRUNCATE TABLE terext_slot_plan_dtls_trg';
  EXECUTE IMMEDIATE 'TRUNCATE TABLE terext_slot_plan_dtls_er';
    -----------------------------------------------------------------------
    -- Success path → TEREXT_SLOT_PLAN_DTLS_TRG
    -----------------------------------------------------------------------
    INSERT INTO terext_slot_plan_dtls_trg (
      slot_id,
	  slot_number,
      pd_qtr,
      platform,
      system,
      slot_type,
      slot_status,
      demand_class,
      customer,
      customer_id,
      partial_flag,
      schedule_date,
      promised_date,
      mrp_qtr,
      source,
      created_by,
      created_date,
	  updated_by,
	  updated_date,
	  planning_organization,
	  manufacture,
	  manufacture_site,
	  operation_comments,
	  marketing_comments,
	  sales_order,
	  config_number,
	  refurb_flag,
      customer_site_id	  
    )
    SELECT
	  s.slot_id,
      s.slot_number,
      s.pd_qtr,
      s.platform,
      s.system,
      s.slot_type,
      s.slot_status,
      s.demand_class,
      s.customer,
      s.customer_id,
      s.partial_flag,
      s.schedule_date,
      s.promised_date,
      s.mrp_qtr,
      s.source,
      s.created_by,
      s.created_date,
	  s.updated_by,
	  s.updated_date,
	  s.planning_organization,
	  s.manufacture,
	  s.manufacture_site,
	  s.operation_comments,
	  s.marketing_comments,
	  s.sales_order,
	  s.config_number,
	  s.refurb_flag ,
      s.customer_site_id	  
    FROM   terext_slot_plan_dtls s
    WHERE  (s.customer_id IS NULL OR EXISTS (
             SELECT 1
             FROM   terar_hz_parties h
             WHERE  h.partynumber = s.customer_id
           ))
    AND    (s.customer IS NULL OR EXISTS (
             SELECT 1
             FROM   terar_hz_parties h
             WHERE  h.partyname = s.customer
           ))
    AND    (s.customer_site_id IS NULL OR EXISTS (
             SELECT 1
             FROM   terslot_party_sites t
             WHERE  t.party_site_number = s.customer_site_id
           ))
    AND    (s.platform IS NULL OR EXISTS (
             SELECT 1
             FROM   terslot_catrgory_data c
             WHERE  c.category_sets_tlcategorysetname = s.platform
           ))
    AND    (s.system IS NULL OR EXISTS (
             SELECT 1
             FROM   terinv_inventory_stg i
             WHERE  i.itemnumber = s.system
           ))
    AND    (s.demand_class IS NULL OR EXISTS (
             SELECT 1
             FROM   terfnd_cmnlkp_vaues v
             WHERE  v.lookuptype='ORA_DOO_DEMAND_CLASS'
			 AND  v.lookupcode = s.demand_class
           ))
    AND    NOT EXISTS (
             SELECT 1
             FROM   terext_slot_plan_dtls_trg t
             WHERE  t.slot_number = s.slot_number
             AND    NVL(t.pd_qtr, '~') = NVL(s.pd_qtr, '~')
             AND    NVL(t.mrp_qtr, '~') = NVL(s.mrp_qtr, '~')
           );

    -----------------------------------------------------------------------
    -- Error path → TEREXT_SLOT_PLAN_DTLS_ER (+ error_message)
    -----------------------------------------------------------------------
    INSERT INTO terext_slot_plan_dtls_er (
      slot_id,
	  slot_number,
      pd_qtr,
      platform,
      system,
      slot_type,
      slot_status,
      demand_class,
      customer,
      customer_id,
      partial_flag,
      schedule_date,
      promised_date,
      mrp_qtr,
      source,
      created_by,
      created_date,
	  updated_by,
	  updated_date,
	  planning_organization,
	  manufacture,
	  manufacture_site,
	  operation_comments,
	  marketing_comments,
	  sales_order,
	  config_number,
	  refurb_flag,
      customer_site_id,
      error_message
    )
    SELECT
      s.slot_id,
      s.slot_number,
      s.pd_qtr,
      s.platform,
      s.system,
      s.slot_type,
      s.slot_status,
      s.demand_class,
      s.customer,
      s.customer_id,
      s.partial_flag,
      s.schedule_date,
      s.promised_date,
      s.mrp_qtr,
      s.source,
      s.created_by,
      s.created_date,
	  s.updated_by,
	  s.updated_date,
	  s.planning_organization,
	  s.manufacture,
	  s.manufacture_site,
	  s.operation_comments,
	  s.marketing_comments,
	  s.sales_order,
	  s.config_number,
	  s.refurb_flag ,
      s.customer_site_id,
      c_err_prefix
      || ' : '
      || TRIM(
           CASE
             WHEN s.customer_id IS NOT NULL AND NOT EXISTS (
                    SELECT 1 FROM terar_hz_parties h
                    WHERE  h.partynumber = s.customer_id
                  ) THEN
               ' CUSTOMER_ID=' || s.customer_id || ';'
           END
           || CASE
                WHEN s.customer IS NOT NULL AND NOT EXISTS (
                       SELECT 1 FROM terar_hz_parties h
                       WHERE  h.partyname = s.customer
                     ) THEN
                  ' CUSTOMER=' || s.customer || ';'
              END
           || CASE
                WHEN s.customer_site_id IS NOT NULL AND NOT EXISTS (
                       SELECT 1 FROM terslot_party_sites t
                       WHERE  t.party_site_number = s.customer_site_id
                     ) THEN
                  ' CUSTOMER_SITE_ID=' || s.customer_site_id || ';'
              END
           || CASE
                WHEN s.platform IS NOT NULL AND NOT EXISTS (
                       SELECT 1 FROM terslot_catrgory_data c
                       WHERE  c.category_sets_tlcategorysetname = s.platform
                     ) THEN
                  ' PLATFORM=' || s.platform || ';'
              END
           || CASE
                WHEN s.system IS NOT NULL AND NOT EXISTS (
                       SELECT 1 FROM terinv_inventory_stg i
                       WHERE  i.itemnumber = s.system
                     ) THEN
                  ' SYSTEM=' || s.system || ';'
              END
           || CASE
                WHEN s.demand_class IS NOT NULL AND NOT EXISTS (
                       SELECT 1 FROM terfnd_cmnlkp_vaues v
                       WHERE v.lookuptype='ORA_DOO_DEMAND_CLASS'
			           AND  v.lookupcode = s.demand_class
                     ) THEN
                  ' DEMAND_CLASS=' || s.demand_class || ';'
              END
         )
    FROM   terext_slot_plan_dtls s
    WHERE  NOT (
             (s.customer_id IS NULL OR EXISTS (
                SELECT 1 FROM terar_hz_parties h
                WHERE  h.partynumber = s.customer_id
              ))
         AND (s.customer IS NULL OR EXISTS (
                SELECT 1 FROM terar_hz_parties h
                WHERE  h.partyname = s.customer
              ))
         AND (s.customer_site_id IS NULL OR EXISTS (
                SELECT 1 FROM terslot_party_sites t
                WHERE  t.party_site_number = s.customer_site_id
              ))
         AND (s.platform IS NULL OR EXISTS (
                SELECT 1 FROM terslot_catrgory_data c
                WHERE  c.category_sets_tlcategorysetname = s.platform
              ))
         AND (s.system IS NULL OR EXISTS (
                SELECT 1 FROM terinv_inventory_stg i
                WHERE  i.itemnumber = s.system
              ))
         AND (s.demand_class IS NULL OR EXISTS (
                SELECT 1 FROM terfnd_cmnlkp_vaues v
                WHERE v.lookuptype='ORA_DOO_DEMAND_CLASS'
			    AND  v.lookupcode = s.demand_class
              ))
           )
    AND    NOT EXISTS (
             SELECT 1
             FROM   terext_slot_plan_dtls_er e
             WHERE  e.slot_number = s.slot_number
             AND    NVL(e.pd_qtr, '~') = NVL(s.pd_qtr, '~')
             AND    NVL(e.mrp_qtr, '~') = NVL(s.mrp_qtr, '~')
           );

    COMMIT;
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      RAISE;
  END p_validate_slot_plan_dtls;

  ---------------------------------------------------------------------------
  -- TEREXT_SLOT_PARTS (section 4.2 — Item / Catalog + Inventory)
  ---------------------------------------------------------------------------
  PROCEDURE p_validate_slot_parts IS
  BEGIN
    EXECUTE IMMEDIATE 'TRUNCATE TABLE terext_slot_parts_trg';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE terext_slot_parts_er';
    INSERT INTO terext_slot_parts_trg (
      id,
	  part_number,
	  part_description,
	  quantity,
	  promise_date,
	  customer_approved,
	  partial_approved,
	  refurb_approved,
	  source,
	  created_date,
	  created_by,
	  updated_date,
	  updated_by,
	  system,
	  slot_number,
     -- platform,
      config_num,
      comments	       

    )
    SELECT
      s.id,
	  s.part_number,
	  s.part_description,
	  s.quantity,
	  s.promise_date,
	  s.customer_approved,
	  s.partial_approved,
	  s.refurb_approved,
	  s.source,
	  s.created_date,
	  s.created_by,
	  s.updated_date,
	  s.updated_by,
	  s.system,
	  s.slot_number,
     -- s.platform,
      s.config_num,
      s.comments
    FROM   terext_slot_parts s
    WHERE  /*(s.platform IS NULL OR EXISTS (
             SELECT 1
             FROM   ter_catalog_map c
             WHERE  c.platform = s.platform
           ))*/
          (s.system IS NULL OR EXISTS (
             SELECT 1
             FROM   terinv_inventory_stg i
             WHERE  i.itemnumber = s.system
           ))     ---as per comment system is looks like item component needs to recheck
    AND    (s.part_number IS NULL OR EXISTS (
             SELECT 1
             FROM   terinv_inventory_stg i
             WHERE  i.itemnumber = s.part_number
           ))
    AND    NOT EXISTS (
             SELECT 1
             FROM   terext_slot_parts_trg t
             WHERE  t.slot_number = s.slot_number
             AND    NVL(t.part_number, '~') = NVL(s.part_number, '~')
           );

    INSERT INTO terext_slot_parts_er (
      id,
	  part_number,
	  part_description,
	  quantity,
	  promise_date,
	  customer_approved,
	  partial_approved,
	  refurb_approved,
	  source,
	  created_date,
	  created_by,
	  updated_date,
	  updated_by,
	  system,
	  slot_number,
     -- platform,
      config_num,
      comments,
      error_message
    )
    SELECT
      s.id,
	  s.part_number,
	  s.part_description,
	  s.quantity,
	  s.promise_date,
	  s.customer_approved,
	  s.partial_approved,
	  s.refurb_approved,
	  s.source,
	  s.created_date,
	  s.created_by,
	  s.updated_date,
	  s.updated_by,
	  s.system,
	  s.slot_number,
     -- s.platform,
      s.config_num,
      s.comments,
      c_err_prefix
      || ' : '
      || TRIM(
          /* CASE
             WHEN s.platform IS NOT NULL AND NOT EXISTS (
                    SELECT 1 FROM ter_catalog_map c
                    WHERE  c.platform = s.platform
                  ) THEN
               ' PLATFORM=' || s.platform || ';'
           END
           ||*/
		   CASE
                WHEN s.system IS NOT NULL AND NOT EXISTS (
                       SELECT 1 FROM terinv_inventory_stg i
                       WHERE  i.itemnumber = s.system
                     ) THEN
                  ' SYSTEM=' || s.system || ';'
              END
           || CASE
                WHEN s.part_number IS NOT NULL AND NOT EXISTS (
                       SELECT 1 FROM terinv_inventory_stg i
                       WHERE  i.itemnumber = s.part_number
                     ) THEN
                  ' PART_NUMBER=' || s.part_number || ';'
              END
         )
    FROM   terext_slot_parts s
    WHERE  NOT (
             /*(s.platform IS NULL OR EXISTS (
                SELECT 1 FROM ter_catalog_map c
                WHERE  c.platform = s.platform
              ))*/
             (s.system IS NULL OR EXISTS (
                SELECT 1 FROM terinv_inventory_stg i
                WHERE  i.itemnumber = s.system
              ))
         AND (s.part_number IS NULL OR EXISTS (
                SELECT 1 FROM terinv_inventory_stg i
                WHERE  i.itemnumber = s.part_number
              ))
           )
    AND    NOT EXISTS (
             SELECT 1
             FROM   terext_slot_parts_er e
             WHERE  e.slot_number = s.slot_number
             AND    NVL(e.part_number, '~') = NVL(s.part_number, '~')
           );

    COMMIT;
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      RAISE;
  END p_validate_slot_parts;

  ---------------------------------------------------------------------------
  -- TEREXT_SLOT_PLAN_FIN_DTLS — no BICC rows in section 4.2 of the lean spec.
  -- All staging rows are inserted into *_TRG; *_ER is not used here.
