	  updated_date,
	  slot_number,
      source,
      pd_qtr,
      slot_status,
      system,
      sales_order,
      platform

    )
    SELECT
      s.finance_id,
	  s.customer,
	  s.slot_type,
	  s.system_count,
	  s.revenue_risk,
	  s.revenue_system_count,
	  s.system_count_adj,
	  s.revenue_adj,
	  s.cogs_adj,
	  s.revenue_qtr,
	  s.adjustment_comment,
	  s.finance_comments,
	  s.created_by,
	  s.created_date,
	  s.updated_by,
	  s.updated_date,
	  s.slot_number,
      s.source,
      s.pd_qtr,
      s.slot_status,
      s.system,
      s.sales_order,
      s.platform
    FROM   terext_slot_plan_fin_dtls s
    WHERE  NOT EXISTS (
             SELECT 1
