      RAISE;
  END p_validate_slot_plan_fin_dtls;

  ---------------------------------------------------------------------------
  -- TEREXT_SLOT_PLAN_OPS_DTLS (section 4.2 — SO, Org, Supplier / Site)
  --TEROM_HEADERS_ALL (ordernumber)
  --TERDTP_RR_ORGCODE (invorgnamepeoname,org_organizationcode)
  --TERPO_VENDOR_STG ( partyname,vendornumber )
  --TERPO_VENDORSITES_STG (vendorsitecode,vendorsiteid)
  ---------------------------------------------------------------------------
  PROCEDURE p_validate_slot_plan_ops_dtls IS
  BEGIN
    EXECUTE IMMEDIATE 'TRUNCATE TABLE terext_slot_plan_ops_dtls_trg';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE terext_slot_plan_ops_dtls_er';

    INSERT INTO terext_slot_plan_ops_dtls_trg (
      operation_id,
      sales_order,
      planning_organization,
      mfr,
      mfr_site,
      actual_date,
      operations_comments,   
      created_by,
      created_date,
	  updated_by,
	  updated_date,
	  slot_type,
      source,
	  slot_number
    )
    SELECT
      s.operation_id,
      s.sales_order,
      s.planning_organization,
      s.mfr,
      s.mfr_site,
      s.actual_date,
      s.operations_comments,   
      s.created_by,
      s.created_date,
	  s.updated_by,
	  s.updated_date,
	  s.slot_type,
      s.source,
	  s.slot_number
    FROM   terext_slot_plan_ops_dtls s
    WHERE  (s.sales_order IS NULL OR EXISTS (
             SELECT 1
             FROM   terom_headers_all o
             WHERE  o.ordernumber = s.sales_order
           ))
    AND    (s.planning_organization IS NULL OR EXISTS (
             SELECT 1
             FROM   terdtp_rr_orgcode r
             WHERE  r.org_organizationcode = s.planning_organization
           ))
    AND    (s.mfr IS NULL OR EXISTS (
             SELECT 1
             FROM   terpo_vendor_stg v
             WHERE  v.partyname = s.mfr
           ))
    AND    (s.mfr_site IS NULL OR EXISTS (
             SELECT 1
             FROM   terpo_vendorsites_stg vs
             WHERE  vs.vendorsitecode = s.mfr_site
           ))
    AND    NOT EXISTS (
             SELECT 1
             FROM   terext_slot_plan_ops_dtls_trg t
             WHERE  t.slot_number = s.slot_number
             AND    NVL(t.sales_order, '~') = NVL(s.sales_order, '~')
           );

    INSERT INTO terext_slot_plan_ops_dtls_er (
      operation_id,
      sales_order,
      planning_organization,
      mfr,
      mfr_site,
      actual_date,
      operations_comments,   
      created_by,
      created_date,
	  updated_by,
	  updated_date,
	  slot_type,
      source,
	  slot_number,
      error_message
    )
    SELECT
      s.operation_id,
      s.sales_order,
      s.planning_organization,
      s.mfr,
      s.mfr_site,
      s.actual_date,
      s.operations_comments,   
      s.created_by,
      s.created_date,
	  s.updated_by,
	  s.updated_date,
	  s.slot_type,
      s.source,
	  s.slot_number,
      c_err_prefix
      || ' : '
      || TRIM(
           CASE
             WHEN s.sales_order IS NOT NULL AND NOT EXISTS (
                    SELECT 1 FROM terom_headers_all o
                    WHERE  o.ordernumber = s.sales_order
                  ) THEN
               ' SALES_ORDER=' || s.sales_order || ';'
           END
           || CASE
                WHEN s.planning_organization IS NOT NULL AND NOT EXISTS (
                       SELECT 1 FROM terdtp_rr_orgcode r
                       WHERE  r.org_organizationcode = s.planning_organization
                     ) THEN
                  ' PLANNING_ORGANIZATION=' || s.planning_organization || ';'
              END
           || CASE
                WHEN s.mfr IS NOT NULL AND NOT EXISTS (
                       SELECT 1 FROM terpo_vendor_stg v
                       WHERE  v.partyname = s.mfr
                     ) THEN
                  ' MFR=' || s.mfr || ';'
              END
           || CASE
                WHEN s.mfr_site IS NOT NULL AND NOT EXISTS (
                       SELECT 1 FROM terpo_vendorsites_stg vs
                       WHERE  vs.vendorsitecode = s.mfr_site
                     ) THEN
                  ' MFR_SITE=' || s.mfr_site || ';'
              END
         )
    FROM   terext_slot_plan_ops_dtls s
    WHERE  NOT (
             (s.sales_order IS NULL OR EXISTS (
                SELECT 1 FROM terom_headers_all o
                WHERE  o.ordernumber = s.sales_order
              ))
         AND (s.planning_organization IS NULL OR EXISTS (
                SELECT 1 FROM terdtp_rr_orgcode r
                WHERE  r.org_organizationcode = s.planning_organization
              ))
         AND (s.mfr IS NULL OR EXISTS (
                SELECT 1 FROM terpo_vendor_stg v
                WHERE  v.partyname = s.mfr
              ))
         AND (s.mfr_site IS NULL OR EXISTS (
                SELECT 1 FROM terpo_vendorsites_stg vs
                WHERE  vs.vendorsitecode = s.mfr_site
              ))
           )
    AND    NOT EXISTS (
             SELECT 1
             FROM   terext_slot_plan_ops_dtls_er e
             WHERE  e.slot_number = s.slot_number
             AND    NVL(e.sales_order, '~') = NVL(s.sales_order, '~')
           );

    COMMIT;
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      RAISE;
  END p_validate_slot_plan_ops_dtls;

  ---------------------------------------------------------------------------
  -- TEREXT_SLOT_PLAN_MKT_DTLS (section 4.2 — Customer / Site on parties)
  --TERAR_HZ_PARTIES ( partyname,partynumber,partytype)
  --TERSLOT_PARTY_SITES (party_site_number,party_site_name) 
  ---------------------------------------------------------------------------
  PROCEDURE p_validate_slot_plan_mkt_dtls IS
  BEGIN
    EXECUTE IMMEDIATE 'TRUNCATE TABLE terext_slot_plan_mkt_dtls_trg';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE terext_slot_plan_mkt_dtls_er';
    INSERT INTO terext_slot_plan_mkt_dtls_trg (
      marketing_id,
	  forecast_name,
      customer_id,
	  s_number,
      revenue,
      config_number,
      request_number,
      customer_date,
      schedule_date,
      marketing_comments,
      created_by,
      created_date,
	  updated_by,
	  updated_date,
	  slot_type,
      promise_date,
	  source,
	  customer_site_id,
	  slot_number
    )
    SELECT
      s.marketing_id,
	  s.forecast_name,
      s.customer_id,
	  s.s_number,
      s.revenue,
      s.config_number,
      s.request_number,
      s.customer_date,
      s.schedule_date,
      s.marketing_comments,
      s.created_by,
      s.created_date,
	  s.updated_by,
	  s.updated_date,
	  s.slot_type,
      s.promise_date,
	  s.source,
	  s.customer_site_id,
	  s.slot_number
    FROM   terext_slot_plan_mkt_dtls s
    WHERE  (s.customer_id IS NULL OR EXISTS (
             SELECT 1
             FROM   terar_hz_parties h
             WHERE  h.partynumber = s.customer_id
           ))
    AND    (s.customer_site_id IS NULL OR EXISTS (
             SELECT 1
             FROM   terslot_party_sites p
             WHERE  p.party_site_number = s.customer_site_id
           ))
    AND    NOT EXISTS (
             SELECT 1
             FROM   terext_slot_plan_mkt_dtls_trg t
             WHERE  t.slot_number = s.slot_number
             AND    NVL(t.request_number, '~') = NVL(s.request_number, '~')
           );

    INSERT INTO terext_slot_plan_mkt_dtls_er (
      marketing_id,
	  forecast_name,
      customer_id,
	  s_number,
      revenue,
      config_number,
      request_number,
      customer_date,
      schedule_date,
      marketing_comments,
      created_by,
      created_date,
	  updated_by,
	  updated_date,
	  slot_type,
      promise_date,
	  source,
	  customer_site_id,
	  slot_number,
      error_message
    )
    SELECT
      s.marketing_id,
	  s.forecast_name,
      s.customer_id,
	  s.s_number,
      s.revenue,
      s.config_number,
      s.request_number,
      s.customer_date,
      s.schedule_date,
      s.marketing_comments,
      s.created_by,
      s.created_date,
	  s.updated_by,
	  s.updated_date,
	  s.slot_type,
      s.promise_date,
	  s.source,
	  s.customer_site_id,
	  s.slot_number,
      c_err_prefix
      || ' : '
      || TRIM(
           CASE
             WHEN s.customer_id IS NOT NULL AND NOT EXISTS (
                    SELECT 1 FROM terar_hz_parties h
                    WHERE  h.partynumber = s.customer_id
                  ) THEN
               ' CUSTOMER_ID=' || s.customer_id || ';'
           END
           || CASE
                WHEN s.customer_site_id IS NOT NULL AND NOT EXISTS (
                       SELECT 1 FROM terslot_party_sites p
                       WHERE  p.party_site_number = s.customer_site_id
                     ) THEN
                  ' CUSTOMER_SITE_ID=' || s.customer_site_id || ';'
              END
         )
    FROM   terext_slot_plan_mkt_dtls s
    WHERE  NOT (
             (s.customer_id IS NULL OR EXISTS (
                SELECT 1 FROM terar_hz_parties h
                WHERE  h.partynumber = s.customer_id
              ))
         AND (s.customer_site_id IS NULL OR EXISTS (
                SELECT 1 FROM terslot_party_sites p
                WHERE  p.party_site_number = s.customer_site_id
              ))
           )
    AND    NOT EXISTS (
             SELECT 1
             FROM   terext_slot_plan_mkt_dtls_er e
             WHERE  e.slot_number = s.slot_number
             AND    NVL(e.request_number, '~') = NVL(s.request_number, '~')
           );

    COMMIT;
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      RAISE;
  END p_validate_slot_plan_mkt_dtls;

  ---------------------------------------------------------------------------
  PROCEDURE p_validate_all IS
  BEGIN
    p_validate_slot_plan_dtls;
    p_validate_slot_parts;
    p_validate_slot_plan_fin_dtls;
    p_validate_slot_plan_ops_dtls;
    p_validate_slot_plan_mkt_dtls;
  END p_validate_all;  
  END ter_pkg_slot_bicc_validate;

