        p_int_log_attribute8_in          IN VARCHAR2,
        p_int_log_attribute9_in          IN VARCHAR2,
        p_int_log_attribute10_in         IN VARCHAR2,
        p_int_log_attribute11_in         IN VARCHAR2,
        p_int_log_attribute12_in         IN VARCHAR2,
        p_int_log_attribute13_in         IN VARCHAR2,
        p_int_log_attribute14_in         IN VARCHAR2,
        p_int_log_attribute15_in         IN VARCHAR2,
        p_int_log_attribute16_in         IN VARCHAR2,
