        p_email_body_out                 OUT CLOB
    ) IS

        l_batch_id                        VARCHAR2(1000) := NULL;
        l_recon_txn_id                    VARCHAR2(1000) := NULL;
        l_batch_id_without_text           VARCHAR2(1000) := NULL;
        l_status                          VARCHAR2(50);
