        l_batch_id :=
            CASE
                WHEN
                    p_log_level_in IN (
                        'GLOBALERROR','ERROR'
                    )
                AND
                    p_log_stage_in IN (
                        'SCHEDULER'
                    )
                THEN 'Instance ID: ' || p_interfacerunid_in
                WHEN p_email_template_in = 'INT_SUCCESS_RECON' OR p_email_template_in = 'INT_ERROR_RECON' THEN 'Recon Transaction ID: ' || p_batchid_in
                ELSE 'Batch ID: ' || p_batchid_in
            END;

        IF
            p_business_identifier_name_in IS NOT NULL
        THEN
            l_batch_id := l_batch_id
             || ' and '
             || p_business_identifier_name_in
             || ': '
             || p_business_identifier_value_in;
        END IF;

        l_batch_id_without_text :=
            CASE
                WHEN
                    p_batchid_in IS NOT NULL
                THEN p_batchid_in
                ELSE p_interfacerunid_in
            END;


		l_status := p_interface_status_in;

        p_email_body_out := NULL;
        IF
            p_log_level_in = 'GLOBALERROR' AND p_log_stage_in = 'SCHEDULER'
        THEN
            p_email_subject_out := l_status
             || ' - '
             || l_batch_id
             || ' - '
             || p_interfacename_in;
        ELSE
            p_email_subject_out := l_status
             || ' - '
             || l_batch_id
             || ' - From '
             || p_source_code_in
             || ' To '
             || p_target_code_in;
        END IF;

        IF
            p_log_level_in = 'Info' AND p_log_stage_in = 'File Transfer'
        THEN
            p_email_subject_out := p_log_stage_in
             || ' - From '
             || p_source_code_in
             || ' To '
             || p_target_code_in
             || '- '
             || l_status;
        END IF;

        IF
            p_email_template_in = 'INT_SUCCESS_RECON' OR p_email_template_in = 'INT_ERROR_RECON'
        THEN
            l_batch_id := 'Recon Transaction ID: <strong>' || p_batchid_in || '</strong>';
        ELSE
            l_batch_id := 'Batch ID: <strong>' || p_batchid_in || '</strong>';
        END IF;

        IF
            p_business_identifier_name_in IS NOT NULL
        THEN
            l_batch_id := l_batch_id
             || ' and '
             || p_business_identifier_name_in
             || ': <strong>'
             || p_business_identifier_value_in
             || '</strong>';
        END IF;


		l_status := '<strong>'||p_interface_status_in||'</strong>';
