            l_common_email_body_part2 := '<tr>
					<th
						style="padding: 3px 10px; background-color: #ffc000; text-align: left; width:170px; font-size: 12px; font-weight: bold; font-family: Arial,Helvetica,sans-serif; border-left: 1px solid #9E9F9F;">
