        l_metadata_notfound_body := '<html>
<head>
</head>
<body>
    <p style="font-size: 12px; font-weight: normal; font-family: Arial,Helvetica,sans-serif;">Dear Receiver,
    </p>
    <table style="border-collapse: collapse; text-align: left; width: 700px;" border="1" cellspacing="0" cellpadding="2">
        <tbody>
            <tr>
                <th style="padding: 3px 10px; background-color: #ffc000; text-align: center; width:170px; font-size: 12px; font-weight: bold; font-family: Arial,Helvetica,sans-serif; border-left: 1px solid #9E9F9F;">
                    <strong>Email Template Not Found in Metadata Table</strong></th>
            </tr>
        </tbody>
    </table>
</body>
</html>'
;
        IF
            p_log_stage_in = 'FILELOAD'
        THEN
            l_stage1_status := 'Error';
            l_stage2_status := 'Not Applicable';
            l_stage3_status := 'Not Applicable';
            l_stage4_status := 'Not Applicable';
            l_stage5_status := 'Not Applicable';
        ELSIF p_log_stage_in = 'VALIDATE' THEN
            l_stage1_status := 'Success';
            l_stage2_status := 'Error';
            l_stage3_status := 'Not Applicable';
            l_stage4_status := 'Not Applicable';
            l_stage5_status := 'Not Applicable';
        ELSIF p_log_stage_in = 'APIINVOKE' THEN
            l_stage1_status := 'Success';
            l_stage2_status := 'Success';
            l_stage3_status := 'Error';
            l_stage4_status := 'Not Applicable';
            l_stage5_status := 'Not Applicable';
        ELSIF p_log_stage_in = 'REPORTGENERATION' THEN
            l_stage1_status := 'Success';
            l_stage2_status := 'Success';
            l_stage3_status := 'Success';
            l_stage4_status :=
                CASE
                    WHEN
                        p_email_template_in LIKE 'INT_SUCCESS%'
                    THEN 'Success'
                    ELSE 'Error'
                END;
            l_stage5_status := 'Not Applicable';
        ELSIF p_log_stage_in = 'CALLBACK' THEN
            l_stage1_status := 'Success';
            l_stage2_status := 'Success';
            l_stage3_status := 'Success';
            l_stage4_status := 'Success';
            l_stage5_status :=
                CASE
                    WHEN
                        p_email_template_in LIKE 'INT_SUCCESS%'
                    THEN 'Success'
                    ELSE 'Error'
                END;
        END IF;

        IF
            p_email_template_in = 'INT_METADATA_NOT_FOUND'
        THEN
            l_error_code := 'Mandatory metadata not present in metadata table';
            l_error_message := '#l_batch_id has failed to execute because metadata for the interface was not found.';
            p_email_body_out := l_common_email_body_start || l_error_details_body || l_content_end_body;
        ELSIF p_email_template_in = 'INT_MULTIPLE_METADATA_FOUND' THEN
            l_error_code := 'Multiple metadata information found in metadata table';
            l_error_message := '#l_batch_id has failed to execute because metadata for the interface was not found.';
            p_email_body_out := l_common_email_body_start || l_error_details_body || l_content_end_body;
        ELSIF p_email_template_in = 'INT_DUPLICATE_FILENAME' THEN
            l_error_code := 'Duplicate file name';
            l_error_message := '<p>#l_batch_id has failed because a file with same name was executed earlier and it could possibly result in duplicate execution.</p>                             
<p>Please review the file contents and rename the file appropriately.</p>
<p>Source File Path: #p_source_directory_in</p>
<p>Source File: #p_filename_in</p>
<p>Integration can be reviewed at below navigation using OIC Instance Run ID: #p_interfacerunid_in </p>'
;
            p_email_body_out := l_common_email_body_start || l_error_details_body || l_content_end_body;
            l_status := 'ERROR';
        ELSIF p_email_template_in = 'INT_FTP_FILE_MOVE' THEN
            l_error_code := p_log_code_in;
            l_error_message := '<p>Error while moving the file to Archive/Error folder: ' || p_error_message_in || '</p>
                <p>Source File Path: #p_source_directory_in</p>
                <p>Source File: #p_filename_in</p>'
;
            p_email_body_out := l_common_email_body_start || l_error_details_body || l_content_end_body;
        ELSIF p_email_template_in = 'INT_ICS_RUNTIME_ERROR' THEN
            l_error_code := p_log_code_in;
            l_error_message := p_error_message_in;
            IF
                p_log_stage_in = 'CALLBACK'
            THEN
                p_email_body_out := l_common_email_body_start
                 || l_error_details_body
                 || l_callback_row_count_body
                 || l_callback_job_status_body
                 || l_content_end_body;
            ELSE
                p_email_body_out := l_common_email_body_start || l_error_details_body || l_content_end_body;
            END IF;

        ELSIF p_email_template_in = 'INT_DB_EXCEPTION' THEN
            l_error_code := 'Database Exception in ' || p_log_stage_in || ' Integration';
            l_error_message := p_error_message_in;
            IF
                p_log_stage_in = 'CALLBACK'
            THEN
                p_email_body_out := l_common_email_body_start
                 || l_error_details_body
                 || l_callback_row_count_body
                 || l_callback_job_status_body
                 || l_content_end_body;
            ELSE
                p_email_body_out := l_common_email_body_start || l_error_details_body || l_content_end_body;
            END IF;

        ELSIF p_email_template_in = 'INT_NO_VALID_RECORDS' THEN
            l_error_code := 'No Valid Records found to process';
            l_error_message := '#l_batch_id has failed to execute because all the records for the batch went into error ';
            p_email_body_out := l_common_email_body_start || l_error_details_body || l_content_end_body;
        ELSIF p_email_template_in = 'INT_FILE_NOT_PRESENT' THEN
            l_error_code := 'No File found to process';
            l_error_message := 'The process has failed to execute because the file is not present in the FTP';
            p_email_body_out := l_common_email_body_start || l_error_details_body || l_content_end_body;
        ELSIF p_email_template_in = 'INT_LOADINT_ESS_ERROR' THEN
            l_error_code := 'Load Interface ESS Job failed';
            l_error_message := 'The interface load for batch #l_batch_id has completed with #p_loadint_ess_jobstatus_in status. ' || p_error_message_in
;
            p_email_body_out := l_common_email_body_start
             || l_error_details_body
             || l_callback_job_status_body
             || l_content_end_body;
        ELSIF p_email_template_in = 'INT_BASEIMPORT_ESS_ERROR' THEN
            l_error_code := 'Base Import ESS Job failed';
            l_error_message := 'The Base Import for batch #l_batch_id has completed with #p_baseimport_ess_jobstatus_in status. ' || p_error_message_in
;
            p_email_body_out := l_common_email_body_start
             || l_error_details_body
             || l_callback_job_status_body
             || l_content_end_body;
        ELSIF p_email_template_in = 'INT_EBS_ERROR_RESPONSE' THEN
            l_error_code := 'EBS upload failed';
            l_error_message := 'The interface failed to upload data to Oracle EBS. ' || p_error_message_in;
            p_email_body_out := l_common_email_body_start || l_error_details_body || l_content_end_body;
        ELSIF p_email_template_in = 'INT_ATTACHMENT_LINK_FAILED' THEN
            l_error_code := 'Failed to upload attachments to the Transaction';
            l_error_message := 'Please refer the error report attached in the email for errors.';
            p_email_body_out := l_common_email_body_start || l_error_details_body || l_content_end_body;
        ELSIF p_email_template_in = 'INT_API_VAL_FAILURES' THEN
            l_error_code := 'API Validation Error';
            l_error_message := p_error_message_in;
            p_email_body_out := l_common_email_body_start || l_error_details_body || l_content_end_body;
        ELSIF p_email_template_in = 'INT_SUCCESS_ATTACHMENT' THEN
            p_email_body_out := l_common_email_body_start || l_content_end_body;
        ELSIF p_email_template_in = 'INT_SUCCESS' THEN
            p_email_body_out := l_common_email_body_start || l_content_end_body;
        ELSIF p_email_template_in = 'INT_SUCCESS_GLJOURNAL' THEN
            p_email_body_out := l_common_email_body_start
             || l_totals_in_journal_body
             || l_callback_row_count_body
             || l_callback_job_status_body
             || l_content_end_body;
        ELSIF p_email_template_in = 'INT_ERROR _GLJOURNAL' THEN
            p_email_body_out := l_common_email_body_start
             || l_totals_in_journal_body
             || l_callback_row_count_body
             || l_callback_job_status_body
             || l_content_end_body;
        ELSIF p_email_template_in = 'INT_ERROR' THEN
            p_email_body_out := l_common_email_body_start
             || l_callback_row_count_body
             || l_callback_job_status_body
             || l_content_end_body;
        ELSIF p_email_template_in = 'INT_ERROR_SINGLE' THEN
            p_email_body_out := l_common_email_body_start || l_content_end_body;
        ELSIF p_email_template_in = 'INT_SINGLE_SERVICE_ERROR' THEN
            p_email_body_out := l_single_email_body_start || l_callback_job_status_body || l_content_end_body;
        ELSIF p_email_template_in = 'INT_SINGLE_SERVICE_NOFILE_ERROR' THEN
            l_error_code := 'No File found to process';
            l_error_message := 'The process has failed to execute because the file is not present in the FTP';
            p_email_body_out := l_single_email_body_start || l_error_details_body || l_content_end_body;
        ELSIF p_email_template_in = 'INT_SUCCESS_SINGLE_SERVICE' THEN
            p_email_body_out := l_single_email_body_start || l_callback_job_status_body || l_content_end_body;
        ELSIF p_email_template_in = 'INT_GENERIC_ERROR' THEN
            l_error_code := p_log_code_in;
            l_error_message := p_error_message_in;
            p_email_body_out := l_single_email_body_start || l_error_details_body || l_callback_row_count_body || l_content_end_body;
		ELSIF p_email_template_in = 'INT_GENERIC_ERROR1' THEN
            l_error_code := p_log_code_in;
            l_error_message := p_error_message_in;
            p_email_body_out := l_single_email_body_start || l_content_end_body;
        ELSIF p_email_template_in = 'INT_SUCCESS_GENERIC' THEN -- 1.3 
            p_email_body_out := l_single_email_body_start || l_content_end_body;
        ELSIF p_email_template_in = 'INT_SUCCESS_RECON' THEN
            p_email_body_out := l_common_email_body_part1
             || l_common_email_body_part2
             || l_recon_email_body_part3
             || l_content_end_body;
        ELSIF p_email_template_in = 'INT_ERROR_RECON' THEN
            l_error_code := p_log_code_in;
            l_error_message := p_error_message_in;
            p_email_body_out := l_common_email_body_part1
             || l_common_email_body_part2
             || l_recon_email_body_part3
             || l_error_details_body
             || l_content_end_body;
        ELSE
            p_email_body_out := l_metadata_notfound_body || l_content_end_body;
        END IF;

        p_email_body_out := replace(p_email_body_out,'#p_interfacename_in',p_interfacename_in);
        p_email_body_out := replace(
            p_email_body_out,
            '#p_rundate_in',
            TO_CHAR(SYSDATE,'DD-MON-YYYY HH24:MI:SS')
        );
        p_email_body_out := replace(p_email_body_out,'#l_stage1_status',l_stage1_status);
        p_email_body_out := replace(p_email_body_out,'#l_stage2_status',l_stage2_status);
        p_email_body_out := replace(p_email_body_out,'#l_stage3_status',l_stage3_status);
        p_email_body_out := replace(p_email_body_out,'#l_stage4_status',l_stage4_status);
        p_email_body_out := replace(p_email_body_out,'#l_stage5_status',l_stage5_status);
        p_email_body_out := replace(p_email_body_out,'#p_total_rowcount_in',p_total_rowcount_in);
        p_email_body_out := replace(p_email_body_out,'#p_error_rowcount_in',p_error_rowcount_in);
        p_email_body_out := replace(p_email_body_out,'#p_success_rowcount_in',p_success_rowcount_in);
        p_email_body_out := replace(p_email_body_out,'#p_log_code_in',l_error_code);
        p_email_body_out := replace(p_email_body_out,'#p_error_message_in',l_error_message);
        p_email_body_out := replace(
            p_email_body_out,
            '#p_prog1_req_id_in',
            nvl(
                substr(
                    p_prog1_req_id_in,
                    instr(p_prog1_req_id_in,'-') + 1
                ),
                p_prog1_req_id_in
            )
        );

        p_email_body_out := replace(
            p_email_body_out,
            '#p_load_conc_req_name_in',
            nvl(
                substr(
                    p_prog1_req_id_in,
                    0,
                    instr(p_prog1_req_id_in,'-') - 1
                ),
                p_prog1_req_id_in
            )
        );

        p_email_body_out := replace(
            p_email_body_out,
            '#p_base_conc_req_name_in',
            nvl(
                substr(
                    p_prog2_req_id_in,
                    0,
                    instr(p_prog2_req_id_in,'-') - 1
                ),
                p_prog2_req_id_in
            )
        );

        p_email_body_out := replace(p_email_body_out,'#p_prog1_req_status_in',p_prog1_req_status_in);
        p_email_body_out := replace(
            p_email_body_out,
            '#p_prog2_req_id_in',
            nvl(
                substr(
                    p_prog2_req_id_in,
                    instr(p_prog2_req_id_in,'-') + 1
                ),
                p_prog2_req_id_in
            )
        );

        p_email_body_out := replace(p_email_body_out,'#p_prog2_req_status_in',p_prog2_req_status_in);
        p_email_body_out := replace(p_email_body_out,'#p_source_directory_in',p_source_directory_in);
        p_email_body_out := replace(p_email_body_out,'#p_filename_in',p_filename_in);
        p_email_body_out := replace(p_email_body_out,'#p_interfacerunid_in',p_interfacerunid_in);
        p_email_body_out := replace(p_email_body_out,'#l_batch_id_without_text',l_batch_id_without_text);
        p_email_body_out := replace(p_email_body_out,'#l_status',l_status);
        p_email_body_out := replace(p_email_body_out,'#p_instance_in',p_instance_in);
        p_email_body_out := replace(p_email_body_out,'#p_source_code_in',p_source_code_in);
        p_email_body_out := replace(p_email_body_out,'#p_log_stage_in',p_log_stage_in);
        p_email_body_out := replace(p_email_body_out,'#p_target_code_in',p_target_code_in);
        p_email_body_out := replace(p_email_body_out,'#p_int_audit_attribute1_in',p_int_audit_attribute1_in);
        p_email_body_out := replace(p_email_body_out,'#p_int_audit_attribute2_in',p_int_audit_attribute2_in);
        IF
            p_business_identifier_name_in IS NOT NULL
        THEN
            p_email_body_out := replace(p_email_body_out,'#l_business_identifier',l_business_identifier);
            p_email_body_out := replace(p_email_body_out,'#p_business_identifier_name_in',p_business_identifier_name_in);
            p_email_body_out := replace(p_email_body_out,'#p_business_identifier_value_in',p_business_identifier_value_in);
            p_email_body_out := replace(p_email_body_out,'#l_batch_id',l_batch_id);
        ELSE
            p_email_body_out := replace(p_email_body_out,'#l_business_identifier',NULL);
            p_email_body_out := replace(p_email_body_out,'#l_batch_id',l_batch_id);
        END IF;

        IF
            p_business_identifier_name1_in IS NOT NULL
        THEN
            p_email_body_out := replace(p_email_body_out,'#l_business1_identifier',l_business1_identifier);
            p_email_body_out := replace(p_email_body_out,'#p_business_identifier_name1_in',p_business_identifier_name1_in);
            p_email_body_out := replace(p_email_body_out,'#p_business_identifier_value1_in',p_business_identifier_value1_in);
            p_email_body_out := replace(p_email_body_out,'#l_batch_id',l_batch_id);
        ELSE
            p_email_body_out := replace(p_email_body_out,'#l_business1_identifier',NULL);
            p_email_body_out := replace(p_email_body_out,'#l_batch_id',l_batch_id);
        END IF;

         IF
            p_business_identifier_name2_in IS NOT NULL
        THEN
            p_email_body_out := replace(p_email_body_out,'#l_business2_identifier',l_business2_identifier);
            p_email_body_out := replace(p_email_body_out,'#p_business_identifier_name2_in',p_business_identifier_name2_in);
            p_email_body_out := replace(p_email_body_out,'#p_business_identifier_value2_in',p_business_identifier_value2_in);
            p_email_body_out := replace(p_email_body_out,'#l_batch_id',l_batch_id);
        ELSE
            p_email_body_out := replace(p_email_body_out,'#l_business2_identifier',NULL);
            p_email_body_out := replace(p_email_body_out,'#l_batch_id',l_batch_id);
        END IF;

        IF
            p_email_template_in = 'INT_SUCCESS_ATTACHMENT'
        THEN
            p_email_body_out := replace(p_email_body_out,'#p_content_end_body_text1',NULL);
        END IF;

    EXCEPTION
        WHEN OTHERS THEN
            p_email_subject_out := 'Exception while generating the subject.';
            p_email_body_out := 'Exception while generating the body.'
             || substr(sqlerrm,1,4000);
    END get_email_data_prc;

END xx_cmn_email_templates_pkg;

/
--------------------------------------------------------
--  DDL for Package Body XX_CMN_INT_EOD_RECON_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."XX_CMN_INT_EOD_RECON_PKG" AS
/* $Header: xx_cmn_int_eod_recon_pkg.pkb 1.0 2025/04/02 Arunasish no ship $ */
/*
Created By   : Arunasish Ray
Creation Date: 02-April-2025
Filename     : xx_cmn_int_eod_recon_pkg.pkb
Description  : Common Package for Reconciliation
Change History:
Date               Version#         Name                       Remarks
-----------        -------       ---------           ----------------------------------------
02-April-2025      1.0          Arunasish Ray              Initial development.
*/
----------------------------------------------------------------------------------------------

    g_overall_status_success     CONSTANT xx_cmn_int_eod_recon.overall_status%TYPE := 'SUCCESS';
    g_overall_status_error       CONSTANT xx_cmn_int_eod_recon.overall_status%TYPE := 'ERROR';
    g_error_code_import_error    CONSTANT xx_cmn_int_eod_recon.error_code%TYPE := 'IMPORT_ERROR';
    g_error_code_file            CONSTANT xx_cmn_int_eod_recon.error_code%TYPE := 'FILE_MISSING_ERROR';
    g_error_code_txnid           CONSTANT xx_cmn_int_eod_recon.error_code%TYPE := 'PAYLOAD_MISSING_ERROR';
    g_error_code_record          CONSTANT xx_cmn_int_eod_recon.error_code%TYPE := 'RECORD_ERROR';
    g_error_code_amount          CONSTANT xx_cmn_int_eod_recon.error_code%TYPE := 'AMOUNT_ERROR';
    g_error_code_amount_record   CONSTANT xx_cmn_int_eod_recon.error_code%TYPE := 'AMOUNT_RECORD_ERROR';
    g_error_msg_status_file      CONSTANT xx_cmn_int_eod_recon.error_message%TYPE := 'Errored file transaction in Oracle';
    g_error_msg_status_txnid     CONSTANT xx_cmn_int_eod_recon.error_message%TYPE := 'Errored realtime transaction in Oracle';
    g_error_msg_file             CONSTANT xx_cmn_int_eod_recon.error_message%TYPE := 'File missing in Oracle';
    g_error_msg_txnid            CONSTANT xx_cmn_int_eod_recon.error_message%TYPE := 'Relatime transaction missing in Oracle';
    g_error_msg_record           CONSTANT xx_cmn_int_eod_recon.error_message%TYPE := 'Row count mismatched';
    g_error_msg_amount           CONSTANT xx_cmn_int_eod_recon.error_message%TYPE := 'Amount mismatched- ';
    g_error_msg_amount_record    CONSTANT xx_cmn_int_eod_recon.error_message%TYPE := 'Row count mismatched. Amount mismatched- ';

    PROCEDURE compare_recon_data (
        o_err_code           OUT VARCHAR2,
        o_err_msg            OUT VARCHAR2,
        p_interface_run_id   xx_cmn_int_eod_recon.interface_run_id%TYPE
    ) IS

        CURSOR cur_xx_cmn_int_eod_recon IS
            SELECT
                recon_id,
                rice_id,
                recon_transaction_id,
                source_system,
                target_system,
                recon_date,
                source_file_name,
                source_transaction_id,
                source_record_count,
                source_total_amount1,
                source_total_amount2,
                source_total_amount3,
                source_total_amount4,
                source_total_amount5
            FROM
                xx_cmn_int_eod_recon t1
            WHERE
                interface_run_id = p_interface_run_id;

        lv_total_amount1           xx_cmn_int_audit.total_amount1%TYPE;
        lv_total_amount2           xx_cmn_int_audit.total_amount2%TYPE;
        lv_total_amount3           xx_cmn_int_audit.total_amount3%TYPE;
        lv_total_amount4           xx_cmn_int_audit.total_amount4%TYPE;
        lv_total_amount5           xx_cmn_int_audit.total_amount5%TYPE;
        lv_file_name               xx_cmn_int_audit.file_name%TYPE;
        lv_total_rowcount          xx_cmn_int_audit.total_rowcount%TYPE;
        lv_source_transaction_id   xx_cmn_int_audit.source_transaction_id%TYPE;
        lv_source_timestamp        xx_cmn_int_audit.source_timestamp%TYPE;
        lv_interface_status        xx_cmn_int_audit.interface_status%TYPE;
        lv_rice_id                 xx_cmn_int_audit.rice_id%TYPE;
        lv_overall_status          xx_cmn_int_eod_recon.overall_status%TYPE;
        lv_error_code              xx_cmn_int_eod_recon.error_code%TYPE;
        lv_error_message           xx_cmn_int_eod_recon.error_message%TYPE;
        lv_filename_flag           VARCHAR2(1);
        lv_txnid_flag              VARCHAR(1);
        lv_audit_status_flag       VARCHAR(1);
        lv_amount_err_flag         VARCHAR(1);
        lv_record_err_flag         VARCHAR(1);
        lv_total_amount1_err       VARCHAR2(50);
        lv_total_amount2_err       VARCHAR2(50);
        lv_total_amount3_err       VARCHAR2(50);
        lv_total_amount4_err       VARCHAR2(50);
        lv_total_amount5_err       VARCHAR2(50);
    BEGIN
        o_err_code := 0;
        o_err_msg := NULL;
        FOR rec IN cur_xx_cmn_int_eod_recon LOOP
            BEGIN
                dbms_output.put_line('Inside For loop');
                lv_overall_status := g_overall_status_success;
                lv_error_code := NULL;
                lv_error_message := NULL;
                lv_filename_flag := 'N';
                lv_txnid_flag := 'N';
                lv_audit_status_flag := 'E';
                lv_amount_err_flag := 'N';
                lv_record_err_flag := 'N';
                lv_total_amount1_err := NULL;
                lv_total_amount2_err := NULL;
                lv_total_amount3_err := NULL;
                lv_total_amount4_err := NULL;
                lv_total_amount5_err := NULL;
                IF
                    length(rec.source_file_name) > 1
                THEN
                    lv_filename_flag := 'Y';
                    dbms_output.put_line('FileNameCheck'
                     || ' | '
                     || lv_filename_flag
                     || ' | '
                     || length(rec.source_file_name) );

                ELSIF length(rec.source_transaction_id) > 1 THEN
                    lv_txnid_flag := 'Y';
                    dbms_output.put_line('TxnId Check-'
                     || ' | '
                     || lv_txnid_flag
                     || ' | '
                     || length(rec.source_transaction_id) );

                END IF;

                SELECT
                    t2.rice_id,
                    t2.total_amount1,
                    t2.total_amount2,
                    t2.total_amount3,
                    t2.total_amount4,
                    t2.total_amount5,
                    t2.file_name,
                    t2.total_rowcount,
                    t2.source_transaction_id,
                    t2.source_timestamp,
                    t2.interface_status
                INTO
                    lv_rice_id,lv_total_amount1,lv_total_amount2,lv_total_amount3,lv_total_amount4,lv_total_amount5,lv_file_name,lv_total_rowcount,lv_source_transaction_id
,lv_source_timestamp,lv_interface_status
                FROM
                    xx_cmn_int_audit t2
                WHERE
                    (
                            rec.source_transaction_id = t2.source_transaction_id
                        OR
                            rec.source_file_name = t2.file_name
                    ) AND
                        upper(rec.source_system) = upper(t2.source_system)
                    AND
                        upper(rec.target_system) = upper(t2.target_system)
                    AND
                        trunc(rec.recon_date) = trunc(t2.source_timestamp)
                    AND
                        upper(rec.rice_id) = upper(t2.rice_id);
                    --AND
                        --upper(t2.interface_status) = 'SUCCESS';

                dbms_output.put_line('Audit Data Fetched');  
--------------------------------------------------------------------------------------------------------------------------------
        --Audit Status Check
--------------------------------------------------------------------------------------------------------------------------------  
                IF
                    upper(lv_interface_status) = 'SUCCESS'
                THEN
                    lv_audit_status_flag := 'S';
                    dbms_output.put_line('lv_audit_status_flag-' || ' | ' || lv_audit_status_flag);

--------------------------------------------------------------------------------------------------------------------------------
        --Amount Error Check
--------------------------------------------------------------------------------------------------------------------------------
                    IF
                        rec.source_total_amount1 != lv_total_amount1
                    THEN
                        lv_total_amount1_err := 'TotalAmount1';
                        lv_amount_err_flag := 'Y';
                    END IF;

                    IF
                        rec.source_total_amount2 != lv_total_amount2
                    THEN
                        lv_total_amount2_err := ' TotalAmount2';
                        lv_amount_err_flag := 'Y';
                    END IF;

                    IF
                        rec.source_total_amount3 != lv_total_amount3
                    THEN
                        lv_total_amount3_err := ' TotalAmount3';
                        lv_amount_err_flag := 'Y';
                    END IF;

                    IF
                        rec.source_total_amount4 != lv_total_amount4
                    THEN
                        lv_total_amount4_err := ' TotalAmount4';
                        lv_amount_err_flag := 'Y';
                    END IF;

                    IF
                        rec.source_total_amount5 != lv_total_amount5
                    THEN
                        lv_total_amount5_err := ' TotalAmount5';
                        lv_amount_err_flag := 'Y';
                    END IF;

                    IF
                        lv_amount_err_flag = 'Y'
                    THEN
                        lv_overall_status := g_overall_status_error;
                        lv_error_code := g_error_code_amount;
                        lv_error_message := g_error_msg_amount
                         || lv_total_amount1_err
                         || lv_total_amount2_err
                         || lv_total_amount3_err
                         || lv_total_amount4_err
                         || lv_total_amount5_err;

                        dbms_output.put_line('Amount Error |'
                         || lv_overall_status
                         || ' | '
                         || lv_error_code
                         || ' | '
                         || lv_error_message);

                    END IF;
--------------------------------------------------------------------------------------------------------------------------------
        --Row Count Check
--------------------------------------------------------------------------------------------------------------------------------

                    IF
                        rec.source_record_count != lv_total_rowcount
                    THEN
                        lv_record_err_flag := 'Y';
                        lv_overall_status := g_overall_status_error;
                        lv_error_code := g_error_code_record;
                        lv_error_message := g_error_msg_record;
                        dbms_output.put_line('Record Error |'
                         || rec.source_record_count
                         || lv_total_rowcount
                         || lv_overall_status
                         || ' | '
                         || lv_error_code
                         || ' | '
                         || lv_error_message);

                    END IF;
--------------------------------------------------------------------------------------------------------------------------------
        --Row Count  Amount Error Check
--------------------------------------------------------------------------------------------------------------------------------

                    IF
                        lv_record_err_flag = 'Y' AND lv_amount_err_flag = 'Y'
                    THEN
                        lv_overall_status := g_overall_status_error;
                        lv_error_code := g_error_code_amount_record;
                        lv_error_message := g_error_msg_amount_record
                         || lv_total_amount1_err
                         || lv_total_amount2_err
                         || lv_total_amount3_err
                         || lv_total_amount4_err
                         || lv_total_amount5_err;

                        dbms_output.put_line('Amount and Record Error |'
                         || lv_overall_status
                         || ' | '
                         || lv_error_code
                         || ' | '
                         || lv_error_message);

                    END IF;
--------------------------------------------------------------------------------------------------------------------------------
        --Update xx_cmn_int_eod_recon table
--------------------------------------------------------------------------------------------------------------------------------

                    UPDATE xx_cmn_int_eod_recon
                        SET
                            audit_table_total_amount1 = lv_total_amount1,
                            audit_table_total_amount2 = lv_total_amount2,
                            audit_table_total_amount3 = lv_total_amount3,
                            audit_table_total_amount4 = lv_total_amount4,
                            audit_table_total_amount5 = lv_total_amount5,
                            audit_table_file_name = lv_file_name,
                            audit_table_record_count = lv_total_rowcount,
                            audit_table_transaction_id = lv_source_transaction_id,
                            overall_status = lv_overall_status,
                            error_code = lv_error_code,
                            error_message = lv_error_message,
                            last_update_date = current_timestamp,
                            last_updated_by = user
                    WHERE
                        recon_id = rec.recon_id;

                    dbms_output.put_line('Recon Table Updated-|'
                     || lv_overall_status
                     || ' | '
                     || lv_error_code
                     || ' | '
                     || lv_error_message);

                ELSE
                    lv_overall_status := g_overall_status_error;
                    lv_error_code := g_error_code_import_error;
                    IF
                        lv_filename_flag = 'Y'
                    THEN
                        lv_error_message := g_error_msg_status_file;
                    ELSIF lv_txnid_flag = 'Y' THEN
                        lv_error_message := g_error_msg_status_txnid;
                    END IF;

                    dbms_output.put_line('Status Error |'
                     || lv_overall_status
                     || ' | '
                     || lv_error_code
                     || ' | '
                     || lv_error_message
                     || ' | '
                     || lv_interface_status);

                    UPDATE xx_cmn_int_eod_recon
                        SET
                            audit_table_file_name = lv_file_name,
                            --audit_table_record_count = NULL,
                            audit_table_transaction_id = lv_source_transaction_id,
                            overall_status = lv_overall_status,
                            error_code = lv_error_code,
                            error_message = lv_error_message,
                            last_update_date = current_timestamp,
                            last_updated_by = user
                    WHERE
                        recon_id = rec.recon_id;

                    dbms_output.put_line('Recon Table Updated-|'
                     || lv_overall_status
                     || ' | '
                     || lv_error_code
                     || ' | '
                     || lv_error_message);

                END IF;

                dbms_output.put_line('Exit For loop');
--------------------------------------------------------------------------------------------------------------------------------
        --FileName/TransactionId Missing in Oracle
--------------------------------------------------------------------------------------------------------------------------------
            EXCEPTION
                WHEN no_data_found THEN
                    o_err_code := sqlcode;
--------------------------------------------------------------------------------------------------------------------------------
        --File Name Missing in Oracle
--------------------------------------------------------------------------------------------------------------------------------
                    IF
                        lv_filename_flag = 'Y'
                    THEN
                        lv_overall_status := g_overall_status_error;
                        lv_error_code := g_error_code_file;
                        lv_error_message := g_error_msg_file;
                        o_err_msg := 'No matching record found in xx_cmn_int_audit for Source System:'
                         || rec.source_system
                         || ',File Name: '
                         || rec.source_file_name;
--------------------------------------------------------------------------------------------------------------------------------
        --TransactionId Missing in Oracle
--------------------------------------------------------------------------------------------------------------------------------
                    ELSIF lv_txnid_flag = 'Y' THEN
                        lv_overall_status := g_overall_status_error;
                        lv_error_code := g_error_code_txnid;
                        lv_error_message := g_error_msg_txnid;
                        o_err_msg := 'No matching record found in xx_cmn_int_audit for Source System:'
                         || rec.source_system
                         || ',Source TansactionId:'
                         || rec.source_transaction_id;
                    END IF;
--------------------------------------------------------------------------------------------------------------------------------
        --Update xx_cmn_int_eod_recon table
--------------------------------------------------------------------------------------------------------------------------------

                    UPDATE xx_cmn_int_eod_recon
                        SET
                            overall_status = lv_overall_status,
                            error_code = lv_error_code,
                            error_message = lv_error_message,
                            last_update_date = current_timestamp,
                            last_updated_by = user
                    WHERE
                        recon_id = rec.recon_id;

                    dbms_output.put_line('Recon Table Updated-|'
                     || lv_overall_status
                     || ' | '
                     || lv_error_code
                     || ' | '
                     || lv_error_message);

                WHEN OTHERS THEN
                    o_err_code := sqlcode;
                    o_err_msg := sqlerrm;
                    dbms_output.put_line('Other Exception-' || o_err_code || o_err_msg);
                    dbms_output.put_line('Exit For loop');
            END;
        END LOOP;

        COMMIT;
    EXCEPTION
        WHEN OTHERS THEN
            o_err_code := sqlcode;
            o_err_msg := sqlerrm;
            ROLLBACK;
            dbms_output.put_line('Other Exception,Rollbacked-' || o_err_code || o_err_msg);
    END;

END xx_cmn_int_eod_recon_pkg;

/
--------------------------------------------------------
--  DDL for Package Body XX_CMN_LOG_AND_AUDIT_PKG
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "TEREXT"."XX_CMN_LOG_AND_AUDIT_PKG" AS

/* $Header: XX_cmn_log_and_audit_pkg.pkg 1.0 2025/04/02 Arunasish no ship $ */ 
/*
Created By   : Arunasish 
 Creation Date: 02-April-2025
 Filename     : XX_cmn_log_and_audit_pkg.pkb
 Description: Common Audit and Log Package

 Change History:

 Date               Version#         Name                       Remarks
 -----------        -------       ---------           ---------------------------------------
 02-April-2025     1.0            Arunasish                     Initial development.

/*********************************************************************************************/

    g_interface_run_id   VARCHAR2(4000) := NULL;
    g_user_id            VARCHAR2(240) := user;
    g_batch_id           VARCHAR2(240) := NULL;

/*********************************************************************************************
    TYPE              :   procedure
    NAME              :   write_log_message
    DESCRIPTION       :   Procedure to Insert errors into the XX_CMN_INT_LOGS table
    INPUT PARAMETERS  :
						p_log_level                 : Log Level
						p_log_message               : Log Message				
    OUTPUT PARAMETERS :

*********************************************************************************************/

    PROCEDURE write_log_message (
        p_log_level     IN VARCHAR2 DEFAULT 'ERROR',
        p_log_message   IN VARCHAR2,
        p_log_source    IN VARCHAR2
    )
        IS
    BEGIN
        xx_cmn_log_and_audit_pkg.write_interface_logs(
            p_interface_run_id_in   => g_interface_run_id,
            p_batch_id_in           => g_batch_id,
            p_log_level_in          => p_log_level,
            p_log_message_in        => p_log_message,
            p_log_source_in         => p_log_source,
            p_user_in               => g_user_id
        );
    END write_log_message;

/*********************************************************************************************
    TYPE              :   procedure
    NAME              :   write_interface_audit
    DESCRIPTION       :   Procedure to Insert/Update into the xx_cmn_int_audit table
    INPUT PARAMETERS  :
						p_rice_id_in                 : RICE ID 
						p_source_system_in           : Source System Name
						p_target_system_in           : Target System Name
						p_instance_run_action_in     : Interface Runc Action. INSERT/UPDATE
						p_interface_run_id_in        : Interface Run Id
						p_batch_id_in                : Batch Id
						p_parent_interface_run_id_in : Parent Interface Run ID
						p_start_time_in              : Start Time
