                    attribute9 = nvl(p_attribute9_in,attribute9),
                    attribute10 = nvl(p_attribute10_in,attribute10),
                    attribute11 = nvl(p_attribute11_in,attribute11),
                    attribute12 = nvl(p_attribute12_in,attribute12),
                    attribute13 = nvl(p_attribute13_in,attribute13),
                    attribute14 = nvl(p_attribute14_in,attribute14),
                    attribute15 = nvl(p_attribute15_in,attribute15),
                    attribute16 = nvl(p_attribute15_in,attribute16),
                    attribute17 = nvl(p_attribute15_in,attribute17),
                    attribute18 = nvl(p_attribute15_in,attribute18),
                    attribute19 = nvl(p_attribute15_in,attribute19),
                    attribute20 = nvl(p_attribute15_in,attribute20),
