  PROCEDURE get_dynamic_payload (
    p_audit_id IN NUMBER,
    p_payload OUT CLOB) AS
    BEGIN
    SELECT
    JSON_MERGEPATCH( JSON_OBJECT('reprocessFlag' VALUE 'Y'),
        JSON_OBJECTAGG(
            attribute_key VALUE attribute_value
        )
     )AS audit_json into p_payload
FROM (
    SELECT
        attribute_key,
        audit_value AS attribute_value
    FROM (
        SELECT
            m.attribute1  AS m_attribute1,   a.attribute1  AS a_attribute1,
            m.attribute2  AS m_attribute2,   a.attribute2  AS a_attribute2,
            m.attribute3  AS m_attribute3,   a.attribute3  AS a_attribute3,
            m.attribute4  AS m_attribute4,   a.attribute4  AS a_attribute4,
            m.attribute5  AS m_attribute5,   a.attribute5  AS a_attribute5,
            m.attribute6  AS m_attribute6,   a.attribute6  AS a_attribute6,
            m.attribute7  AS m_attribute7,   a.attribute7  AS a_attribute7,
            m.attribute8  AS m_attribute8,   a.attribute8  AS a_attribute8,
            m.attribute9  AS m_attribute9,   a.attribute9  AS a_attribute9,
            m.attribute10 AS m_attribute10,  a.attribute10 AS a_attribute10,
            m.attribute11 AS m_attribute11,  a.attribute11 AS a_attribute11,
            m.attribute12 AS m_attribute12,  a.attribute12 AS a_attribute12,
            m.attribute13 AS m_attribute13,  a.attribute13 AS a_attribute13,
            m.attribute14 AS m_attribute14,  a.attribute14 AS a_attribute14,
            m.attribute15 AS m_attribute15,  a.attribute15 AS a_attribute15,
            m.attribute16 AS m_attribute16,  a.attribute16 AS a_attribute16,
            m.attribute17 AS m_attribute17,  a.attribute17 AS a_attribute17,
            m.attribute18 AS m_attribute18,  a.attribute18 AS a_attribute18,
            m.attribute19 AS m_attribute19,  a.attribute19 AS a_attribute19,
            m.attribute20 AS m_attribute20,  a.attribute20 AS a_attribute20
        FROM xx_cmn_int_metadata m
        JOIN xx_cmn_int_audit a
          ON m.RICE_ID = a.RICE_ID
          AND interface_audit_id = p_audit_id
    )
    UNPIVOT (
        (attribute_key, audit_value)
        FOR attr_name IN (
            (m_attribute1,  a_attribute1)  AS 'ATTRIBUTE1',
            (m_attribute2,  a_attribute2)  AS 'ATTRIBUTE2',
            (m_attribute3,  a_attribute3)  AS 'ATTRIBUTE3',
            (m_attribute4,  a_attribute4)  AS 'ATTRIBUTE4',
            (m_attribute5,  a_attribute5)  AS 'ATTRIBUTE5',
            (m_attribute6,  a_attribute6)  AS 'ATTRIBUTE6',
            (m_attribute7,  a_attribute7)  AS 'ATTRIBUTE7',
            (m_attribute8,  a_attribute8)  AS 'ATTRIBUTE8',
            (m_attribute9,  a_attribute9)  AS 'ATTRIBUTE9',
            (m_attribute10, a_attribute10) AS 'ATTRIBUTE10',
            (m_attribute11, a_attribute11) AS 'ATTRIBUTE11',
            (m_attribute12, a_attribute12) AS 'ATTRIBUTE12',
            (m_attribute13, a_attribute13) AS 'ATTRIBUTE13',
            (m_attribute14, a_attribute14) AS 'ATTRIBUTE14',
            (m_attribute15, a_attribute15) AS 'ATTRIBUTE15',
            (m_attribute16, a_attribute16) AS 'ATTRIBUTE16',
            (m_attribute17, a_attribute17) AS 'ATTRIBUTE17',
            (m_attribute18, a_attribute18) AS 'ATTRIBUTE18',
            (m_attribute19, a_attribute19) AS 'ATTRIBUTE19',
            (m_attribute20, a_attribute20) AS 'ATTRIBUTE20'
        )
    )
    WHERE attribute_key IS NOT NULL
);
    END;
END xx_cmn_log_and_audit_pkg;

/
--------------------------------------------------------
--  DDL for Function LOGIN_FUN
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE FUNCTION "TEREXT"."LOGIN_FUN" (p_username IN VARCHAR2, p_password IN VARCHAR2) RETURN BOOLEAN IS
    v_count INTEGER := 0;
BEGIN

    SELECT COUNT(*)
    INTO v_count
    FROM USER_ACCS
    WHERE upper(uname) = upper(p_username)
      AND upper(password) = upper(p_password)
	  ; -- Replace with password hash comparison as needed

    IF v_count = 1 THEN
        RETURN TRUE;
    ELSE
        RETURN FALSE;
    END IF;
EXCEPTION
    WHEN OTHERS THEN
        RETURN FALSE;
END Login_Fun;

