--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE FUNCTION "TEREXT"."TERSLOT_GENERATE_SLOTNUM_SEQ" (
    p_platform IN TEREXT_SLOT_PLATFORM_PREFIX_DTLS.platform%TYPE
) RETURN VARCHAR2
IS
    v_prefix           TEREXT_SLOT_PLATFORM_PREFIX_DTLS.prefix%TYPE;
    v_last_seq         NUMBER;
    v_last_seq_in_plan NUMBER;
    v_next_seq         NUMBER;
BEGIN
    SELECT prefix, NVL(last_seq, 0)
      INTO v_prefix, v_last_seq
      FROM TEREXT_SLOT_PLATFORM_PREFIX_DTLS
     WHERE platform = p_platform;
     --FOR UPDATE;

    SELECT NVL(MAX(TO_NUMBER(REGEXP_SUBSTR(slot_number, '[0-9]+$'))), 0)
      INTO v_last_seq_in_plan
      FROM TEREXT_SLOT_PLAN_DTLS
     WHERE slot_number LIKE v_prefix || '%';

    IF v_last_seq_in_plan > v_last_seq THEN
        v_last_seq := v_last_seq_in_plan;
    END IF;

    v_next_seq := v_last_seq + 1;

    UPDATE TEREXT_SLOT_PLATFORM_PREFIX_DTLS
       SET last_seq = v_next_seq
     WHERE platform = p_platform;

    RETURN v_prefix || v_next_seq;

EXCEPTION
    WHEN NO_DATA_FOUND THEN
        RAISE_APPLICATION_ERROR(
            -20001,
            'No platform prefix row found for platform=' || NVL(TO_CHAR(p_platform), '<NULL>')
        );
END;

